DROP PROCEDURE IF EXISTS `AllCustomerInvoice`;
DELIMITER |
CREATE PROCEDURE `AllCustomerInvoice`(in date1 date,
date2 date)
BEGIN
SELECT B.SOHDId as BillNo
, B.ReferanceNo
, B.DailyId AS DayInvoiceNo
, B.SODate as SalesDate
, B.CustomerName
, A.CustomerAddress
, A.CustomerTelNo
, A.CustomerNICNo
, B.SONetTotal as BillTotal
, B.AdvanceAmount
, C.InvoiceStatus
, B.CreatedOn AS CreatedDate
, F.BranchName
, CASE B.CancelStatus
WHEN 1 THEN 'Cancelled'
ELSE ' '
END AS CancellStatus
, B.CancelRemark
, B.InvoiceStatusId
FROM salesorderhd B
INNER JOIN branch F
ON B.BranchId = F.BranchId
INNER JOIN invoicestatus C
ON B.InvoiceStatusId = C.InvoiceStatusId
LEFT OUTER JOIN customer A
ON A.CustomerId = B.CustomerId
WHERE B.SODate BETWEEN date1 AND date2
ORDER BY B.SODate DESC, B.SOHDId DESC;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `AllCustomerPendingInvoice`;
DELIMITER |
CREATE PROCEDURE `AllCustomerPendingInvoice`()
BEGIN
SELECT B.SOHDId as BillNo
, B.ReferanceNo
, B.SODate as SalesDate
, B.CustomerName
, A.CustomerAddress
, A.CustomerTelNo
, A.CustomerNICNo
, B.SONetTotal as BillTotal
, F.BranchName
FROM salesorderhd B
INNER JOIN branch F
ON B.BranchId = F.BranchId
LEFT OUTER JOIN customer A
ON A.CustomerId = B.CustomerId
WHERE B.PayModeId = 10
and B.CancelStatus = 0
ORDER BY B.SODate DESC, B.SOHDId DESC;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `AllCustomerQuotation`;
DELIMITER |
CREATE PROCEDURE `AllCustomerQuotation`()
BEGIN
SELECT B.SOHDId as QuotationNo
, B.ReferanceNo
, B.SODate as SalesDate
, A.CustomerName
, A.CustomerAddress
, A.CustomerTelNo
, A.CustomerNICNo
, B.SONetTotal as QuotationTotal
, CASE B.CancelStatus
WHEN 1 THEN 'Cancelled'
ELSE ' '
END AS InvoiceStatus
FROM salesquotationhd B
LEFT OUTER JOIN customer A
ON A.CustomerId = B.CustomerId
ORDER BY B.SODate DESC, B.SOHDId DESC;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `AllCustomerSalesReturn`;
DELIMITER |
CREATE PROCEDURE `AllCustomerSalesReturn`()
BEGIN
SELECT B.SOHDId as ReturnNo
, B.ReferanceNo
, B.SODate as ReturnDate
, A.CustomerName
, A.CustomerAddress
, A.CustomerTelNo
, A.CustomerNICNo
, B.SONetTotal as ReturnTotal
FROM salesorderhdreturn B
LEFT OUTER JOIN customer A
ON A.CustomerId = B.CustomerId
ORDER BY B.SODate DESC, B.SOHDId DESC;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `AllKOTPendingInvoice`;
DELIMITER |
CREATE PROCEDURE `AllKOTPendingInvoice`()
BEGIN
SELECT B.SOHDId as BillNo
, B.ReferanceNo
, B.SODate as SalesDate
, B.CustomerName
, A.CustomerAddress
, A.CustomerTelNo
, B.SONetTotal as BillTotal
, J.InvoiceStatus AS InvoiceMode
, B.TableId AS TableNo
, B.CreatedOn AS CreatedDate
, F.BranchName
FROM salesorderhd B
INNER JOIN branch F
ON B.BranchId = F.BranchId
INNER JOIN invoicestatus J
ON B.InvoiceStatusId = J.InvoiceStatusId
LEFT OUTER JOIN customer A
ON A.CustomerId = B.CustomerId
WHERE B.CancelStatus = 0
AND EXISTS(SELECT 1 FROM kot C
WHERE B.SOHDId = C.SOHDId
AND C.PrintStatus = 0)
ORDER BY B.SODate DESC, B.SOHDId DESC;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `AllSupplierGRN`;
DELIMITER |
CREATE PROCEDURE `AllSupplierGRN`()
BEGIN
SELECT A.PIHDId
, A.PINo as InvoiceNo
, A.PIDate as InvoiceDate
, A.SupplierInvoiceNo
, B.SupplierName
, B.Address
, A.ContactPerson
, A.PINetTotal AS InvoiceAmount
, CASE A.ConfirmStatus
WHEN 1 THEN 'Confirmed'
ELSE ' '
END AS ConfirmStatus
, CASE A.CancelStatus
WHEN 1 THEN 'Cancelled'
ELSE ' '
END AS InvoiceStatus
, A.Remarks
FROM pihd A 
INNER JOIN supplier B 
ON A.SupplierId = B.SupplierId
ORDER BY A.PIDate DESC, A.PIHDId DESC;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `CancellVoucher`;
DELIMITER |
CREATE PROCEDURE `CancellVoucher`(in VoucherNo1 int, CreatedBy1 int)
BEGIN
DECLARE UTCDate1 date;
SET UTCDate1 = (select CONVERT_TZ(now(), @@session.time_zone, '+05:30'));
UPDATE giftvoucher
SET CancelStatus = 1
, ModifiedOn = UTCDate1
, ModifiedBy = CreatedBy1
WHERE VoucherNo = VoucherNo1;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `CashHistory`;
DELIMITER |
CREATE PROCEDURE `CashHistory`(in date1 DATE, date2 DATE)
BEGIN
SELECT X.DocDate
, X.DocNo
, X.Memo
, X.InAmount
, X.OutAmount
FROM
(
SELECT SODate AS DocDate
, SOHDId AS DocNo
, 'Cash Bill Sales' AS Memo
, IFNULL(((SONetTotal-ReturnTotal-VoucherAmount-ReturnNoteAmount-AdvanceAmount)), 0) AS InAmount
, 0 AS OutAmount
, 2 AS SeqId
FROM salesorderhd
WHERE (SODate BETWEEN date1 AND date2)
AND (PayModeId = 1)
AND (CancelStatus = 0)
UNION ALL
SELECT SODate AS DocDate
, SOHDId AS DocNo
, 'Other Bill Cash Sales' AS Memo
, IFNULL(((Cash)), 0) AS InAmount
, 0 AS OutAmount
, 3 AS SeqId
FROM salesorderhd
WHERE (SODate BETWEEN date1 AND date2)
AND (PayModeId <> 1)
AND (CancelStatus = 0)
UNION ALL
SELECT PaymentDate AS DocDate
, BillNo AS DocNo
, 'Customer Credit Payment' AS Memo
, IFNULL(((PaymentAmount)),0) AS InAmount
, 0 AS OutAmount
, 4 AS SeqId
FROM custcreditpayment
WHERE (PaymentDate BETWEEN date1 AND date2)
AND (PayModeId = 1)
UNION ALL
SELECT PaymentDate AS DocDate
, CreatedBy AS DocNo
, 'CashIn' AS Memo
, IFNULL(((PaymentAmount)), 0) AS InAmount
, 0 AS OutAmount
, 5 AS SeqId
FROM paidin
WHERE (PaymentDate BETWEEN date1 AND date2)
UNION ALL
SELECT A.PaymentDate
, A.ExpensesId
, CONCAT('Expenses - ', B.CatDescription) AS Memo
, 0 AS InAmount
, IFNULL(((A.PaymentAmount)), 0) AS OutAmount
, 6 AS SeqId
FROM allexpenses A
INNER JOIN expensescategory B
ON A.PayCatId = B.PayCatId
WHERE (A.PaymentDate BETWEEN date1 AND date2)
AND (A.PayModeId = 1)
UNION ALL
SELECT PaymentDate AS DocDate
, BillNo AS DocNo
, 'Supplier Credit Pay' AS Memo
, 0 AS InAmount
, IFNULL(((PaymentAmount)),0) AS OutAmount
, 7 AS SeqId
FROM suppcreditpayment
WHERE (PaymentDate BETWEEN date1 AND date2)
AND (PayModeId = 1)
UNION ALL
SELECT SODate AS DocDate
, SOHDId AS DocNo
, 'SalesReturn1' AS Memo
, 0 AS InAmount
, SONetTotal AS OutAmount
, 8 AS SeqId
FROM salesorderhdreturn
WHERE (CancelStatus = 0)
AND (PayModeId = 1)
AND (SODate BETWEEN date1 AND date2)
UNION ALL
SELECT RtnDate AS DocDate
, SOHDId AS DocNo
, 'SalesReturn2' AS Memo
, 0 AS InAmount
, NetAmount AS OutAmount
, 8 AS SeqId
FROM salesreturn
WHERE (RtnDate BETWEEN date1 AND date2)
UNION ALL
SELECT A.SODate AS DocDate
, A.SOHDId AS DocNo
, 'SalesReturn3' AS Memo
, 0 AS InAmount
, B.NetAmount AS OutAmount
, 8 AS SeqId
FROM salesorderhd A
INNER JOIN directsalesreturn B
ON A.SOHDId = B.SOHDId
WHERE (A.CancelStatus = 0)
AND (A.SODate BETWEEN date1 AND date2)
UNION ALL
SELECT BalanceDate AS DocDate
, CBalanceId AS DocNo
, 'Opening Balance' AS Memo
, IFNULL(((OpeningBalance)),0) AS InAmount
, 0 AS OutAmount
, 1 AS SeqId
FROM cashbalance
WHERE (BalanceDate BETWEEN date1 AND date2)
AND OpeningBalance > 0
UNION ALL
SELECT PIDate AS DocDate
, PINo AS DocNo
, 'Cash Purchasing' AS Memo
, 0 AS InAmount
, PINetTotal - ReturnTotal AS OutAmount
, 9 AS SeqId
FROM pihd
WHERE (CancelStatus = 0)
AND (PayModeId = 1)
AND (PIDate BETWEEN date1 AND date2)
UNION ALL
SELECT PIDate AS DocDate
, PINo AS DocNo
, 'Other Cash Purchasing' AS Memo
, 0 AS InAmount
, PICash AS OutAmount
, 10 AS SeqId
FROM pihd
WHERE (CancelStatus = 0)
AND (PayModeId <> 1)
AND (PIDate BETWEEN date1 AND date2)
AND PICash > 0
UNION ALL
SELECT PIDate AS DocDate
, PINo AS DocNo
, 'Purchase Return Cash' AS Memo
, PINetTotal AS InAmount
, 0 AS OutAmount
, 11 AS SeqId
FROM pihdreturn
WHERE (CancelStatus = 0)
AND (PayModeId = 1)
AND (PIDate BETWEEN date1 AND date2)
UNION ALL
SELECT SODate AS DocDate
, SOHDId AS DocNo
, 'Advance Payment' AS Memo
, AdvanceAmount AS InAmount
, 0 AS OutAmount
, 12 AS SeqId
FROM sohd
WHERE (CancelStatus = 0)
AND (SODate BETWEEN date1 AND date2)
UNION ALL
SELECT IssueDate AS DocDate
, VoucherNo AS DocNo
, 'Issued Voucher' AS Memo
, IFNULL(((VoucherAmount)), 0) AS InAmount
, 0 AS OutAmount
, 13 AS SeqId
FROM giftvoucher
WHERE (IssueDate BETWEEN date1 AND date2)
AND (CancelStatus = 0)
)X
ORDER BY X.DocDate, X.SeqId, X.Memo, X.DocNo;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `CustomerAdvAll`;
DELIMITER |
CREATE PROCEDURE `CustomerAdvAll`(in date1 DATE, date2 DATE)
BEGIN
SELECT X.CustomerId
, X.CustomerName
, X.BillNo
, X.DocDate
, X.Memo
, X.Debit
, X.Credit
, date1 as FromDate
, date2 AS ToDate
FROM
(
SELECT A.CustomerId
, B.CustomerName
, 0 AS BillNo
, A.AdvanceDate AS DocDate
, 'Advance Amount' AS Memo
, A.AdvanceAmount AS Debit
, 0 AS Credit
FROM custadvance A
INNER JOIN customer B
ON A.CustomerId = B.CustomerId
WHERE (A.AdvanceDate BETWEEN date1 AND date2)
UNION ALL
SELECT A.CustomerId
, B.CustomerName
, A.SOHDId AS BillNo
, A.UsedDate AS DocDate
, 'Pay Bill By Advance' AS Memo
, 0 AS Debit
, A.UsedAmount AS Credit
FROM custadvanceusage A
INNER JOIN customer B
ON A.CustomerId = B.CustomerId
WHERE (A.UsedDate BETWEEN date1 AND date2)
)X
ORDER BY X.CustomerName, X.DocDate;
END |
DELIMITER ;

