DROP PROCEDURE IF EXISTS `CustomerHistoryAll`;
DELIMITER |
CREATE PROCEDURE `CustomerHistoryAll`(in date1 DATE, date2 DATE)
BEGIN
SELECT X.CustomerId
, X.CustomerName
, X.Id
, X.DocDate
, X.Memo
, X.Debit
, X.Credit
, date1 as FromDate
, date2 AS ToDate
FROM
(
SELECT A.CustomerId
, B.CustomerName
, A.BillNo AS Id
, A.CreditDate AS DocDate
, 'Credit - Opening Balance' AS Memo
, A.CreditAmount AS Debit
, 0 AS Credit
FROM customercredit A
INNER JOIN customer B
ON A.CustomerId = B.CustomerId
WHERE (A.CreditDate BETWEEN date1 AND date2)
AND (A.BillNo = 0)
UNION ALL
SELECT A.CustomerId
, B.CustomerName
, A.BillNo AS Id
, A.CreditDate AS DocDate
, 'Credit - Credit Sale' AS Memo
, A.CreditAmount AS Debit
, 0 AS Credit
FROM customercredit A
INNER JOIN customer B
ON A.CustomerId = B.CustomerId
WHERE (A.CreditDate BETWEEN date1 AND date2)
AND (A.BillNo <> 0)
UNION ALL
SELECT A.CustomerId
, B.CustomerName
, A.BillNo AS Id
, A.PaymentDate AS DocDate
, CONCAT('[Credit Payment]', C.PayMode) AS Memo
, 0 AS Debit
, A.PaymentAmount AS Credit
FROM custcreditpayment A
INNER JOIN customer B
ON A.CustomerId = B.CustomerId
INNER JOIN paymentmode C
ON A.PayModeId = C.PayModeId
WHERE (A.PaymentDate BETWEEN date1 AND date2)
)X
ORDER BY X.CustomerName, X.DocDate;
END |
