DROP PROCEDURE IF EXISTS `CustomerInvoiceCredit`;
DELIMITER |
CREATE PROCEDURE `CustomerInvoiceCredit`(in
CustomerId1 int
, BillNo1 int
, CreditAmount1 DECIMAL(20,2)
, CreatedBy1 int
, CreditDueDays1 int)
BEGIN
UPDATE customer
SET BalanceAmount = BalanceAmount + CreditAmount1
WHERE (CustomerId = CustomerId1);
INSERT INTO customercredit
(CustomerId
, BillNo
, CreditDate
, CreditAmount
, CreatedOn
, CreatedBy
, BalanceAmount
, CreditDueDate
, NextDueDate
, CreditDueDays
, CreditDueDayDate)
VALUES (CustomerId1
, BillNo1
, CONVERT_TZ(now(), @@session.time_zone, '+05:30')
, CreditAmount1
, CONVERT_TZ(now(), @@session.time_zone, '+05:30')
, CreatedBy1
, CreditAmount1
, (SELECT DATE_ADD(NOW(), INTERVAL 14 DAY))
, (SELECT DATE_ADD(NOW(), INTERVAL 14 DAY))
, CreditDueDays1
, (SELECT DATE_ADD(NOW(), INTERVAL (CASE WHEN CreditDueDays1 = 0 THEN 1 ELSE CreditDueDays1 END) DAY))
);
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `CustomerOutstandingPaymentReport`;
DELIMITER |
CREATE PROCEDURE `CustomerOutstandingPaymentReport`(CustomerId1 int)
BEGIN
DECLARE TotalBalance1 DECIMAL(10,2) DEFAULT 0;
SELECT (SUM(A.CreditAmount) - IFNULL(SUM(D.PaymentAmount), 0)) INTO TotalBalance1
FROM customercredit A
LEFT OUTER JOIN (SELECT Z.CustomerId, SUM(Z.PaymentAmount) AS PaymentAmount, Z.BillNo
FROM custcreditpayment Z
WHERE Z.CustomerId = CustomerId1
AND Z.PaymentAmount > 0
GROUP BY Z.CustomerId, Z.BillNo) D
ON A.CustomerId = D.CustomerId
AND A.BillNo = D.BillNo
WHERE A.CustomerId = CustomerId1
AND A.CreditAmount > 0;
SELECT B.CustomerName
, B.ContactPerson as CustomerCode
, B.CustomerAddress
, B.CustomerTelNo
, A.BillNo
, A.CreditDate
, A.CreditAmount
, IFNULL(D.PaymentAmount, 0) AS TotalPayment
, (A.CreditAmount - IFNULL(D.PaymentAmount, 0)) AS BalanceAmount
, C.CreditPayHDId AS PaymentReceiptNo
, C.PaymentDate
, C.PaymentAmount
, E.CompanyName
, E.CompanyAddress1
, E.CompanyAddress2
, E.ContactNo1
, E.ContactNo2
, E.Web
, E.Email
, E.CompanyLogo
, A.CustomerId
, TotalBalance1 AS TotalBalance
FROM customercredit A
INNER JOIN customer B
ON A.CustomerId = B.CustomerId
LEFT OUTER JOIN (SELECT Z.CustomerId, Z.PaymentDate, SUM(Z.PaymentAmount) AS PaymentAmount, Z.BillNo, Z.CreditPayHDId
FROM custcreditpayment Z
WHERE Z.CustomerId = CustomerId1
AND Z.PaymentAmount > 0
GROUP BY Z.CustomerId, Z.PaymentDate, Z.BillNo, Z.CreditPayHDId) C
ON A.CustomerId = C.CustomerId
AND A.BillNo = C.BillNo
LEFT OUTER JOIN (SELECT Z.CustomerId, SUM(Z.PaymentAmount) AS PaymentAmount, Z.BillNo
FROM custcreditpayment Z
WHERE Z.CustomerId = CustomerId1
AND Z.PaymentAmount > 0
GROUP BY Z.CustomerId, Z.BillNo) D
ON A.CustomerId = D.CustomerId
AND A.BillNo = D.BillNo
, companyinfo E
WHERE A.CustomerId = CustomerId1
AND A.CreditAmount > 0;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `CustomerOutstandingReport`;
DELIMITER |
CREATE PROCEDURE `CustomerOutstandingReport`(CustomerId1 int)
BEGIN
DECLARE UTCDate1 date;
SET UTCDate1 = (select CONVERT_TZ(now(), @@session.time_zone, '+05:30'));
SELECT B.ContactPerson AS CustomerCode
, B.CustomerName
, B.CustomerAddress
, B.CustomerTelNo
, B.CustomerFaxNo
, B.CustomerEmail
, IFNULL(C.SODate, A.CreditDate) AS CreditDate
, A.BillNo
,((SELECT DATEDIFF(CreditDate, CONVERT_TZ(now(), @@session.time_zone, '+05:30'))
FROM customercredit
WHERE (BillNo = A.BillNo)
AND (CustomerId = A.CustomerId)) * -1) AS DueDays
, A.CreditAmount
,(SELECT CreditAmount - PaymentAmount
FROM customercredit
WHERE (BillNo = A.BillNo)
AND (CustomerId = A.CustomerId)) AS BalanceAmount
, (SELECT IFNULL(SUM(CreditAmount),0) - IFNULL(SUM(PaymentAmount),0) AS CreditAmount
FROM customercredit
WHERE (CreditDate = UTCDate1)
AND (CustomerId = CustomerId1)) AS CurrentDay
, (SELECT IFNULL(SUM(CreditAmount),0) - IFNULL(SUM(PaymentAmount),0) AS CreditAmount
FROM customercredit
WHERE (CreditDate < UTCDate1)
AND (CreditDate > (NOW() - INTERVAL 31 DAY))
AND (CustomerId = CustomerId1)) AS OnetoThirty
, (SELECT IFNULL(SUM(CreditAmount),0) - IFNULL(SUM(PaymentAmount),0) AS CreditAmount
FROM customercredit
WHERE (CreditDate < (NOW() - INTERVAL 30 DAY))
AND (CreditDate > (NOW() - INTERVAL 61 DAY))
AND (CustomerId = CustomerId1)) AS ThirtyoneToSixty
, (SELECT IFNULL(SUM(CreditAmount),0) - IFNULL(SUM(PaymentAmount),0) AS CreditAmount
FROM customercredit
WHERE (CreditDate < (NOW() - INTERVAL 60 DAY))
AND (CreditDate > (NOW() - INTERVAL 91 DAY))
AND (CustomerId = CustomerId1)) AS SixtyonetoNinty
, (SELECT IFNULL(SUM(CreditAmount),0) - IFNULL(SUM(PaymentAmount),0) AS CreditAmount
FROM customercredit
WHERE (CreditDate < (NOW() - INTERVAL 90 DAY))
AND (CreditDate > (NOW() - INTERVAL 121 DAY))
AND (CustomerId = CustomerId1)) AS NintyOneToOneTwenty
, (SELECT IFNULL(SUM(CreditAmount),0) - IFNULL(SUM(PaymentAmount),0) AS CreditAmount
FROM customercredit
WHERE (CreditDate < (NOW() - INTERVAL 120 DAY))
AND (CustomerId = CustomerId1)) AS OverOneTwenty
, D.CompanyName
, D.CompanyAddress1
, D.CompanyAddress2
, D.ContactNo1
, D.ContactNo2
, D.Web
, D.Email
, A.CustomerId
FROM customercredit A
INNER JOIN customer B
ON A.CustomerId = B.CustomerId
LEFT OUTER JOIN salesorderhd C
ON A.BillNo = C.SOHDId
, companyinfo D
WHERE (A.CreditAmount > 0)
AND(A.PaymentCompletedStatus = 0)
AND (A.CustomerId = CustomerId1);
END |
DELIMITER ;

