DROP PROCEDURE IF EXISTS `DeleteExpense`;
DELIMITER |
CREATE PROCEDURE `DeleteExpense`(in ExpensesId1 int)
BEGIN
DECLARE AdvanceID1 INT DEFAULT 0;
DECLARE PaymentID1 INT DEFAULT 0;
IF EXISTS (SELECT 1 FROM allexpenses WHERE (ExpensesId = ExpensesId1) AND (IsAdvance = 1)) THEN
BEGIN
SELECT AdvanceID INTO AdvanceID1
FROM allexpenses
where ExpensesId = ExpensesId1;
DELETE FROM employeeadvance
WHERE AdvanceID = AdvanceID1
AND AdvanceID <> 0;
END;
END IF;
IF EXISTS (SELECT 1 FROM allexpenses WHERE (ExpensesId = ExpensesId1) AND (IsSalary = 1)) THEN
BEGIN
SELECT PaymentID INTO PaymentID1
FROM allexpenses
where ExpensesId = ExpensesId1;
DELETE FROM employeepayment
WHERE PaymentID = PaymentID1
AND PaymentID <> 0;
END;
END IF;
DELETE FROM allexpenses
WHERE (ExpensesId = ExpensesId1);
END |
DELIMITER ;

