DELIMITER |
CREATE PROCEDURE `DeletePermission`(in USERROLEID1 int, USERID1 int)
BEGIN
DECLARE ROLEID1 INT DEFAULT 0;
IF(USERID1 = 1)THEN
BEGIN
SELECT ROLE_ID INTO ROLEID1
FROM user_roles
WHERE (USER_ROLE_ID =  USERROLEID1);
UPDATE roles
SET ApprovedRole = 0
WHERE ROLE_ID = ROLEID1;
END;
END IF;
DELETE
FROM user_roles
WHERE (USER_ROLE_ID =  USERROLEID1);
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `DeletePODT`;
DELIMITER |
CREATE PROCEDURE `DeletePODT`(in
PODTId1 int
, POHDId1 int
, ItemCode1 VARCHAR(50)
, PurchaseQty1 decimal(10, 2)
, SupplierId1 int)
BEGIN
DELETE FROM purchaseorderdt
WHERE (PODTId = PODTId1);
UPDATE itemsummary
SET AvailableQty = AvailableQty - PurchaseQty1
WHERE (ItemCode = ItemCode1);
if exists (SELECT POHDId, PayModeId FROM purchaseorderhd WHERE (POHDId = POHDId1) AND ((PayModeId = 3) OR (PayModeId = 4))) THEN
begin
UPDATE supplier
SET BalanceAmount = BalanceAmount - PurchaseQty1
WHERE (SupplierId = SupplierId1);
UPDATE suppliercredit
SET CreditAmount = CreditAmount - PurchaseQty1
, BalanceAmount = BalanceAmount - PurchaseQty1
WHERE (POHDId = POHDId1);
END;
END IF;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `DeletePOHD`;
DELIMITER |
CREATE PROCEDURE `DeletePOHD`(in POHDId1 int, SupplierId1 int, BalanceAmount1 decimal(10, 2))
BEGIN
declare sumDTAmount int;
if exists (SELECT POHDId, PayModeId FROM purchaseorderhd WHERE (POHDId = POHDId1) AND ((PayModeId = 3) OR (PayModeId = 4))) THEN
begin
UPDATE supplier
SET BalanceAmount = BalanceAmount - BalanceAmount1
WHERE (SupplierId = SupplierId1);
END;
END IF;
DELETE FROM suppliercredit
WHERE (POHDId = POHDId1);
DELETE FROM purchaseorderdt
WHERE (POHDId = POHDId1);
