DROP PROCEDURE IF EXISTS `ImportPIDT`;
DELIMITER |
CREATE PROCEDURE `ImportPIDT`(in
PIHDId1 BIGINT(20),
ItemCode1 VARCHAR(50),
PurchaseQty1 decimal(10, 2),
PurchasePrice1 decimal(10, 2),
NetAmount1 decimal(10, 2),
CreatedBy1 int,
PurchaseDate1 date,
BranchId1 int,
Discount1 decimal(10, 2),
AddBarcode1 bool)
BEGIN
DECLARE ItemsId1 int DEFAULT 0;
DECLARE i INT DEFAULT 0;
SELECT IFNULL(ItemsId, 0) INTO ItemsId1
FROM itemsummary
WHERE (ItemCode = ItemCode1);
if(ItemsId1 <> 0) then
begin
INSERT INTO pidt
(PIHDId
, ItemsId
, ItemCode
, ItemCatId
, ItemUnit
, PurchaseQty
, MinQty
, PurchasePrice
, SellingPrice
, FreeIssue
, NetAmount
, CreatedOn
, CreatedBy
, Discount)
SELECT PIHDId1
, ItemsId
, ItemCode1
, ItemCatId
, ItemUnit
, PurchaseQty1
, MinQty
, PurchasePrice1
, SellingPrice
, 0
, NetAmount1
, CONVERT_TZ(now(), @@session.time_zone, '+05:30')
, CreatedBy1
, Discount1
FROM itemsummary
WHERE (ItemsId = ItemsId1);
INSERT INTO purchasing
(ItemCode
, ItemCatId
, ItemName
, ItemUnit
, CostPrice
, PurhaseQty
, PurchasedDate
, OpenBalStatus
, SupplierId)
SELECT
ItemCode1
, A.ItemCatId
, A.ItemName
, A.ItemUnit
, PurchasePrice1
, PurchaseQty1
, PurchaseDate1
, 0
, B.SupplierId
FROM itemsummary A
, pihd B
WHERE (A.ItemsId = ItemsId1)
AND (B.PIHDId = PIHDId1);
if(AddBarcode1 = true) then
begin
WHILE i < PurchaseQty1 DO
INSERT INTO barcodeitem
(ItemsId
, ItemCode
, ItemName
, InternalNo
, BCQty
, BCPrice
, BCStart
, BCEnd)
SELECT
ItemsId1
, ItemCode1
, A.ItemName
, 'PI'
, PurchaseQty1
, A.SellingPrice
, 1
, 1
FROM itemsummary A
, pihd B
WHERE (A.ItemsId = ItemsId1);
SET i = i + 1;
END WHILE;
end;
end if;
IF EXISTS (SELECT 1 FROM branchstock WHERE ItemsId = ItemsId1 AND BranchId = BranchId1) THEN
BEGIN
UPDATE branchstock
SET  AvailableQty = AvailableQty + PurchaseQty1
WHERE BranchId = BranchId1
AND ItemsId = ItemsId1;
END;
ELSE
BEGIN
INSERT INTO branchstock
(BranchId
, ItemsId
, ItemCode
, AvailableQty)
VALUES
(BranchId1
, ItemsId1
, ItemCode1
, PurchaseQty1);
END;
END IF;
UPDATE itemsummary
SET CostPrice = PurchasePrice1
, AvailableQty = AvailableQty + PurchaseQty1
WHERE (ItemsId = ItemsId1);
end;
end if;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ImportStock`;
DELIMITER |
CREATE PROCEDURE `ImportStock`(in
ItemCode1 VARCHAR(50),
ItemCategory1 VARCHAR(50),
ItemName1 VARCHAR(150),
Discount1 decimal(10, 2),
ItemUnit1 varchar(45),
CostPrice1 decimal(10, 2),
SellingPrice1 decimal(10, 2),
SellingPrice2 decimal(10, 2),
MinQty1 decimal(10, 2),
AvailableQty1 decimal(10, 2),
ItemMode1 varchar(20),
OpenBalDate1 date,
CreatedBy1 int,
InQty1 decimal(10, 2),
InValue1 decimal(10, 2),
OutQty1 decimal(10, 2),
OutValue1 decimal(10, 2),
OpenStates int,
SItemName1 varchar(150),
ItemStatus varchar(10),
SupplierId1 int,
WarrantyPeriod1 VARCHAR(20),
FreeIssueEffectFrom1 INT,
SPPRiceEffectFrom1 decimal(10, 2),
BranchId1 int,
RackNo1 VARCHAR(25),
ItemSubCateory1 VARCHAR(50),
DefaultCostPrice1 decimal(10, 2),
AddBarcode1 bool,
WholeSaleDiscount1 decimal(10, 2),
ShopPrice1 decimal(10, 2),
MinSellingPrice1 decimal(10, 2),
RetailDiscPer1 decimal(10, 2),
WholesaleDiscPer1 decimal(10, 2),
MaintainQty1 decimal(10, 2),
SerialNo1 VARCHAR(45),
TItemName1 VARCHAR(150),
ScaleItem1 TINYINT(1),
BundleItem1 TINYINT(1),
RawMaterial1 TINYINT(1),
AllowSales1 TINYINT(1),
AllowPurchase1 TINYINT(1),
AllowInventory1 TINYINT(1),
SearchText1 VARCHAR(200),
CostCode1 VARCHAR(45)
)
BEGIN
DECLARE NewItemsId1 int DEFAULT 0;
DECLARE ItemCatId1 int DEFAULT 0;
DECLARE ItemSubCatId1 int DEFAULT 0;
DECLARE i INT DEFAULT 0;
SELECT IFNULL(ItemCatId, 0) INTO ItemCatId1
FROM itemcategory
WHERE (ItemCatName = ItemCategory1);
SELECT IFNULL(ItemSubCatId, 0) INTO ItemSubCatId1
FROM itemsubcategory
WHERE (ItemCatId = ItemCatId1)
AND (ItemSubCatName = ItemSubCateory1);
IF NOT EXISTS (SELECT 1 FROM itemsummary WHERE (ItemCode = ItemCode1)) THEN
BEGIN
INSERT INTO itemsummary
(ItemMode
, ItemCode
, ItemCatId
, ItemName
, Discount
, ItemUnit
, CostPrice
, SellingPrice
, SPSellingPrice
, MinQty
, AvailableQty
, PurchasedDate
, SItemName
, NewStatus
, OpenBalStatus
, WarrantyPeriod
, FreeIssueEffectFrom
, SPPRiceEffectFrom
, RackNo
, ItemSubCatId
, DefaultCostPrice
, OpenBalQty
, WholeSaleDiscount
, ShopPrice
, AvgCost
, MinSellingPrice
, RetailDiscPer
, WholesaleDiscPer
, MaintainQty
, TItemName
, ScaleItem
, BundleItem
, RawMaterial
, AllowSales
, AllowPurchase
, AllowInventory
, SearchText
, CostCode)
VALUES
(ItemMode1
,ItemCode1
,ItemCatId1
,ItemName1
,Discount1
,ItemUnit1
,CostPrice1
,SellingPrice1
,SellingPrice2
,MinQty1
,AvailableQty1
,OpenBalDate1
,SItemName1
,1
,1
,WarrantyPeriod1
,FreeIssueEffectFrom1
,SPPRiceEffectFrom1
,RackNo1
,ItemSubCatId1
,DefaultCostPrice1
,AvailableQty1
,WholeSaleDiscount1
,ShopPrice1
,CostPrice1
,MinSellingPrice1
,RetailDiscPer1
,WholesaleDiscPer1
,MaintainQty1
,TItemName1
, ScaleItem1
, BundleItem1
, RawMaterial1
, AllowSales1
, AllowPurchase1
, AllowInventory1
, SearchText1
, CostCode1);
SET NewItemsId1 = LAST_INSERT_ID();
IF (SellingPrice1 > 0) THEN
BEGIN
INSERT INTO itemretailprice
(ItemsId
, ItemCode
, RetailPrice)
VALUES
(NewItemsId1
, ItemCode1
, SellingPrice1);
END;
END IF;
IF (SellingPrice2 > 0) THEN
BEGIN
INSERT INTO itemwholesaleprice
(ItemsId
, ItemCode
, WholesalePrice)
VALUES
(NewItemsId1
, ItemCode1
, SellingPrice2);
END;
END IF;
IF (ShopPrice1 > 0) THEN
BEGIN
INSERT INTO itemshopprice
(ItemsId
, ItemCode
, ShopPrice)
VALUES
(NewItemsId1
, ItemCode1
, ShopPrice1);
END;
END IF;
IF(SerialNo1 <> '') THEN
BEGIN
INSERT INTO serialpurchase
(
SerialNo
,PurchaseDate
,ItemsId
,PIHDId
)
VALUES(SerialNo1
, CONVERT_TZ(now(), @@session.time_zone, '+05:30')
, NewItemsId1
,0
);
END;
END IF;
INSERT INTO branchstock
(BranchId
, ItemsId
, ItemCode
, AvailableQty
, RackNo)
SELECT BranchId
, NewItemsId1
, ItemCode1
, 0
, RackNo1
FROM branch
WHERE BranchId <> BranchId1;
INSERT INTO branchstock
(BranchId
, ItemsId
, ItemCode
, AvailableQty
, RackNo)
SELECT BranchId
, NewItemsId1
, ItemCode1
, AvailableQty1
, RackNo1
FROM branch
WHERE BranchId = BranchId1;
END;
ELSE
BEGIN
SELECT ItemsId INTO NewItemsId1
FROM itemsummary
WHERE ItemCode = ItemCode1;
IF NOT EXISTS (SELECT 1 FROM itemretailprice WHERE (ItemsId = NewItemsId1) AND (RetailPrice = SellingPrice1)) THEN
BEGIN
INSERT INTO itemretailprice
(ItemsId
, ItemCode
, RetailPrice)
VALUES
(NewItemsId1
, ItemCode1
, SellingPrice1);
END;
END IF;
IF NOT EXISTS (SELECT 1 FROM itemwholesaleprice WHERE (ItemsId = NewItemsId1) AND (WholesalePrice = SellingPrice2)) THEN
BEGIN
INSERT INTO itemwholesaleprice
(ItemsId
, ItemCode
, WholesalePrice)
VALUES
(NewItemsId1
, ItemCode1
, SellingPrice2);
END;
END IF;
IF NOT EXISTS (SELECT 1 FROM itemshopprice WHERE (ItemsId = NewItemsId1) AND (ShopPrice = ShopPrice1)) THEN
BEGIN
INSERT INTO itemshopprice
(ItemsId
, ItemCode
, ShopPrice)
VALUES
(NewItemsId1
, ItemCode1
, ShopPrice1);
END;
END IF;
UPDATE itemsummary
SET SellingPrice = CASE SellingPrice1 WHEN 0 THEN SellingPrice ELSE SellingPrice1 END
, SPSellingPrice = CASE SellingPrice2 WHEN 0 THEN SPSellingPrice ELSE SellingPrice2 END
, CostPrice = CASE CostPrice1 WHEN 0 THEN CostPrice ELSE CostPrice1 END
, ShopPrice = CASE ShopPrice1 WHEN 0 THEN ShopPrice ELSE ShopPrice1 END
WHERE ItemsId = NewItemsId1;
IF(SerialNo1 <> '') THEN
BEGIN
INSERT INTO serialpurchase
(
SerialNo
,PurchaseDate
,ItemsId
,PIHDId
)
VALUES(SerialNo1
, CONVERT_TZ(now(), @@session.time_zone, '+05:30')
, NewItemsId1
,0
);
END;
END IF;
END;
END IF;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ImportStockQty`;
DELIMITER |
CREATE PROCEDURE `ImportStockQty`(in
ItemCode1 VARCHAR(50),
AvailableQty1 decimal(10, 2)
)
BEGIN
DECLARE NewItemsId1 int DEFAULT 0;
DECLARE ItemsCostPrice1 DECIMAL(20,2) DEFAULT 0;
DECLARE CurrentQty1 DECIMAL(20,2) DEFAULT 0;
SELECT ItemsId, CostPrice, AvailableQty INTO NewItemsId1, ItemsCostPrice1, CurrentQty1
FROM itemsummary
WHERE ItemCode = ItemCode1;
UPDATE itemsummary
SET AvailableQty = AvailableQty1
WHERE ItemsId = NewItemsId1;
UPDATE branchstock
SET  AvailableQty = 0
WHERE BranchId <> 1
AND ItemsId = NewItemsId1;
UPDATE branchstock
SET  AvailableQty = AvailableQty1
WHERE BranchId = 1
AND ItemsId = NewItemsId1;
INSERT INTO importstockqty
(BranchId
, ItemsId
, ItemCode
, AvailableQty
, PreviousQty
, QtyDifferent
, CostPrice
, CreatedOn
, StockImportDate)
VALUES
(1
, NewItemsId1
, ItemCode1
, AvailableQty1
, CurrentQty1
, (AvailableQty1 - CurrentQty1)
, ItemsCostPrice1
, CONVERT_TZ(now(), @@session.time_zone, '+05:30')
, CONVERT_TZ(now(), @@session.time_zone, '+05:30')
);
END |
DELIMITER ;

