CREATE PROCEDURE `InsertAdvance`(in
EmployeeID1 int
, Amount1 int
, AdvanceDate1 date
, CreatedBy1 int)
BEGIN
DECLARE UTCDate1 date;
DECLARE AdvanceID1 INT DEFAULT 0;
SET UTCDate1 = (select CONVERT_TZ(now(), @@session.time_zone, '+05:30'));
UPDATE cashbalance
SET CashOutAmount = CashOutAmount + Amount1
, LastBalance = LastBalance - Amount1
WHERE (UserId = CreatedBy1)
AND (BalanceDate = UTCDate1);
INSERT INTO employeeadvance
(EmployeeID
, Amount
, AdvanceDate)
VALUES (EmployeeID1
, Amount1
, AdvanceDate1);
SET AdvanceID1 = LAST_INSERT_ID();
INSERT INTO allexpenses
(PayCatId
, PaymentDate
, PaymentAmount
, RefId
, CreatedOn
, CreatedBy
, AdvanceID
, IsAdvance)
VALUES (1
, AdvanceDate1
