CREATE PROCEDURE `InsertBarcodeItems`(in ItemCode1 VARCHAR(50))
BEGIN
DECLARE ItemsId1 INT;
DECLARE ItemName1 VARCHAR(150);
DECLARE InternalNo1 VARCHAR(20);
DECLARE BCQty1 decimal(10, 2);
DECLARE BCPrice1 decimal(10, 2);
DECLARE i INT DEFAULT 0;
SELECT ItemsId INTO ItemsId1
FROM itemsummary
where ItemCode = ItemCode1;
SELECT ItemName INTO ItemName1
FROM itemsummary
where ItemCode = ItemCode1;
SELECT RackNo INTO InternalNo1
FROM itemsummary
where ItemCode = ItemCode1;
SELECT AvailableQty INTO BCQty1
FROM itemsummary
where ItemCode = ItemCode1;
SELECT SellingPrice INTO BCPrice1
FROM itemsummary
where ItemCode = ItemCode1;
WHILE i < BCQty1 DO
INSERT INTO barcodeitem
(ItemsId
, ItemCode
, ItemName
, InternalNo
, BCQty
, BCPrice
, BCStart
, BCEnd)
VALUES (ItemsId1
, ItemCode1
, ItemName1
, InternalNo1
, BCQty1
, BCPrice1
, 1
, 1);
SET i = i + 1;
END WHILE;
END |
DELIMITER ;

