, BillNo1 int
, PayModeId1 int
, CardChequeNo1 varchar(45)
, CreditPayHDId1 int
, ReciptNo1 VARCHAR(20)
, BankId1 int)
BEGIN
DECLARE UTCDate1 date;
SET UTCDate1 = (select CONVERT_TZ(now(), @@session.time_zone, '+05:30'));
INSERT INTO custcreditpayment
(CustomerId
, PaymentDate
, PaymentAmount
, PayModeId
, CardChequeNo
, BillNo
, CreditPayHDId
, CreatedBy
, CreatedOn
, ReciptNo
, BankId
)
VALUES (CustomerId1
, PaymentDate1
, PaymentAmount1
, PayModeId1
, CardChequeNo1
, BillNo1
, CreditPayHDId1
, UserId1
, CONVERT_TZ(now(), @@session.time_zone, '+05:30')
, ReciptNo1
, BankId1);
UPDATE customer
SET BalanceAmount = BalanceAmount - PaymentAmount1
WHERE (CustomerId = CustomerId1);
IF(PayModeId1 = 1) THEN
BEGIN
UPDATE cashbalance
SET LastBalance = LastBalance + PaymentAmount1
, CashInAmount = CashInAmount + PaymentAmount1
WHERE (UserId = UserId1)
AND (BalanceDate = UTCDate1);
END;
ELSEIF(PayModeId1 = 6) THEN
BEGIN
UPDATE customer
SET AdvanceAmount = AdvanceAmount - PaymentAmount1
WHERE (CustomerId = CustomerId1);
INSERT INTO custadvanceusage
(CustomerId
, SOHDId
, UsedDate
, UsedAmount
, CreatedBy
, CreatedOn)
