, CONVERT_TZ(now(), @@session.time_zone, '+05:30')
, PaymentAmount1
, 0
, CONVERT_TZ(now(), @@session.time_zone, '+05:30'));
END;
END IF;
if exists(SELECT 1 FROM customercredit WHERE CustomerId = CustomerId1 AND BillNo = BillNo1 AND CreditAmount <= PaymentAmount1+PaymentAmount) then
begin
UPDATE customercredit
SET PaymentCompletedStatus = 1
WHERE (BillNo = BillNo1)
AND (CustomerId = CustomerId1);
end;
end if;
UPDATE customercredit
SET PaymentDate = PaymentDate1
, PaymentAmount = PaymentAmount + PaymentAmount1
, BalanceAmount = BalanceAmount - PaymentAmount1
, LastPayment = PaymentAmount1
WHERE (BillNo = BillNo1)
AND (CustomerId = CustomerId1);
END |
