DROP PROCEDURE IF EXISTS `InsertCustomerTotalPayment`;
DELIMITER |
CREATE PROCEDURE `InsertCustomerTotalPayment`(in CustomerId1 int, PaymentDate1 date, TotalBalance1 DECIMAL(20,2), PaymentAmount1 DECIMAL(20,2), UserId1 int)
BEGIN
DECLARE minbill, maxbill INT DEFAULT 0;
SET maxbill = (SELECT MAX(BillNo)
FROM tempcustomercredit
WHERE (CustomerId = CustomerId1));
SET minbill = (SELECT MIN(BillNo)
FROM tempcustomercredit
WHERE (CustomerId = CustomerId1));
UPDATE customercredit A
INNER JOIN tempcustomercredit B
ON A.CustomerId = B.CustomerId
AND A.BillNo = B.BillNo
SET  A.PaymentCompleteStatus = 1
, A.TotalPayment = B.TotalPayment + B.BalanceAmount
, A.LastPayment = B.BalanceAmount
, A.BalanceAmount = 0
WHERE A.CustomerId = CustomerId1;
IF TotalBalance1 > 0 THEN
UPDATE customercredit
SET  PaymentCompleteStatus = 0
, LastPayment = TotalPayment - TotalBalance1
, TotalPayment = TotalPayment - TotalBalance1
, BalanceAmount = TotalBalance1
WHERE CustomerId = CustomerId1
AND BillNo = maxbill
AND maxbill <> minbill;
END IF;
INSERT INTO custcreditpayment
(CustomerId, BillNo, PaymentDate, PaymentAmount)
SELECT       customercredit.CustomerId, customercredit.BillNo,PaymentDate1,customercredit.LastPayment
FROM         customercredit
INNER JOIN tempcustomercredit
ON customercredit.CustomerId = tempcustomercredit.CustomerId
AND customercredit.BillNo = tempcustomercredit.BillNo
WHERE (customercredit.CustomerId = CustomerId1);
UPDATE  customer
SET     BalanceAmount = BalanceAmount - PaymentAmount1
WHERE   (CustomerId = CustomerId1);
UPDATE  cashbalance
SET     LastBalance = LastBalance + PaymentAmount1
, CashInAmount = CashInAmount + PaymentAmount1
WHERE   (UserId = UserId1)
AND (BalanceDate = CURDATE());
TRUNCATE TABLE tempcustomercredit;
END |
DELIMITER ;

