IF EXISTS (SELECT 1 FROM fixedassetdepreciation WHERE (AssetId = AssetId1)) THEN
BEGIN
INSERT INTO fixedassetdepreciation
(AssetId
,LineId
,DepreciationDate
,DepreciationAmount
,NetValue
,DepreciatedUserId
,DepreciatedDate
,CreatedDate
)
