, RemainingDepreciationPeriod = RemainingDepreciationPeriod - 1
, NextDepreciationDate = (SELECT DATE_ADD(NextDepreciationDate, INTERVAL 1 MONTH))
, LastDepreciationDate = UTCDate1
WHERE FAId = AssetId1;
end;
end if;
END |
