DROP PROCEDURE IF EXISTS `InsertInvoiceCancellation`;
DELIMITER |
CREATE PROCEDURE `InsertInvoiceCancellation`(in
SOHDId1 INT,
ModifiedBy1 INT,
RtnReason1 varchar(100)
)
BEGIN
DECLARE PayModeId1 INT;
DECLARE CustomerId1 INT;
DECLARE Amount1 decimal;
DECLARE UTCDate1 date;
DECLARE BranchId1 INT;
DECLARE InvoiceDate1 date;
DECLARE LoyaltyPoints1 DECIMAL(20,2);
DECLARE DirectReturnAmount1 DECIMAL(20,2) DEFAULT 0;
declare AdvanceAmount1 DECIMAL(20,2) DEFAULT 0;
DECLARE CreatedBy1 INT;

SET UTCDate1 = (select CONVERT_TZ(now(), @@session.time_zone, '+05:30'));

IF EXISTS (SELECT 1 FROM salesorderhd WHERE SOHDId = SOHDId1 AND CancelStatus = 0) THEN
begin

SELECT CustomerId, PayModeId, BranchId, SODate, LoyaltyPoints, AdvanceAmount, CreatedBy INTO CustomerId1, PayModeId1, BranchId1, InvoiceDate1, LoyaltyPoints1, AdvanceAmount1, CreatedBy1
FROM salesorderhd
WHERE (SOHDId = SOHDId1);

IF EXISTS (SELECT 1 FROM salesreturn WHERE SOHDId = SOHDId1) THEN
begin
SELECT SUM(NetAmount) INTO DirectReturnAmount1
FROM salesreturn
WHERE SOHDId = SOHDId1;
END;
END IF;
UPDATE customer
SET TotalLoyaltyPoints = TotalLoyaltyPoints - LoyaltyPoints1
WHERE (CustomerId = CustomerId1);
UPDATE salesorderhd
SET CancelStatus = 1
, ModifiedBy = ModifiedBy1
, ModifiedOn = CONVERT_TZ(now(), @@session.time_zone, '+05:30')
, CancelRemark = RtnReason1
WHERE (SOHDId = SOHDId1);
UPDATE sohd
SET AdvanceUsedAmount = AdvanceUsedAmount - AdvanceAmount1
, AdvanceBalanceAmount = AdvanceBalanceAmount + AdvanceAmount1
WHERE (RefInvNo = SOHDId1);
IF PayModeId1 = 1 THEN
BEGIN
SET Amount1 = (SELECT SONetTotal - (ReturnTotal + DirectReturnAmount1)
FROM salesorderhd
WHERE (SOHDId = SOHDId1));
UPDATE cashbalance
SET CashInAmount = CashInAmount - Amount1
, LastBalance = LastBalance - Amount1
WHERE (UserId = CreatedBy1)
AND (BalanceDate = InvoiceDate1);
END;
ELSEIF PayModeId1 = 2 THEN
BEGIN
DELETE FROM customercheque
WHERE (SOHDId = SOHDId1);
END;
ELSEIF PayModeId1 = 7 THEN
BEGIN
DELETE FROM customerbankdeposit
WHERE (SOHDId = SOHDId1);
END;
ELSEIF PayModeId1 IN(3, 2) THEN
BEGIN
SET Amount1 = (SELECT CreditAmount
FROM customercredit
WHERE (BillNo = SOHDId1));
DELETE FROM customercredit
WHERE (BillNo = SOHDId1);
UPDATE customer
SET BalanceAmount = BalanceAmount - Amount1
WHERE (CustomerId = CustomerId1);
END;
ELSEIF PayModeId1 = 4 THEN
BEGIN
DELETE FROM customercreditcard
WHERE (SOHDId = SOHDId1);
END;
END IF;
UPDATE giftvoucher
SET VoucherStatus = 0
WHERE SOHDId = SOHDId1;
UPDATE serialsummary A
INNER JOIN (SELECT SOHDId, B.ItemsId, B.SerialNo
FROM salesorderdt B
WHERE B.SOHDId = SOHDId1
)B
ON A.ItemsId = B.ItemsId
AND A.SerialNo = B.SerialNo
SET A.Availability =  1
WHERE B.SOHDId = SOHDId1;
UPDATE itemsummary A
INNER JOIN (SELECT B.SOHDId, B.ItemsId, SUM(B.ReturnQty) AS ReturnQty
FROM salesreturn B
WHERE B.SOHDId = SOHDId1
GROUP BY SOHDId, B.ItemsId)B
ON A.ItemsId = B.ItemsId
SET A.AvailableQty =  A.AvailableQty - B.ReturnQty
WHERE B.SOHDId = SOHDId1;
UPDATE branchstock A
INNER JOIN (SELECT SOHDId, B.ItemsId, SUM(B.ReturnQty) AS ReturnQty
FROM salesreturn B
WHERE B.SOHDId = SOHDId1
GROUP BY SOHDId, B.ItemsId)B
ON A.ItemsId = B.ItemsId
SET A.AvailableQty =  A.AvailableQty - B.ReturnQty
WHERE B.SOHDId = SOHDId1
AND A.BranchId = BranchId1;
UPDATE itemsummary A
INNER JOIN (SELECT B.SOHDId, B.ItemsId, SUM(B.SalesQty) AS SalesQty
FROM directsalesreturn B
WHERE B.SOHDId = SOHDId1
GROUP BY B.SOHDId, B.ItemsId)B
ON A.ItemsId = B.ItemsId
SET A.AvailableQty =  A.AvailableQty - B.SalesQty
WHERE B.SOHDId = SOHDId1;
UPDATE branchstock A
INNER JOIN (SELECT B.SOHDId, B.ItemsId, SUM(B.SalesQty) AS SalesQty
FROM directsalesreturn B
WHERE B.SOHDId = SOHDId1
GROUP BY B.SOHDId, B.ItemsId)B
ON A.ItemsId = B.ItemsId
SET A.AvailableQty =  A.AvailableQty - B.SalesQty
WHERE B.SOHDId = SOHDId1
AND A.BranchId = BranchId1;
UPDATE itemsummary A
INNER JOIN (SELECT B.SOHDId, B.ItemsId, SUM(B.SalesQty + B.FreeIssue) AS SalesQty
FROM salesorderdt B
WHERE B.SOHDId = SOHDId1
GROUP BY SOHDId, B.ItemsId)B
ON A.ItemsId = B.ItemsId
SET A.AvailableQty =  A.AvailableQty + B.SalesQty
WHERE B.SOHDId = SOHDId1;
UPDATE branchstock A
INNER JOIN (SELECT SOHDId, B.ItemsId, SUM(B.SalesQty + B.FreeIssue) AS SalesQty
FROM salesorderdt B
WHERE B.SOHDId = SOHDId1
GROUP BY SOHDId, B.ItemsId)B
ON A.ItemsId = B.ItemsId
SET A.AvailableQty =  A.AvailableQty + B.SalesQty
WHERE B.SOHDId = SOHDId1
AND A.BranchId = BranchId1;

END;
END IF;
END |
DELIMITER ;

