DROP PROCEDURE IF EXISTS `InsertInvoiceReturn`;
DELIMITER |
CREATE PROCEDURE `InsertInvoiceReturn`(in
SOHDId1 int
,ItemsId1 varchar(50)
,SalesQty1 DECIMAL(20,2)
,SalesPrice1 DECIMAL(20,2)
,Discount1 DECIMAL(20,2)
,NetAmount1 DECIMAL(20,2)
,CreatedBy1 int
,ItemCode1 varchar(50)
,ItemCatId1 int
,InternalNo1 varchar(30)
,Warranty1 varchar(15)
,BranchId1 int
,ItemName1 varchar(150)
,Damage1 int
, SerialNo1 varchar(45)
,PriceMethod1 varchar(15)
,DiscPer1 DECIMAL(20,2)
)
BEGIN
DECLARE ItemsCostPrice1 DECIMAL(20,2) DEFAULT 0;
DECLARE AvgCost1 DECIMAL(20,2) DEFAULT 0;
DECLARE AllowInventory1 TINYINT(1) DEFAULT 0;
SELECT CostPrice INTO ItemsCostPrice1
FROM itemsummary
WHERE (ItemsId = ItemsId1);
SELECT AvgCost INTO AvgCost1
FROM itemsummary
WHERE (ItemsId = ItemsId1);
SELECT AllowInventory INTO AllowInventory1
FROM itemsummary
WHERE (ItemsId = ItemsId1);
IF (SerialNo1 <> '') THEN
BEGIN
UPDATE serialsummary
SET SalesReturnId = SOHDId1
, SalesReturnDate = CONVERT_TZ(now(), @@session.time_zone, '+05:30')
, Availability = 1
WHERE ItemsId = ItemsId1
AND SerialNo = SerialNo1;
END;
END IF;
UPDATE branchstock
SET Damage = Damage + SalesQty1
WHERE (ItemsId = ItemsId1)
AND (Damage1 = 1)
and BranchId = BranchId1;
UPDATE itemsummary
SET Damage = Damage + SalesQty1
WHERE (ItemsId = ItemsId1)
AND (Damage1 = 1);
IF EXISTS (SELECT 1 FROM itemsummary WHERE (AllowInventory1 = 1) AND (ItemsId = ItemsId1)) THEN
BEGIN
IF (Damage1 = 1) THEN
BEGIN
UPDATE branchstock
SET AvailableQty = AvailableQty - SalesQty1
WHERE (ItemsId = ItemsId1)
AND (Damage1 = 1)
and BranchId = BranchId1;
UPDATE itemsummary
SET AvailableQty = AvailableQty - SalesQty1
WHERE (ItemsId = ItemsId1)
AND (Damage1 = 1);
INSERT INTO itemspoilage
(ItemsId
, ItemCode
, ItemCatId
, Qty
, SpoilDate
, BranchId
, Remarks
, SOHDId)
VALUES (ItemsId1
, ItemCode1
, ItemCatId1
, SalesQty1
, CONVERT_TZ(now(), @@session.time_zone, '+05:30')
, BranchId1
, CONCAT('Return from Invoice [', SOHDId1, ']')
, SOHDId
);
END;
ELSE
BEGIN
UPDATE branchstock
SET AvailableQty = AvailableQty + SalesQty1
WHERE (ItemsId = ItemsId1)
AND (Damage1 = 0)
and BranchId = BranchId1;
UPDATE itemsummary
SET AvailableQty = AvailableQty + SalesQty1
WHERE (ItemsId = ItemsId1)
AND (Damage1 = 0);
END;
END IF;
END;
END IF;
INSERT INTO directsalesreturn
(SOHDId
, ItemsId
, SalesQty
, SalesPrice
, Discount
, NetAmount
, CreatedOn
, CreatedBy
, Itemcode
, InternalNo
, Warranty
, ItemName
, Damage
, CostPrice
, SerialNo
, PriceMethod
, DiscPer
, AvgCost)
VALUES
(SOHDId1
, ItemsId1
, SalesQty1
, SalesPrice1
, Discount1
, NetAmount1
, CONVERT_TZ(now(), @@session.time_zone, '+05:30')
, CreatedBy1
, ItemCode1
, InternalNo1
, Warranty1
, ItemName1
, Damage1
, ItemsCostPrice1
, SerialNo1
, PriceMethod1
, DiscPer1
, AvgCost1);
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `InsertInvoiceSODT`;
DELIMITER |
CREATE PROCEDURE `InsertInvoiceSODT`(in
SOHDId1 int
,ItemsId1 int
,SalesQty1 DECIMAL(20,2)
,SalesPrice1 DECIMAL(20,2)
,Discount1 DECIMAL(20,2)
,NetAmount1 DECIMAL(20,2)
,CreatedBy1 int
,ItemCode1 varchar(50)
,ItemCatId1 int
,InternalNo1 varchar(30)
,Warranty1 varchar(15)
,BranchId1 int
,ItemName1 varchar(150)
,FreeIssue1 int
,SerialNo1 varchar(45)
,PriceMethod1 varchar(15)
,DiscPer1 DECIMAL(20,2)
,OurPrice1 DECIMAL(20,2)
)
BEGIN
DECLARE ItemsCostPrice1 DECIMAL(20,2) DEFAULT 0;
DECLARE AvgCost1 DECIMAL(20,2) DEFAULT 0;
DECLARE RetailPrice1 DECIMAL(20,2) DEFAULT 0;
DECLARE FromItemId1 int DEFAULT 0;
DECLARE FromItemCode1 varchar(50) DEFAULT '';
DECLARE ToQty1 DECIMAL(20,2) DEFAULT 0;
DECLARE FromQty1 DECIMAL(20,2) DEFAULT 1;
DECLARE ConvertionQty1 DECIMAL(20,6) DEFAULT 1;
DECLARE BundleItem1 TINYINT(1) DEFAULT 0;
DECLARE GINHDId1 int DEFAULT 0;
DECLARE AllowInventory1 TINYINT(1) DEFAULT 0;
SELECT CostPrice INTO ItemsCostPrice1
FROM itemsummary
WHERE (ItemsId = ItemsId1);
SELECT AvgCost INTO AvgCost1
FROM itemsummary
WHERE (ItemsId = ItemsId1);
SELECT AllowInventory INTO AllowInventory1
FROM itemsummary
WHERE (ItemsId = ItemsId1);
IF (SerialNo1 <> '') THEN
BEGIN
SELECT A.PurchasePrice INTO ItemsCostPrice1
FROM serialsummary A
WHERE A.ItemsId = ItemsId1
AND A.SerialNo = SerialNo1;
END;
END IF;
SELECT SellingPrice INTO RetailPrice1
FROM itemsummary
WHERE (ItemsId = ItemsId1);
SELECT BundleItem INTO BundleItem1
FROM itemsummary
WHERE (ItemsId = ItemsId1);
IF EXISTS (SELECT 1 FROM branchstock WHERE (ItemsId = ItemsId1) AND (BranchId = BranchId1) AND (AvailableQty < SalesQty1)) THEN
BEGIN
IF EXISTS (SELECT 1 FROM itemsummary A
INNER JOIN branchstock B
ON A.MItemsId = B.ItemsId
AND B.BranchId = BranchId1
WHERE (A.ItemsId = ItemsId1)
AND (B.AvailableQty > 0)) THEN
BEGIN
DECLARE DevideQty1 decimal(10,6) DEFAULT 1;
DECLARE IntQty1 decimal(10,2) DEFAULT 1;
DECLARE DecimalQty1 DECIMAL(20,2) DEFAULT 1;
SELECT MItemsId INTO FromItemId1
FROM itemsummary
WHERE (ItemsId = ItemsId1);
SELECT MItemCode INTO FromItemCode1
FROM itemsummary
WHERE (ItemsId = ItemsId1);
SELECT ConvertionQty INTO ConvertionQty1
FROM itemsummary
WHERE (ItemsId = ItemsId1);
SET DevideQty1 = SalesQty1 * ConvertionQty1;
SET ToQty1 = SalesQty1;
CALL UpdateProductConvertNew(FromItemId1, ItemsId1 , FromItemCode1, ItemCode1 , DevideQty1, ToQty1, BranchId1, SOHDId1);
END;
END IF;
END;
END IF;
IF (SerialNo1 <> '') THEN
BEGIN
INSERT INTO serialsales (
SerialNo
,SOHDId
,SalesDate
,ItemsId
)
VALUES(
SerialNo1
,SOHDId1
,CONVERT_TZ(now(), @@session.time_zone, '+05:30')
,ItemsId1
);
UPDATE serialsummary
SET SellingPrice = SalesPrice1
, SOHDId = SOHDId1
, SalesDate = CONVERT_TZ(now(), @@session.time_zone, '+05:30')
, Availability = 0
WHERE ItemsId = ItemsId1
AND SerialNo = SerialNo1;
END;
END IF;
IF(BundleItem1 = 1) THEN
BEGIN
SELECT MAX(PIHDId) INTO GINHDId1
FROM ginhd A
WHERE A.ItemsId = ItemsId1;
IF(GINHDId1 <> 0) THEN
BEGIN
UPDATE itemsummary B
INNER JOIN gindt A
ON A.ItemsId = B.ItemsId
SET B.AvailableQty = B.AvailableQty - (A.PurchaseQty * SalesQty1)
WHERE A.PIHDId = GINHDId1;
UPDATE branchstock B
INNER JOIN gindt A
ON A.ItemsId = B.ItemsId
SET B.AvailableQty = B.AvailableQty - (A.PurchaseQty * SalesQty1)
WHERE A.PIHDId = GINHDId1;
END;
END IF;
END;
END IF;
IF EXISTS (SELECT 1 FROM itemsummary WHERE (AllowInventory1 = 1) AND (ItemsId = ItemsId1) AND (GINHDId1 = 0)) THEN
BEGIN
UPDATE branchstock
SET AvailableQty = AvailableQty - (SalesQty1 + FreeIssue1)
WHERE (ItemsId = ItemsId1)
AND (BranchId = BranchId1);
UPDATE itemsummary
SET AvailableQty = AvailableQty - (SalesQty1 + FreeIssue1)
WHERE (ItemsId = ItemsId1);
END;
END IF;
INSERT INTO salesorderdt
(SOHDId
, ItemsId
, SalesQty
, SalesPrice
, Discount
, NetAmount
, CreatedOn
, CreatedBy
, Itemcode
, InternalNo
, Warranty
, CostPrice
, ItemName
, FreeIssue
, RetailPrice
, SerialNo
, PriceMethod
, DiscPer
, AvgCost
, OurPrice)
VALUES
(SOHDId1
, ItemsId1
, SalesQty1
, SalesPrice1
, Discount1
, NetAmount1
, CONVERT_TZ(now(), @@session.time_zone, '+05:30')
, CreatedBy1
, ItemCode1
, InternalNo1
, Warranty1
, ItemsCostPrice1
, ItemName1
, FreeIssue1
, RetailPrice1
, SerialNo1
, PriceMethod1
, DiscPer1
, AvgCost1
, OurPrice1);
END |
DELIMITER ;

