DELIMITER |
CREATE PROCEDURE `InsertInvoiceSODTReturn`(in
SOHDId1 int
,ItemsId1 varchar(50)
,SalesQty1 DECIMAL(20,2)
,SalesPrice1 DECIMAL(20,2)
,Discount1 DECIMAL(20,2)
,NetAmount1 DECIMAL(20,2)
,CreatedBy1 int
,ItemCode1 varchar(50)
,ItemCatId1 int
,InternalNo1 varchar(30)
,Warranty1 varchar(15)
,BranchId1 int
,ItemName1 varchar(150)
,Damage1 int
, SerialNo1 varchar(45)
)
BEGIN
DECLARE ItemsCostPrice1 DECIMAL(20,2) DEFAULT 0;
DECLARE AvgCost1 DECIMAL(20,2) DEFAULT 0;
SELECT CostPrice INTO ItemsCostPrice1
FROM itemsummary
WHERE (ItemsId = ItemsId1);
SELECT AvgCost INTO AvgCost1
FROM itemsummary
WHERE (ItemsId = ItemsId1);
INSERT INTO salesorderdtreturn
(SOHDId
, ItemsId
, SalesQty
, SalesPrice
, Discount
, NetAmount
, CreatedOn
, CreatedBy
, Itemcode
, InternalNo
, Warranty
, CostPrice
, ItemName
, Damage
, SerialNo
,AvgCost)
VALUES
(SOHDId1
, ItemsId1
, SalesQty1
, SalesPrice1
, Discount1
, NetAmount1
, CONVERT_TZ(now(), @@session.time_zone, '+05:30')
, CreatedBy1
, ItemCode1
, InternalNo1
, Warranty1
, ItemsCostPrice1
, ItemName1
, Damage1
, SerialNo1
, AvgCost1);
IF (SerialNo1 <> '') THEN
BEGIN
UPDATE serialsummary
SET SalesReturnId = SOHDId1
, SalesReturnDate = CONVERT_TZ(now(), @@session.time_zone, '+05:30')
, Availability = 1
WHERE ItemsId = ItemsId1
AND SerialNo = SerialNo1;
END;
END IF;
IF EXISTS (SELECT 1 FROM itemsummary WHERE (ItemCatId <> 1) AND (ItemsId = ItemsId1)) THEN
BEGIN
UPDATE branchstock
SET Damage = Damage + SalesQty1
WHERE (ItemsId = ItemsId1)
AND (Damage1 = 1)
and BranchId = BranchId1;
UPDATE itemsummary
SET Damage = Damage + SalesQty1
WHERE (ItemsId = ItemsId1)
AND (Damage1 = 1);
UPDATE branchstock
SET AvailableQty = AvailableQty + SalesQty1
WHERE (ItemsId = ItemsId1)
AND (Damage1 = 0)
and BranchId = BranchId1;
UPDATE itemsummary
SET AvailableQty = AvailableQty + SalesQty1
WHERE (ItemsId = ItemsId1)
AND (Damage1 = 0);
END;
END IF;
UPDATE itemsummary t1
INNER JOIN branchstock t2
ON t1.ItemsId = t2.ItemsId
AND t1.ItemsId = ItemsId1
SET t1.AvailableQty = (SELECT IFNULL((SUM(Y.AvailableQty)), 0)
FROM branchstock Y
WHERE Y.ItemsId = t1.ItemsId
AND Y.ItemsId = ItemsId1);
END |
DELIMITER ;

