CREATE PROCEDURE `InsertNewExpenses`(in
PayCatId1 int
, PaymentDate1 date
, PaymentAmount1 decimal(10, 2)
, Remarks1 VARCHAR(75)
, CreatedBy1 int
, Status1 int
, BranchId1 int
, PayModeId1 int
, BankId1 int
, VehicleId1 int
, OUT ExpensesId1 INT
)
BEGIN
DECLARE UTCDate1 date;
DECLARE SupplierId1 int DEFAULT 0;
SET UTCDate1 = (select CONVERT_TZ(now(), @@session.time_zone, '+05:30'));
SELECT SupplierId INTO SupplierId1
FROM supplier A
inner join expensescategory B
on A.SupplierName = B.CatDescription
and A.ExpenseStatus = 1
where B.PayCatId = PayCatId1;
if (Status1 = 1) THEN
begin
IF(PayModeId1 = 1) THEN
BEGIN
UPDATE cashbalance
SET CashOutAmount = CashOutAmount + PaymentAmount1
, LastBalance = LastBalance - PaymentAmount1
WHERE (UserId = CreatedBy1)
AND (BalanceDate = UTCDate1);
END;
elseif(PayModeId1 = 3) THEN
begin
INSERT INTO suppliercredit
(SupplierId
, PIHDId
, CreditDate
, CreditAmount
, CreatedOn
, CreatedBy)
VALUES
(SupplierId1
, 0
, CONVERT_TZ(now(), @@session.time_zone, '+05:30')
, PaymentAmount1
, CONVERT_TZ(now(), @@session.time_zone, '+05:30')
, CreatedBy1);
UPDATE supplier
SET BalanceAmount = BalanceAmount + PaymentAmount1
WHERE (SupplierId = SupplierId1);
END;
END IF;
END;
END IF;
INSERT INTO allexpenses
(PayCatId
, PaymentDate
, PaymentAmount
, Remarks
, CreatedOn
, CreatedBy
, BranchId
, PayModeId
, BankId
, VehicleId)
VALUES
(PayCatId1
, PaymentDate1
, PaymentAmount1
, Remarks1
, CONVERT_TZ(now(), @@session.time_zone, '+05:30')
, CreatedBy1
, BranchId1
, PayModeId1
, BankId1
, VehicleId1);
SET ExpensesId1 = LAST_INSERT_ID();
SELECT ExpensesId1;
END |
DELIMITER ;

