DROP PROCEDURE IF EXISTS `InsertNewInvoiceSOHD`;
DELIMITER |
CREATE PROCEDURE `InsertNewInvoiceSOHD`(in
PayModeId1 int,
CustomerId1 int,
BillNo1 int,
SOGrossTotal1 DECIMAL(20,2),
AdditionalChgs1 DECIMAL(20,2),
SODiscount1 DECIMAL(20,2),
SONetTotal1 DECIMAL(20,2),
CreatedBy1 int,
Cash1 DECIMAL(20,2),
Remarks1 varchar(100),
RepId1 int,
VAT1 DECIMAL(20,2),
NBT1 DECIMAL(20,2),
BranchId1 int,
ReturnTotal1 DECIMAL(20,2),
CreditPay1 DECIMAL(20,2),
CreditTotal1 DECIMAL(20,2),
RefNo1 int,
ReferanceNo1 varchar(20),
TerminalNo1 int,
VoucherNo1 int,
VoucherAmount1 DECIMAL(20,2),
ReceivableAmount1 DECIMAL(20,2),
CustomerName1 varchar(100),
Charges1 DECIMAL(20,2),
CreditDueDays1 int,
CompletedDate1 date,
InvoiceStatusId1 INT,
RepairBill1 TINYINT(1),
LoyaltyPoints1 DECIMAL(20,2),
LoyaltyBalance1 DECIMAL(20,2),
CashBalance1 DECIMAL(20,2),
ReturnNoteNo1 INT,
ReturnNoteAmount1 DECIMAL(20,2),
TotDiscPer1 DECIMAL(20,2),
VATPer1 DECIMAL(20,2),
NBTPer1 DECIMAL(20,2),
ChargesPer1 DECIMAL(20,2),
AdvanceAmount1 DECIMAL(20,2),
OUT SOHDId1 INT
)
BEGIN
DECLARE UTCDate1 date;
DECLARE DailyMaxId1 int DEFAULT 1;
SET UTCDate1 = (select CONVERT_TZ(now(), @@session.time_zone, '+05:30'));
INSERT INTO salesorderhd
(SODate
, PayModeId
, CustomerId
, RepId
, BillNo
, SOGrossTotal
, AdditionalChgs
, SODiscount
, SONetTotal
, CreatedOn
, CreatedBy
, Cash
, Remarks
, VAT
, NBT
, BranchId
, ReturnTotal
, CreditPay
, CreditTotal
, ReferanceNo
, TerminalNo
, VoucherNo
, VoucherAmount
, ReceivableAmount
, CustomerName
, Charges
, CreditDueDays
, CompletedDate
, InvoiceStatusId
, StatusUpdateDate
, RepairBill
, LoyaltyPoints
, LoyaltyBalance
, CashBalance
, ReturnNoteNo
, ReturnNoteAmount
, TotDiscPer
, VATPer
, NBTPer
, ChargesPer
, AdvanceAmount )
VALUES
(CONVERT_TZ(now(), @@session.time_zone, '+05:30')
, PayModeId1
, CustomerId1
, RepId1
, BillNo1
, SOGrossTotal1
, AdditionalChgs1
, SODiscount1
, SONetTotal1
, CONVERT_TZ(now(), @@session.time_zone, '+05:30')
, CreatedBy1
, Cash1
, Remarks1
, VAT1
, NBT1
, BranchId1
, ReturnTotal1
, CreditPay1
, CreditTotal1
, ReferanceNo1
, TerminalNo1
, VoucherNo1
, VoucherAmount1
, ReceivableAmount1
, CustomerName1
, Charges1
, CreditDueDays1
, CompletedDate1
, InvoiceStatusId1
, CONVERT_TZ(now(), @@session.time_zone, '+05:30')
, RepairBill1
, LoyaltyPoints1
, LoyaltyBalance1
, CashBalance1
, ReturnNoteNo1
, ReturnNoteAmount1
, TotDiscPer1
, VATPer1
, NBTPer1
, ChargesPer1
, AdvanceAmount1
);
SET SOHDId1 = LAST_INSERT_ID();
IF EXISTS (SELECT 1 FROM salesdailyinvoiceno WHERE (SODate = UTCDate1)) THEN
BEGIN
SELECT IFNULL(MAX(DailyId), 0) + 1 INTO DailyMaxId1
FROM salesdailyinvoiceno
WHERE (SODate = UTCDate1);
INSERT INTO salesdailyinvoiceno
(SOHDId
, SODate
, DailyId)
VALUES(SOHDId1
, CONVERT_TZ(now(), @@session.time_zone, '+05:30')
, DailyMaxId1);
END;
else
BEGIN
SET DailyMaxId1 = 1;
INSERT INTO salesdailyinvoiceno
(SOHDId
, SODate
, DailyId)
VALUES(SOHDId1
, CONVERT_TZ(now(), @@session.time_zone, '+05:30')
, 1);
END;
END IF;
if(PayModeId1 = 1) THEN
BEGIN
UPDATE cashbalance
SET CashInAmount = CashInAmount + (SONetTotal1 - ReturnTotal1 - VoucherAmount1)
, LastBalance = LastBalance + (SONetTotal1 - ReturnTotal1 - VoucherAmount1)
WHERE BalanceDate= UTCDate1
AND UserId = CreatedBy1;
END;
elseif(PayModeId1 = 3) THEN
BEGIN

INSERT INTO updatedinvoice
(SOHDId
, SOGrossTotal
, SODiscount
, Charges
, SONetTotal
, CreatedOn
, CreatedBy
)
VALUES (SOHDId1
, SOGrossTotal1
, SODiscount1
, Charges1
, SONetTotal1
, CONVERT_TZ(now(), @@session.time_zone, '+05:30')
, CreatedBy1)
;

END;
elseif(PayModeId1 = 6) THEN
BEGIN
UPDATE cashbalance
SET CashInAmount = CashInAmount + 0
, LastBalance = LastBalance + 0
WHERE BalanceDate= UTCDate1
AND UserId = CreatedBy1;
END;
elseif(PayModeId1 = 8) THEN
BEGIN
INSERT INTO usedloyaltypoints
(CustomerId
, UsedDate
, UsedPoints
, ResetStatus
, SOHDId
)
VALUES (CustomerId1
