DROP PROCEDURE IF EXISTS `InsertNewProductionHD`;
DELIMITER |
CREATE PROCEDURE `InsertNewProductionHD`(in
PINetTotal1 decimal(10, 2),
Remarks1 nvarchar(150),
CreatedBy1 int,
BranchId1 int,
ItemsId1 int,
ItemCode1 VARCHAR(50),
Qty1 decimal(10, 2),
PurchasePrice1 decimal(10, 2),
SellingPrice1 decimal(10, 2),
EmployeeID1 int,
OUT PIHDId1 BIGINT(20)
)
BEGIN
DECLARE AvgCost1 decimal(10, 2) DEFAULT 0;
DECLARE UTCDate1 date;
SET UTCDate1 = (select CONVERT_TZ(now(), @@session.time_zone, '+05:30'));
INSERT INTO productionhd
(PIDate
, PINetTotal
, Remarks
, CreatedOn
, CreatedBy
, BranchId
, ItemsId
, ItemCode
, Qty
, PurchasePrice
, SellingPrice
, EmployeeID)
VALUES
(UTCDate1
, PINetTotal1
, Remarks1
, CONVERT_TZ(now(), @@session.time_zone, '+05:30')
, CreatedBy1
, BranchId1
, ItemsId1
, ItemCode1
, Qty1
, PurchasePrice1
, SellingPrice1
, EmployeeID1);
SET PIHDId1 = LAST_INSERT_ID();
IF EXISTS (SELECT 1 FROM branchstock WHERE ItemsId = ItemsId1 AND BranchId = BranchId1) THEN
BEGIN
UPDATE branchstock
SET  AvailableQty = AvailableQty + Qty1
WHERE BranchId = BranchId1
AND ItemsId = ItemsId1;
END;
end if;
SELECT IFNULL((SUM(X.CostPrice)/ SUM(Qty)), 0) INTO AvgCost1
FROM(
SELECT ItemsId, (AvgCost * AvailableQty)  AS CostPrice, AvailableQty AS Qty
FROM itemsummary
WHERE (ItemsId = ItemsId1)
AND (CostPrice <> 0)
union all
SELECT ItemsId, (PurchasePrice * Qty1) as CostPrice, Qty1 AS Qty
FROM productionhd
WHERE (ItemsId = ItemsId1)
AND (PurchasePrice <> 0)
)X;
UPDATE itemsummary
SET AvgCost = AvgCost1
where ItemsId = ItemsId1;
UPDATE itemsummary
SET AvailableQty = AvailableQty + Qty1
,CostPrice = PurchasePrice1
,SellingPrice = SellingPrice1
WHERE (ItemsId = ItemsId1);
IF NOT EXISTS (SELECT 1 FROM itemretailprice WHERE (ItemsId = ItemsId1) AND (RetailPrice = SellingPrice1)) THEN
BEGIN
INSERT INTO itemretailprice
(ItemsId
, ItemCode
, RetailPrice)
VALUES
(ItemsId1
, ItemCode1
, SellingPrice1);
END;
END IF;
SELECT PIHDId1;
END |
DELIMITER ;

