DELIMITER |
CREATE PROCEDURE `InsertPIHD`(in
PIHDId1 BIGINT(20),
PINo1 varchar(45),
SupplierId1 int,
PurchaseDate1 date,
ContactPerson1 nvarchar(60),
PIGrossTotal1 decimal(10, 2),
PIDiscount1 decimal(10, 2),
PINetTotal1 decimal(10, 2),
PICash1 decimal(10, 2),
PIBalance1 decimal(10, 2),
Remarks1 nvarchar(150),
CreatedBy1 int,
PayModeId1 int,
SupplierInvoiceNo1 varchar(45),
BranchId1 int
)
BEGIN
DECLARE UTCDate1 date;
SET UTCDate1 = (select CONVERT_TZ(now(), @@session.time_zone, '+05:30'));
if exists (SELECT 1 FROM pihd WHERE (PIHDId = PIHDId1)) THEN
BEGIN
UPDATE itemsummary
INNER JOIN pidt
ON itemsummary.ItemsId = pidt.ItemsId
SET itemsummary.AvailableQty = itemsummary.AvailableQty - pidt.PurchaseQty
WHERE (pidt.PIHDId = PIHDId1);
UPDATE branchstock
INNER JOIN pidt
ON branchstock.ItemsId = pidt.ItemsId
SET branchstock.AvailableQty = branchstock.AvailableQty - pidt.PurchaseQty
WHERE (pidt.PIHDId = PIHDId1)
AND branchstock.BranchId = BranchId1;
DELETE FROM pidt
WHERE (PIHDId = PIHDId1);
UPDATE pihd
SET SupplierId = SupplierId1
, PIDate = PurchaseDate1
, ContactPerson = ContactPerson1
, PIGrossTotal = PIGrossTotal1
, PIDiscount = PIDiscount1
, PINetTotal = PINetTotal1
, PICash = PICash1
, PIBalance = PIBalance1
, Remarks = Remarks1
, ModifiedOn = CONVERT_TZ(now(), @@session.time_zone, '+05:30')
, ModifiedBy = CreatedBy1
, PayModeId = PayModeId1
, SupplierInvoiceNo = SupplierInvoiceNo1
, BranchId = BranchId1
WHERE (PIHDId = PIHDId1);
end;
ELSE
BEGIN
if(PayModeId1 = 1) then
begin
UPDATE cashbalance
SET CashOutAmount = CashOutAmount + PICash1
, LastBalance = LastBalance - PICash1
WHERE (UserId = CreatedBy1)
AND (BalanceDate = UTCDate1);
end;
end if;
INSERT INTO pihd
(PINo
, SupplierId
, PIDate
, ContactPerson
, PIGrossTotal
, PIDiscount
, PINetTotal
, PICash
, PIBalance
, Remarks
, CreatedOn
, CreatedBy
, PayModeId
, SupplierInvoiceNo
, BranchId)
VALUES
(PINo1
, SupplierId1
, PurchaseDate1
, ContactPerson1
, PIGrossTotal1
, PIDiscount1
, PINetTotal1
, PICash1
, PIBalance1
, Remarks1
, CONVERT_TZ(now(), @@session.time_zone, '+05:30')
, CreatedBy1
, PayModeId1
, SupplierInvoiceNo1
, BranchId1);
END;
END IF;
END |
DELIMITER ;

