DROP PROCEDURE IF EXISTS `InsertPurchaseCancellation`;
DELIMITER |
CREATE PROCEDURE `InsertPurchaseCancellation`(in
PIHDId1 INT,
ModifiedBy1 INT
)
BEGIN
DECLARE PayModeId1 INT;
DECLARE SupplierId1 INT;
DECLARE Amount1 decimal;
DECLARE BranchId1 INT;
IF NOT EXISTS (SELECT 1 FROM pihd WHERE (PIHDId = PIHDId1) AND (CancelStatus = 1)) THEN
BEGIN
SET PayModeId1 = (SELECT PayModeId
FROM pihd
WHERE (PIHDId = PIHDId1));
SET BranchId1 = (SELECT BranchId
FROM pihd
WHERE (PIHDId = PIHDId1));
UPDATE pihd
SET CancelStatus = 1
, ModifiedBy = ModifiedBy1
, ModifiedOn = CONVERT_TZ(now(), @@session.time_zone, '+05:30')
WHERE (PIHDId = PIHDId1);
IF PayModeId1 = 1 THEN
BEGIN
SET Amount1 = (SELECT PINetTotal
FROM pihd
WHERE (PIHDId = PIHDId1));
END;
ELSEIF PayModeId1 = 2 THEN
BEGIN
DELETE FROM suppliercheque
WHERE (POHDId = PIHDId1);
END;
ELSEIF PayModeId1 IN(3, 2) THEN
BEGIN
SET SupplierId1 = (SELECT SupplierId
FROM pihd
WHERE (PIHDId = PIHDId1));
SET Amount1 = (SELECT CreditAmount
FROM suppliercredit
WHERE (PIHDId = PIHDId1));
DELETE FROM suppliercredit
WHERE (PIHDId = PIHDId1);
UPDATE supplier
SET BalanceAmount = BalanceAmount - Amount1
WHERE (SupplierId = SupplierId1);
END;
END IF;
DELETE FROM serialsummary
WHERE PIHDId = PIHDId1;
UPDATE branchstock A
INNER JOIN (SELECT B.PIHDId, B.ItemsId, SUM(B.PurchaseQty) AS PurchaseQty
FROM pidtrtn B
WHERE B.PIHDId = PIHDId1
GROUP BY B.PIHDId, B.ItemsId)B
ON A.ItemsId = B.ItemsId
SET A.AvailableQty =  A.AvailableQty + B.PurchaseQty
WHERE B.PIHDId = PIHDId1
AND A.BranchId = BranchId1;
UPDATE itemsummary A
INNER JOIN (SELECT B.PIHDId, B.ItemsId, SUM(B.PurchaseQty) AS PurchaseQty
FROM pidtrtn B
WHERE B.PIHDId = PIHDId1
GROUP BY B.PIHDId, B.ItemsId)B
ON A.ItemsId = B.ItemsId
SET A.AvailableQty =  A.AvailableQty + B.PurchaseQty
WHERE B.PIHDId = PIHDId1;
UPDATE branchstock A
INNER JOIN (SELECT B.PIHDId, B.ItemsId, SUM(B.PurchaseQty + B.FreeIssue) AS PurchaseQty
FROM pidt B
WHERE B.PIHDId = PIHDId1
GROUP BY B.PIHDId, B.ItemsId)B
ON A.ItemsId = B.ItemsId
SET  A.AvailableQty = A.AvailableQty - B.PurchaseQty
WHERE BranchId = BranchId1
AND B.PIHDId = PIHDId1;
UPDATE itemsummary A
INNER JOIN (SELECT B.PIHDId, B.ItemsId, SUM(B.PurchaseQty + B.FreeIssue) AS PurchaseQty
FROM pidt B
WHERE B.PIHDId = PIHDId1
GROUP BY B.PIHDId, B.ItemsId)B
ON A.ItemsId = B.ItemsId
SET  A.AvailableQty = A.AvailableQty - B.PurchaseQty
WHERE B.PIHDId = PIHDId1;
END;
END IF;
END |
DELIMITER ;

