DROP PROCEDURE IF EXISTS `InsertQuotationDT`;
DELIMITER |
CREATE PROCEDURE `InsertQuotationDT`(in
SOHDId1 int
,ItemsId1 int
,SalesQty1 DECIMAL(20,2)
,SalesPrice1 DECIMAL(20,2)
,Discount1 DECIMAL(20,2)
,NetAmount1 DECIMAL(20,2)
,CreatedBy1 int
,ItemCode1 varchar(50)
,ItemCatId1 int
,InternalNo1 varchar(30)
,Warranty1 varchar(15)
,BranchId1 int
,ItemName1 varchar(150)
,FreeIssue1 int
)
BEGIN
DECLARE ItemsCostPrice1 DECIMAL(20,2) DEFAULT 0;
DECLARE RetailPrice1 DECIMAL(20,2) DEFAULT 0;
SELECT AvgCost INTO ItemsCostPrice1
FROM itemsummary
WHERE (ItemsId = ItemsId1);
SELECT SellingPrice INTO RetailPrice1
FROM itemsummary
WHERE (ItemsId = ItemsId1);
INSERT INTO salesquotationdt
(SOHDId
, ItemsId
, SalesQty
, SalesPrice
, Discount
, NetAmount
, CreatedOn
, CreatedBy
, Itemcode
, InternalNo
, Warranty
, CostPrice
, ItemName
, FreeIssue
, RetailPrice)
VALUES
(SOHDId1
, ItemsId1
