SODiscount1 DECIMAL(20,2),
SONetTotal1 decimal(10,0),
CreatedBy1 int,
Cash1 DECIMAL(20,2),
Remarks1 varchar(100),
RepId1 int,
VAT1 DECIMAL(20,2),
NBT1 DECIMAL(20,2)
)
BEGIN
DECLARE ScopeId1 int;
DECLARE UTCDate1 date;
SET UTCDate1 = (select CONVERT_TZ(now(), @@session.time_zone, '+05:30'));
UPDATE cashbalance
SET CashInAmount = CashInAmount + SONetTotal1
, LastBalance = LastBalance + SONetTotal1
WHERE BalanceDate= UTCDate1
AND UserId = CreatedBy1;
INSERT INTO salesorderhd
(SODate
, PayModeId
, CustomerId
, RepId
, BillNo
, SOGrossTotal
, AdditionalChgs
, SODiscount
, SONetTotal
, CreatedOn
, CreatedBy
, Cash
, Remarks
, VAT
, NBT)
VALUES
(CONVERT_TZ(now(), @@session.time_zone, '+05:30')
, PayModeId1
, CustomerId1
, RepId1
, 0
, SOGrossTotal1
, AdditionalChgs1
, SODiscount1
, SONetTotal1
, CONVERT_TZ(now(), @@session.time_zone, '+05:30')
, CreatedBy1
, Cash1
, Remarks1
, VAT1
, NBT1);
SET ScopeId1 = LAST_INSERT_ID();
UPDATE salesorderhd
SET BillNo = ScopeId1
WHERE (SOHDId = ScopeId1);
INSERT INTO salesorderdt
(SOHDId
, ItemsId
, SalesQty
, SalesPrice
, Discount
, NetAmount
