FROM tempsodt
WHERE (CreatedOn = UTCDate1)
AND (CreatedBy = CreatedBy1);
DELETE FROM tempsodt
WHERE (CreatedBy = CreatedBy1);
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `InsertSalesReturn`;
DELIMITER |
CREATE PROCEDURE `InsertSalesReturn`(in
SOHDId1 int
, SODTId1 int
, ItemsId1 int
, ItemCode1 VARCHAR(50)
, RtnReason1 VARCHAR(75)
, ReturnQty1 DECIMAL(20,2)
, SalesPrice1 DECIMAL(20,2)
, NetAmount1 DECIMAL(20,2)
, CreatedBy1 int
, CreditStatus int
, FreeIssue1 DECIMAL(20,2))
BEGIN
DECLARE BranchId1 int DEFAULT 1;
DECLARE UTCDate1 date;
DECLARE SerialNo1 varchar(45);
DECLARE Discount1 DECIMAL(10,2) DEFAULT 0;
DECLARE CustomerId1 int DEFAULT 0;

SET UTCDate1 = (select CONVERT_TZ(now(), @@session.time_zone, '+05:30'));
SELECT IFNULL(BranchId, 0) INTO BranchId1
FROM salesorderhd
WHERE (SOHDId = SOHDId1);
SELECT IFNULL(SerialNo, '') INTO SerialNo1
FROM salesorderdt
WHERE (SOHDId = SOHDId1)
AND SODTId = SODTId1;
SELECT (Discount/SalesQty) * ReturnQty1 INTO Discount1
FROM salesorderdt
WHERE (SODTId = SODTId1);
SET NetAmount1 = NetAmount1 - Discount1;
IF NOT EXISTS (SELECT 1 FROM  salesorderhd WHERE (CancelStatus = 0) AND (PayModeId = 1) AND (SOHDId = SOHDId1)) THEN
BEGIN
UPDATE customercredit
SET CreditAmount = CreditAmount - NetAmount1
WHERE (BillNo = SOHDId1);

UPDATE customer
SET BalanceAmount = BalanceAmount - NetAmount1
WHERE (CustomerId = CustomerId1);

END;
ELSE
Begin
UPDATE cashbalance
SET CashOutAmount = CashOutAmount + NetAmount1
, LastBalance = LastBalance - NetAmount1
WHERE (UserId = CreatedBy1)
AND (BalanceDate = UTCDate1);
End;
END IF;
INSERT INTO salesreturn
(SOHDId
, SODTId
, ItemsId
, ItemCode
, RtnDate
, RtnReason
, ReturnQty
, SalesPrice
, NetAmount
, CreatedOn
, CreatedBy
, FreeIssue
, Discount)
VALUES
(SOHDId1
, SODTId1
, ItemsId1
, ItemCode1
, CONVERT_TZ(now(), @@session.time_zone, '+05:30')
, RtnReason1
, ReturnQty1
, SalesPrice1
, NetAmount1
, CONVERT_TZ(now(), @@session.time_zone, '+05:30')
, CreatedBy1
, FreeIssue1
, Discount1);
IF (SerialNo1 <> '') THEN
BEGIN
UPDATE serialsummary
SET SalesReturnId = SOHDId1
, SalesReturnDate = CONVERT_TZ(now(), @@session.time_zone, '+05:30')
, Availability = 1
WHERE ItemsId = ItemsId1
AND SerialNo = SerialNo1;
END;
END IF;
UPDATE itemsummary
SET AvailableQty = AvailableQty + (ReturnQty1 + FreeIssue1)
WHERE (ItemCode = ItemCode1);
UPDATE branchstock
SET AvailableQty = AvailableQty + (ReturnQty1 + FreeIssue1)
WHERE (ItemCode = ItemCode1)
and BranchId = BranchId1;
END |
DELIMITER ;

