DELIMITER |
CREATE PROCEDURE `InsertStockAdjustmentDT`(in
StkAdjHDId1 int,
BranchId1 int,
ItemsId1 int,
ItemCode1 VARCHAR(50),
SystemQty1 decimal(10, 2),
PhisicalQty1 decimal(10, 2),
VarrienceQty1 decimal(10, 2),
AvgCost1 decimal(10, 2),
VarrienceValue1 decimal(10, 2),
CreatedBy1 int
)
BEGIN
INSERT INTO stkadjdt
(StkAdjHDId
, AdjDate
, ItemsId
, ItemCode
, SystemQty
, PhisicalQty
, VarrienceQty
, AvgCost
, VarrienceValue
, BranchId
, CreatedDate
, CreatedBy)
VALUES (StkAdjHDId1
, CONVERT_TZ(now(), @@session.time_zone, '+05:30')
, ItemsId1
, ItemCode1
, SystemQty1
, PhisicalQty1
, VarrienceQty1
, AvgCost1
, VarrienceValue1
, BranchId1
, CONVERT_TZ(now(), @@session.time_zone, '+05:30')
, CreatedBy1);
IF EXISTS (SELECT 1 FROM branchstock WHERE (BranchId = BranchId1) AND (ItemsId = ItemsId1)) THEN
BEGIN
UPDATE branchstock
SET AvailableQty = PhisicalQty1
WHERE (BranchId = BranchId1)
AND (ItemsId = ItemsId1);
UPDATE itemsummary t1
INNER JOIN branchstock t2
ON t1.ItemsId = t2.ItemsId
SET t1.AvailableQty = (SELECT IFNULL((SUM(Y.AvailableQty)), 0)
FROM branchstock Y
WHERE Y.ItemsId = t1.ItemsId
AND Y.ItemsId = ItemsId1)
where t1.ItemsId = ItemsId1;
END;
ELSE
BEGIN
INSERT INTO branchstock
(BranchId
, ItemsId
, ItemCode
, AvailableQty
, RefId)
VALUES
(BranchId1
, ItemsId1
, ItemCode1
, PhisicalQty1
, StkAdjHDId1);
end;
end if;
END |
DELIMITER ;

