ItemsId1 int,
ItemCode1 VARCHAR(50),
PurchaseQty1 decimal(10, 2),
BranchId1 int,
ToBranchId1 int,
TransferHDId1 int
)
BEGIN
IF EXISTS (SELECT 1 FROM branchstock WHERE (BranchId = ToBranchId1) AND (ItemsId = ItemsId1)) THEN
BEGIN
UPDATE branchstock
SET AvailableQty = AvailableQty - PurchaseQty1
WHERE (BranchId = BranchId1) AND (ItemsId = ItemsId1);
UPDATE branchstock
SET AvailableQty = AvailableQty + PurchaseQty1
WHERE (BranchId = ToBranchId1) AND (ItemsId = ItemsId1);
END;
ELSE
BEGIN
UPDATE branchstock
SET AvailableQty = AvailableQty - PurchaseQty1
WHERE (BranchId = BranchId1)
AND (ItemsId = ItemsId1);
INSERT INTO branchstock
(BranchId
, ItemsId
, ItemCode
, AvailableQty
, RefId)
VALUES
(ToBranchId1
, ItemsId1
, ItemCode1
, PurchaseQty1
, 0);
end;
end if;
INSERT INTO stocktransferdt
(TransferHDId
, ItemsId
, Qty)
VALUES (TransferHDId1
, ItemsId1
, PurchaseQty1);
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `InsertSuppCreditPay`;
DELIMITER |
CREATE PROCEDURE `InsertSuppCreditPay`(in
UserId1 int
, SupplierId1 int
, PaymentDate1 date
, PaymentAmount1 DECIMAL(20,2)
, PIHDId1 int
, PayModeId1 int
, CardChequeNo1 varchar(45)
, CreditPayHDId1 int
, SuppCreditId1 int)
BEGIN
DECLARE UTCDate1 date;
SET UTCDate1 = (select CONVERT_TZ(now(), @@session.time_zone, '+05:30'));
INSERT INTO suppcreditpayment
(SupplierId
, PaymentDate
, PaymentAmount
, PayModeId
, CardChequeNo
, BillNo
, CreditPayHDId
, CreatedBy
, CreatedOn
, SuppCreditId)
VALUES
(SupplierId1
, PaymentDate1
, PaymentAmount1
, PayModeId1
, CardChequeNo1
, PIHDId1
, CreditPayHDId1
, UserId1
, CONVERT_TZ(now(), @@session.time_zone, '+05:30')
, SuppCreditId1);
UPDATE supplier
SET BalanceAmount = BalanceAmount - PaymentAmount1
WHERE (SupplierId = SupplierId1);
if exists(SELECT 1 FROM suppliercredit WHERE SupplierId = SupplierId1 AND PIHDId = PIHDId1 AND SuppCreditId = SuppCreditId1 AND CreditAmount <= PaymentAmount1+PaymentAmount) then
begin
UPDATE suppliercredit
SET PaymentCompletedStatus = 1
WHERE (PIHDId = PIHDId1)
AND (SupplierId = SupplierId1)
AND SuppCreditId = SuppCreditId1;
end;
end if;
IF(PayModeId1 = 1) THEN
BEGIN
UPDATE cashbalance
SET LastBalance = LastBalance - PaymentAmount1
, CashOutAmount = CashOutAmount + PaymentAmount1
WHERE (UserId = UserId1)
AND (BalanceDate = UTCDate1);
END;
END IF;
UPDATE suppliercredit
SET PaymentDate = PaymentDate1
, PaymentAmount = PaymentAmount + PaymentAmount1
WHERE (PIHDId = PIHDId1)
AND (SupplierId = SupplierId1)
AND SuppCreditId = SuppCreditId1;
END |
DELIMITER ;

