CREATE PROCEDURE `InsertTransferHD`(in
FromBranchId1 int,
ToBranchId1 int,
CreatedBy1 int,
OUT TransferHDId1 INT
)
BEGIN
INSERT INTO stocktransferhd
(TransferDate
, FromBranchId
, ToBranchId
, CreatedOn
, CreatedBy)
VALUES (CONVERT_TZ(now(), @@session.time_zone, '+05:30')
, FromBranchId1
, ToBranchId1
, CONVERT_TZ(now(), @@session.time_zone, '+05:30')
, CreatedBy1);
SET TransferHDId1 = LAST_INSERT_ID();
SELECT TransferHDId1;
END |
DELIMITER ;

