DROP PROCEDURE IF EXISTS `InsertUpdateSupCredit`;
DELIMITER |
CREATE PROCEDURE `InsertUpdateSupCredit`(in
SupplierId1 int
, POHDId1 int
, CreditAmount1 DECIMAL(20,2)
, BalanceAmount1 DECIMAL(20,2)
, CreatedBy1 int
, CreditDueDays1 int)
BEGIN
if exists (SELECT 1 FROM suppliercredit WHERE (PIHDId = POHDId1)) THEN
begin
UPDATE suppliercredit
SET SupplierId = SupplierId1
, CreditDate = CONVERT_TZ(now(), @@session.time_zone, '+05:30')
, CreditAmount = CreditAmount1
, ModifiedOn = CONVERT_TZ(now(), @@session.time_zone, '+05:30')
, ModifiedBy = CreatedBy1
WHERE (PIHDId = POHDId1);
UPDATE supplier
SET BalanceAmount = BalanceAmount + CreditAmount1
WHERE (SupplierId = SupplierId1);
end;
ELSE
BEGIN
INSERT INTO suppliercredit
(SupplierId
, PIHDId
, CreditDate
, CreditAmount
, CreatedOn
, CreatedBy
, CreditDueDays
, CreditDueDate)
VALUES
(SupplierId1
, POHDId1
, CONVERT_TZ(now(), @@session.time_zone, '+05:30')
, CreditAmount1
, CONVERT_TZ(now(), @@session.time_zone, '+05:30')
, CreatedBy1
, CreditDueDays1
, (SELECT DATE_ADD(NOW(), INTERVAL (CASE WHEN CreditDueDays1 = 0 THEN 1 ELSE CreditDueDays1 END) DAY))
);
UPDATE supplier
SET BalanceAmount = BalanceAmount + CreditAmount1
WHERE (SupplierId = SupplierId1);
END;
END IF;
END |
DELIMITER ;

