CREATE PROCEDURE `IsertBarcodeItem`(IN
ItemsId1 int,
ItemCode1 VARCHAR(50),
ItemName1 VARCHAR(150),
InternalNo1 varchar(20),
BCQty1 decimal(10, 2),
BCPrice1 decimal(10, 2),
BCStart1 int,
BCEnd1 int,
SerialNo1 VARCHAR(45)
)
BEGIN
DECLARE i INT DEFAULT 0;
WHILE i < BCQty1 DO
INSERT INTO barcodeitem
(ItemsId
, ItemCode
, ItemName
, InternalNo
, BCQty
, BCPrice
, BCStart
, BCEnd
, SerialNo)
VALUES (ItemsId1
, ItemCode1
, ItemName1
, InternalNo1
, BCQty1
, BCPrice1
, BCStart1
, BCEnd1
, SerialNo1);
SET i = i + 1;
END WHILE;
END |
DELIMITER ;

