DROP PROCEDURE IF EXISTS `ItemHistory`;
DELIMITER |
CREATE PROCEDURE `ItemHistory`(in ItemCode1 VARCHAR(50))
BEGIN
SELECT PurchasedDate AS DocDate
, ItemsId AS DocNo
, ItemCode
, ItemName
, 'Opening Balance' AS Memo
, OpenBalQty AS InQty
, 0 AS OutQty
FROM itemsummary
WHERE (ItemCode = ItemCode1)
UNION ALL
SELECT A.SODate AS DocDate
, B.SOHDId AS DocNo
, C.ItemCode
, C.ItemName
, 'Sales' AS Memo
, 0 AS InQty
, B.SalesQty AS OutQty
FROM salesorderhd A
INNER JOIN salesorderdt B
ON A.SOHDId = B.SOHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
WHERE (A.CancelStatus = 0)
AND (C.ItemCode = ItemCode1)
UNION ALL
SELECT A.PIDate AS DocDate
, B.PIHDId AS DocNo
, C.ItemCode
, C.ItemName
, 'Purchasing' AS Memo
, B.PurchaseQty AS InQty
, 0 AS OutQty
FROM pihd A
INNER JOIN pidt B
ON A.PIHDId = B.PIHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
WHERE (A.CancelStatus = 0)
AND (C.ItemCode = ItemCode1)
UNION ALL
SELECT B.SODate AS DocDate
, A.SOHDId AS DocNo
, C.ItemCode
, C.ItemName
, 'Sales Return' AS Memo
, A.SalesQty AS InQty
, 0 AS OutQty
FROM itemsummary C
INNER JOIN directsalesreturn A
ON C.ItemsId = A.ItemsId
INNER JOIN salesorderhd B
ON A.SOHDId = B.SOHDId
WHERE (C.ItemCode = ItemCode1)
AND (B.CancelStatus = 0);
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ItemHistoryAll`;
DELIMITER |
CREATE PROCEDURE `ItemHistoryAll`()
BEGIN
SELECT X.DocDate
, X.DocNo
, X.ItemCode
, X.ItemName
, X.Memo
, X.InQty
, X.OutQty
FROM
(
SELECT PurchasedDate AS DocDate
, ItemsId AS DocNo
, ItemCode
, ItemName
, 'Opening Balance' AS Memo
, OpenBalQty AS InQty
, 0 AS OutQty
FROM itemsummary
WHERE OpenBalQty > 0
UNION ALL
SELECT A.AdjDate AS DocDate
, A.StkAdjHDId AS DocNo
, A.ItemCode
, B.ItemName
, 'Stock + Adjustments' AS Memo
, A.VarrienceQty AS InQty
, 0 AS OutQty
FROM stkadjdt A
INNER JOIN itemsummary B
ON A.ItemsId = B.ItemsId
WHERE A.VarrienceQty > 0
UNION ALL
SELECT A.AdjDate AS DocDate
, A.StkAdjHDId AS DocNo
, A.ItemCode
, B.ItemName
, 'Stock - Adjustments' AS Memo
, 0 AS InQty
, A.VarrienceQty * -1 AS OutQty
FROM stkadjdt A
INNER JOIN itemsummary B
ON A.ItemsId = B.ItemsId
WHERE A.VarrienceQty < 0
UNION ALL
SELECT A.MovementDate AS DocDate
, A.SOHDId AS DocNo
, B.ItemCode
, B.ItemName
, CONCAT('Convert From - ', C.ItemCode, '') AS Memo
, A.Qty AS InQty
, 0 AS OutQty
FROM inventorymovement A
INNER JOIN itemsummary B
ON A.ToItemsId = B.ItemsId
INNER JOIN itemsummary C
ON A.FromItemsId = C.ItemsId
WHERE A.ConvertTo = 1
UNION ALL
SELECT A.MovementDate AS DocDate
, A.SOHDId AS DocNo
, B.ItemCode
, B.ItemName
, CONCAT('Convert To - ', C.ItemCode, '') AS Memo
, 0 AS InQty
, A.Qty AS OutQty
FROM inventorymovement A
INNER JOIN itemsummary B
ON A.FromItemsId = B.ItemsId
INNER JOIN itemsummary C
ON A.ToItemsId = C.ItemsId
WHERE A.ConvertFrom = 1
UNION ALL
SELECT A.SODate AS DocDate
, B.SOHDId AS DocNo
, C.ItemCode
, C.ItemName
, 'Sales' AS Memo
, 0 AS InQty
, B.SalesQty AS OutQty
FROM salesorderhd A
INNER JOIN salesorderdt B
ON A.SOHDId = B.SOHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
WHERE (A.CancelStatus = 0)
AND B.SalesQty > 0
UNION ALL
SELECT A.SODate AS DocDate
, B.SOHDId AS DocNo
, C.ItemCode
, C.ItemName
, 'Free Issue' AS Memo
, 0 AS InQty
, B.FreeIssue AS OutQty
FROM salesorderhd A
INNER JOIN salesorderdt B
ON A.SOHDId = B.SOHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
WHERE (A.CancelStatus = 0)
AND B.FreeIssue > 0
UNION ALL
SELECT A.PIDate AS DocDate
, B.PIHDId AS DocNo
, C.ItemCode
, C.ItemName
, 'Purchasing' AS Memo
, B.PurchaseQty AS InQty
, 0 AS OutQty
FROM pihd A
INNER JOIN pidt B
ON A.PIHDId = B.PIHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
WHERE (A.CancelStatus = 0)
AND B.PurchaseQty > 0
UNION ALL
SELECT A.PIDate AS DocDate
, B.PIHDId AS DocNo
, C.ItemCode
, C.ItemName
, 'FreeIssue' AS Memo
, B.FreeIssue AS InQty
, 0 AS OutQty
FROM pihd A
INNER JOIN pidt B
ON A.PIHDId = B.PIHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
WHERE (A.CancelStatus = 0)
AND B.FreeIssue > 0
UNION ALL
SELECT B.SODate AS DocDate
, A.SOHDId AS DocNo
, C.ItemCode
, C.ItemName
, 'Sales Return' AS Memo
, A.SalesQty AS InQty
, 0 AS OutQty
FROM itemsummary C
INNER JOIN directsalesreturn A
ON C.ItemsId = A.ItemsId
INNER JOIN salesorderhd B
ON A.SOHDId = B.SOHDId
WHERE (B.CancelStatus = 0)
AND A.SalesQty > 0
AND A.Damage = 0
UNION ALL
SELECT B.SODate AS DocDate
, A.SOHDId AS DocNo
, C.ItemCode
, C.ItemName
, 'Sales Return [Damage]' AS Memo
, 0 AS InQty
, A.SalesQty AS OutQty
FROM itemsummary C
INNER JOIN directsalesreturn A
ON C.ItemsId = A.ItemsId
INNER JOIN salesorderhd B
ON A.SOHDId = B.SOHDId
WHERE (B.CancelStatus = 0)
AND A.SalesQty > 0
AND A.Damage = 1
UNION ALL
SELECT A.RtnDate AS DocDate
, A.SOHDId AS DocNo
, B.ItemCode
, B.ItemName
, 'Sales Return' AS Memo
, A.ReturnQty AS InQty
, 0 AS OutQty
FROM salesreturn A
INNER JOIN itemsummary B
ON A.ItemsId = B.ItemsId
WHERE A.ReturnQty > 0
UNION ALL
SELECT A.SODate AS DocDate
, A.SOHDId AS DocNo
, C.ItemCode
, C.ItemName
, 'Sales Return' AS Memo
, B.SalesQty AS InQty
, 0 AS OutQty
FROM salesorderhdreturn A
INNER JOIN salesorderdtreturn B
ON A.SOHDId = B.SOHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
WHERE (A.CancelStatus = 0)
AND B.SalesQty > 0
UNION ALL
SELECT C.PIDate AS DocDate
, C.PIHDId AS DocNo
, A.ItemCode
, A.ItemName
, 'Purchase Return' AS Memo
, 0 AS InQty
, B.PurchaseQty AS OutQty
FROM itemsummary A
INNER JOIN pidtrtn B
ON A.ItemsId = B.ItemsId
INNER JOIN pihd C
ON B.PIHDId = C.PIHDId
WHERE B.PurchaseQty > 0
UNION ALL
SELECT C.PIDate AS DocDate
, C.PIHDId AS DocNo
, A.ItemCode
, A.ItemName
, 'Purchase Return' AS Memo
, 0 AS InQty
, B.PurchaseQty AS OutQty
FROM itemsummary A
INNER JOIN pidtreturn B
ON A.ItemsId = B.ItemsId
INNER JOIN pihdreturn C
ON B.PIHDId = C.PIHDId
WHERE B.PurchaseQty > 0
UNION ALL
SELECT B.SpoilDate AS DocDate
, B.ItemsId AS DocNo
, A.ItemCode
, A.ItemName
, 'Item Damage' AS Memo
, 0 AS InQty
, B.Qty AS OutQty
FROM itemsummary A
INNER JOIN itemspoilage B
ON A.ItemsId = B.ItemsId
WHERE B.Qty > 0
AND B.SOHDId = 0
UNION ALL
SELECT A.PIDate AS DocDate
, A.PIHDId AS DocNo
, A.ItemCode
, C.ItemName
, 'Production FG' AS Memo
, A.Qty AS InQty
, 0 AS OutQty
FROM productionhd A
INNER JOIN itemsummary C
ON A.ItemsId = C.ItemsId
WHERE (A.CancelStatus = 0)
AND A.Qty > 0
UNION ALL
SELECT A.PIDate AS DocDate
, A.PIHDId AS DocNo
, B.ItemCode
, C.ItemName
, 'Production RM' AS Memo
, 0 AS InQty
, B.PurchaseQty AS OutQty
FROM productionhd A
INNER JOIN productiondt B
ON A.PIHDId = B.PIHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
WHERE (A.CancelStatus = 0)
AND B.PurchaseQty > 0
UNION ALL
SELECT B.StockImportDate AS DocDate
, B.ImportStockId AS DocNo
, A.ItemCode
, A.ItemName
, 'Qty Adjustment' AS Memo
, CASE WHEN B.QtyDifferent > 0 THEN B.QtyDifferent ELSE 0 END AS InQty
, CASE WHEN B.QtyDifferent < 0 THEN (B.QtyDifferent * -1) ELSE 0 END AS OutQty
FROM itemsummary A
INNER JOIN importstockqty B
ON A.ItemsId = B.ItemsId
WHERE B.AvailableQty > 0
)X
ORDER BY X.ItemCode
, X.ItemName
, X.DocDate
, X.Memo
;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ItemHistoryByCode`;
DELIMITER |
CREATE PROCEDURE `ItemHistoryByCode`(in ItemCode1 VARCHAR(50))
BEGIN
SELECT X.DocDate
, X.DocNo
, X.ItemCode
, X.ItemName
, X.Memo
, X.InQty
, X.OutQty
FROM
(
SELECT PurchasedDate AS DocDate
, ItemsId AS DocNo
, ItemCode
, ItemName
, 'Opening Balance' AS Memo
, OpenBalQty AS InQty
, 0 AS OutQty
FROM itemsummary
WHERE (ItemCode = ItemCode1)
AND OpenBalQty > 0
UNION ALL
SELECT A.AdjDate AS DocDate
, A.StkAdjHDId AS DocNo
, A.ItemCode
, B.ItemName
, 'Stock + Adjustments' AS Memo
, A.VarrienceQty AS InQty
, 0 AS OutQty
FROM stkadjdt A
INNER JOIN itemsummary B
ON A.ItemsId = B.ItemsId
WHERE (A.ItemCode = ItemCode1)
AND (A.VarrienceQty > 0)
UNION ALL
SELECT A.AdjDate AS DocDate
, A.StkAdjHDId AS DocNo
, A.ItemCode
, B.ItemName
, 'Stock - Adjustments' AS Memo
, 0 AS InQty
, A.VarrienceQty * -1 AS OutQty
FROM stkadjdt A
INNER JOIN itemsummary B
ON A.ItemsId = B.ItemsId
WHERE (A.ItemCode = ItemCode1)
AND (A.VarrienceQty < 0)
UNION ALL
SELECT A.MovementDate AS DocDate
, A.SOHDId AS DocNo
, B.ItemCode
, B.ItemName
, CONCAT('Convert From - ', C.ItemCode, '') AS Memo
, A.Qty AS InQty
, 0 AS OutQty
FROM inventorymovement A
INNER JOIN itemsummary B
ON A.ToItemsId = B.ItemsId
INNER JOIN itemsummary C
ON A.FromItemsId = C.ItemsId
WHERE A.ConvertTo = 1
AND (B.ItemCode = ItemCode1)
UNION ALL
SELECT A.MovementDate AS DocDate
, A.SOHDId AS DocNo
, B.ItemCode
, B.ItemName
, CONCAT('Convert To - ', C.ItemCode, '') AS Memo
, 0 AS InQty
, A.Qty AS OutQty
FROM inventorymovement A
INNER JOIN itemsummary B
ON A.FromItemsId = B.ItemsId
INNER JOIN itemsummary C
ON A.ToItemsId = C.ItemsId
WHERE A.ConvertFrom = 1
AND (B.ItemCode = ItemCode1)
UNION ALL
SELECT A.SODate AS DocDate
, B.SOHDId AS DocNo
, C.ItemCode
, C.ItemName
, 'Sales' AS Memo
, 0 AS InQty
, B.SalesQty AS OutQty
FROM salesorderhd A
INNER JOIN salesorderdt B
ON A.SOHDId = B.SOHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
WHERE (A.CancelStatus = 0)
AND (C.ItemCode = ItemCode1)
AND B.SalesQty > 0
UNION ALL
SELECT A.SODate AS DocDate
, B.SOHDId AS DocNo
, C.ItemCode
, C.ItemName
, 'Free Issue' AS Memo
, 0 AS InQty
, B.FreeIssue AS OutQty
FROM salesorderhd A
INNER JOIN salesorderdt B
ON A.SOHDId = B.SOHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
WHERE (A.CancelStatus = 0)
AND (C.ItemCode = ItemCode1)
AND B.FreeIssue > 0
UNION ALL
SELECT A.PIDate AS DocDate
, B.PIHDId AS DocNo
, C.ItemCode
, C.ItemName
, 'Purchasing' AS Memo
, B.PurchaseQty AS InQty
, 0 AS OutQty
FROM pihd A
INNER JOIN pidt B
ON A.PIHDId = B.PIHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
WHERE (A.CancelStatus = 0)
AND (C.ItemCode = ItemCode1)
AND B.PurchaseQty > 0
UNION ALL
SELECT A.PIDate AS DocDate
, B.PIHDId AS DocNo
, C.ItemCode
, C.ItemName
, 'Free Issue' AS Memo
, B.FreeIssue AS InQty
, 0 AS OutQty
FROM pihd A
INNER JOIN pidt B
ON A.PIHDId = B.PIHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
WHERE (A.CancelStatus = 0)
AND (C.ItemCode = ItemCode1)
AND B.FreeIssue > 0
UNION ALL
SELECT B.SODate AS DocDate
, A.SOHDId AS DocNo
, C.ItemCode
, C.ItemName
, 'Sales Return' AS Memo
, A.SalesQty AS InQty
, 0 AS OutQty
FROM itemsummary C
INNER JOIN directsalesreturn A
ON C.ItemsId = A.ItemsId
INNER JOIN salesorderhd B
ON A.SOHDId = B.SOHDId
WHERE (C.ItemCode = ItemCode1)
AND (B.CancelStatus = 0)
AND A.SalesQty > 0
AND A.Damage = 0
UNION ALL
SELECT B.SODate AS DocDate
, A.SOHDId AS DocNo
, C.ItemCode
, C.ItemName
, 'Sales Return [Damage]' AS Memo
, 0 AS InQty
, A.SalesQty AS OutQty
FROM itemsummary C
INNER JOIN directsalesreturn A
ON C.ItemsId = A.ItemsId
INNER JOIN salesorderhd B
ON A.SOHDId = B.SOHDId
WHERE (C.ItemCode = ItemCode1)
AND (B.CancelStatus = 0)
AND A.SalesQty > 0
AND A.Damage = 1
UNION ALL
SELECT A.RtnDate AS DocDate
, A.SOHDId AS DocNo
, B.ItemCode
, B.ItemName
, 'Sales Return' AS Memo
, A.ReturnQty AS InQty
, 0 AS OutQty
FROM salesreturn A
INNER JOIN itemsummary B
ON A.ItemsId = B.ItemsId
WHERE (B.ItemCode = ItemCode1)
AND A.ReturnQty > 0
UNION ALL
SELECT A.SODate AS DocDate
, A.SOHDId AS DocNo
, C.ItemCode
, C.ItemName
, 'Sales Return' AS Memo
, B.SalesQty AS InQty
, 0 AS OutQty
FROM salesorderhdreturn A
INNER JOIN salesorderdtreturn B
ON A.SOHDId = B.SOHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
WHERE (A.CancelStatus = 0)
AND (B.SalesQty > 0)
AND (B.ItemCode = ItemCode1)
UNION ALL
SELECT C.PIDate AS DocDate
, C.PIHDId AS DocNo
, A.ItemCode
, A.ItemName
, 'Purchase Return' AS Memo
, 0 AS InQty
, B.PurchaseQty AS OutQty
FROM itemsummary A
INNER JOIN pidtrtn B
ON A.ItemsId = B.ItemsId
INNER JOIN pihd C
ON B.PIHDId = C.PIHDId
WHERE (A.ItemCode = ItemCode1)
AND B.PurchaseQty > 0
UNION ALL
SELECT C.PIDate AS DocDate
, C.PIHDId AS DocNo
, A.ItemCode
, A.ItemName
, 'Purchase Return' AS Memo
, 0 AS InQty
, B.PurchaseQty AS OutQty
FROM itemsummary A
INNER JOIN pidtreturn B
ON A.ItemsId = B.ItemsId
INNER JOIN pihdreturn C
ON B.PIHDId = C.PIHDId
WHERE B.PurchaseQty > 0
AND (A.ItemCode = ItemCode1)
UNION ALL
SELECT B.SpoilDate AS DocDate
, B.ItemsId AS DocNo
, A.ItemCode
, A.ItemName
, 'Item Damage' AS Memo
, 0 AS InQty
, B.Qty AS OutQty
FROM itemsummary A
INNER JOIN itemspoilage B
ON A.ItemsId = B.ItemsId
WHERE (A.ItemCode = ItemCode1)
AND B.Qty > 0
AND B.SOHDId = 0
UNION ALL
SELECT A.PIDate AS DocDate
, A.PIHDId AS DocNo
, A.ItemCode
, C.ItemName
, 'Production FG' AS Memo
, A.Qty AS InQty
, 0 AS OutQty
FROM productionhd A
INNER JOIN itemsummary C
ON A.ItemsId = C.ItemsId
WHERE (A.CancelStatus = 0)
AND (A.Qty > 0)
AND (A.ItemCode = ItemCode1)
UNION ALL
SELECT A.PIDate AS DocDate
, A.PIHDId AS DocNo
, B.ItemCode
, C.ItemName
, 'Production RM' AS Memo
, 0 AS InQty
, B.PurchaseQty AS OutQty
FROM productionhd A
INNER JOIN productiondt B
ON A.PIHDId = B.PIHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
WHERE (A.CancelStatus = 0)
AND (B.PurchaseQty > 0)
AND (B.ItemCode = ItemCode1)
UNION ALL
SELECT B.SpoilDate AS DocDate
, B.ItemsId AS DocNo
, A.ItemCode
, A.ItemName
, 'Item Damage' AS Memo
, 0 AS InQty
, B.Qty AS OutQty
FROM itemsummary A
INNER JOIN itemspoilage B
ON A.ItemsId = B.ItemsId
WHERE (A.ItemCode = ItemCode1)
AND B.Qty > 0
AND B.SOHDId = 0
UNION ALL
SELECT B.StockImportDate AS DocDate
, B.ImportStockId AS DocNo
, A.ItemCode
, A.ItemName
, 'Qty Adjustment' AS Memo
, CASE WHEN B.QtyDifferent > 0 THEN B.QtyDifferent ELSE 0 END AS InQty
, CASE WHEN B.QtyDifferent < 0 THEN (B.QtyDifferent * -1) ELSE 0 END AS OutQty
FROM itemsummary A
INNER JOIN importstockqty B
ON A.ItemsId = B.ItemsId
WHERE B.AvailableQty > 0
AND (A.ItemCode = ItemCode1)
)X
ORDER BY X.ItemCode
, X.ItemName
, X.DocDate
, X.Memo
;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ItemIdInvData`;
DELIMITER |
CREATE PROCEDURE `ItemIdInvData`(in
ItemsId1 int
)
BEGIN
SELECT ItemName
, SellingPrice
, ItemCode
, AvailableQty
, ItemCatId
, DiscEffectFrom
, DiscEffectTo
, Discount
, SItemName
, FreeIssueEffectFrom
, SPSellingPrice
, SPPRiceEffectFrom
, CostPrice
, MinSellingPrice
, WholeSaleDiscount
, ShopPrice
, RetailDiscPer
, WholesaleDiscPer
FROM itemsummary
WHERE (ItemsId = ItemsId1);
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ItemInvData`;
DELIMITER |
CREATE PROCEDURE `ItemInvData`(in
ItemCode1 varchar(50)
, BranchId1 int
)
BEGIN
IF(BranchId1 = 0)THEN
begin
SET BranchId1 = 1;
END;
END IF;
SELECT A.ItemName
, A.SellingPrice
, A.ItemsId
, B.AvailableQty
, A.ItemCatId
, A.DiscEffectFrom
, A.DiscEffectTo
, A.Discount
, A.SItemName
, A.FreeIssueEffectFrom
, A.SPSellingPrice
, A.SPPRiceEffectFrom
, A.CostPrice
, A.MinSellingPrice
, A.WholeSaleDiscount
, A.ShopPrice
, A.RetailDiscPer
, A.WholesaleDiscPer
, A.RackNo
, A.MinQty
FROM itemsummary A
INNER JOIN branchstock B
ON A.ItemsId = B.ItemsId
WHERE (A.ItemCode = ItemCode1)
AND (B.BranchId = BranchId1);
SELECT ItemCode
, ItemName
, SellingPrice
, AvailableQty
, ItemsId
, ItemCatId
, ScaleItem
FROM itemsummary
WHERE (ItemCode = ItemCode1);
SELECT ItemCode
FROM barcodes
WHERE (Barcode = ItemCode1);
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `LoginUser`;
DELIMITER |
CREATE PROCEDURE `LoginUser`(in UserName1 varchar(45), Password1 varchar(45))
BEGIN
SELECT UserType
, UserName
, Password
FROM useraccount
WHERE (UserName = UserName1)
AND (Password = Password1);
SELECT A.UserID, A.UserName, B.ActDate, DATEDIFF(B.ActDate, CURDATE()) AS DueDays, A.BranchId
FROM useraccount A
, sysactivation B
WHERE (A.UserName = UserName1);
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `MasterGrid`;
DELIMITER |
CREATE PROCEDURE `MasterGrid`()
BEGIN
SELECT USER_TYPE_ID AS TypeId
, USER_TYPE AS UserType
FROM user_type
ORDER BY UserType;
SELECT ROLE_ID AS RoleId
, FORM_NAME AS FormName
, ROLE_TITLE AS RoleName
FROM roles
ORDER BY FormName, RoleName;
SELECT user_type.USER_TYPE AS UserType
, roles.FORM_NAME AS FormName
, roles.ROLE_TITLE AS RoleName
FROM roles
INNER JOIN user_profile
ON roles.ROLE_ID = user_profile.ROLE_ID
INNER JOIN user_type
ON user_profile.USER_TYPE_ID = user_type.USER_TYPE_ID
ORDER BY UserType, FormName, RoleName;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `PrintGiftVoucher`;
DELIMITER |
CREATE PROCEDURE `PrintGiftVoucher`(in VoucherNo1 int)
BEGIN
SELECT A.VoucherNo
, A.CustomerId
, A.IssueDate
, A.ExpireDate
, A.VoucherAmount
, D.UserName
, G.CompanyName
, G.CompanyAddress1
, G.CompanyAddress2
, G.ContactNo1
, G.ContactNo2
, G.CompanyLogo
, G.Web
, G.Email
, A.VoucherCode
FROM giftvoucher A
LEFT OUTER JOIN useraccount D
ON A.CreatedBy = D.UserID
, companyinfo G
WHERE A.VoucherNo = VoucherNo1;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `PrintGINNewr`;
DELIMITER |
CREATE PROCEDURE `PrintGINNewr`(in TransferHDId1 int)
BEGIN
SELECT F.CompanyName
, F.CompanyAddress1
, F.CompanyAddress2
, F.ContactNo1
, F.ContactNo2
, F.FooterMsg
, F.FooterMsg2
, F.CompanyLogo
, F.Web
, F.Email
, D.BranchName AS FromBranch
, E.CatDescription AS ToBranch
, A.TransferDate
, C.ItemCode
, C.ItemName
, B.Qty
, B.TransferDTId
, A.TransferHDId
, A.TotalCost
, B.PurchasePrice
, B.SellingPrice
, B.NetAmount
FROM ginhdnew A
INNER JOIN gindtnew B
ON A.TransferHDId = B.TransferHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
INNER JOIN branch D
ON A.FromBranchId = D.BranchId
INNER JOIN expensescategory E
ON A.ToBranchId = E.PayCatId
, companyinfo F
WHERE (A.TransferHDId = TransferHDId1)
ORDER BY B.TransferDTId;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `PrintStockTransfer`;
DELIMITER |
CREATE PROCEDURE `PrintStockTransfer`(in TransferHDId1 int)
BEGIN
SELECT F.CompanyName
, F.CompanyAddress1
, F.CompanyAddress2
, F.ContactNo1
, F.ContactNo2
, F.FooterMsg
, F.FooterMsg2
, F.CompanyLogo
, F.Web
, F.Email
, D.BranchName AS FromBranch
, E.BranchName AS ToBranch
, A.TransferDate
, C.ItemCode
, C.ItemName
, B.Qty
, B.TransferDTId
, A.TransferHDId
FROM stocktransferhd A
INNER JOIN stocktransferdt B
ON A.TransferHDId = B.TransferHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
INNER JOIN branch D
ON A.FromBranchId = D.BranchId
INNER JOIN branch E
ON A.ToBranchId = E.BranchId
, companyinfo F
WHERE (A.TransferHDId = TransferHDId1)
ORDER BY B.TransferDTId;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `RegisterEmployee`;
DELIMITER |
CREATE PROCEDURE `RegisterEmployee`(in
EmployeeName1 VARCHAR(100)
, Address1 VARCHAR(250)
, MobileNo1 VARCHAR(30)
, Email1 VARCHAR(100)
, Bloodgroup1 VARCHAR(20)
, DSId1 int
, DateOfJoining1 DATE
, Salary1 INT(11)
, BasicWorkingTime1 VARCHAR(50)
, HourlyRate1 DECIMAL(20,2)
, OTRate1 DECIMAL(20,2)
, LeaveDeductionPerDay1 DECIMAL(20,2)
, DOB1 DATE
, AllocatedLeaveDays1 DECIMAL(20,2)
, WorkingHoursPerDay1 DECIMAL(20,2)
)
BEGIN
INSERT INTO employeeregistration
(EmployeeName
, Address
, MobileNo
, Email
, Bloodgroup
, DSId
, DateOfJoining
, Salary
, BasicWorkingTime
, HourlyRate
, OTRate
, LeaveDeductionPerDay
, DOB
, AllocatedLeaveDays
, WorkingHoursPerDay
)
VALUES (EmployeeName1
, Address1
, MobileNo1
, Email1
, Bloodgroup1
, DSId1
, DateOfJoining1
, Salary1
, BasicWorkingTime1
, HourlyRate1
, OTRate1
, LeaveDeductionPerDay1
, DOB1
, AllocatedLeaveDays1
, WorkingHoursPerDay1
);
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `Report0ItemStock`;
DELIMITER |
CREATE PROCEDURE `Report0ItemStock`()
BEGIN
SELECT A.ItemCode
, A.ItemName
, A.AvgCost AS CostPrice
, A.CostPrice AS LPP
, A.SellingPrice
, SUM(B.AvailableQty) AS AvailableQty
, A.MinQty
, A.ItemUnit
, A.ItemCatId
, C.CompanyName
, C.CompanyAddress1
, C.CompanyAddress2
, (A.AvgCost * SUM(B.AvailableQty)) AS AVGCostValue
, (A.CostPrice * SUM(B.AvailableQty)) AS LPPCostValue
, (A.SellingPrice * SUM(B.AvailableQty)) AS SellingPriceValue
FROM itemsummary A
INNER JOIN branchstock B
ON A.ItemsId = B.ItemsId
, companyinfo C
GROUP BY A.ItemCode
, A.ItemName
, A.AvgCost
, A.CostPrice
, A.SellingPrice
, A.MinQty
, A.ItemUnit
, A.ItemCatId
, C.CompanyName
, C.CompanyAddress1
, C.CompanyAddress2
HAVING SUM(B.AvailableQty) = 0
ORDER BY A.ItemCode;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportAllAvailableStock`;
DELIMITER |
CREATE PROCEDURE `ReportAllAvailableStock`()
BEGIN
SELECT A.ItemCode
, A.ItemName
, A.AvailableQty
, A.CostPrice
, A.AvailableQty * A.CostPrice AS StockValue
, B.CompanyName
, B.CompanyAddress1
, B.CompanyAddress2
, B.ContactNo1
, B.ContactNo2
FROM itemsummary A, companyinfo B
WHERE A.AvailableQty > 0
ORDER BY A.ItemCode;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportAllBills`;
DELIMITER |
CREATE PROCEDURE `ReportAllBills`(in date1 date, date2 date)
BEGIN
SELECT salesorderhd.BillNo
, salesorderhd.SOGrossTotal
, salesorderhd.SODiscount
, salesorderhd.SONetTotal
, paymentmode.PayMode
, customer.CustomerName
, useraccount.UserName
, salesorderhd.SODate
, salesorderhd.PayModeId
, salesorderhd.CustomerId
, companyinfo.CompanyName
, companyinfo.CompanyAddress1
, companyinfo.CompanyAddress2
, salesorderhd.Remarks
FROM salesorderhd
INNER JOIN paymentmode
ON salesorderhd.PayModeId = paymentmode.PayModeId
INNER JOIN useraccount
ON salesorderhd.CreatedBy = useraccount.UserID
LEFT OUTER JOIN customer
ON salesorderhd.CustomerId = customer.CustomerId
, companyinfo
WHERE (salesorderhd.SODate BETWEEN date1 AND date2)
ORDER BY salesorderhd.BillNo, salesorderhd.SODate;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportAllBillsUser`;
DELIMITER |
CREATE PROCEDURE `ReportAllBillsUser`(in date1 date, date2 date, UserID1 int)
BEGIN
SELECT salesorderhd.BillNo
, salesorderhd.SOGrossTotal
, salesorderhd.SODiscount
, salesorderhd.SONetTotal
, paymentmode.PayMode
, customer.CustomerName
, useraccount.UserName
, salesorderhd.SODate
, salesorderhd.PayModeId
, salesorderhd.CustomerId
, companyinfo.CompanyName
, companyinfo.CompanyAddress1
, companyinfo.CompanyAddress2
, salesorderhd.Remarks
FROM salesorderhd
INNER JOIN paymentmode
ON salesorderhd.PayModeId = paymentmode.PayModeId
INNER JOIN useraccount
ON salesorderhd.CreatedBy = useraccount.UserID
LEFT OUTER JOIN customer
ON salesorderhd.CustomerId = customer.CustomerId
, companyinfo
WHERE (salesorderhd.SODate BETWEEN date1 AND date2)
AND (salesorderhd.CreatedBy = UserID1)
ORDER BY salesorderhd.BillNo, salesorderhd.SODate;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportAllBranchStock`;
DELIMITER |
CREATE PROCEDURE `ReportAllBranchStock`()
BEGIN
SELECT A.ItemCode
, A.ItemName
, A.AvgCost AS CostPrice
, A.CostPrice AS LPP
, A.SellingPrice
, SUM(B.AvailableQty) AS AvailableQty
, A.MinQty
, A.ItemUnit
, A.ItemCatId
, C.CompanyName
, C.CompanyAddress1
, C.CompanyAddress2
, (A.AvgCost * SUM(B.AvailableQty)) AS AVGCostValue
, (A.CostPrice * SUM(B.AvailableQty)) AS LPPCostValue
, (A.SellingPrice * SUM(B.AvailableQty)) AS SellingPriceValue
FROM itemsummary A
INNER JOIN branchstock B
ON A.ItemsId = B.ItemsId
, companyinfo C
GROUP BY A.ItemCode
, A.ItemName
, A.AvgCost
, A.CostPrice
, A.SellingPrice
, A.MinQty
, A.ItemUnit
, A.ItemCatId
, C.CompanyName
, C.CompanyAddress1
, C.CompanyAddress2
ORDER BY A.ItemCode;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportAllCashBills`;
DELIMITER |
CREATE PROCEDURE `ReportAllCashBills`(in date1 date, date2 date)
BEGIN
SELECT salesorderhd.BillNo
, salesorderhd.SOGrossTotal
, salesorderhd.SODiscount
, salesorderhd.SONetTotal
, paymentmode.PayMode
, customer.CustomerName
, useraccount.UserName
, salesorderhd.SODate
, salesorderhd.PayModeId
, salesorderhd.CustomerId
, companyinfo.CompanyName
, companyinfo.CompanyAddress1
, companyinfo.CompanyAddress2
, salesorderhd.Remarks
FROM salesorderhd
INNER JOIN paymentmode
ON salesorderhd.PayModeId = paymentmode.PayModeId
INNER JOIN useraccount
ON salesorderhd.CreatedBy = useraccount.UserID
LEFT OUTER JOIN customer
ON salesorderhd.CustomerId = customer.CustomerId
, companyinfo
WHERE (salesorderhd.SODate BETWEEN date1 AND date2)
and  (salesorderhd.PayModeId = 1)
ORDER BY salesorderhd.BillNo, salesorderhd.SODate;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportAllCreditBills`;
DELIMITER |
