DROP PROCEDURE IF EXISTS `ReportAllCustomerCheque`;
DELIMITER |
CREATE PROCEDURE `ReportAllCustomerCheque`()
BEGIN
SELECT B.CustomerId
, B.CustomerName
, B.CustomerTelNo
, A.IssueDate
, A.ChequeExpDate AS RealizeDate
, A.ChequeBank
, A.ChequeNo
, A.ChequeAmount
, A.SOHDId AS InvoiceNo
, A.RealizeStatus
, A.DepositStatus
, D.BankName AS DepositBank
, A.DepositDate
, A.ReturnStatus
, A.ReturnDate
, A.RtnRemark AS Remark
FROM customercheque A
INNER JOIN customer B
ON A.CustomerId = B.CustomerId
LEFT OUTER JOIN banks D
ON A.BankId = D.BankId;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportAllStock`;
DELIMITER |
CREATE PROCEDURE `ReportAllStock`()
BEGIN
SELECT A.ItemCode
, A.ItemName
, A.AvgCost AS CostPrice
, A.CostPrice AS LPP
, A.SellingPrice
, SUM(B.AvailableQty) AS AvailableQty
, A.MinQty
, A.ItemUnit
, A.ItemCatId
, C.CompanyName
, C.CompanyAddress1
, C.CompanyAddress2
, (A.AvgCost * SUM(B.AvailableQty)) AS AVGCostValue
, (A.CostPrice * SUM(B.AvailableQty)) AS LPPCostValue
, (A.SellingPrice * SUM(B.AvailableQty)) AS SellingPriceValue
FROM itemsummary A
INNER JOIN branchstock B
ON A.ItemsId = B.ItemsId
, companyinfo C
GROUP BY A.ItemCode
, A.ItemName
, A.AvgCost
, A.CostPrice
, A.SellingPrice
, A.MinQty
, A.ItemUnit
, A.ItemCatId
, C.CompanyName
, C.CompanyAddress1
, C.CompanyAddress2
ORDER BY A.ItemCode;
END |
DELIMITER ;

