DROP PROCEDURE IF EXISTS `ReportBalanceSheet`;
DELIMITER |
CREATE PROCEDURE `ReportBalanceSheet`(in date1 date, date2 date)
BEGIN
DECLARE FixedAsset1 DECIMAL(20,2) DEFAULT 0;
DECLARE DepreciatedAmount1 DECIMAL(20,2) DEFAULT 0;
DECLARE Cash1 DECIMAL(20,2) DEFAULT 0;
DECLARE Bank1 DECIMAL(20,2) DEFAULT 0;
DECLARE Inventory1 DECIMAL(20,2) DEFAULT 0;
DECLARE AccountsReceivable1 DECIMAL(20,2) DEFAULT 0;
DECLARE AccountsPayable1 DECIMAL(20,2) DEFAULT 0;
DECLARE LongTermLiabilities1 DECIMAL(20,2) DEFAULT 0;
DECLARE OwnerEquity1 DECIMAL(20,2) DEFAULT 0;

SELECT IFNULL(SUM(Amount), 0) INTO FixedAsset1
FROM fixedasset
WHERE (NetAmount > 0);

SELECT IFNULL(SUM(DepreciatedAmount), 0) INTO DepreciatedAmount1
FROM fixedasset
WHERE (NetAmount > 0);

-- Replace your current Cash1 SELECT with this:
SELECT IFNULL(SUM(X.InAmount) - SUM(X.OutAmount), 0) INTO Cash1
FROM (
    SELECT IFNULL(((SONetTotal-ReturnTotal-VoucherAmount-ReturnNoteAmount)), 0) AS InAmount, 0 AS OutAmount
    FROM salesorderhd
    WHERE (SODate BETWEEN date1 AND date2)
      AND (PayModeId = 1)
      AND (CancelStatus = 0)

    UNION ALL
    SELECT IFNULL(((Cash)), 0) AS InAmount, 0 AS OutAmount
    FROM salesorderhd
    WHERE (SODate BETWEEN date1 AND date2)
      AND (PayModeId <> 1)
      AND (CancelStatus = 0)

    UNION ALL
    SELECT IFNULL(((PaymentAmount)),0) AS InAmount, 0 AS OutAmount
    FROM custcreditpayment
    WHERE (PaymentDate BETWEEN date1 AND date2)
      AND (PayModeId = 1)

    UNION ALL
    SELECT IFNULL(((PaymentAmount)),0) AS InAmount, 0 AS OutAmount
    FROM paidin
    WHERE (PaymentDate BETWEEN date1 AND date2)

    UNION ALL
    SELECT 0 AS InAmount, IFNULL(((A.PaymentAmount)),0) AS OutAmount
    FROM allexpenses A
    WHERE (A.PaymentDate BETWEEN date1 AND date2)
      AND (A.PayModeId = 1)

    UNION ALL
    SELECT 0 AS InAmount, IFNULL(((PaymentAmount)),0) AS OutAmount
    FROM suppcreditpayment
    WHERE (PaymentDate BETWEEN date1 AND date2)
      AND (PayModeId = 1)

    UNION ALL
    SELECT 0 AS InAmount, SONetTotal AS OutAmount
    FROM salesorderhdreturn
    WHERE (CancelStatus = 0)
      AND (PayModeId = 1)
      AND (SODate BETWEEN date1 AND date2)

    UNION ALL
    SELECT 0 AS InAmount, NetAmount AS OutAmount
    FROM salesreturn
    WHERE (RtnDate BETWEEN date1 AND date2)

    UNION ALL
    SELECT 0 AS InAmount, B.NetAmount AS OutAmount
    FROM salesorderhd A
    INNER JOIN directsalesreturn B ON A.SOHDId = B.SOHDId
    WHERE (A.CancelStatus = 0)
      AND (A.SODate BETWEEN date1 AND date2)

    UNION ALL
    SELECT IFNULL(((OpeningBalance)),0) AS InAmount, 0 AS OutAmount
    FROM cashbalance
    WHERE (BalanceDate BETWEEN date1 AND date2)
      AND OpeningBalance > 0

    UNION ALL
    SELECT 0 AS InAmount, (PINetTotal - ReturnTotal) AS OutAmount
    FROM pihd
    WHERE (CancelStatus = 0)
      AND (PayModeId = 1)
      AND (PIDate BETWEEN date1 AND date2)

    UNION ALL
    SELECT 0 AS InAmount, PICash AS OutAmount
    FROM pihd
    WHERE (CancelStatus = 0)
      AND (PayModeId <> 1)
      AND (PIDate BETWEEN date1 AND date2)
      AND PICash > 0

    UNION ALL
    SELECT PINetTotal AS InAmount, 0 AS OutAmount
    FROM pihdreturn
    WHERE (CancelStatus = 0)
      AND (PayModeId = 1)
      AND (PIDate BETWEEN date1 AND date2)
)X;



SELECT IFNULL(SUM(X.Amount), 0) INTO Bank1
FROM (
    SELECT BankId, SUM(Amount) AS Amount
    FROM (
        SELECT A.BankId, A.OBAmount AS Amount
        FROM bankopeningbalance A
        WHERE (A.OBDate BETWEEN date1 AND date2)
        
        UNION ALL
        SELECT A.BankId, A.PaymentAmount AS Amount
        FROM allexpenses A
        WHERE A.PayCatId = 8
          AND (A.PaymentDate BETWEEN date1 AND date2)

        UNION ALL
        SELECT A.BankId, A.PaymentAmount * -1 AS Amount
        FROM allexpenses A
        WHERE A.PayModeId = 7
          AND (A.PaymentDate BETWEEN date1 AND date2)

        UNION ALL
        SELECT A.BankId, A.ChequeAmount AS Amount
        FROM customercheque A
        WHERE A.DepositStatus = 1
          AND A.CreditPayHDId = 0
          AND (A.DepositDate BETWEEN date1 AND date2)

        UNION ALL
        SELECT A.BankId, A.ChequeAmount * -1 AS Amount
        FROM customercheque A
        WHERE A.ReturnStatus = 1
          AND A.DepositStatus = 1
          AND A.CreditPayHDId = 0
          AND (A.ReturnDate BETWEEN date1 AND date2)

        UNION ALL
        SELECT A.BankId, A.ChequeAmount * -1 AS Amount
        FROM suppliercheque A
        WHERE A.ReturnStatus = 0
          AND (A.ChequeExpDate BETWEEN date1 AND date2)

        UNION ALL
        SELECT C.BankId, C.DepositAmount * -1 AS Amount
        FROM supplierbankdeposit C
        INNER JOIN pihd A ON C.POHDId = A.PIHDId
        WHERE (A.PIDate BETWEEN date1 AND date2)
          AND A.CancelStatus = 0
          AND A.PayModeId = 7

        UNION ALL
        SELECT A.BankId, A.PayTotal * -1 AS Amount
        FROM suppcreditpaymenthd A
        WHERE (A.PaymentDate BETWEEN date1 AND date2)

        UNION ALL
        SELECT C.BankId, A.PayTotal AS Amount
        FROM custcreditpaymenthd A
        INNER JOIN customercheque C
          ON A.CustomerId = C.CustomerId
         AND A.CustChqId = C.CustChqId
        WHERE C.DepositStatus = 1
          AND C.CreditPayHDId <> 0
          AND (C.DepositDate BETWEEN date1 AND date2)

        UNION ALL
        SELECT C.BankId, A.PayTotal * -1 AS Amount
        FROM custcreditpaymenthd A
        INNER JOIN customercheque C
          ON A.CustomerId = C.CustomerId
         AND A.CustChqId = C.CustChqId
        WHERE C.DepositStatus = 1
          AND C.CreditPayHDId <> 0
          AND C.ReturnStatus = 1
          AND (C.ReturnDate BETWEEN date1 AND date2)

        UNION ALL
        SELECT C.BankId, C.DepositAmount AS Amount
        FROM customerbankdeposit C
        INNER JOIN salesorderhd A ON C.SOHDId = A.SOHDId
        WHERE (A.SODate BETWEEN date1 AND date2)
          AND A.CancelStatus = 0
          AND A.PayModeId = 7

        UNION ALL
        SELECT C.BankId, C.CardAmount AS Amount
        FROM customercreditcard C
        INNER JOIN salesorderhd A ON C.SOHDId = A.SOHDId
        WHERE (A.SODate BETWEEN date1 AND date2)
          AND A.CancelStatus = 0
          AND A.PayModeId = 4

        UNION ALL
        SELECT A.BankId, A.PayTotal AS Amount
        FROM custcreditpaymenthd A
        WHERE (A.PaymentDate BETWEEN date1 AND date2)
          AND A.CancelStatus = 0
          AND A.PayModeId = 7

        UNION ALL
        SELECT A.FromBankId AS BankId, A.TransferAmount * -1 AS Amount
        FROM banktransfer A
        WHERE (A.TransferDate BETWEEN date1 AND date2)

        UNION ALL
        SELECT A.ToBankId AS BankId, A.TransferAmount AS Amount
        FROM banktransfer A
        WHERE (A.TransferDate BETWEEN date1 AND date2)
    ) T
    GROUP BY BankId
) X;

SELECT IFNULL(SUM(AvailableQty * AvgCost), 0) INTO Inventory1
FROM itemsummary;
SELECT IFNULL(SUM(BalanceAmount), 0) INTO AccountsReceivable1
FROM customercredit;
SELECT IFNULL(SUM(CreditAmount - PaymentAmount), 0) INTO AccountsPayable1
FROM suppliercredit;
SELECT IFNULL(SUM(X.Loan), 0) INTO LongTermLiabilities1
FROM(
SELECT IFNULL(SUM(TotalAmount),0) AS Loan
FROM loanhd
union all
SELECT IFNULL(SUM(PaymentAmount),0) *-1 AS Loan
FROM loandt
)X;

SELECT FixedAsset1 AS FixedAsset
, DepreciatedAmount1 AS DepreciatedAmount
, (FixedAsset1 - DepreciatedAmount1) AS TotalFixedAssets
, Cash1 AS Cash
, Bank1 AS Bank
, Inventory1 AS Inventory
, AccountsReceivable1 AS AccountsReceivable
, AccountsPayable1 AS AccountsPayable
, LongTermLiabilities1 AS LongTermLiabilities
,(((FixedAsset1 - DepreciatedAmount1)+Cash1+Bank1+Inventory1+AccountsReceivable1) - (AccountsPayable1 + LongTermLiabilities1))AS OwnerEquity
, A.CompanyName
, A.CompanyAddress1
, A.CompanyAddress2
, A.ContactNo1
, A.ContactNo2
, date1 AS FromDate
,date2 AS ToDate
FROM companyinfo A;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportBankBalance`;
DELIMITER |
CREATE PROCEDURE `ReportBankBalance`(IN
date1 DATE
, date2 DATE
, BankId1 INT)
BEGIN
SELECT X.BankId
,X.BankName
,X.TransactionDate
,X.TransactionType
,X.DebitAmount
,X.CreditAmount
,X.Amount
,X.TranType
FROM
(
SELECT A.BankId
, B.BankName
, A.BalanceDate AS TransactionDate
, 'OPENING BALANCE' AS TransactionType
, A.BalanceAmount AS DebitAmount
, 0 AS CreditAmount
, A.BalanceAmount AS Amount
, 1 AS TranType
FROM bankbalance A
INNER JOIN banks B
ON A.BankId = B.BankId
WHERE (A.BankId = BankId1)
AND (A.BalanceDate BETWEEN date1 AND date2)
UNION ALL
SELECT A.BankId
, B.BankName
, A.PaymentDate AS TransactionDate
, 'BANK DEPOSIT BY CASHIER' AS TransactionType
, A.PaymentAmount AS DebitAmount
, 0 AS CreditAmount
, A.PaymentAmount AS Amount
, 2 AS TranType
FROM allexpenses A
INNER JOIN banks B
ON A.BankId = B.BankId
WHERE (A.PayCatId = 8)
AND (A.BankId = BankId1)
AND (A.PaymentDate BETWEEN date1 AND date2)
UNION ALL
SELECT A.BankId
, B.BankName
, A.PaymentDate AS TransactionDate
, 'BANK TRANSFER [EXPENSES]' AS TransactionType
, 0 AS DebitAmount
, A.PaymentAmount AS CreditAmount
, A.PaymentAmount * - 1 AS Amount
, 2 AS TranType
FROM allexpenses A
INNER JOIN banks B
ON A.BankId = B.BankId
WHERE (A.PayModeId = 7)
AND (A.BankId = BankId1)
AND (A.PaymentDate BETWEEN date1 AND date2)
UNION ALL
SELECT A.BankId
, B.BankName
, A.DepositDate AS TransactionDate
, CONCAT('RECEIVED CHEQUE - Chq No : ', A.ChequeNo) AS TransactionType
, A.ChequeAmount AS DebitAmount
, 0 AS CreditAmount
, A.ChequeAmount AS Amount
, 3 AS TranType
FROM banks B
INNER JOIN customercheque A
ON B.BankId = A.BankId
WHERE (A.BankId = BankId1)
AND A.DepositStatus = 1
AND A.CreditPayHDId = 0
AND (A.DepositDate BETWEEN date1 AND date2)
UNION ALL
SELECT A.BankId
, B.BankName
, A.ReturnDate AS TransactionDate
, CONCAT('RECEIVED CHEQUE - Chq No : ', A.ChequeNo, ' RETURN') AS TransactionType
, 0 AS DebitAmount
, A.ChequeAmount AS CreditAmount
, A.ChequeAmount * -1 AS Amount
, 3.1 AS TranType
FROM banks B
INNER JOIN customercheque A
ON B.BankId = A.BankId
WHERE (A.BankId = BankId1)
AND A.ReturnStatus = 1
AND A.DepositStatus = 1
AND A.CreditPayHDId = 0
AND (A.ReturnDate BETWEEN date1 AND date2)
UNION all
SELECT A.BankId
, B.BankName
, A.ChequeExpDate AS TransactionDate
, 'ISSUE CHEQUE' AS TransactionType
, 0 AS DebitAmount
, A.ChequeAmount AS CreditAmount
, A.ChequeAmount * - 1 AS Amount
, 4 AS TranType
FROM banks B
INNER JOIN suppliercheque A
ON B.BankId = A.BankId
AND A.ReturnStatus = 0
WHERE (A.BankId = BankId1)
AND (A.ChequeExpDate BETWEEN date1 AND date2)
UNION all
SELECT C.BankId
, B.BankName
, A.PIDate AS TransactionDate
, '[Bank Transfer] - Purchase Invoice' AS TransactionType
, 0 AS DebitAmount
, C.DepositAmount AS CreditAmount
, C.DepositAmount * -1 AS Amount
, 4.1 AS TranType
FROM banks B
INNER JOIN supplierbankdeposit C
ON B.BankId = C.BankId
INNER JOIN pihd A
ON C.POHDId = A.PIHDId
WHERE (C.BankId = BankId1)
AND (A.PIDate BETWEEN date1 AND date2)
AND A.CancelStatus = 0
AND A.PayModeId = 7
UNION all
SELECT A.BankId
, B.BankName
, A.PaymentDate AS TransactionDate
, '[SUPPLIER CREDIT PAY]' AS TransactionType
, 0 AS DebitAmount
, A.PayTotal AS CreditAmount
, A.PayTotal * - 1 AS Amount
, 4 AS TranType
FROM banks B
INNER JOIN suppcreditpaymenthd A
ON B.BankId = A.BankId
WHERE (A.BankId = BankId1)
AND (A.PaymentDate BETWEEN date1 AND date2)
UNION ALL
SELECT A.BankId
, B.BankName
, C.DepositDate AS TransactionDate
, CONCAT('[CUSTOMER CREDIT PAY] - Chq No : ', C.ChequeNo) AS TransactionType
, A.PayTotal AS DebitAmount
, 0 AS CreditAmount
, A.PayTotal AS Amount
, 3.2 AS TranType
FROM custcreditpaymenthd A
INNER JOIN customercheque C
ON A.CustomerId = C.CustomerId
AND A.CustChqId = C.CustChqId
AND C.DepositStatus = 1
AND C.CreditPayHDId <> 0
INNER JOIN banks B
ON C.BankId = B.BankId
WHERE (C.BankId = BankId1)
AND (C.DepositDate BETWEEN date1 AND date2)
UNION ALL
SELECT A.BankId
, B.BankName
, C.ReturnDate AS TransactionDate
, CONCAT('[CUSTOMER CREDIT PAY] - Chq No : ', C.ChequeNo, ' RETURN') AS TransactionType
, 0 AS DebitAmount
, A.PayTotal AS CreditAmount
, A.PayTotal * -1 AS Amount
, 3.3 AS TranType
FROM custcreditpaymenthd A
INNER JOIN customercheque C
ON A.CustomerId = C.CustomerId
AND A.CustChqId = C.CustChqId
AND C.DepositStatus = 1
AND C.CreditPayHDId <> 0
AND C.ReturnStatus = 1
INNER JOIN banks B
ON C.BankId = B.BankId
WHERE (C.BankId = BankId1)
AND (C.ReturnDate BETWEEN date1 AND date2)
UNION all
SELECT C.BankId
, B.BankName
, A.SODate AS TransactionDate
, '[Bank Transfer] - Invoice' AS TransactionType
, C.DepositAmount AS DebitAmount
, 0 AS CreditAmount
, C.DepositAmount AS Amount
, 3.4 AS TranType
FROM banks B
INNER JOIN customerbankdeposit C
ON B.BankId = C.BankId
INNER JOIN salesorderhd A
ON C.SOHDId = A.SOHDId
WHERE (C.BankId = BankId1)
AND (A.SODate BETWEEN date1 AND date2)
AND A.CancelStatus = 0
AND A.PayModeId = 7
UNION all
SELECT C.BankId
, B.BankName
, A.SODate AS TransactionDate
, '[CARD PAYMENTS] - Invoice' AS TransactionType
, C.CardAmount AS DebitAmount
, 0 AS CreditAmount
, C.CardAmount AS Amount
, 3.5 AS TranType
FROM banks B
INNER JOIN customercreditcard C
ON B.BankId = C.BankId
INNER JOIN salesorderhd A
ON C.SOHDId = A.SOHDId
WHERE (C.BankId = BankId1)
AND (A.SODate BETWEEN date1 AND date2)
AND A.CancelStatus = 0
AND A.PayModeId = 4
UNION ALL
SELECT A.BankId
, B.BankName
, A.PaymentDate AS TransactionDate
, CONCAT('[CUSTOMER CREDIT PAY - BANK TRANSFER]') AS TransactionType
, A.PayTotal AS DebitAmount
, 0 AS CreditAmount
, A.PayTotal AS Amount
, 3.6 AS TranType
FROM custcreditpaymenthd A
INNER JOIN banks B
ON A.BankId = B.BankId
WHERE (A.BankId = BankId1)
AND (A.PaymentDate BETWEEN date1 AND date2)
AND A.CancelStatus = 0
AND A.PayModeId = 7
)X
ORDER BY X.TransactionDate, X.TranType;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportBillsByBillNo`;
DELIMITER |
CREATE PROCEDURE `ReportBillsByBillNo`(in BillNo1 int)
BEGIN
SELECT salesorderhd.BillNo
, salesorderhd.SOGrossTotal
, salesorderhd.SODiscount
, salesorderhd.SONetTotal
, paymentmode.PayMode
, customer.CustomerName
, useraccount.UserName
, salesorderhd.SODate
, salesorderhd.PayModeId
, salesorderhd.CustomerId
, companyinfo.CompanyName
, companyinfo.CompanyAddress1
, companyinfo.CompanyAddress2
FROM salesorderhd
INNER JOIN paymentmode
ON salesorderhd.PayModeId = paymentmode.PayModeId
INNER JOIN useraccount
ON salesorderhd.CreatedBy = useraccount.UserID
LEFT OUTER JOIN customer
ON salesorderhd.CustomerId = customer.CustomerId
, companyinfo
WHERE (salesorderhd.BillNo = BillNo1)
ORDER BY salesorderhd.BillNo, salesorderhd.SODate;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportBranchAllStock`;
DELIMITER |
CREATE PROCEDURE `ReportBranchAllStock`(in BranchId1 int)
BEGIN
SELECT A.ItemCode
, A.ItemName
, A.AvgCost AS CostPrice
, A.CostPrice AS LPP
, A.SellingPrice
, B.AvailableQty
, A.MinQty
, A.ItemUnit
, A.ItemCatId
, C.CompanyName
, C.CompanyAddress1
, C.CompanyAddress2
, (A.AvgCost * B.AvailableQty) AS AVGCostValue
, (A.CostPrice * B.AvailableQty) AS LPPCostValue
, (A.SellingPrice * B.AvailableQty) AS SellingPriceValue
FROM itemsummary A
INNER JOIN branchstock B
ON A.ItemsId = B.ItemsId
AND B.BranchId = BranchId1
, companyinfo C
ORDER BY A.ItemCode;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportBranchAvailableStock`;
DELIMITER |
CREATE PROCEDURE `ReportBranchAvailableStock`(in BranchId1 int)
BEGIN
SELECT A.ItemCode
, A.ItemName
, A.AvgCost AS CostPrice
, A.CostPrice AS LPP
, A.SellingPrice
, B.AvailableQty
, A.MinQty
, A.ItemUnit
, A.ItemCatId
, C.CompanyName
, C.CompanyAddress1
, C.CompanyAddress2
, (A.AvgCost * B.AvailableQty) AS AVGCostValue
, (A.CostPrice * B.AvailableQty) AS LPPCostValue
, (A.SellingPrice * B.AvailableQty) AS SellingPriceValue
FROM itemsummary A
INNER JOIN branchstock B
ON A.ItemsId = B.ItemsId
AND B.BranchId = BranchId1
AND B.AvailableQty > 0
, companyinfo C
ORDER BY A.ItemCode;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportBranchCreditCollection`;
DELIMITER |
CREATE PROCEDURE `ReportBranchCreditCollection`(in
date1 date,
date2 date)
BEGIN
SELECT A.BillNo
, A.CreditDate
, B.CustomerName
, A.CreditAmount
, A.PaymentAmount AS TotalPaymentAmount
, A.CreditAmount - A.PaymentAmount AS BalanceAmount
, '_________________________' AS PaymentDate
, '_________________________' AS PaymentAmount
, '_________________________' AS PaymentMode
, '_________________________' AS ChequeNo
FROM customercredit A
INNER JOIN customer B
ON A.CustomerId = B.CustomerId
WHERE (A.PaymentCompletedStatus = 0)
AND (A.CreditDate BETWEEN date1 AND date2);
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportBranchCustomerCreditData`;
DELIMITER |
CREATE PROCEDURE `ReportBranchCustomerCreditData`(in
date1 date,
date2 date)
BEGIN
SELECT C.CustomerName
, E.BillNo
, E.CreditDate
, E.CreditAmount
, E.CreditDueDays
, E.CreditDueDayDate AS CreditDueDate
, DATEDIFF(E.CreditDueDayDate, CURDATE()) AS DaysLeft
, A.CreditPayHDId AS PaymentId
, A.PaymentDate
, B.PaymentAmount
, D.PayMode
, B.CardChequeNo
FROM customercredit E
INNER JOIN customer C
ON E.CustomerId = C.CustomerId
LEFT OUTER JOIN custcreditpayment B
ON E.CustomerId = B.CustomerId
AND E.BillNo = B.BillNo
LEFT OUTER JOIN custcreditpaymenthd A
ON A.CreditPayHDId = B.CreditPayHDId
LEFT OUTER JOIN paymentmode D
ON A.PayModeId = D.PayModeId
WHERE (E.CreditDate BETWEEN date1 AND date2);
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportBranchCustomerPayment`;
DELIMITER |
CREATE PROCEDURE `ReportBranchCustomerPayment`(in
date1 date,
date2 date)
BEGIN
SELECT A.CreditPayHDId AS PaymentId
, A.PaymentDate
, C.CustomerName
, B.BillNo
, B.PaymentAmount
, D.PayMode
, B.CardChequeNo
FROM custcreditpaymenthd A
INNER JOIN custcreditpayment B
ON A.CreditPayHDId = B.CreditPayHDId
INNER JOIN customer C
ON A.CustomerId = C.CustomerId
INNER JOIN paymentmode D
ON A.PayModeId = D.PayModeId
WHERE (A.PaymentDate BETWEEN date1 AND date2);
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportBranchProduction`;
DELIMITER |
CREATE PROCEDURE `ReportBranchProduction`(in
date1 date,
date2 date)
BEGIN
SELECT A.PIHDId AS ProductionId
, A.PIDate AS ProductionDate
, C.ItemCode AS FGItemCode
, C.ItemName AS FGItemName
, A.Qty AS ProductionFGQty
, D.ItemCode AS RMItemCode
, D.ItemName AS RMItemName
, B.PurchaseQty AS RMQty
, B.PurchasePrice AS RMCostPrice
, B.NetAmount AS RMCost
, G.EmployeeName AS ResponsibleEmployee
, E.UserName
, F.BranchName
FROM productionhd A
INNER JOIN productiondt B
ON A.PIHDId = B.PIHDId
INNER JOIN itemsummary C
ON A.ItemsId = C.ItemsId
INNER JOIN itemsummary D
ON B.ItemsId = D.ItemsId
INNER JOIN useraccount E
ON A.CreatedBy = E.UserID
INNER JOIN branch F
ON A.BranchId = F.BranchId
LEFT OUTER JOIN employeeregistration G
ON A.EmployeeID = G.EmployeeID
WHERE A.PIDate BETWEEN date1 AND date2
ORDER BY A.PIHDId;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportBranchPurchase`;
DELIMITER |
CREATE PROCEDURE `ReportBranchPurchase`(in
date1 date,
date2 date)
BEGIN
SELECT A.PIHDId AS InvoiceNo
, A.PINo
, A.SupplierInvoiceNo
, A.PIDate AS PurchasedDate
, B.ItemCode
, B.ItemName
, G.ItemCatName AS ItemCategory
, F.ItemSubCatName AS ItemSubCategory
, B.PurchaseQty
, B.PurchasePrice
, B.PurchaseQty * B.PurchasePrice AS GrossAmount
, B.Discount
, B.NetAmount
, I.SupplierName AS SupplierName
, J.SupplierType
, E.PayMode
, B.SerialNo
, H.UserName
, TRIM(Replace(Replace(Replace(D.BranchName,'\t',''),'\n',''),'\r','')) AS BranchName
FROM pihd A
INNER JOIN pidt B
ON A.PIHDId = B.PIHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
INNER JOIN branch D
ON A.BranchId = D.BranchId
INNER JOIN  paymentmode E
ON A.PayModeId = E.PayModeId
LEFT OUTER JOIN useraccount H
ON A.CreatedBy = H.UserID
LEFT OUTER JOIN supplier I
ON A.SupplierId = I.SupplierId
LEFT OUTER JOIN itemsubcategory F
ON C.ItemSubCatId = F.ItemSubCatId
LEFT OUTER JOIN itemcategory G
ON C.ItemCatId = G.ItemCatId
LEFT OUTER JOIN suppliertypes J
ON I.SupplierTypeId = J.SupplierTypeId
WHERE (A.CancelStatus = 0)
AND (A.PIDate BETWEEN date1 AND date2);
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportBranchPurchaseSummary`;
DELIMITER |
CREATE PROCEDURE `ReportBranchPurchaseSummary`(in
date1 date,
date2 date)
BEGIN
SELECT A.PIHDId AS InvoiceNo
, A.PINo
, A.SupplierInvoiceNo
, A.PIDate AS PurchasedDate
, A.PIGrossTotal AS GrossTotal
, A.PIDiscount AS Discount
, A.VATAmount
, A.PINetTotal AS NetAmount
, I.SupplierName AS SupplierName
, J.SupplierType
, E.PayMode
, H.UserName
, TRIM(Replace(Replace(Replace(D.BranchName,'\t',''),'\n',''),'\r','')) AS BranchName
FROM pihd A
INNER JOIN branch D
ON A.BranchId = D.BranchId
INNER JOIN  paymentmode E
