LEFT OUTER JOIN supplier I
ON A.SupplierId = I.SupplierId
LEFT OUTER JOIN suppliertypes J
ON I.SupplierTypeId = J.SupplierTypeId
WHERE (A.CancelStatus = 0)
AND (A.PIDate BETWEEN date1 AND date2);
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportBranchSales`;
DELIMITER |
CREATE PROCEDURE `ReportBranchSales`(in
date1 date,
date2 date)
BEGIN
SELECT A.SOHDId AS InvoiceNo
, A.SODate AS InvoiceDate
, A.DailyId AS DayInvoiceNo
, A.ReferanceNo
, J.CustomerName
, J.CustomerTelNo
, K.CustomerType
, A.TerminalNo
, B.ItemCode
, B.ItemName
, G.ItemCatName AS ItemCategory
, F.ItemSubCatName AS ItemSubCategory
, C.ItemUnit
, B.SalesQty
, B.SalesPrice
, B.OurPrice
, B.SalesQty * B.SalesPrice AS GrossAmount
, B.Discount
, B.NetAmount
, B.CostPrice
, (B.CostPrice * B.SalesQty) AS TotalCost
, (B.NetAmount - (B.CostPrice * B.SalesQty)) AS GrossProfit
, B.PriceMethod
, I.EmployeeName AS SalesRep
, E.PayMode
, A.Cash
, A.AdvanceAmount
, A.VATPer
, A.VAT
, B.SerialNo
, H.UserName
, A.Remarks
, A.CreatedOn AS CreatedDate
, TRIM(Replace(Replace(Replace(D.BranchName,'\t',''),'\n',''),'\r','')) AS BranchName
, A.CancelRemark
, CASE A.CancelStatus
WHEN 1 THEN 'Cancelled'
ELSE ' '
END AS InvoiceStatus
, A.CancelStatus
, 'Sales Invoice' AS DocType
, A.ReturnNoteNo
, A.ReturnNoteAmount
FROM salesorderhd A
INNER JOIN salesorderdt B
ON A.SOHDId = B.SOHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
INNER JOIN branch D
ON A.BranchId = D.BranchId
INNER JOIN  paymentmode E
ON A.PayModeId = E.PayModeId
LEFT OUTER JOIN useraccount H
ON A.CreatedBy = H.UserID
LEFT OUTER JOIN employeeregistration I
ON A.RepId = I.EmployeeID
LEFT OUTER JOIN itemsubcategory F
ON C.ItemSubCatId = F.ItemSubCatId
LEFT OUTER JOIN itemcategory G
ON C.ItemCatId = G.ItemCatId
LEFT OUTER JOIN customer J
ON A.CustomerId = J.CustomerId
LEFT OUTER JOIN customertypes K
ON J.CustomerTypeId = K.CustomerTypeId
WHERE (A.SODate BETWEEN date1 AND date2)
union all
SELECT A.SOHDId AS InvoiceNo
, A.SODate AS InvoiceDate
, A.DailyId AS DayInvoiceNo
, A.ReferanceNo
, J.CustomerName
, J.CustomerTelNo
, K.CustomerType
, A.TerminalNo
, CONCAT(B.ItemCode, '[Rtn]') AS ItemCode
, CONCAT(B.ItemName, '[Return - With Invoice]') AS ItemName
, G.ItemCatName AS ItemCategory
, F.ItemSubCatName AS ItemSubCategory
, C.ItemUnit
, B.SalesQty * -1 AS SalesQty
, B.SalesPrice
, B.OurPrice
, ((B.SalesQty * B.SalesPrice) * -1) AS GrossAmount
, (B.Discount * -1) AS Discount
, (B.NetAmount * -1) AS NetAmount
, C.CostPrice
, ((C.CostPrice * B.SalesQty) * -1) AS TotalCost
, ((B.NetAmount - (C.CostPrice * B.SalesQty)) * -1) AS GrossProfit
, B.PriceMethod
, I.EmployeeName AS SalesRep
, E.PayMode
, A.Cash
, A.AdvanceAmount
, A.VATPer
, A.VAT
, B.SerialNo
, H.UserName
, A.Remarks
, A.CreatedOn AS CreatedDate
, TRIM(Replace(Replace(Replace(D.BranchName,'\t',''),'\n',''),'\r','')) AS BranchName
, A.CancelRemark
, CASE A.CancelStatus
WHEN 1 THEN 'Cancelled'
ELSE ' '
END AS InvoiceStatus
, A.CancelStatus
, 'Return - With Invoice' AS DocType
, A.ReturnNoteNo
, A.ReturnNoteAmount
FROM salesorderhd A
INNER JOIN directsalesreturn B
ON A.SOHDId = B.SOHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
INNER JOIN branch D
ON A.BranchId = D.BranchId
INNER JOIN  paymentmode E
ON A.PayModeId = E.PayModeId
LEFT OUTER JOIN useraccount H
ON A.CreatedBy = H.UserID
LEFT OUTER JOIN employeeregistration I
ON A.RepId = I.EmployeeID
LEFT OUTER JOIN itemsubcategory F
ON C.ItemSubCatId = F.ItemSubCatId
LEFT OUTER JOIN itemcategory G
ON C.ItemCatId = G.ItemCatId
LEFT OUTER JOIN customer J
ON A.CustomerId = J.CustomerId
LEFT OUTER JOIN customertypes K
ON J.CustomerTypeId = K.CustomerTypeId
WHERE (A.SODate BETWEEN date1 AND date2)
union all
SELECT A.SOHDId AS InvoiceNo
, A.SODate AS InvoiceDate
, 0 AS DayInvoiceNo
, A.ReferanceNo
, J.CustomerName
, J.CustomerTelNo
, K.CustomerType
, A.TerminalNo
, CONCAT(B.ItemCode, '[Rtn]') AS ItemCode
, CONCAT(C.ItemName, '[Return - Direct Return Invoice]') AS ItemName
, G.ItemCatName AS ItemCategory
, F.ItemSubCatName AS ItemSubCategory
, C.ItemUnit
, B.SalesQty * -1 AS SalesQty
, B.SalesPrice
, 0 as OurPrice
, ((B.SalesQty * B.SalesPrice) * -1) AS GrossAmount
, (B.Discount * -1) AS Discount
, (B.NetAmount * -1) AS NetAmount
, C.CostPrice
, ((C.CostPrice * B.SalesQty) * -1) AS TotalCost
, ((B.NetAmount - (C.CostPrice * B.SalesQty)) * -1) AS GrossProfit
, '' AS PriceMethod
, I.EmployeeName AS SalesRep
, E.PayMode
, 0 AS Cash
, 0 as AdvanceAmount
, 0 as VATPer
, 0 as VAT
, '' AS SerialNo
, H.UserName
, A.Remarks
, A.CreatedOn AS CreatedDate
, TRIM(Replace(Replace(Replace(D.BranchName,'\t',''),'\n',''),'\r','')) AS BranchName
, '' AS CancelRemark
, CASE A.CancelStatus
WHEN 1 THEN 'Cancelled'
ELSE ' '
END AS InvoiceStatus
, A.CancelStatus
, 'Return - Direct Return Invoice' AS DocType
, 0 AS ReturnNoteNo
, 0 AS ReturnNoteAmount
FROM salesorderhdreturn A
INNER JOIN salesorderdtreturn B
ON A.SOHDId = B.SOHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
INNER JOIN branch D
ON A.BranchId = D.BranchId
INNER JOIN  paymentmode E
ON A.PayModeId = E.PayModeId
LEFT OUTER JOIN useraccount H
ON A.CreatedBy = H.UserID
LEFT OUTER JOIN employeeregistration I
ON A.RepId = I.EmployeeID
LEFT OUTER JOIN itemsubcategory F
ON C.ItemSubCatId = F.ItemSubCatId
LEFT OUTER JOIN itemcategory G
ON C.ItemCatId = G.ItemCatId
LEFT OUTER JOIN customer J
ON A.CustomerId = J.CustomerId
LEFT OUTER JOIN customertypes K
ON J.CustomerTypeId = K.CustomerTypeId
WHERE (A.SODate BETWEEN date1 AND date2)
UNION ALL
SELECT A.SOHDId AS InvoiceNo
, B.RtnDate AS InvoiceDate
, A.DailyId AS DayInvoiceNo
, A.ReferanceNo
, J.CustomerName
, J.CustomerTelNo
, K.CustomerType
, A.TerminalNo
, CONCAT(B.ItemCode, '[Rtn]') AS ItemCode
, CONCAT(C.ItemName, '[Return - Return Invoiced Items]') AS ItemName
, G.ItemCatName AS ItemCategory
, F.ItemSubCatName AS ItemSubCategory
, C.ItemUnit
, B.ReturnQty * -1 AS SalesQty
, B.SalesPrice
, BB.OurPrice
, ((B.ReturnQty * B.SalesPrice) * -1) AS GrossAmount
, (B.Discount * -1) AS Discount
, (B.NetAmount * -1) AS NetAmount
, C.CostPrice
, ((C.CostPrice * B.ReturnQty) * -1) AS TotalCost
, ((B.NetAmount - (C.CostPrice * B.ReturnQty)) * -1) AS GrossProfit
, '' AS PriceMethod
, I.EmployeeName AS SalesRep
, E.PayMode
, A.Cash
, A.AdvanceAmount
, A.VATPer
, A.VAT
, '' AS SerialNo
, H.UserName
, A.Remarks
, A.CreatedOn AS CreatedDate
, TRIM(Replace(Replace(Replace(D.BranchName,'\t',''),'\n',''),'\r','')) AS BranchName
, A.CancelRemark
, CASE A.CancelStatus
WHEN 1 THEN 'Cancelled'
ELSE ' '
END AS InvoiceStatus
, A.CancelStatus
, 'Return - Return Invoiced Items' AS DocType
, A.ReturnNoteNo
, A.ReturnNoteAmount
FROM salesorderhd A
INNER JOIN salesorderdt BB
ON A.SOHDId = BB.SOHDId
INNER JOIN salesreturn B
ON BB.SOHDId = B.SOHDId
AND BB.SODTId = B.SODTId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
INNER JOIN branch D
ON A.BranchId = D.BranchId
INNER JOIN  paymentmode E
ON A.PayModeId = E.PayModeId
LEFT OUTER JOIN useraccount H
ON A.CreatedBy = H.UserID
LEFT OUTER JOIN employeeregistration I
ON A.RepId = I.EmployeeID
LEFT OUTER JOIN itemsubcategory F
ON C.ItemSubCatId = F.ItemSubCatId
LEFT OUTER JOIN itemcategory G
ON C.ItemCatId = G.ItemCatId
LEFT OUTER JOIN customer J
ON A.CustomerId = J.CustomerId
LEFT OUTER JOIN customertypes K
ON J.CustomerTypeId = K.CustomerTypeId
WHERE (B.RtnDate BETWEEN date1 AND date2);
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportBranchSalesByInvoice`;
DELIMITER |
CREATE PROCEDURE `ReportBranchSalesByInvoice`(in
date1 date,
date2 date)
BEGIN
SELECT A.SOHDId AS InvoiceNo
, A.SODate AS InvoiceDate
, A.DailyId AS DayInvoiceNo
, A.ReferanceNo
, J.CustomerName
, J.CustomerTelNo
, K.CustomerType
, I.EmployeeName AS SalesRep
, E.PayMode
, A.SOGrossTotal AS SOGrossTotal
, A.SODiscount as Discount
, A.ReturnTotal
, A.Charges
, A.VAT
, A.SONetTotal as NetTotal
, A.Cash
, A.AdvanceAmount
, H.UserName
, A.Remarks
, A.CreatedOn AS CreatedDate
, TRIM(Replace(Replace(Replace(D.BranchName,'\t',''),'\n',''),'\r','')) AS BranchName
FROM salesorderhd A
INNER JOIN branch D
ON A.BranchId = D.BranchId
INNER JOIN  paymentmode E
ON A.PayModeId = E.PayModeId
LEFT OUTER JOIN useraccount H
ON A.CreatedBy = H.UserID
LEFT OUTER JOIN employeeregistration I
ON A.RepId = I.EmployeeID
LEFT OUTER JOIN customer J
ON A.CustomerId = J.CustomerId
LEFT OUTER JOIN customertypes K
ON J.CustomerTypeId = K.CustomerTypeId
WHERE (A.SODate BETWEEN date1 AND date2)
AND (A.CancelStatus = 0);
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportBranchSalesCancel`;
DELIMITER |
CREATE PROCEDURE `ReportBranchSalesCancel`(in
date1 date,
date2 date)
BEGIN
SELECT A.SOHDId AS InvoiceNo
, A.SODate AS InvoiceDate
, A.DailyId AS DayInvoiceNo
, A.ReferanceNo
, J.CustomerName
, J.CustomerTelNo
, K.CustomerType
, A.TerminalNo
, B.ItemCode
, B.ItemName
, G.ItemCatName AS ItemCategory
, F.ItemSubCatName AS ItemSubCategory
, C.ItemUnit
, B.SalesQty
, B.SalesPrice
, B.SalesQty * B.SalesPrice AS GrossAmount
, B.Discount
, B.NetAmount
, B.CostPrice
, (B.CostPrice * B.SalesQty) AS TotalCost
, (B.NetAmount - (B.CostPrice * B.SalesQty)) AS GrossProfit
, B.PriceMethod
, I.EmployeeName AS SalesRep
, E.PayMode
, A.Cash
, A.AdvanceAmount
, B.SerialNo
, H.UserName
, A.Remarks
, A.CreatedOn AS CreatedDate
, TRIM(Replace(Replace(Replace(D.BranchName,'\t',''),'\n',''),'\r','')) AS BranchName
, A.CancelRemark
, CASE A.CancelStatus
WHEN 1 THEN 'Cancelled'
ELSE ' '
END AS InvoiceStatus
, A.CancelStatus
, L.UserName AS CancelledUser
, A.ModifiedOn AS CancelledDate
, 'Sales Invoice' AS DocType
, A.ReturnNoteNo
, A.ReturnNoteAmount
FROM salesorderhd A
INNER JOIN salesorderdt B
ON A.SOHDId = B.SOHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
INNER JOIN branch D
ON A.BranchId = D.BranchId
INNER JOIN  paymentmode E
ON A.PayModeId = E.PayModeId
LEFT OUTER JOIN useraccount H
ON A.CreatedBy = H.UserID
LEFT OUTER JOIN employeeregistration I
ON A.RepId = I.EmployeeID
LEFT OUTER JOIN itemsubcategory F
ON C.ItemSubCatId = F.ItemSubCatId
LEFT OUTER JOIN itemcategory G
ON C.ItemCatId = G.ItemCatId
LEFT OUTER JOIN customer J
ON A.CustomerId = J.CustomerId
LEFT OUTER JOIN customertypes K
ON J.CustomerTypeId = K.CustomerTypeId
LEFT OUTER JOIN useraccount L
ON A.ModifiedBy = L.UserID
WHERE (A.SODate BETWEEN date1 AND date2)
AND A.CancelStatus = 1;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportBranchSalesCard`;
DELIMITER |
