, B.ItemCode
, B.ItemName
, G.ItemCatName AS ItemCategory
, F.ItemSubCatName AS ItemSubCategory
, B.SalesQty
, B.SalesPrice
, B.SalesQty * B.SalesPrice AS GrossAmount
, B.Discount
, B.NetAmount
, I.EmployeeName AS SalesRep
, E.PayMode
, B.SerialNo
, H.UserName
, TRIM(Replace(Replace(Replace(D.BranchName,'\t',''),'\n',''),'\r','')) AS BranchName
, A.CancelRemark
