DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportBranchSalesCardRefNo`;
DELIMITER |
CREATE PROCEDURE `ReportBranchSalesCardRefNo`(in
ReferanceNo1 VARCHAR(20))
BEGIN
SELECT A.SOHDId AS InvoiceNo
, A.ReferanceNo
, A.SODate AS InvoiceDate
, B.ItemCode
, B.ItemName
, G.ItemCatName AS ItemCategory
, F.ItemSubCatName AS ItemSubCategory
, B.SalesQty
, B.SalesPrice
, B.SalesQty * B.SalesPrice AS GrossAmount
, B.Discount
, B.NetAmount
, I.EmployeeName AS SalesRep
, E.PayMode
, B.SerialNo
, H.UserName
, CASE A.CancelStatus
WHEN 1 THEN 'Cancelled'
ELSE ' '
END AS InvoiceStatus
, TRIM(Replace(Replace(Replace(D.BranchName,'\t',''),'\n',''),'\r','')) AS BranchName
, A.CancelRemark
FROM salesorderhd A
INNER JOIN salesorderdt B
ON A.SOHDId = B.SOHDId
INNER JOIN itemsummary C
