DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportBranchSalesRtn`;
DELIMITER |
CREATE PROCEDURE `ReportBranchSalesRtn`(in
date1 date,
date2 date)
BEGIN
SELECT A.SOHDId AS ReturnInvoiceNo
, A.SODate AS ReturnInvoiceDate
, B.ItemCode
, C.ItemName
, G.ItemCatName AS ItemCategory
, F.ItemSubCatName AS ItemSubCategory
, B.SalesQty AS ReturnQty
, B.SalesPrice
, B.SalesQty * B.SalesPrice AS ReturnGrossAmount
, B.Discount
, B.NetAmount AS ReturnNetAmount
, I.EmployeeName AS SalesRep
, E.PayMode
, H.UserName
, TRIM(Replace(Replace(Replace(D.BranchName,'\t',''),'\n',''),'\r','')) AS BranchName
, 'Return - With Invoice' AS DocType
FROM salesorderhd A
INNER JOIN directsalesreturn B
ON A.SOHDId = B.SOHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
INNER JOIN branch D
ON A.BranchId = D.BranchId
INNER JOIN  paymentmode E
ON A.PayModeId = E.PayModeId
LEFT OUTER JOIN useraccount H
ON A.CreatedBy = H.UserID
LEFT OUTER JOIN employeeregistration I
ON A.RepId = I.EmployeeID
LEFT OUTER JOIN itemsubcategory F
ON C.ItemSubCatId = F.ItemSubCatId
LEFT OUTER JOIN itemcategory G
ON C.ItemCatId = G.ItemCatId
WHERE (A.CancelStatus = 0)
AND (A.SODate BETWEEN date1 AND date2)
UNION ALL
SELECT A.SOHDId AS ReturnInvoiceNo
, B.RtnDate AS ReturnInvoiceDate
, B.ItemCode
, C.ItemName
, G.ItemCatName AS ItemCategory
, F.ItemSubCatName AS ItemSubCategory
, B.ReturnQty AS ReturnQty
, B.SalesPrice
, B.ReturnQty * B.SalesPrice AS ReturnGrossAmount
, B.Discount
, B.NetAmount AS ReturnNetAmount
, I.EmployeeName AS SalesRep
, E.PayMode
, H.UserName
, TRIM(Replace(Replace(Replace(D.BranchName,'\t',''),'\n',''),'\r','')) AS BranchName
, 'Return - Return Invoiced Items' AS DocType
FROM salesorderhd A
INNER JOIN salesorderdt BB
ON A.SOHDId = BB.SOHDId
INNER JOIN salesreturn B
ON BB.SOHDId = B.SOHDId
AND BB.SODTId = B.SODTId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
INNER JOIN branch D
ON A.BranchId = D.BranchId
INNER JOIN  paymentmode E
ON A.PayModeId = E.PayModeId
LEFT OUTER JOIN useraccount H
ON A.CreatedBy = H.UserID
LEFT OUTER JOIN employeeregistration I
ON A.RepId = I.EmployeeID
LEFT OUTER JOIN itemsubcategory F
ON C.ItemSubCatId = F.ItemSubCatId
LEFT OUTER JOIN itemcategory G
ON C.ItemCatId = G.ItemCatId
WHERE (A.CancelStatus = 0)
AND (B.RtnDate BETWEEN date1 AND date2)
UNION ALL
SELECT A.SOHDId AS ReturnInvoiceNo
, A.SODate AS ReturnInvoiceDate
, B.ItemCode
, C.ItemName
, G.ItemCatName AS ItemCategory
, F.ItemSubCatName AS ItemSubCategory
, B.SalesQty AS ReturnQty
, B.SalesPrice
, B.SalesQty * B.SalesPrice AS ReturnGrossAmount
, B.Discount
, B.NetAmount AS ReturnNetAmount
, I.EmployeeName AS SalesRep
, E.PayMode
, H.UserName
, TRIM(Replace(Replace(Replace(D.BranchName,'\t',''),'\n',''),'\r','')) AS BranchName
, 'Return - Direct Return Invoice' AS DocType
FROM salesorderhdreturn A
INNER JOIN salesorderdtreturn B
ON A.SOHDId = B.SOHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
INNER JOIN branch D
ON A.BranchId = D.BranchId
INNER JOIN  paymentmode E
ON A.PayModeId = E.PayModeId
LEFT OUTER JOIN useraccount H
ON A.CreatedBy = H.UserID
LEFT OUTER JOIN employeeregistration I
ON A.RepId = I.EmployeeID
LEFT OUTER JOIN itemsubcategory F
ON C.ItemSubCatId = F.ItemSubCatId
LEFT OUTER JOIN itemcategory G
ON C.ItemCatId = G.ItemCatId
WHERE (A.CancelStatus = 0)
AND (A.SODate BETWEEN date1 AND date2)
;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportBranchSalesSummary`;
DELIMITER |
CREATE PROCEDURE `ReportBranchSalesSummary`(in
date1 date,
date2 date)
BEGIN
SELECT A.SODate AS SalesDate
,IFNULL((SUM(A.SONetTotal)), 0) AS TotalSale
,IFNULL(((B.SalesReturn)), 0) AS SalesReturn
,(IFNULL((SUM(A.SONetTotal)), 0) - IFNULL(((B.SalesReturn)), 0)) AS NetSale
,IFNULL(((C.Cashsale)), 0) AS CashSale
,IFNULL(((D.ChequeSale)), 0) AS ChequeSale
,IFNULL(((E.CreditSale)), 0) AS CreditSale
,IFNULL(((F.CardSale)), 0) AS CardSale
,IFNULL(((G.BankTransferSale)), 0) AS BankTransferSale
,IFNULL(((H.VAT)), 0) AS VAT
FROM salesorderhd A
LEFT OUTER JOIN (
SELECT X.ReturnDate, IFNULL((SUM(X.SalesReturn)), 0) AS SalesReturn
FROM(
SELECT RtnDate AS ReturnDate, IFNULL((SUM(NetAmount)), 0) AS SalesReturn
FROM salesreturn
WHERE (RtnDate BETWEEN date1 AND date2)
group by RtnDate
UNION ALL
SELECT A.SODate AS ReturnDate, IFNULL(SUM(B.NetAmount), 0) AS SalesReturn
FROM salesorderhd A
INNER JOIN directsalesreturn B
ON A.SOHDId = B.SOHDId
WHERE (A.CancelStatus = 0)
AND (A.SODate BETWEEN date1 AND date2)
group by A.SODate
UNION all
SELECT A.SODate AS ReturnDate, IFNULL(SUM(B.NetAmount), 0) AS SalesReturn
FROM salesorderhdreturn A
INNER JOIN salesorderdtreturn B
ON A.SOHDId = B.SOHDId
WHERE (A.CancelStatus = 0)
AND (A.SODate BETWEEN date1 AND date2)
group by A.SODate
)X
GROUP BY X.ReturnDate
)B
ON A.SODate = B.ReturnDate
LEFT OUTER JOIN (
SELECT X.SODate, IFNULL((SUM(X.Cashsale)), 0) AS Cashsale
FROM(
SELECT SODate AS SODate, IFNULL((SUM(SONetTotal-ReturnTotal-VoucherAmount)), 0) AS Cashsale
FROM salesorderhd
WHERE (SODate BETWEEN date1 AND date2)
AND (PayModeId = 1)
AND (CancelStatus = 0)
GROUP BY SODate
UNION all
SELECT SODate AS SODate, IFNULL((SUM(Cash)), 0) AS Cashsale
FROM salesorderhd
WHERE (SODate BETWEEN date1 AND date2)
AND (PayModeId <> 1)
AND (CancelStatus = 0)
GROUP BY SODate
)X
GROUP BY X.SODate
)C
ON A.SODate = C.SODate
LEFT OUTER JOIN(
SELECT SODate, IFNULL((SUM(SONetTotal-ReturnTotal-VoucherAmount-Cash)), 0) AS ChequeSale
FROM salesorderhd
WHERE (SODate BETWEEN date1 AND date2)
AND (PayModeId = 2)
AND (CancelStatus = 0)
GROUP BY SODate
)D
ON A.SODate = D.SODate
LEFT OUTER JOIN(
SELECT SODate, IFNULL((SUM(SONetTotal-ReturnTotal-VoucherAmount-Cash)), 0) AS CreditSale
FROM salesorderhd
WHERE (SODate BETWEEN date1 AND date2)
AND (PayModeId = 3)
AND (CancelStatus = 0)
GROUP BY SODate
)E
ON A.SODate = E.SODate
LEFT OUTER JOIN(
SELECT SODate, IFNULL((SUM(SONetTotal-ReturnTotal-VoucherAmount-Cash)), 0) AS CardSale
FROM salesorderhd
WHERE (SODate BETWEEN date1 AND date2)
AND (PayModeId = 4)
AND (CancelStatus = 0)
GROUP BY SODate
)F
ON A.SODate = F.SODate
LEFT OUTER JOIN(
SELECT SODate, IFNULL((SUM(SONetTotal-ReturnTotal-VoucherAmount-Cash)), 0) AS BankTransferSale
FROM salesorderhd
WHERE (SODate BETWEEN date1 AND date2)
AND (PayModeId = 7)
AND (CancelStatus = 0)
GROUP BY SODate
)G
ON A.SODate = G.SODate
LEFT OUTER JOIN(
SELECT SODate, IFNULL((SUM(VAT)), 0) AS VAT
FROM salesorderhd
WHERE (SODate BETWEEN date1 AND date2)
AND (CancelStatus = 0)
GROUP BY SODate
)H
ON A.SODate = H.SODate
WHERE (A.CancelStatus = 0)
AND (A.SODate BETWEEN date1 AND date2)
GROUP BY A.SODate, B.SalesReturn, C.Cashsale, D.ChequeSale,E.CreditSale,F.CardSale,G.BankTransferSale,H.VAT;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportBranchSalesWithStock`;
DELIMITER |
CREATE PROCEDURE `ReportBranchSalesWithStock`(in
date1 date,
date2 date)
BEGIN
SELECT X.ItemCode
, X.ItemName
, X.ItemCategory
, X.ItemSubCategory
, SUM(X.SalesQty) AS SalesQty
, SUM(X.GrossAmount) AS GrossAmount
, SUM(X.Discount) AS Discount
, SUM(X.NetAmount) AS NetAmount
, X.AvailableQty
, X.BranchName
FROM(
SELECT B.ItemCode
, B.ItemName
, G.ItemCatName AS ItemCategory
, F.ItemSubCatName AS ItemSubCategory
, B.SalesQty
, B.SalesPrice
, B.SalesQty * B.SalesPrice AS GrossAmount
, B.Discount
, B.NetAmount
, E.AvailableQty
, TRIM(Replace(Replace(Replace(D.BranchName,'\t',''),'\n',''),'\r','')) AS BranchName
FROM salesorderhd A
INNER JOIN salesorderdt B
ON A.SOHDId = B.SOHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
INNER JOIN branch D
ON A.BranchId = D.BranchId
INNER JOIN branchstock E
ON C.ItemsId = E.ItemsId
LEFT OUTER JOIN itemsubcategory F
ON C.ItemSubCatId = F.ItemSubCatId
LEFT OUTER JOIN itemcategory G
ON C.ItemCatId = G.ItemCatId
WHERE (A.CancelStatus = 0)
AND (A.SODate BETWEEN date1 AND date2)
union all
SELECT CONCAT(B.ItemCode, '[Rtn]') AS ItemCode
, CONCAT(B.ItemName, '[Return]') AS ItemName
, G.ItemCatName AS ItemCategory
, F.ItemSubCatName AS ItemSubCategory
, B.SalesQty * -1 AS SalesQty
, B.SalesPrice
, ((B.SalesQty * B.SalesPrice) * -1) AS GrossAmount
, (B.Discount * -1) AS Discount
, (B.NetAmount * -1) AS NetAmount
, E.AvailableQty
, TRIM(Replace(Replace(Replace(D.BranchName,'\t',''),'\n',''),'\r','')) AS BranchName
FROM salesorderhd A
INNER JOIN directsalesreturn B
ON A.SOHDId = B.SOHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
INNER JOIN branch D
ON A.BranchId = D.BranchId
INNER JOIN branchstock E
ON C.ItemsId = E.ItemsId
LEFT OUTER JOIN itemsubcategory F
ON C.ItemSubCatId = F.ItemSubCatId
LEFT OUTER JOIN itemcategory G
ON C.ItemCatId = G.ItemCatId
WHERE (A.CancelStatus = 0)
AND (A.SODate BETWEEN date1 AND date2)
)X
GROUP BY X.ItemCode
, X.ItemName
, X.ItemCategory
, X.ItemSubCategory
, X.AvailableQty
, X.BranchName;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportBranchSerial`;
DELIMITER |
CREATE PROCEDURE `ReportBranchSerial`()
BEGIN
SELECT A.ItemsId
, A.ItemCode
, A.ItemName
, B.ItemCatName AS ItemCategory
, C.SerialNo
, C.PIHDId AS GRNNo
, C.PurchaseDate
, D.SOHDId AS InvoiceNo
, D.SalesDate
FROM itemsummary A
INNER JOIN itemcategory B
ON A.ItemCatId = B.ItemCatId
INNER JOIN serialpurchase C
ON A.ItemsId = C.ItemsId
LEFT OUTER JOIN serialsales D
ON C.ItemsId = D.ItemsId
AND C.SerialNo = D.SerialNo;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportBranchSpoilage`;
DELIMITER |
CREATE PROCEDURE `ReportBranchSpoilage`(in
date1 date,
date2 date)
BEGIN
SELECT TRIM(Replace(Replace(Replace(C.BranchName,'\t',''),'\n',''),'\r','')) AS BranchName
, A.Remarks
, A.SpoilDate AS DamageDate
, A.ItemCode
, B.ItemName
, G.ItemCatName AS ItemCategory
, F.ItemSubCatName AS ItemSubCategory
, A.Qty AS DamageQty
FROM itemspoilage A
INNER JOIN itemsummary B
ON A.ItemsId = B.ItemsId
INNER JOIN branch C
ON A.BranchId = C.BranchId
LEFT OUTER JOIN itemsubcategory F
ON B.ItemSubCatId = F.ItemSubCatId
LEFT OUTER JOIN itemcategory G
ON B.ItemCatId = G.ItemCatId
WHERE (A.SpoilDate BETWEEN date1 AND date2);
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportBranchStock0Items`;
DELIMITER |
CREATE PROCEDURE `ReportBranchStock0Items`(in BranchId1 int)
BEGIN
SELECT A.ItemCode
, A.ItemName
, A.AvgCost AS CostPrice
, A.CostPrice AS LPP
, A.SellingPrice
, B.AvailableQty
, A.MinQty
, A.ItemUnit
, A.ItemCatId
, C.CompanyName
, C.CompanyAddress1
, C.CompanyAddress2
, (A.AvgCost * B.AvailableQty) AS AVGCostValue
, (A.CostPrice * B.AvailableQty) AS LPPCostValue
, (A.SellingPrice * B.AvailableQty) AS SellingPriceValue
FROM itemsummary A
INNER JOIN branchstock B
ON A.ItemsId = B.ItemsId
AND B.BranchId = BranchId1
AND B.AvailableQty = 0
, companyinfo C
ORDER BY A.ItemCode;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportBranchStockByItemCode`;
DELIMITER |
CREATE PROCEDURE `ReportBranchStockByItemCode`(in ItemCode1 varchar(50), BranchId1 int)
BEGIN
SELECT A.ItemCode
, A.ItemName
, '' AS SupplierName
, A.CostPrice
, A.SellingPrice
, D.AvailableQty
, A.MinQty
, A.ItemUnit
, A.ItemCatId
, C.CompanyName
, C.CompanyAddress1
, C.CompanyAddress2
FROM itemsummary A
INNER JOIN branchstock D
ON A.ItemsId = D.ItemsId
, companyinfo C
WHERE (A.ItemCode = ItemCode1)
AND (D.BranchId = BranchId1)
ORDER BY A.ItemName;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportBranchStockMovement`;
DELIMITER |
CREATE PROCEDURE `ReportBranchStockMovement`(in
date1 date,
date2 date)
BEGIN
SELECT A.ItemsId
, A.ItemCode
, A.ItemName
, B.ItemCatName AS ItemCategory
, E.ItemSubCatName AS ItemSubCategory
, C.AvailableQty AS BranchQty
, A.AvailableQty AS TotalQty
, CASE WHEN D.BranchId = 1 THEN IFNULL(A.OpenBalQty, 0) ELSE 0 END AS OpeningQty
, IFNULL(G.PurchaseQty, 0) AS PurchaseQty
, IFNULL(N.PurchaseFreeIssue, 0) AS PurchaseFreeIssue
, IFNULL(H.PlusAdjustment, 0) AS PlusAdjustment
, IFNULL(K.TransferIn, 0) AS TransferIn
, IFNULL(L.SalesReturn, 0) AS SalesReturn
, IFNULL(P.SalesReturnFreeIssue, 0) AS SalesReturnFreeIssue
, IFNULL(F.SalesQty, 0) AS SalesQty
, IFNULL(O.SalesFreeIssue, 0) AS SalesFreeIssue
, IFNULL(I.MinusAdjustment, 0) AS MinusAdjustment
, IFNULL(J.TransferOut, 0) AS TransferOut
, IFNULL(M.DamageQty, 0) AS DamageQty
, IFNULL(Q.PurchaseReturn, 0) AS PurchaseReturn
, IFNULL(R.PurchaseFreeIssueReturn, 0) AS PurchaseFreeIssueReturn
, (((CASE WHEN D.BranchId = 1 THEN IFNULL(A.OpenBalQty, 0) ELSE 0 END) + IFNULL(G.PurchaseQty, 0) + IFNULL(N.PurchaseFreeIssue, 0) + IFNULL(H.PlusAdjustment, 0) + IFNULL(K.TransferIn, 0) + IFNULL(L.SalesReturn, 0) + IFNULL(P.SalesReturnFreeIssue, 0)) - (IFNULL(I.MinusAdjustment, 0) + IFNULL(F.SalesQty, 0) + IFNULL(O.SalesFreeIssue, 0) + IFNULL(J.TransferOut, 0) + IFNULL(M.DamageQty, 0) + IFNULL(Q.PurchaseReturn, 0) + IFNULL(R.PurchaseFreeIssueReturn, 0))) AS CurrentBalance
,TRIM(Replace(Replace(Replace(D.BranchName,'\t',''),'\n',''),'\r','')) AS BranchName
, A.SellingPrice AS RetailPrice
, A.Discount AS RetailDiscount
, A.SPSellingPrice AS WholesalePrice
, A.WholeSaleDiscount AS WholesaleDiscount
, A.ShopPrice
, A.MinSellingPrice
, A.AvgCost AS AverageCost
, A.CostPrice AS LastPurchasePrice
, C.Damage AS DamageQty
, (A.AvgCost * C.AvailableQty) AS AVGCostStockValue
, (A.CostPrice * C.AvailableQty) AS LPPStockValue
, C.RackNo
FROM itemsummary A
INNER JOIN itemcategory B
ON A.ItemCatId = B.ItemCatId
INNER JOIN branchstock C
ON A.ItemsId = C.ItemsId
INNER JOIN branch D
ON C.BranchId = D.BranchId
LEFT OUTER JOIN itemsubcategory E
ON A.ItemSubCatId = E.ItemSubCatId
AND A.ItemCatId = E.ItemCatId
LEFT OUTER JOIN (SELECT B.ItemsId, A.BranchId, SUM(B.SalesQty) AS SalesQty
FROM salesorderhd A
INNER JOIN salesorderdt B
ON A.SOHDId = B.SOHDId
WHERE A.CancelStatus = 0
AND (A.SODate BETWEEN date1 AND date2)
GROUP BY B.ItemsId, A.BranchId) F
ON C.ItemsId = F.ItemsId
AND C.BranchId = F.BranchId
LEFT OUTER JOIN (SELECT B.ItemsId, A.BranchId, SUM(B.PurchaseQty) AS PurchaseQty
FROM pihd A
INNER JOIN pidt B
ON A.PIHDId = B.PIHDId
WHERE A.CancelStatus = 0
AND (A.PIDate BETWEEN date1 AND date2)
GROUP BY B.ItemsId, A.BranchId) G
ON C.ItemsId = G.ItemsId
AND C.BranchId = G.BranchId
LEFT OUTER JOIN (SELECT A.ItemsId, B.BranchId, SUM(A.VarrienceQty) AS PlusAdjustment
FROM stkadjdt A
INNER JOIN stkadjhd B
ON A.StkAdjHDId = B.StkAdjHDId
WHERE A.VarrienceQty > 0
AND (B.AdjDate BETWEEN date1 AND date2)
GROUP BY A.ItemsId, B.BranchId)H
ON C.ItemsId = H.ItemsId
AND C.BranchId = H.BranchId
LEFT OUTER JOIN (SELECT A.ItemsId, B.BranchId, SUM(A.VarrienceQty) * -1 AS MinusAdjustment
FROM stkadjdt A
INNER JOIN stkadjhd B
ON A.StkAdjHDId = B.StkAdjHDId
WHERE A.VarrienceQty < 0
AND (B.AdjDate BETWEEN date1 AND date2)
GROUP BY A.ItemsId, B.BranchId)I
ON C.ItemsId = I.ItemsId
AND C.BranchId = I.BranchId
LEFT OUTER JOIN (SELECT T.ItemsId, H.FromBranchId, IFNULL((SUM(T.Qty)), 0) AS TransferOut
FROM stocktransferhd H
INNER JOIN stocktransferdt T
ON H.TransferHDId = T.TransferHDId
WHERE (H.TransferDate BETWEEN date1 AND date2)
GROUP BY T.ItemsId, H.FromBranchId)J
ON C.ItemsId = J.ItemsId
AND C.BranchId = J.FromBranchId
LEFT OUTER JOIN (SELECT T.ItemsId, H.ToBranchId, IFNULL((SUM(T.Qty)), 0) AS TransferIn
FROM stocktransferhd H
INNER JOIN stocktransferdt T
ON H.TransferHDId = T.TransferHDId
WHERE (H.TransferDate BETWEEN date1 AND date2)
GROUP BY T.ItemsId, H.ToBranchId)K
ON C.ItemsId = K.ItemsId
AND C.BranchId = K.ToBranchId
LEFT OUTER JOIN (SELECT X.ItemsId, X.BranchId, IFNULL(SUM(X.SalesQty), 0) AS SalesReturn
FROM(
SELECT B.ItemsId, A.BranchId, B.SalesQty
FROM salesorderhdreturn A
INNER JOIN salesorderdtreturn B
ON A.SOHDId = B.SOHDId
WHERE A.CancelStatus = 0
AND (A.SODate BETWEEN date1 AND date2)
UNION ALL
SELECT B.ItemsId, A.BranchId, B.SalesQty
FROM salesorderhd A
INNER JOIN directsalesreturn B
ON A.SOHDId = B.SOHDId
WHERE A.CancelStatus = 0
AND (A.SODate BETWEEN date1 AND date2)
UNION ALL
SELECT BB.ItemsId, A.BranchId, B.ReturnQty AS SalesQty
FROM salesorderhd A
INNER JOIN salesorderdt BB
ON A.SOHDId = BB.SOHDId
INNER JOIN (SELECT E.SOHDId, E.SODTId, SUM(E.ReturnQty) AS ReturnQty
FROM salesreturn E
GROUP BY E.SOHDId, E.SODTId) B
ON BB.SOHDId = B.SOHDId
AND BB.SODTId = B.SODTId
WHERE A.CancelStatus = 0
AND (A.SODate BETWEEN date1 AND date2)
)X
GROUP BY X.ItemsId, X.BranchId
)L
ON C.ItemsId = L.ItemsId
AND C.BranchId = L.BranchId
LEFT OUTER JOIN (SELECT A.ItemsId, A.BranchId, SUM(A.Qty) AS DamageQty
FROM itemspoilage A
WHERE (A.SpoilDate BETWEEN date1 AND date2)
GROUP BY A.ItemsId, A.BranchId) M
ON C.ItemsId = M.ItemsId
AND C.BranchId = M.BranchId
LEFT OUTER JOIN (SELECT B.ItemsId, A.BranchId, SUM(B.FreeIssue) AS PurchaseFreeIssue
FROM pihd A
INNER JOIN pidt B
ON A.PIHDId = B.PIHDId
WHERE A.CancelStatus = 0
AND (A.PIDate BETWEEN date1 AND date2)
GROUP BY B.ItemsId, A.BranchId) N
ON C.ItemsId = N.ItemsId
AND C.BranchId = N.BranchId
LEFT OUTER JOIN (SELECT B.ItemsId, A.BranchId, SUM(B.FreeIssue) AS SalesFreeIssue
FROM salesorderhd A
INNER JOIN salesorderdt B
ON A.SOHDId = B.SOHDId
WHERE A.CancelStatus = 0
AND (A.SODate BETWEEN date1 AND date2)
GROUP BY B.ItemsId, A.BranchId) O
ON C.ItemsId = O.ItemsId
AND C.BranchId = O.BranchId
LEFT OUTER JOIN (SELECT X.ItemsId, X.BranchId, IFNULL(SUM(X.FreeIssue), 0) AS SalesReturnFreeIssue
FROM(
SELECT B.ItemsId, A.BranchId, B.FreeIssue
FROM salesorderhdreturn A
INNER JOIN salesorderdtreturn B
ON A.SOHDId = B.SOHDId
WHERE A.CancelStatus = 0
AND (A.SODate BETWEEN date1 AND date2)
UNION ALL
SELECT B.ItemsId, A.BranchId, B.FreeIssue
FROM salesorderhd A
INNER JOIN directsalesreturn B
ON A.SOHDId = B.SOHDId
WHERE A.CancelStatus = 0
AND (A.SODate BETWEEN date1 AND date2)
UNION ALL
SELECT BB.ItemsId, A.BranchId, B.FreeIssue AS FreeIssue
FROM salesorderhd A
INNER JOIN salesorderdt BB
ON A.SOHDId = BB.SOHDId
INNER JOIN (SELECT E.SOHDId, E.SODTId, SUM(E.FreeIssue) AS FreeIssue
FROM salesreturn E
GROUP BY E.SOHDId, E.SODTId) B
ON BB.SOHDId = B.SOHDId
AND BB.SODTId = B.SODTId
WHERE A.CancelStatus = 0
AND (A.SODate BETWEEN date1 AND date2)
)X
GROUP BY X.ItemsId, X.BranchId
)P
ON C.ItemsId = P.ItemsId
AND C.BranchId = P.BranchId
LEFT OUTER JOIN (SELECT X.ItemsId, X.BranchId, IFNULL(SUM(X.ReturnQty), 0) AS PurchaseReturn
FROM(
SELECT B.ItemsId, A.BranchId, B.PurchaseQty AS ReturnQty
FROM pihdreturn A
INNER JOIN pidtreturn B
ON A.PIHDId = B.PIHDId
WHERE (A.PIDate BETWEEN date1 AND date2)
UNION ALL
SELECT B.ItemsId, A.BranchId, B.PurchaseQty AS ReturnQty
FROM pihd A
INNER JOIN pidtrtn B
ON A.PIHDId = B.PIHDId
WHERE A.CancelStatus = 0
AND (A.PIDate BETWEEN date1 AND date2)
)X
GROUP BY X.ItemsId, X.BranchId
)Q
ON C.ItemsId = Q.ItemsId
AND C.BranchId = Q.BranchId
LEFT OUTER JOIN (SELECT X.ItemsId, X.BranchId, IFNULL(SUM(X.ReturnFreeIssue), 0) AS PurchaseFreeIssueReturn
FROM(
SELECT B.ItemsId, A.BranchId, B.FreeIssue AS ReturnFreeIssue
FROM pihdreturn A
INNER JOIN pidtreturn B
ON A.PIHDId = B.PIHDId
WHERE (A.PIDate BETWEEN date1 AND date2)
UNION ALL
SELECT B.ItemsId, A.BranchId, B.FreeIssue AS ReturnFreeIssue
FROM pihd A
INNER JOIN pidtrtn B
ON A.PIHDId = B.PIHDId
WHERE A.CancelStatus = 0
AND (A.PIDate BETWEEN date1 AND date2)
)X
GROUP BY X.ItemsId, X.BranchId
)R
ON C.ItemsId = R.ItemsId
AND C.BranchId = R.BranchId
ORDER BY A.ItemsId, A.ItemCode, D.BranchName;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportBranchStocks`;
DELIMITER |
CREATE PROCEDURE `ReportBranchStocks`()
BEGIN
SELECT A.ItemsId
, A.ItemCode
, A.ItemName
, B.ItemCatName AS ItemCategory
, E.ItemSubCatName AS ItemSubCategory
, A.SellingPrice AS RetailPrice
, A.Discount AS RetailDiscount
, A.SPSellingPrice AS WholesalePrice
, A.WholeSaleDiscount AS WholesaleDiscount
, A.ShopPrice
, A.MinSellingPrice
, A.AvgCost AS AverageCost
, A.CostPrice AS LastPurchasePrice
, C.AvailableQty AS BranchQty
, C.Damage AS DamageQty
, (A.AvgCost * C.AvailableQty) AS AVGCostStockValue
, (A.CostPrice * C.AvailableQty) AS LPPStockValue
, C.RackNo
, A.RawMaterial
, A.AllowSales
, A.AllowPurchase
, A.AllowInventory
, F.SupplierName AS SupplierName
,TRIM(Replace(Replace(Replace(D.BranchName,'\t',''),'\n',''),'\r','')) AS BranchName
FROM itemsummary A
INNER JOIN itemcategory B
ON A.ItemCatId = B.ItemCatId
INNER JOIN branchstock C
ON A.ItemsId = C.ItemsId
INNER JOIN branch D
ON C.BranchId = D.BranchId
LEFT OUTER JOIN itemsubcategory E
ON A.ItemSubCatId = E.ItemSubCatId
AND A.ItemCatId = E.ItemCatId
LEFT OUTER JOIN supplier F
ON A.SupplierId = F.SupplierId
ORDER BY A.ItemsId, A.ItemCode, D.BranchName;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportBranchStocksReport`;
DELIMITER |
CREATE PROCEDURE `ReportBranchStocksReport`()
BEGIN
SELECT A.ItemsId
, A.ItemCode
, A.ItemName
, B.ItemCatName AS ItemCategory
, E.ItemSubCatName AS ItemSubCategory
, A.SellingPrice AS RetailPrice
, A.Discount AS RetailDiscount
, A.SPSellingPrice AS WholesalePrice
, A.WholeSaleDiscount AS WholesaleDiscount
, A.ShopPrice
, A.MinSellingPrice
, A.AvgCost AS AverageCost
, A.CostPrice AS LastPurchasePrice
, C.AvailableQty AS BranchQty
, C.Damage AS DamageQty
, (A.AvgCost * C.AvailableQty) AS AVGCostStockValue
, (A.CostPrice * C.AvailableQty) AS LPPStockValue
, C.RackNo
,TRIM(Replace(Replace(Replace(D.BranchName,'\t',''),'\n',''),'\r','')) AS BranchName
FROM itemsummary A
INNER JOIN itemcategory B
ON A.ItemCatId = B.ItemCatId
INNER JOIN branchstock C
ON A.ItemsId = C.ItemsId
INNER JOIN branch D
ON C.BranchId = D.BranchId
LEFT OUTER JOIN itemsubcategory E
ON A.ItemSubCatId = E.ItemSubCatId
AND A.ItemCatId = E.ItemCatId
ORDER BY A.ItemsId, A.ItemCode, D.BranchName;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportBranchStockTransfer`;
DELIMITER |
CREATE PROCEDURE `ReportBranchStockTransfer`(in
date1 date,
date2 date)
BEGIN
SELECT A.TransferHDId
, A.TransferDate
, F.ItemCatName AS ItemCategory
, C.ItemCode
, C.ItemName
, B.Qty AS TransferQty
, D.BranchName AS FromBranch
, E.BranchName AS ToBranch
, G.UserName
FROM stocktransferhd A
INNER JOIN stocktransferdt B
ON A.TransferHDId = B.TransferHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
INNER JOIN branch D
ON A.FromBranchId = D.BranchId
INNER JOIN branch E
ON A.ToBranchId = E.BranchId
INNER JOIN itemcategory F
ON C.ItemCatId = F.ItemCatId
INNER JOIN useraccount G
ON A.CreatedBy = G.UserID
WHERE A.TransferDate BETWEEN date1 AND date2
ORDER BY A.TransferHDId;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportBranchSupplierCreditData`;
DELIMITER |
CREATE PROCEDURE `ReportBranchSupplierCreditData`(in
date1 date,
date2 date)
BEGIN
SELECT D.SupplierName
, E.CreditDate
, E.PIHDId AS GRNNo
, E.CreditAmount
, E.CreditDueDays
, E.CreditDueDate
, DATEDIFF(E.CreditDueDate, CURDATE()) AS DaysLeft
, A.CreditPayHDId AS PaymentId
, A.PaymentDate
, B.PaymentAmount
, C.PayMode
, B.CardChequeNo
FROM suppliercredit E
INNER JOIN supplier D
ON E.SupplierId = D.SupplierId
LEFT OUTER JOIN suppcreditpayment B
ON E.SupplierId = B.SupplierId
AND E.PIHDId = B.BillNo
LEFT OUTER JOIN suppcreditpaymenthd A
ON A.CreditPayHDId = B.CreditPayHDId
LEFT OUTER JOIN paymentmode C
ON A.PayModeId = C.PayModeId
WHERE (E.CreditDate BETWEEN date1 AND date2);
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportBranchSupplierPayment`;
DELIMITER |
CREATE PROCEDURE `ReportBranchSupplierPayment`(in
date1 date,
date2 date)
BEGIN
SELECT A.CreditPayHDId AS PaymentId
, A.PaymentDate
, D.SupplierName
, B.BillNo
, B.PaymentAmount
, C.PayMode
, B.CardChequeNo
FROM suppcreditpaymenthd A
INNER JOIN suppcreditpayment B
ON A.CreditPayHDId = B.CreditPayHDId
INNER JOIN paymentmode C
ON A.PayModeId = C.PayModeId
INNER JOIN supplier D
ON A.SupplierId = D.SupplierId
WHERE (A.PaymentDate BETWEEN date1 AND date2);
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportByCategorySalesDateAll`;
DELIMITER |
CREATE PROCEDURE `ReportByCategorySalesDateAll`(in date1 date,
date2 date)
BEGIN
SELECT X.SODate
, X.ItemCategory
, SUM(X.SalesQty) AS SalesQty
, SUM(X.SalesAmount) AS SalesAmount
, SUM(X.Discount) AS Discount
, SUM(X.NetAmount) AS NetAmount
, SUM(X.ReturnAmount) AS ReturnAmount
, date1 as FromDate
, date2 as ToDate
FROM(
SELECT A.SODate
, E.ItemCatName AS ItemCategory
, B.SalesQty
, B.SalesQty * B.SalesPrice AS SalesAmount
, B.Discount
, B.NetAmount
, 0 AS ReturnAmount
FROM salesorderhd A
INNER JOIN salesorderdt B
ON A.SOHDId = B.SOHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
INNER JOIN itemcategory E
ON C.ItemCatId = E.ItemCatId
WHERE (A.CancelStatus = 0)
and (A.SODate BETWEEN date1 AND date2)
UNION ALL
SELECT A.SODate
, E.ItemCatName AS ItemCategory
, B.SalesQty * -1 AS SalesQty
, (B.SalesQty * B.SalesPrice) * -1 AS SalesAmount
, (B.Discount * -1) AS Discount
, ((B.SalesQty * B.SalesPrice) - B.Discount) * -1 AS NetAmount
, B.NetAmount AS ReturnAmount
FROM salesorderhd A
INNER JOIN directsalesreturn B
ON A.SOHDId = B.SOHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
INNER JOIN itemcategory E
ON C.ItemCatId = E.ItemCatId
WHERE (A.CancelStatus = 0)
and (A.SODate BETWEEN date1 AND date2)
UNION ALL
SELECT A.SODate
, E.ItemCatName AS ItemCategory
, B.SalesQty * -1 AS 'SalesQty'
, (B.SalesQty * B.SalesPrice) * -1 AS SalesAmount
, B.Discount * -1 AS Discount
, B.NetAmount * -1 AS NetAmount
, B.NetAmount AS ReturnAmount
FROM salesorderhdreturn A
INNER JOIN salesorderdtreturn B
ON A.SOHDId = B.SOHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
INNER JOIN itemcategory E
ON C.ItemCatId = E.ItemCatId
WHERE (A.CancelStatus = 0)
and (A.SODate BETWEEN date1 AND date2)
UNION ALL
SELECT A.SODate
, E.ItemCatName AS ItemCategory
, B.ReturnQty * -1 AS SalesQty
, (B.ReturnQty * B.SalesPrice) * -1 AS SalesAmount
, B.Discount * -1 AS Discount
, ((B.ReturnQty * B.SalesPrice) - B.Discount) * -1 AS NetAmount
, B.NetAmount AS ReturnAmount
FROM salesorderhd A
INNER JOIN salesorderdt BB
ON A.SOHDId = BB.SOHDId
INNER JOIN salesreturn B
ON BB.SOHDId = B.SOHDId
AND BB.SODTId = B.SODTId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
INNER JOIN itemcategory E
ON C.ItemCatId = E.ItemCatId
WHERE (A.CancelStatus = 0)
and (A.SODate BETWEEN date1 AND date2)
)X
GROUP BY X.SODate
, X.ItemCategory
;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportByCustSales`;
DELIMITER |
CREATE PROCEDURE `ReportByCustSales`(in date1 date, date2 date, CustomerId1 int)
BEGIN
SELECT        A.SODate, D.CustomerName, C.ItemName, SUM(B.SalesQty) AS SalesQty, B.SalesPrice, SUM(B.SalesQty) * B.SalesPrice AS SalesAmount, A.CustomerId, E.CompanyName, E.CompanyAddress1,
E.CompanyAddress2, E.ContactNo1, E.ContactNo2, E.CompanyLogo
FROM            salesorderhd A INNER JOIN
salesorderdt B ON A.SOHDId = B.SOHDId INNER JOIN
itemsummary C ON B.ItemsId = C.ItemsId LEFT OUTER JOIN
customer D ON A.CustomerId = D.CustomerId, companyinfo E
GROUP BY B.SalesPrice, C.ItemName, A.SODate, A.CustomerId
HAVING        (A.SODate BETWEEN date1 AND date2) AND (A.CustomerId = CustomerId1)
ORDER BY A.SODate, D.CustomerName;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportByItemCategory`;
DELIMITER |
