DROP PROCEDURE IF EXISTS `ReportByPurchaseDate`;
DELIMITER |
CREATE PROCEDURE `ReportByPurchaseDate`(in date1 date, date2 date)
BEGIN
SELECT A.PIDate AS PurchasedDate
,A.PIHDId
,A.PINo
,A.SupplierInvoiceNo
, C.ItemCode
, C.ItemName
, D.SupplierName
, B.PurchasePrice AS Price
, B.PurchaseQty
, B.FreeIssue
, B.Discount
, B.NetAmount
, E.CompanyName
, E.CompanyAddress1
, E.CompanyAddress2
, E.ContactNo1
, E.Web
, E.Email
FROM pihd A
INNER JOIN pidt B
ON A.PIHDId = B.PIHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
INNER JOIN supplier D
ON A.SupplierId = D.SupplierId
, companyinfo E
WHERE (A.PIDate BETWEEN date1 AND date2)
AND (A.CancelStatus = 0)
ORDER BY PurchasedDate, C.ItemName;
END |
DELIMITER ;

