DROP PROCEDURE IF EXISTS `ReportBySalesDate`;
DELIMITER |
CREATE PROCEDURE `ReportBySalesDate`(in date1 date,
date2 date)
BEGIN
SELECT X.BillNo
, X.SODate
, X.ItemName
, X.SalesQty
, X.SellingPrice
, X.SalesAmount
, X.Discount
, X.NetAmount
, X.CompanyName
, X.CompanyAddress1
, X.CompanyAddress2
, X.ContactNo1
, X.ContactNo2
, X.ItemCode
, X.ItemCatId
, X.RepId
, X.CustomerId
, X.TotDisc
, X.ReturnAmount
, date1 as FromDate
, date2 as ToDate
FROM(
SELECT A.SOHDId AS BillNo
, A.SODate
, C.ItemName
, B.SalesQty
, B.SalesPrice AS SellingPrice
, B.SalesQty * B.SalesPrice AS SalesAmount
, B.Discount
, B.NetAmount
, D.CompanyName
, D.CompanyAddress1
, D.CompanyAddress2
, D.ContactNo1
, D.ContactNo2
, C.ItemCode
, C.ItemCatId
, A.RepId
, A.CustomerId
, E.SODiscount AS TotDisc
, 0 AS ReturnAmount
FROM salesorderhd A
INNER JOIN salesorderdt B
ON A.SOHDId = B.SOHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
INNER JOIN companyinfo D
ON A.CompanyInfoId = D.CompanyInfoId
,(SELECT SUM(SODiscount) AS SODiscount
FROM salesorderhd
WHERE (CancelStatus = 0)
and SODate BETWEEN date1 AND date2) E
WHERE (A.CancelStatus = 0)
and (A.SODate BETWEEN date1 AND date2)
UNION ALL
SELECT A.SOHDId AS BillNo
, A.SODate
, CONCAT(C.ItemName, '[Return]') AS ItemName
, B.SalesQty * -1 AS SalesQty
, 0 AS SellingPrice
, 0 AS SalesAmount
, 0 AS Discount
, 0 AS NetAmount
, D.CompanyName
, D.CompanyAddress1
, D.CompanyAddress2
, D.ContactNo1
, D.ContactNo2
, CONCAT(C.ItemCode, '[Rtn]') AS ItemCode
, C.ItemCatId
, A.RepId
, A.CustomerId
