DROP PROCEDURE IF EXISTS `ReportBySalesDate3in`;
DELIMITER |
CREATE PROCEDURE `ReportBySalesDate3in`(in date1 date,
date2 date)
BEGIN
SELECT C.ItemName
, SUM(B.SalesQty) AS SalesQty
, B.SalesPrice AS SellingPrice
, SUM(B.SalesQty) * B.SalesPrice AS SalesAmount
, D.CompanyName
, D.CompanyAddress1
, D.CompanyAddress2
, D.ContactNo1
, D.ContactNo2
, D.CompanyLogo
FROM salesorderhd A
INNER JOIN salesorderdt B
ON A.SOHDId = B.SOHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
, companyinfo D
WHERE (A.SODate BETWEEN date1 AND date2)
AND (A.CancelStatus = 0)
GROUP BY C.ItemName, B.SalesPrice
ORDER BY C.ItemName;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportBySalesDateAllBranch`;
DELIMITER |
CREATE PROCEDURE `ReportBySalesDateAllBranch`(in
date1 date,
date2 date)
BEGIN
SELECT A.SOHDId AS BillNo
, A.ReferanceNo
, A.SODate
, C.ItemCode
, C.ItemName
, B.SalesQty
, B.SalesPrice AS SellingPrice
, B.SalesQty * B.SalesPrice AS SalesAmount
, B.Discount
, B.NetAmount
, E.EmployeeName AS SalesRep
, D.BranchName
FROM salesorderhd A
INNER JOIN salesorderdt B
ON A.SOHDId = B.SOHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
INNER JOIN branch D
ON A.BranchId = D.BranchId
LEFT OUTER JOIN employeeregistration E
ON A.RepId = E.EmployeeID
WHERE (A.CancelStatus = 0)
and (A.SODate BETWEEN date1 AND date2)
ORDER BY BillNo, A.SODate, C.ItemName;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportBySalesDateBranch`;
DELIMITER |
CREATE PROCEDURE `ReportBySalesDateBranch`(in
date1 date,
date2 date,
BranchId1 int)
BEGIN
SELECT A.SOHDId AS BillNo
, A.SODate
, C.ItemName
, B.SalesQty
, B.SalesPrice AS SellingPrice
, B.SalesQty * B.SalesPrice AS SalesAmount
, B.Discount
, B.NetAmount
, D.CompanyName
, D.CompanyAddress1
, D.CompanyAddress2
, D.ContactNo1
, D.ContactNo2
, C.ItemCode
, C.ItemCatId
, A.RepId
, A.CustomerId
, E.SODiscount AS TotDisc
FROM salesorderhd A
INNER JOIN salesorderdt B
ON A.SOHDId = B.SOHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
, companyinfo D,
(SELECT SUM(SODiscount) AS SODiscount
FROM salesorderhd
WHERE (CancelStatus = 0)
and SODate BETWEEN date1 AND date2) E
WHERE (A.CancelStatus = 0)
and (A.SODate BETWEEN date1 AND date2)
AND (A.BranchId = BranchId1)
ORDER BY BillNo, A.SODate, C.ItemName;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportBySalesDateBranchTax`;
DELIMITER |
CREATE PROCEDURE `ReportBySalesDateBranchTax`(in
date1 date,
date2 date,
BranchId1 int)
BEGIN
SELECT A.SOHDId AS BillNo
, A.SODate
, C.ItemName
, B.SalesQty
, (B.SalesPrice * (G.CommissionRate/100)) AS SellingPrice
, B.SalesQty * (B.SalesPrice * (G.CommissionRate/100)) AS SalesAmount
, B.Discount
, (B.SalesQty * (B.SalesPrice * (G.CommissionRate/100))) - (B.Discount * (G.CommissionRate/100)) AS NetAmount
, D.BranchName AS CompanyName
, D.BranchAddress AS CompanyAddress1
, D.BranchAddress2 AS CompanyAddress2
, D.BranchTelNo AS ContactNo1
, D.BranchTelNo2 AS ContactNo2
, C.ItemCode
, C.ItemCatId
, A.RepId
, A.CustomerId
, (E.SODiscount * (G.CommissionRate/100)) AS TotDisc
, 0 AS ReturnAmount
FROM salesorderhd A
INNER JOIN salesorderdt B
ON A.SOHDId = B.SOHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
INNER JOIN branch D
ON A.BranchId = D.BranchId
INNER JOIN companyinfo G
ON A.CompanyInfoId = G.CompanyInfoId ,
(SELECT SUM(SODiscount) AS SODiscount
FROM salesorderhd
WHERE (CancelStatus = 0)
AND (BranchId = BranchId1)
and SODate BETWEEN date1 AND date2) E
WHERE (A.CancelStatus = 0)
AND (A.BranchId = BranchId1)
and (A.SODate BETWEEN date1 AND date2)
ORDER BY BillNo, A.SODate, C.ItemName;
END |
DELIMITER ;

