, companyinfo D,
(SELECT SUM(SODiscount) AS SODiscount
FROM salesorderhd
WHERE (CancelStatus = 0)
and (PayModeId = PayModeId1)
and SODate BETWEEN date1 AND date2) E
WHERE (A.CancelStatus = 0)
and (A.SODate BETWEEN date1 AND date2)
and (A.PayModeId = PayModeId1)
)X
ORDER BY X.BillNo, X.SODate, X.ItemName;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportBySalesDatePrice`;
DELIMITER |
CREATE PROCEDURE `ReportBySalesDatePrice`(in
date1 date,
date2 date)
BEGIN
SELECT X.SOHDId
, X.SODate
, X.CustomerName
, X.ItemCode
, X.ItemName
, X.SalesQty
, X.SalesPrice
, X.RetailPrice
, X.Debit
, X.Cretit
, date1 as FromDate
, date2 as ToDate
FROM(
SELECT A.SOHDId
, A.SODate
, D.CustomerName
, B.ItemCode
, C.ItemName
, B.SalesQty
, B.SalesPrice
, C.SellingPrice AS RetailPrice
, ((B.SalesPrice - C.SellingPrice) * B.SalesQty) AS Debit
, 0 AS Cretit
FROM salesorderhd A
INNER JOIN salesorderdt B
ON A.SOHDId = B.SOHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
AND B.SalesPrice > C.SellingPrice
LEFT OUTER JOIN customer D
ON A.CustomerId = D.CustomerId
WHERE (A.CancelStatus = 0)
AND (A.SODate BETWEEN date1 AND date2)
UNION ALL
SELECT A.SOHDId
, A.SODate
, D.CustomerName
, B.ItemCode
, C.ItemName
, B.SalesQty
, B.SalesPrice
, C.SellingPrice AS RetailPrice
, 0 AS Debit
,((C.SellingPrice - B.SalesPrice) * B.SalesQty) AS Cretit
FROM salesorderhd A
INNER JOIN salesorderdt B
ON A.SOHDId = B.SOHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
AND B.SalesPrice < C.SellingPrice
LEFT OUTER JOIN customer D
ON A.CustomerId = D.CustomerId
WHERE (A.CancelStatus = 0)
AND (A.SODate BETWEEN date1 AND date2)
)X
ORDER BY X.SOHDId;
END |
DELIMITER ;

