DROP PROCEDURE IF EXISTS `ReportBySalesDateTax`;
DELIMITER |
CREATE PROCEDURE `ReportBySalesDateTax`(in date1 date,
date2 date)
BEGIN
SELECT A.SOHDId AS BillNo
, A.SODate
, C.ItemName
, B.SalesQty
, (B.SalesPrice * (G.CommissionRate/100)) AS SellingPrice
, B.SalesQty * (B.SalesPrice * (G.CommissionRate/100)) AS SalesAmount
, B.Discount
, (B.SalesQty * (B.SalesPrice * (G.CommissionRate/100))) - (B.Discount * (G.CommissionRate/100)) AS NetAmount
, D.BranchName AS CompanyName
, D.BranchAddress AS CompanyAddress1
, D.BranchAddress2 AS CompanyAddress2
, D.BranchTelNo AS ContactNo1
, D.BranchTelNo2 AS ContactNo2
, C.ItemCode
, C.ItemCatId
, A.RepId
, A.CustomerId
, (E.SODiscount* (G.CommissionRate/100)) AS TotDisc
, 0 AS ReturnAmount
FROM salesorderhd A
INNER JOIN salesorderdt B
ON A.SOHDId = B.SOHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
INNER JOIN branch D
ON A.BranchId = D.BranchId
INNER JOIN companyinfo G
ON A.CompanyInfoId = G.CompanyInfoId ,
(SELECT SUM(SODiscount) AS SODiscount
FROM salesorderhd
WHERE (CancelStatus = 0)
and SODate BETWEEN date1 AND date2) E
WHERE (A.CancelStatus = 0)
and (A.SODate BETWEEN date1 AND date2)
ORDER BY BillNo, A.SODate, C.ItemName;
END |
DELIMITER ;

