FROM salesorderhd
WHERE (CancelStatus = 0)
and SODate BETWEEN date1 AND date2) E
WHERE (A.CancelStatus = 0)
and (A.SODate BETWEEN date1 AND date2)
)X
ORDER BY X.BillNo, X.SODate, X.ItemName;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportBySalesDateWithRtnBranch`;
DELIMITER |
CREATE PROCEDURE `ReportBySalesDateWithRtnBranch`(in
date1 date,
date2 date
, BranchId1 int)
BEGIN
SELECT X.BillNo
, X.SODate
, X.ItemName
, X.SalesQty
, X.SellingPrice
, X.SalesAmount
, X.Discount
, X.NetAmount
, X.CompanyName
, X.CompanyAddress1
, X.CompanyAddress2
, X.ContactNo1
, X.ContactNo2
, X.ItemCode
, X.ItemCatId
, X.RepId
, X.CustomerId
, X.TotDisc
FROM
(
SELECT A.SOHDId AS BillNo
, A.SODate
, C.ItemName
, B.SalesQty
, B.SalesPrice AS SellingPrice
, B.SalesQty * B.SalesPrice AS SalesAmount
, B.Discount
, B.NetAmount
, D.CompanyName
, D.CompanyAddress1
, D.CompanyAddress2
, D.ContactNo1
, D.ContactNo2
, C.ItemCode
, C.ItemCatId
, A.RepId
, A.CustomerId
, E.SODiscount AS TotDisc
FROM salesorderhd A
INNER JOIN salesorderdt B
ON A.SOHDId = B.SOHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
, companyinfo D,
(SELECT SUM(SODiscount) AS SODiscount
FROM salesorderhd
WHERE (CancelStatus = 0)
and SODate BETWEEN date1 AND date2) E
WHERE (A.CancelStatus = 0)
and (A.SODate BETWEEN date1 AND date2)
AND (A.BranchId = BranchId1)
UNION ALL
SELECT A.SOHDId AS BillNo
, A.SODate
, CONCAT(C.ItemName, '[Return]') AS ItemName
, B.SalesQty * -1 AS 'SalesQty'
, B.SalesPrice AS SellingPrice
, (B.SalesQty * -1) * B.SalesPrice AS SalesAmount
, B.Discount * -1
, B.NetAmount * -1
, D.CompanyName
, D.CompanyAddress1
, D.CompanyAddress2
, D.ContactNo1
, D.ContactNo2
, C.ItemCode
, C.ItemCatId
, A.RepId
, A.CustomerId
, E.SODiscount AS TotDisc
FROM salesorderhd A
INNER JOIN directsalesreturn B
ON A.SOHDId = B.SOHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
, companyinfo D,
(SELECT SUM(SODiscount) AS SODiscount
FROM salesorderhd
WHERE (CancelStatus = 0)
and SODate BETWEEN date1 AND date2) E
WHERE (A.CancelStatus = 0)
and (A.SODate BETWEEN date1 AND date2)
AND (A.BranchId = BranchId1)
UNION ALL
SELECT A.SOHDId AS BillNo
, A.SODate
, CONCAT(C.ItemName, '[Return]') AS ItemName
, B.SalesQty * -1 AS 'SalesQty'
, B.SalesPrice AS SellingPrice
, (B.SalesQty * -1) * B.SalesPrice AS SalesAmount
, B.Discount * -1
, B.NetAmount * -1
, D.CompanyName
, D.CompanyAddress1
, D.CompanyAddress2
, D.ContactNo1
, D.ContactNo2
, C.ItemCode
, C.ItemCatId
, A.RepId
, A.CustomerId
, 0 AS TotDisc
FROM salesorderhdreturn A
INNER JOIN salesorderdtreturn B
ON A.SOHDId = B.SOHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
, companyinfo D
WHERE (A.CancelStatus = 0)
and (A.SODate BETWEEN date1 AND date2)
AND (A.BranchId = BranchId1)
)X
ORDER BY X.BillNo, X.SODate, X.ItemName;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportBySalesRtnDate`;
DELIMITER |
CREATE PROCEDURE `ReportBySalesRtnDate`(in date1 date,
date2 date)
BEGIN
SELECT A.SOHDId AS BillNo
, A.SODate
, C.ItemName
, B.SalesQty
, B.SalesPrice AS SellingPrice
, B.SalesQty * B.SalesPrice AS SalesAmount
, B.Discount
, B.NetAmount
, D.CompanyName
, D.CompanyAddress1
, D.CompanyAddress2
, D.ContactNo1
, D.ContactNo2
, C.ItemCode
, C.ItemCatId
, A.RepId
, A.CustomerId
, 0 AS TotDisc
, E.CustomerName
FROM salesorderhdreturn A
INNER JOIN salesorderdtreturn B
ON A.SOHDId = B.SOHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
LEFT OUTER JOIN customer E
ON A.CustomerId = E.CustomerId
, companyinfo D
WHERE (A.CancelStatus = 0)
and (A.SODate BETWEEN date1 AND date2)
ORDER BY BillNo, A.SODate, C.ItemName;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportBySteward`;
DELIMITER |
CREATE PROCEDURE `ReportBySteward`(in date1 date, date2 date, Steward1 int)
BEGIN
SELECT salesorderhd.SODate
, salesorderdt.ItemCode
, itemsummary.ItemName
, itemcategory.ItemCatName
, SUM(salesorderdt.SalesQty) AS SalesQty
, salesorderdt.SalesPrice
, SUM(salesorderdt.SalesQty) * salesorderdt.SalesPrice AS NetAmount
, itemsummary.ItemCatId
, useraccount.UserName
FROM salesorderhd
INNER JOIN salesorderdt
ON salesorderhd.SOHDId = salesorderdt.SOHDId
INNER JOIN itemsummary
ON salesorderdt.ItemsId = itemsummary.ItemsId
INNER JOIN itemcategory
ON itemsummary.ItemCatId = itemcategory.ItemCatId
LEFT OUTER JOIN useraccount
ON salesorderhd.CreatedBy = useraccount.UserID
GROUP BY salesorderdt.SalesPrice
, salesorderdt.ItemCode
, itemsummary.ItemName
, salesorderhd.SODate
, itemsummary.ItemCatId
, itemcategory.ItemCatName
, useraccount.UserName
, salesorderhd.CreatedBy
HAVING (salesorderhd.SODate BETWEEN date1 AND date2)
AND (salesorderhd.CreatedBy = Steward1)
ORDER BY salesorderhd.SODate, salesorderdt.ItemCode, itemsummary.ItemName;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportCustomerCredit`;
DELIMITER |
CREATE PROCEDURE `ReportCustomerCredit`(in date1 date, date2 date)
BEGIN
SELECT B.CustomerName
, A.BillNo
, A.CreditDate
, A.CreditAmount
, C.PaymentDate
, IFNULL(D.PaymentAmount, 0) AS PaymentAmount
, A.CustomerId
, B.NewAreaId
,((SELECT DATEDIFF(CreditDate, CONVERT_TZ(now(), @@session.time_zone, '+05:30'))
FROM customercredit
WHERE (BillNo = A.BillNo)
AND (CustomerId = A.CustomerId)) * -1) AS DueDays
, C.PaymentAmount AS Payments
, B.CustomerTelNo
FROM customercredit A
INNER JOIN customer B
ON A.CustomerId = B.CustomerId
LEFT OUTER JOIN (SELECT Z.CustomerId, Z.PaymentDate, SUM(Z.PaymentAmount) AS PaymentAmount, Z.BillNo, Z.CreditPayHDId
FROM custcreditpayment Z
WHERE Z.PaymentAmount > 0
GROUP BY Z.CustomerId, Z.PaymentDate, Z.BillNo, Z.CreditPayHDId) C
ON A.CustomerId = C.CustomerId
AND A.BillNo = C.BillNo
LEFT OUTER JOIN (SELECT Z.CustomerId, SUM(Z.PaymentAmount) AS PaymentAmount, Z.BillNo
FROM custcreditpayment Z
WHERE Z.PaymentAmount > 0
GROUP BY Z.CustomerId, Z.BillNo) D
ON A.CustomerId = D.CustomerId
AND A.BillNo = D.BillNo
WHERE (A.CreditDate BETWEEN date1 AND date2)
AND (A.CreditAmount > 0)
AND (A.CreditAmount > A.PaymentAmount)
ORDER BY B.CustomerName, A.BillNo;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportCustomerCreditBalance`;
DELIMITER |
CREATE PROCEDURE `ReportCustomerCreditBalance`()
BEGIN
SELECT X.CustomerName
,X.CreditBalance
FROM(
SELECT A.CustomerName
, ((SELECT IFNULL((SUM(B.CreditAmount)), 0) AS CreditAmount
FROM customercredit B
where A.CustomerId = B.CustomerId) - (SELECT IFNULL((SUM(B.PaymentAmount)), 0) AS Expr1
FROM custcreditpayment B
where A.CustomerId = B.CustomerId))
AS CreditBalance
FROM customer A
ORDER BY CustomerName)X
WHERE X.CreditBalance > 0;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportCustomerCreditByArea`;
DELIMITER |
CREATE PROCEDURE `ReportCustomerCreditByArea`(in date1 date, date2 date, NewAreaId1 int)
BEGIN
SELECT B.CustomerName
, A.BillNo
, A.CreditDate
, A.CreditAmount
, A.PaymentDate
, A.PaymentAmount
, A.CustomerId
, B.NewAreaId
,((SELECT DATEDIFF(CreditDate, CONVERT_TZ(now(), @@session.time_zone, '+05:30'))
FROM customercredit
WHERE (BillNo = A.BillNo)
AND (CustomerId = A.CustomerId)) * -1) AS DueDays
, C.PaymentAmount AS Payments
, B.CustomerTelNo
FROM customercredit A
INNER JOIN customer B
ON A.CustomerId = B.CustomerId
LEFT OUTER JOIN custcreditpayment C
ON A.CustomerId = C.CustomerId
AND A.BillNo = C.BillNo
WHERE (A.CreditDate BETWEEN date1 AND date2)
AND (B.NewAreaId = NewAreaId1)
AND (A.CreditAmount > 0)
AND (A.CreditAmount > A.PaymentAmount)
ORDER BY B.CustomerName, A.BillNo;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportCustomerCreditByCust`;
DELIMITER |
CREATE PROCEDURE `ReportCustomerCreditByCust`(in date1 date, date2 date, CustomerId1 int)
BEGIN
SELECT B.CustomerName
, A.BillNo
, A.CreditDate
, A.CreditAmount
, C.PaymentDate
, IFNULL(D.PaymentAmount, 0) AS PaymentAmount
, A.CustomerId
, B.NewAreaId
,((SELECT DATEDIFF(CreditDate, CONVERT_TZ(now(), @@session.time_zone, '+05:30'))
FROM customercredit
WHERE (BillNo = A.BillNo)
AND (CustomerId = A.CustomerId)) * -1) AS DueDays
, C.PaymentAmount AS Payments
, B.CustomerTelNo
FROM customercredit A
INNER JOIN customer B
ON A.CustomerId = B.CustomerId
LEFT OUTER JOIN (SELECT Z.CustomerId, Z.PaymentDate, SUM(Z.PaymentAmount) AS PaymentAmount, Z.BillNo, Z.CreditPayHDId
FROM custcreditpayment Z
WHERE Z.CustomerId = CustomerId1
AND Z.PaymentAmount > 0
GROUP BY Z.CustomerId, Z.PaymentDate, Z.BillNo, Z.CreditPayHDId) C
ON A.CustomerId = C.CustomerId
AND A.BillNo = C.BillNo
LEFT OUTER JOIN (SELECT Z.CustomerId, SUM(Z.PaymentAmount) AS PaymentAmount, Z.BillNo
FROM custcreditpayment Z
WHERE Z.CustomerId = CustomerId1
AND Z.PaymentAmount > 0
GROUP BY Z.CustomerId, Z.BillNo) D
ON A.CustomerId = D.CustomerId
AND A.BillNo = D.BillNo
WHERE (A.CreditDate BETWEEN date1 AND date2)
AND (A.CustomerId = CustomerId1)
AND (A.CreditAmount > 0)
AND (A.CreditAmount > A.PaymentAmount)
ORDER BY B.CustomerName, A.BillNo;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportCustomerCreditPay`;
DELIMITER |
CREATE PROCEDURE `ReportCustomerCreditPay`(in CustomerId1 int, PayModeId1 int, CreditPayHDId1 INT)
BEGIN
SELECT B.BillNo AS RefNo
, IFNULL(E.SODate, B.CreditDate) AS CreditDate
, B.CreditAmount
, A.PaymentDate
, A.PaymentAmount
, (SELECT Z.CreditAmount - Z.PaymentAmount AS BalanceAmount
FROM customercredit Z
WHERE (Z.CustomerId = A.CustomerId)
AND (BillNo = A.BillNo)) AS BalanceAmount
, C.CustomerName
, C.ContactPerson AS CustomerCode
, C.CustomerAddress
, C.CustomerTelNo
, C.CustomerFaxNo
, C.CustomerEmail
, D.PayMode
, A.CardChequeNo
, F.CompanyName
, F.CompanyAddress1
, F.CompanyAddress2
, F.ContactNo1
, F.ContactNo2
, F.Web
, F.Email
, A.CustomerId
, G.ChequeAmount
, G.ChequeBank
, H.CreditPayHDId
, H.PaymentDate AS CreditPaymentDate
, H.CreatedOn
FROM custcreditpayment A
INNER JOIN customercredit B
ON A.CustomerId = B.CustomerId
AND A.BillNo = B.BillNo
INNER JOIN customer C
ON A.CustomerId = C.CustomerId
INNER JOIN paymentmode D
ON A.PayModeId = D.PayModeId
LEFT OUTER JOIN salesorderhd E
ON B.BillNo = E.SOHDId
LEFT OUTER JOIN customercheque G
ON A.CustomerId = G.CustomerId
AND A.CardChequeNo = G.ChequeNo
AND A.CreditPayHDId = G.CreditPayHDId
INNER JOIN custcreditpaymenthd H
ON A.CreditPayHDId = H.CreditPayHDId
INNER JOIN companyinfo F
ON H.CompanyInfoId = F.CompanyInfoId
WHERE (H.CreditPayHDId = CreditPayHDId1);
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportCustomerCreditSummary`;
DELIMITER |
CREATE PROCEDURE `ReportCustomerCreditSummary`(in date1 date, date2 date)
BEGIN
SELECT B.CustomerName
, IFNULL(SUM(A.CreditAmount), 0) AS CreditAmount
, IFNULL(SUM(BB.PaymentAmount), 0) AS PaymentAmount
FROM customercredit A
INNER JOIN customer B
ON A.CustomerId = B.CustomerId
LEFT OUTER JOIN (SELECT B.BillNo, B.CustomerId, IFNULL((SUM(B.PaymentAmount)), 0) AS PaymentAmount
FROM custcreditpayment B
WHERE B.PaymentDate <= date2
GROUP BY B.BillNo, B.CustomerId
)BB
ON A.CustomerId = BB.CustomerId
AND A.BillNo = BB.BillNo
WHERE (A.CreditDate between date1 and  date2)
GROUP BY B.CustomerName
HAVING IFNULL(SUM(A.CreditAmount), 0) > IFNULL(SUM(BB.PaymentAmount), 0);
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportCustomerSales`;
DELIMITER |
CREATE PROCEDURE `ReportCustomerSales`(in
date1 date,
date2 date)
BEGIN
SELECT A.CustomerId
, A.CustomerName
, ContactPerson as CustomerCode
, A.CustomerAddress
, A.CustomerTelNo
, A.CustomerFaxNo
, A.CustomerEmail
, A.CustomerNICNo
, K.CustomerType
, SUM(D.SONetTotal) AS NetSales
FROM customer A
INNER JOIN salesorderhd D
ON A.CustomerId = D.CustomerId
LEFT OUTER JOIN customertypes K
ON A.CustomerTypeId = K.CustomerTypeId
WHERE (D.CancelStatus = 0)
AND (D.SODate BETWEEN date1 AND date2)
GROUP BY A.CustomerId
, A.CustomerName
, ContactPerson
, A.CustomerAddress
, A.CustomerTelNo
, A.CustomerFaxNo
, A.CustomerEmail
, A.CustomerNICNo
, K.CustomerType;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportDayCollection`;
DELIMITER |
CREATE PROCEDURE `ReportDayCollection`(in BranchId1 int)
BEGIN
DECLARE date1 date;
SET date1 = (select CONVERT_TZ(now(), @@session.time_zone, '+05:30'));
SELECT X.ItemsId
, X.ItemCode
, X.ItemName
, X.ItemCategory
, (X.BranchQty + X.SalesQty + X.FreeIssueQty + X.UnloadingQty) - (X.LoadingQty + X.ReturnQty) AS OpeningStock
, X.LoadingQty
, (((X.BranchQty + X.SalesQty + X.FreeIssueQty + X.UnloadingQty) - (X.LoadingQty + X.ReturnQty)) + X.LoadingQty) AS TotalStock
, X.SalesQty
, X.FreeIssueQty
, X.ReturnQty AS NonDamageReturnItem
, X.DamageReturnQty
, X.UnloadingQty
, X.BranchQty AS EndingBalance
, X.AverageCost
, X.LastPurchasePrice
, X.BranchName
, (X.BranchQty - X.UnloadingQty) AS ShortExces
FROM(
SELECT A.ItemsId
, A.ItemCode
, A.ItemName
, B.ItemCatName AS ItemCategory
, C.AvailableQty AS BranchQty
, (SELECT IFNULL((SUM(BB.Qty)), 0) AS TransferQty
FROM stocktransferhd AA
INNER JOIN stocktransferdt BB
ON AA.TransferHDId = BB.TransferHDId
WHERE BB.ItemsId = C.ItemsId
AND AA.ToBranchId = C.BranchId
AND AA.ToBranchId = BranchId1
AND AA.TransferDate = date1) AS LoadingQty
, (SELECT IFNULL((SUM(BB.SalesQty)), 0) AS SalesQty
FROM salesorderhd AA
INNER JOIN salesorderdt BB
ON AA.SOHDId = BB.SOHDId
WHERE BB.ItemsId = C.ItemsId
AND AA.CancelStatus = 0
AND AA.BranchId = C.BranchId
AND AA.BranchId = BranchId1
AND AA.SODate = date1) AS SalesQty
, (SELECT IFNULL((SUM(BB.FreeIssue)), 0) AS FreeIssueQty
FROM salesorderhd AA
INNER JOIN salesorderdt BB
ON AA.SOHDId = BB.SOHDId
WHERE BB.ItemsId = C.ItemsId
AND AA.CancelStatus = 0
AND AA.BranchId = C.BranchId
AND AA.BranchId = BranchId1
AND AA.SODate = date1) AS FreeIssueQty
, ((SELECT IFNULL((SUM(BB.SalesQty)), 0) AS ReturnQty
FROM salesorderhd AA
INNER JOIN directsalesreturn BB
ON AA.SOHDId = BB.SOHDId
WHERE BB.ItemsId = C.ItemsId
AND AA.CancelStatus = 0
AND BB.Damage = 0
AND AA.BranchId = C.BranchId
AND AA.BranchId = BranchId1
AND AA.SODate = date1) +
(SELECT IFNULL((SUM(BB.SalesQty)), 0) AS ReturnQty
FROM salesorderhdreturn AA
INNER JOIN salesorderdtreturn BB
ON AA.SOHDId = BB.SOHDId
WHERE BB.ItemsId = C.ItemsId
AND AA.CancelStatus = 0
AND BB.Damage = 0
AND AA.BranchId = C.BranchId
AND AA.BranchId = BranchId1
AND AA.SODate = date1)) AS ReturnQty
, ((SELECT IFNULL((SUM(BB.SalesQty)), 0) AS ReturnQty
FROM salesorderhd AA
INNER JOIN directsalesreturn BB
ON AA.SOHDId = BB.SOHDId
WHERE BB.ItemsId = C.ItemsId
AND AA.CancelStatus = 0
AND BB.Damage = 1
AND AA.BranchId = C.BranchId
AND AA.BranchId = BranchId1
AND AA.SODate = date1) +
(SELECT IFNULL((SUM(BB.SalesQty)), 0) AS ReturnQty
FROM salesorderhdreturn AA
INNER JOIN salesorderdtreturn BB
ON AA.SOHDId = BB.SOHDId
WHERE BB.ItemsId = C.ItemsId
AND AA.CancelStatus = 0
AND BB.Damage = 1
AND AA.BranchId = C.BranchId
AND AA.BranchId = BranchId1
AND AA.SODate = date1)) AS DamageReturnQty
, (SELECT IFNULL((SUM(BB.Qty)), 0) AS TransferQty
FROM stocktransferhd AA
INNER JOIN stocktransferdt BB
ON AA.TransferHDId = BB.TransferHDId
WHERE BB.ItemsId = C.ItemsId
AND AA.FromBranchId = C.BranchId
AND AA.FromBranchId = BranchId1
AND AA.TransferDate = date1) AS UnloadingQty
, A.AvgCost AS AverageCost
, A.CostPrice AS LastPurchasePrice
,TRIM(Replace(Replace(Replace(D.BranchName,'\t',''),'\n',''),'\r','')) AS BranchName
FROM itemsummary A
INNER JOIN itemcategory B
ON A.ItemCatId = B.ItemCatId
INNER JOIN branchstock C
ON A.ItemsId = C.ItemsId
INNER JOIN branch D
ON C.BranchId = D.BranchId
WHERE C.BranchId = BranchId1)X;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportDayEndStockBalance`;
DELIMITER |
CREATE PROCEDURE `ReportDayEndStockBalance`(in date1 date)
BEGIN
SELECT A.ItemsId
, A.ItemCode
, A.ItemName
, A.RackNo AS InternalCode
, C.AvailableQty AS OpeningQty
, B.AvailableQty AS AvailableQty
, date1 AS OBDate
FROM itemsummary A
INNER JOIN branchstock B
ON A.ItemsId = B.ItemsId
INNER JOIN obstockbalance C
ON A.ItemsId = C.ItemsId
WHERE C.OBStockDate = date1
AND B.BranchId = 1
AND C.BranchId = 1
AND (C.AvailableQty > 0 OR B.AvailableQty)
Order by A.RackNo;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportExpenses`;
DELIMITER |
CREATE PROCEDURE `ReportExpenses`(in
date1 date,
date2 date)
BEGIN
SELECT A.ExpensesId
, B.CatDescription as ExpenseCategory
, A.PaymentDate
, A.PaymentAmount
, CASE WHEN A.PayCatId IN (1,2) THEN I.EmployeeName ELSE A.Remarks END AS Remarks
, C.UserName
, E.PayMode
, H.VehicleNo
FROM allexpenses A
INNER JOIN expensescategory B
ON A.PayCatId = B.PayCatId
INNER JOIN useraccount C
ON A.CreatedBy = C.UserID
INNER JOIN paymentmode E
ON A.PayModeId = E.PayModeId
LEFT OUTER JOIN vehicles H
ON A.VehicleId = H.VehicleId
LEFT OUTER JOIN employeeregistration I
ON A.RefId = I.EmployeeID
AND A.PayCatId IN (1,2)
WHERE A.PaymentDate BETWEEN date1 AND date2;

END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportExpensesByCategory`;
DELIMITER |
CREATE PROCEDURE `ReportExpensesByCategory`(in date1 date, date2 date, PayCatId1 int)
BEGIN
SELECT C.UserName AS PaiedBy
, B.CatDescription AS ExpCategory
, A.PaymentDate
, A.PaymentAmount
, D.CompanyName
, D.CompanyAddress1
, D.CompanyAddress2
, A.PayCatId
, A.Remarks
, E.BranchName
, A.BranchId
FROM allexpenses A
INNER JOIN expensescategory B
ON A.PayCatId = B.PayCatId
INNER JOIN useraccount C
ON A.CreatedBy = C.UserID
LEFT OUTER JOIN branch E
ON A.BranchId = E.BranchId
, companyinfo D
WHERE (A.PaymentDate BETWEEN date1 AND date2)
AND (A.PayCatId = PayCatId1)
ORDER BY A.PaymentDate, PaiedBy;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportExpensesByDate`;
DELIMITER |
CREATE PROCEDURE `ReportExpensesByDate`(in date1 date, date2 date)
BEGIN
SELECT C.UserName AS PaiedBy
, B.CatDescription AS ExpCategory
, A.PaymentDate
, A.PaymentAmount
, D.CompanyName
, D.CompanyAddress1
, D.CompanyAddress2
, A.PayCatId
, A.Remarks
, E.BranchName
, A.BranchId
FROM allexpenses A
INNER JOIN expensescategory B
ON A.PayCatId = B.PayCatId
INNER JOIN useraccount C
ON A.CreatedBy = C.UserID
LEFT OUTER JOIN branch E
ON A.BranchId = E.BranchId
, companyinfo D
WHERE (A.PaymentDate BETWEEN date1 AND date2)
ORDER BY A.PaymentDate, PaiedBy;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportFGByDate`;
DELIMITER |
CREATE PROCEDURE `ReportFGByDate`(in date1 date, date2 date)
BEGIN
SELECT A.PIHDId AS FGNo
, A.PIDate AS FGDate
, A.Remarks
, A.BranchId
, B.ItemsId
, B.ItemCode
, C.ItemName
, B.PurchaseQty AS Qty
, B.PurchasePrice AS CostPrice
, B.SellingPrice
, B.NetAmount AS TotalCost
, B.PurchaseQty * B.SellingPrice AS SalesValue
FROM fghd A
INNER JOIN fgdt B
ON A.PIHDId = B.PIHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
WHERE (A.PIDate BETWEEN date1 AND date2);
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportFGPrint`;
DELIMITER |
CREATE PROCEDURE `ReportFGPrint`(in CreditPayHDId1 INT)
BEGIN
SELECT A.PIHDId AS FGNo
, A.PIDate AS FGDate
, A.Remarks
, A.BranchId
, B.ItemsId
, B.ItemCode
, C.ItemName
, B.PurchaseQty AS Qty
, B.PurchasePrice AS CostPrice
, C.SellingPrice
, B.NetAmount AS TotalCost
, B.PurchaseQty * C.SellingPrice AS SalesValue
, A.Qty AS FGQty
FROM productionhd A
INNER JOIN productiondt B
ON A.PIHDId = B.PIHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
WHERE (A.PIHDId = CreditPayHDId1);
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportFreeIssue`;
DELIMITER |
CREATE PROCEDURE `ReportFreeIssue`(in date1 date, date2 date)
BEGIN
SELECT salesorderhd.SOHDId
, salesorderhd.SODate
, salesorderdt.ItemCode
, itemsummary.ItemName
, salesorderdt.FreeIssue
, companyinfo.CompanyName
, companyinfo.CompanyAddress1
, companyinfo.CompanyAddress2
FROM salesorderhd
INNER JOIN salesorderdt
ON salesorderhd.SOHDId = salesorderdt.SOHDId
INNER JOIN itemsummary
ON salesorderdt.ItemsId = itemsummary.ItemsId
, companyinfo
WHERE (salesorderdt.FreeIssue > 0)
AND (salesorderhd.SODate BETWEEN date1 AND date2)
ORDER BY salesorderhd.SOHDId, salesorderhd.SODate;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportGINByDate`;
DELIMITER |
CREATE PROCEDURE `ReportGINByDate`(in date1 date, date2 date)
BEGIN
SELECT A.PIHDId AS FGNo
, A.PIDate AS FGDate
, A.Remarks
, A.BranchId
, B.ItemsId
, B.ItemCode
, C.ItemName
, B.PurchaseQty AS Qty
, B.PurchasePrice AS CostPrice
, 0 AS SellingPrice
, B.NetAmount AS TotalCost
, 0 AS SalesValue
FROM ginhd A
INNER JOIN gindt B
ON A.PIHDId = B.PIHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
WHERE (A.PIDate BETWEEN date1 AND date2);
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportGINPrint`;
DELIMITER |
CREATE PROCEDURE `ReportGINPrint`(in CreditPayHDId1 INT)
BEGIN
SELECT A.PIHDId AS FGNo
, A.PIDate AS FGDate
, A.Remarks
, A.BranchId
, B.ItemsId
, B.ItemCode
, C.ItemName
, B.PurchaseQty AS Qty
, B.PurchasePrice AS CostPrice
, 0 AS SellingPrice
, B.NetAmount AS TotalCost
, 0 AS SalesValue
, A.ItemCode AS FGItemCode
FROM ginhd A
INNER JOIN gindt B
ON A.PIHDId = B.PIHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
WHERE (A.PIHDId = CreditPayHDId1);
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportGrossProfit`;
DELIMITER |
CREATE PROCEDURE `ReportGrossProfit`(in date1 date, date2 date)
BEGIN
SELECT X.SODate
, X.ItemCode
, X.ItemName
, SUM(X.SalesQty) AS SalesQty
, X.SalesPrice
, SUM(X.SalesAmount) AS SalesAmount
, X.CostPrice
, SUM(X.PurchaseCost) AS PurchaseCost
, SUM(X.NetSale) AS NetSale
, X.ItemCatId
, X.DocStatus
, X.BranchId
, date1 as FromDate
, date2 as ToDate
FROM
(
SELECT A.SODate
, B.ItemCode
, C.ItemName
, SUM(B.SalesQty) AS SalesQty
, B.SalesPrice
, (((SUM(B.SalesQty)) * B.SalesPrice) - (SUM(B.Discount))) AS SalesAmount
, B.CostPrice AS CostPrice
, (SUM(B.SalesQty)) * B.CostPrice AS PurchaseCost
, ((((SUM(B.SalesQty)) * B.SalesPrice) - (SUM(B.Discount))) - ((SUM(B.SalesQty)) * B.CostPrice)) AS NetSale
, C.ItemCatId
, 'Sales' AS DocStatus
, A.BranchId
FROM salesorderhd A
INNER JOIN salesorderdt B
ON A.SOHDId = B.SOHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
WHERE (A.CancelStatus = 0)
AND (A.SODate BETWEEN date1 AND date2)
GROUP BY A.SODate, B.ItemCode, B.SalesPrice, B.CostPrice
UNION ALL
SELECT A.SODate
, B.ItemCode
, C.ItemName
, (SUM(B.SalesQty))*-1 AS SalesQty
, B.SalesPrice
, ((SUM(B.SalesQty)))*-1 * B.SalesPrice AS SalesAmount
, B.CostPrice AS CostPrice
, ((SUM(B.SalesQty)))*-1 * B.CostPrice AS PurchaseCost
, (((SUM(B.SalesQty)) * B.SalesPrice) - ((SUM(B.SalesQty)) * B.CostPrice))*-1 AS NetSale
, C.ItemCatId
, 'Sales Return' AS DocStatus
, A.BranchId
FROM salesorderhdreturn A
INNER JOIN salesorderdtreturn B
ON A.SOHDId = B.SOHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
WHERE (A.CancelStatus = 0)
AND (A.SODate BETWEEN date1 AND date2)
GROUP BY A.SODate, B.ItemCode, B.SalesPrice, B.CostPrice
UNION ALL
SELECT A.SODate
, B.ItemCode
, C.ItemName
, (SUM(B.SalesQty))*-1 AS SalesQty
, B.SalesPrice
, ((SUM(B.SalesQty)))*-1 * B.SalesPrice AS SalesAmount
, B.CostPrice AS CostPrice
, ((SUM(B.SalesQty)))*-1 * B.CostPrice AS PurchaseCost
, (((SUM(B.SalesQty)) * B.SalesPrice) - ((SUM(B.SalesQty)) * B.CostPrice))*-1 AS NetSale
, C.ItemCatId
, 'Sales Return' AS DocStatus
, A.BranchId
FROM salesorderhd A
INNER JOIN directsalesreturn B
ON A.SOHDId = B.SOHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
WHERE (A.CancelStatus = 0)
AND (A.SODate BETWEEN date1 AND date2)
GROUP BY A.SODate, B.ItemCode, B.SalesPrice, B.CostPrice
UNION ALL
SELECT A.SODate
, B.ItemCode
, C.ItemName
, (SUM(B.ReturnQty))*-1 AS SalesQty
, B.SalesPrice
, ((SUM(B.ReturnQty)))*-1 * B.SalesPrice AS SalesAmount
, BB.CostPrice AS CostPrice
, ((SUM(B.ReturnQty)))*-1 * BB.CostPrice AS PurchaseCost
, (((SUM(B.ReturnQty)) * B.SalesPrice) - ((SUM(B.ReturnQty)) * BB.CostPrice))*-1 AS NetSale
, C.ItemCatId
, 'Sales Return' AS DocStatus
, A.BranchId
FROM salesorderhd A
INNER JOIN salesorderdt BB
ON A.SOHDId = BB.SOHDId
INNER JOIN salesreturn B
ON BB.SOHDId = B.SOHDId
AND BB.SODTId = B.SODTId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
WHERE (A.CancelStatus = 0)
AND (A.SODate BETWEEN date1 AND date2)
GROUP BY A.SODate, B.ItemCode, B.SalesPrice, BB.CostPrice
)X
GROUP BY X.SODate
, X.ItemCode
, X.ItemName
, X.SalesPrice
, X.CostPrice
, X.ItemCatId
, X.DocStatus
, X.BranchId;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportGrossProfitBranch`;
DELIMITER |
CREATE PROCEDURE `ReportGrossProfitBranch`(in date1 date, date2 date, BranchId1 int)
BEGIN
SELECT X.SODate
, X.ItemCode
, X.ItemName
, SUM(X.SalesQty) AS SalesQty
, X.SalesPrice
, SUM(X.SalesAmount) AS SalesAmount
, X.CostPrice
, SUM(X.PurchaseCost) AS PurchaseCost
, SUM(X.NetSale) AS NetSale
, X.ItemCatId
, X.DocStatus
, X.BranchId
, date1 as FromDate
, date2 as ToDate
FROM
(
SELECT A.SODate
, B.ItemCode
, C.ItemName
, SUM(B.SalesQty) AS SalesQty
, B.SalesPrice
, (((SUM(B.SalesQty)) * B.SalesPrice) - (SUM(B.Discount))) AS SalesAmount
, B.CostPrice AS CostPrice
, (SUM(B.SalesQty)) * B.CostPrice AS PurchaseCost
, ((((SUM(B.SalesQty)) * B.SalesPrice) - (SUM(B.Discount))) - ((SUM(B.SalesQty)) * B.CostPrice)) AS NetSale
, C.ItemCatId
, 'Sales' AS DocStatus
, A.BranchId
FROM salesorderhd A
INNER JOIN salesorderdt B
ON A.SOHDId = B.SOHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
WHERE (A.CancelStatus = 0)
AND (A.BranchId = BranchId1)
AND (A.SODate BETWEEN date1 AND date2)
GROUP BY A.SODate, B.ItemCode, B.SalesPrice, B.CostPrice
UNION ALL
SELECT A.SODate
, B.ItemCode
, C.ItemName
, (SUM(B.SalesQty))*-1 AS SalesQty
, B.SalesPrice
, ((SUM(B.SalesQty)))*-1 * B.SalesPrice AS SalesAmount
, B.CostPrice AS CostPrice
, ((SUM(B.SalesQty)))*-1 * B.CostPrice AS PurchaseCost
, (((SUM(B.SalesQty)) * B.SalesPrice) - ((SUM(B.SalesQty)) * B.CostPrice))*-1 AS NetSale
, C.ItemCatId
, 'Sales Return' AS DocStatus
, A.BranchId
FROM salesorderhdreturn A
INNER JOIN salesorderdtreturn B
ON A.SOHDId = B.SOHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
WHERE (A.CancelStatus = 0)
AND (A.BranchId = BranchId1)
AND (A.SODate BETWEEN date1 AND date2)
GROUP BY A.SODate, B.ItemCode, B.SalesPrice, B.CostPrice
UNION ALL
SELECT A.SODate
, B.ItemCode
, C.ItemName
, (SUM(B.SalesQty))*-1 AS SalesQty
, B.SalesPrice
, ((SUM(B.SalesQty)))*-1 * B.SalesPrice AS SalesAmount
, C.AvgCost AS CostPrice
, ((SUM(B.SalesQty)))*-1 * C.AvgCost AS PurchaseCost
, (((SUM(B.SalesQty)) * B.SalesPrice) - ((SUM(B.SalesQty)) * C.AvgCost))*-1 AS NetSale
, C.ItemCatId
, 'Sales Return' AS DocStatus
, A.BranchId
FROM salesorderhd A
INNER JOIN directsalesreturn B
ON A.SOHDId = B.SOHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
WHERE (A.CancelStatus = 0)
AND (A.BranchId = BranchId1)
AND (A.SODate BETWEEN date1 AND date2)
GROUP BY A.SODate, B.ItemCode, B.SalesPrice, C.AvgCost
UNION ALL
SELECT A.SODate
, B.ItemCode
, C.ItemName
, (SUM(B.ReturnQty))*-1 AS SalesQty
, B.SalesPrice
, ((SUM(B.ReturnQty)))*-1 * B.SalesPrice AS SalesAmount
, BB.CostPrice AS CostPrice
, ((SUM(B.ReturnQty)))*-1 * BB.CostPrice AS PurchaseCost
, (((SUM(B.ReturnQty)) * B.SalesPrice) - ((SUM(B.ReturnQty)) * BB.CostPrice))*-1 AS NetSale
, C.ItemCatId
, 'Sales Return' AS DocStatus
, A.BranchId
FROM salesorderhd A
INNER JOIN salesorderdt BB
ON A.SOHDId = BB.SOHDId
INNER JOIN salesreturn B
ON BB.SOHDId = B.SOHDId
AND BB.SODTId = B.SODTId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
WHERE (A.CancelStatus = 0)
AND (A.SODate BETWEEN date1 AND date2)
AND (A.BranchId = BranchId1)
GROUP BY A.SODate, B.ItemCode, B.SalesPrice, BB.CostPrice
)X
GROUP BY X.SODate
, X.ItemCode
, X.ItemName
, X.SalesPrice
, X.CostPrice
, X.ItemCatId
, X.DocStatus
, X.BranchId;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportGrossProfitBranchData`;
DELIMITER |
CREATE PROCEDURE `ReportGrossProfitBranchData`(in
date1 date
, date2 date
, BranchId1 int)
BEGIN
SELECT A.SOHDId AS BillNo
, A.SODate
, B.ItemCode
, C.ItemName
, SUM(B.SalesQty) AS SalesQty
, IFNULL(SUM(D.ReturnQty), 0) AS ReturnQty
, B.SalesPrice
, (SUM(B.SalesQty) - IFNULL(SUM(D.ReturnQty), 0)) * B.SalesPrice AS SalesAmount
, B.CostPrice
, (SUM(B.SalesQty) - IFNULL(SUM(D.ReturnQty), 0)) * B.CostPrice AS PurchaseCost
, ((SUM(B.SalesQty) - IFNULL(SUM(D.ReturnQty), 0)) * B.SalesPrice) - ((SUM(B.SalesQty) - IFNULL(SUM(D.ReturnQty), 0)) * B.CostPrice) AS NetSale
, E.ItemDisc
, F.TotalDisc
, date1 as FromDate
, date2 as ToDate
, C.ItemCatId
FROM salesorderhd A
INNER JOIN salesorderdt B
ON A.SOHDId = B.SOHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
LEFT OUTER JOIN salesreturn D ON A.SOHDId = D.SOHDId,
(SELECT IFNULL(SUM(B.Discount), 0) AS ItemDisc
FROM salesorderhd A
INNER JOIN salesorderdt B
ON A.SOHDId = B.SOHDId
WHERE (A.SODate BETWEEN date1 AND date2)
AND (A.CancelStatus = 0)
AND(A.BranchId = BranchId1))E,
(SELECT IFNULL(SUM(SODiscount), 0) AS TotalDisc
FROM salesorderhd A
WHERE (SODate BETWEEN date1 AND date2)
AND (CancelStatus = 0)
AND(A.BranchId = BranchId1))F
WHERE (A.CancelStatus = 0)
AND (A.SODate BETWEEN date1 AND date2)
AND(A.BranchId = BranchId1)
GROUP BY B.ItemCode, B.SalesPrice
ORDER BY BillNo, A.SODate, C.ItemName;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportGrossProfitByCat`;
DELIMITER |
CREATE PROCEDURE `ReportGrossProfitByCat`(in date1 date, date2 date, ItemCatId1 int)
BEGIN
SELECT X.SODate
, X.ItemCode
, X.ItemName
, SUM(X.SalesQty) AS SalesQty
, X.SalesPrice
, SUM(X.SalesAmount) AS SalesAmount
, X.CostPrice
, SUM(X.PurchaseCost) AS PurchaseCost
, SUM(X.NetSale) AS NetSale
, X.ItemCatId
, X.DocStatus
, X.BranchId
, date1 as FromDate
, date2 as ToDate
FROM
(
SELECT A.SODate
, B.ItemCode
, C.ItemName
, SUM(B.SalesQty) AS SalesQty
, B.SalesPrice
, (((SUM(B.SalesQty)) * B.SalesPrice) - (SUM(B.Discount))) AS SalesAmount
, B.CostPrice AS CostPrice
, (SUM(B.SalesQty)) * B.CostPrice AS PurchaseCost
, ((((SUM(B.SalesQty)) * B.SalesPrice) - (SUM(B.Discount))) - ((SUM(B.SalesQty)) * B.CostPrice)) AS NetSale
, C.ItemCatId
, 'Sales' AS DocStatus
, A.BranchId
FROM salesorderhd A
INNER JOIN salesorderdt B
ON A.SOHDId = B.SOHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
WHERE (A.CancelStatus = 0)
AND C.ItemCatId = ItemCatId1
AND (A.SODate BETWEEN date1 AND date2)
GROUP BY A.SODate, B.ItemCode, B.SalesPrice, B.CostPrice
UNION ALL
SELECT A.SODate
, B.ItemCode
, C.ItemName
, (SUM(B.SalesQty))*-1 AS SalesQty
, B.SalesPrice
, ((SUM(B.SalesQty)))*-1 * B.SalesPrice AS SalesAmount
, B.CostPrice AS CostPrice
, ((SUM(B.SalesQty)))*-1 * B.CostPrice AS PurchaseCost
, (((SUM(B.SalesQty)) * B.SalesPrice) - ((SUM(B.SalesQty)) * B.CostPrice))*-1 AS NetSale
, C.ItemCatId
, 'Sales Return' AS DocStatus
, A.BranchId
FROM salesorderhdreturn A
INNER JOIN salesorderdtreturn B
ON A.SOHDId = B.SOHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
WHERE (A.CancelStatus = 0)
AND C.ItemCatId = ItemCatId1
AND (A.SODate BETWEEN date1 AND date2)
GROUP BY A.SODate, B.ItemCode, B.SalesPrice, B.CostPrice
UNION ALL
SELECT A.SODate
, B.ItemCode
, C.ItemName
, (SUM(B.SalesQty))*-1 AS SalesQty
, B.SalesPrice
, ((SUM(B.SalesQty)))*-1 * B.SalesPrice AS SalesAmount
, B.CostPrice AS CostPrice
, ((SUM(B.SalesQty)))*-1 * B.CostPrice AS PurchaseCost
, (((SUM(B.SalesQty)) * B.SalesPrice) - ((SUM(B.SalesQty)) * B.CostPrice))*-1 AS NetSale
, C.ItemCatId
, 'Sales Return' AS DocStatus
, A.BranchId
FROM salesorderhd A
INNER JOIN directsalesreturn B
ON A.SOHDId = B.SOHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
WHERE (A.CancelStatus = 0)
AND C.ItemCatId = ItemCatId1
AND (A.SODate BETWEEN date1 AND date2)
GROUP BY A.SODate, B.ItemCode, B.SalesPrice, B.CostPrice
UNION ALL
SELECT A.SODate
, B.ItemCode
, C.ItemName
, (SUM(B.ReturnQty))*-1 AS SalesQty
, B.SalesPrice
, ((SUM(B.ReturnQty)))*-1 * B.SalesPrice AS SalesAmount
, BB.CostPrice AS CostPrice
, ((SUM(B.ReturnQty)))*-1 * BB.CostPrice AS PurchaseCost
, (((SUM(B.ReturnQty)) * B.SalesPrice) - ((SUM(B.ReturnQty)) * BB.CostPrice))*-1 AS NetSale
, C.ItemCatId
, 'Sales Return' AS DocStatus
, A.BranchId
FROM salesorderhd A
INNER JOIN salesorderdt BB
ON A.SOHDId = BB.SOHDId
INNER JOIN salesreturn B
ON BB.SOHDId = B.SOHDId
AND BB.SODTId = B.SODTId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
WHERE (A.CancelStatus = 0)
AND C.ItemCatId = ItemCatId1
AND (A.SODate BETWEEN date1 AND date2)
GROUP BY A.SODate, B.ItemCode, B.SalesPrice, BB.CostPrice
)X
GROUP BY X.SODate
, X.ItemCode
, X.ItemName
, X.SalesPrice
, X.CostPrice
, X.ItemCatId
, X.DocStatus
, X.BranchId;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportGrossProfitDate`;
DELIMITER |
CREATE PROCEDURE `ReportGrossProfitDate`(in date1 date, date2 date)
BEGIN
SELECT A.BillNo
, A.SODate
, C.ItemName
, B.SalesQty
, B.SalesPrice
, B.SalesQty * B.SalesPrice AS GrossSales
, B.Discount
, B.NetAmount
, IFNULL(D.ReturnQty, 0) AS ReturnQty
, IFNULL(D.NetAmount, 0) AS ReturnAmount
, IFNULL(B.NetAmount, 0) - IFNULL(D.NetAmount, 0) AS NetSalesAmount
, B.SalesQty * C.CostPrice AS PurchaseCost
, (IFNULL(B.NetAmount, 0) - IFNULL(D.NetAmount, 0)) - B.SalesQty * C.CostPrice AS GrossProfit
, A.CreatedBy
, A.RepId
, B.ItemCode
, C.ItemCatId
, E.CompanyName
, E.CompanyAddress1
, E.CompanyAddress2
, F.SODiscount AS TotDisc
FROM salesorderhd A
INNER JOIN salesorderdt B
ON A.SOHDId = B.SOHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
LEFT OUTER JOIN salesreturn D
ON B.SODTId = D.SODTId
, companyinfo E
,(SELECT SUM(SODiscount) AS SODiscount
FROM salesorderhd
WHERE (CancelStatus = 0)
and (SODate BETWEEN date1 AND date2)) F
WHERE (A.SODate BETWEEN date1 AND date2)
AND  (A.CancelStatus = 0)
ORDER BY A.BillNo, A.SODate;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportGrossProfitItmCat`;
DELIMITER |
CREATE PROCEDURE `ReportGrossProfitItmCat`(in date1 date, date2 date, ItemCatId1 int)
BEGIN
SELECT A.BillNo
, A.SODate
, C.ItemName
, B.SalesQty
, B.SalesPrice
, B.SalesQty * B.SalesPrice AS GrossSales
, B.Discount, B.NetAmount, IFNULL(D.ReturnQty, 0) AS ReturnQty, IFNULL(D.NetAmount, 0) AS ReturnAmount,
IFNULL(B.NetAmount, 0) - IFNULL(D.NetAmount, 0) AS NetSalesAmount, B.SalesQty * C.CostPrice AS PurchaseCost, (IFNULL(B.NetAmount, 0) - IFNULL(D.NetAmount, 0)) - B.SalesQty * C.CostPrice AS GrossProfit,
A.CreatedBy, A.RepId, B.ItemCode, C.ItemCatId, E.CompanyName, E.CompanyAddress1, E.CompanyAddress2, F.SODiscount AS TotDisc
FROM            salesorderhd A INNER JOIN
salesorderdt B ON A.SOHDId = B.SOHDId INNER JOIN
itemsummary C ON B.ItemsId = C.ItemsId LEFT OUTER JOIN
salesreturn D ON B.SODTId = D.SODTId, companyinfo E,
(SELECT        SUM(SODiscount) AS SODiscount
FROM            salesorderhd
WHERE        (CancelStatus = 0) and (SODate BETWEEN date1 AND date2)) F
WHERE      (A.SODate BETWEEN date1 AND date2) AND  (A.CancelStatus = 0) AND (C.ItemCatId = ItemCatId1)
ORDER BY A.BillNo, A.SODate;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportGrossProfitItMCode`;
DELIMITER |
CREATE PROCEDURE `ReportGrossProfitItMCode`(in date1 date, date2 date, ItemCode1 varchar(50))
BEGIN
SELECT X.SODate
, X.ItemCode
, X.ItemName
, SUM(X.SalesQty) AS SalesQty
, X.SalesPrice
, SUM(X.SalesAmount) AS SalesAmount
, X.CostPrice
, SUM(X.PurchaseCost) AS PurchaseCost
, SUM(X.NetSale) AS NetSale
, X.ItemCatId
, X.DocStatus
, X.BranchId
, date1 as FromDate
, date2 as ToDate
FROM
(
SELECT A.SODate
, B.ItemCode
, C.ItemName
, SUM(B.SalesQty) AS SalesQty
, B.SalesPrice
, (((SUM(B.SalesQty)) * B.SalesPrice) - (SUM(B.Discount) + A.SODiscount)) AS SalesAmount
, B.CostPrice AS CostPrice
, (SUM(B.SalesQty)) * B.CostPrice AS PurchaseCost
, ((((SUM(B.SalesQty)) * B.SalesPrice) - (SUM(B.Discount) + A.SODiscount)) - ((SUM(B.SalesQty)) * B.CostPrice)) AS NetSale
, C.ItemCatId
, 'Sales' AS DocStatus
, A.BranchId
FROM salesorderhd A
INNER JOIN salesorderdt B
ON A.SOHDId = B.SOHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
WHERE (A.CancelStatus = 0)
AND (B.ItemCode = ItemCode1)
AND (A.SODate BETWEEN date1 AND date2)
GROUP BY A.SODate, B.ItemCode, B.SalesPrice, B.CostPrice
UNION ALL
SELECT A.SODate
, B.ItemCode
, C.ItemName
, (SUM(B.SalesQty))*-1 AS SalesQty
, B.SalesPrice
, ((SUM(B.SalesQty)))*-1 * B.SalesPrice AS SalesAmount
, B.CostPrice AS CostPrice
, ((SUM(B.SalesQty)))*-1 * B.CostPrice AS PurchaseCost
, (((SUM(B.SalesQty)) * B.SalesPrice) - ((SUM(B.SalesQty)) * B.CostPrice))*-1 AS NetSale
, C.ItemCatId
, 'Sales Return' AS DocStatus
, A.BranchId
FROM salesorderhdreturn A
INNER JOIN salesorderdtreturn B
ON A.SOHDId = B.SOHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
WHERE (A.CancelStatus = 0)
AND (B.ItemCode = ItemCode1)
AND (A.SODate BETWEEN date1 AND date2)
GROUP BY A.SODate, B.ItemCode, B.SalesPrice, B.CostPrice
UNION ALL
SELECT A.SODate
, B.ItemCode
, C.ItemName
, (SUM(B.SalesQty))*-1 AS SalesQty
, B.SalesPrice
, ((SUM(B.SalesQty)))*-1 * B.SalesPrice AS SalesAmount
, C.AvgCost AS CostPrice
, ((SUM(B.SalesQty)))*-1 * C.AvgCost AS PurchaseCost
, (((SUM(B.SalesQty)) * B.SalesPrice) - ((SUM(B.SalesQty)) * C.AvgCost))*-1 AS NetSale
, C.ItemCatId
, 'Sales Return' AS DocStatus
, A.BranchId
FROM salesorderhd A
INNER JOIN directsalesreturn B
ON A.SOHDId = B.SOHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
WHERE (A.CancelStatus = 0)
AND (B.ItemCode = ItemCode1)
AND (A.SODate BETWEEN date1 AND date2)
GROUP BY A.SODate, B.ItemCode, B.SalesPrice, C.AvgCost
UNION ALL
SELECT A.SODate
, B.ItemCode
, C.ItemName
, (SUM(B.ReturnQty))*-1 AS SalesQty
, B.SalesPrice
, ((SUM(B.ReturnQty)))*-1 * B.SalesPrice AS SalesAmount
, BB.CostPrice AS CostPrice
, ((SUM(B.ReturnQty)))*-1 * BB.CostPrice AS PurchaseCost
, (((SUM(B.ReturnQty)) * B.SalesPrice) - ((SUM(B.ReturnQty)) * BB.CostPrice))*-1 AS NetSale
, C.ItemCatId
, 'Sales Return' AS DocStatus
, A.BranchId
FROM salesorderhd A
INNER JOIN salesorderdt BB
ON A.SOHDId = BB.SOHDId
INNER JOIN salesreturn B
ON BB.SOHDId = B.SOHDId
AND BB.SODTId = B.SODTId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
WHERE (A.CancelStatus = 0)
AND (BB.ItemCode = ItemCode1)
AND (A.SODate BETWEEN date1 AND date2)
GROUP BY A.SODate, B.ItemCode, B.SalesPrice, BB.CostPrice
)X
GROUP BY X.SODate
, X.ItemCode
, X.ItemName
, X.SalesPrice
, X.CostPrice
, X.ItemCatId
, X.DocStatus
, X.BranchId;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportInstallmentByDate`;
DELIMITER |
CREATE PROCEDURE `ReportInstallmentByDate`(in date1 date, date2 date)
BEGIN
SELECT A.AreaName, B.CustomerName, B.CustomerAddress, B.CustomerTelNo, C.InstallmentDate, C.InstallmentAmount, D.CompanyName, D.CompanyAddress1, D.CompanyAddress2, A.AreaId
FROM areas A
INNER JOIN customer B
ON A.AreaId = B.AreaId
INNER JOIN custcreditinstallment C
ON B.CustomerId = C.CustomerId
, companyinfo D
WHERE (C.InstallmentDate BETWEEN date1 AND date2)
ORDER BY A.AreaName, C.InstallmentDate, B.CustomerName;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportInstallmentByDateArea`;
DELIMITER |
CREATE PROCEDURE `ReportInstallmentByDateArea`(in date1 date, date2 date, AreaId1 int)
BEGIN
SELECT A.AreaName, B.CustomerName, B.CustomerAddress, B.CustomerTelNo, C.InstallmentDate, C.InstallmentAmount, D.CompanyName, D.CompanyAddress1, D.CompanyAddress2, A.AreaId
FROM areas A
INNER JOIN customer B
ON A.AreaId = B.AreaId
INNER JOIN custcreditinstallment C
ON B.CustomerId = C.CustomerId
, companyinfo D
WHERE (C.InstallmentDate BETWEEN date1 AND date2)
AND (A.AreaId = AreaId1)
ORDER BY A.AreaName, C.InstallmentDate, B.CustomerName;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportInvoice`;
DELIMITER |
CREATE PROCEDURE `ReportInvoice`(in BillNo1 int)
BEGIN
SELECT        salesorderhd.SODate, paymentmode.PayMode, salesorderhd.BillNo, salesorderhd.SOGrossTotal, salesorderhd.SODiscount, salesorderhd.SONetTotal, menuitem.ItemName, salesorderdt.SalesQty,
salesorderdt.SalesPrice, salesorderdt.NetAmount, salesorderhd.SOHDId
FROM            salesorderhd INNER JOIN
salesorderdt ON salesorderhd.SOHDId = salesorderdt.SOHDId INNER JOIN
paymentmode ON salesorderhd.PayModeId = paymentmode.PayModeId INNER JOIN
menuitem ON salesorderdt.ItemsId = menuitem.ItemsId
WHERE        (salesorderhd.BillNo = BillNo1);
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportIssChekIssDate`;
DELIMITER |
CREATE PROCEDURE `ReportIssChekIssDate`(in date1 date, date2 date)
BEGIN
SELECT B.SupplierId
, A.SupplierName
, A.MobileNo
, B.IssueDate
, B.ChequeExpDate
, B.ChequeBank
, B.ChequeNo
, B.ChequeAmount
, C.CompanyName
, C.CompanyAddress1
, C.CompanyAddress2
FROM supplier A
INNER JOIN suppliercheque B
ON A.SupplierId = B.SupplierId
, companyinfo C
WHERE (B.IssueDate BETWEEN date1 AND date2)
ORDER BY A.SupplierName;
END |
DELIMITER ;

