DROP PROCEDURE IF EXISTS `ReportItemHistoryAll`;
DELIMITER |
CREATE PROCEDURE `ReportItemHistoryAll`(in
date1 date,
date2 date)
BEGIN
SELECT A.ItemsId
, A.DocNo
, A.DocDate
, A.ItemCode
, A.ItemName
, A.Memo
, A.Qty
, A.InQty
, A.OutQty
, A.AvailableQty
,TRIM(Replace(Replace(Replace(B.BranchName,'\t',''),'\n',''),'\r','')) AS BranchName
FROM(
SELECT A.ItemsId
, A.ItemCode AS DocNo
, A.PurchasedDate AS DocDate
, A.ItemCode
, A.ItemName
, 'Opening Balance' AS Memo
, A.OpenBalQty AS Qty
, A.OpenBalQty AS InQty
, 0 AS OutQty
, 1 AS BranchId
, A.AvailableQty
, 1 AS RecOrder
FROM itemsummary A
WHERE A.OpenBalQty > 0
UNION ALL
SELECT B.ItemsId
, A.PIHDId AS DocNo
, A.PIDate AS DocDate
, C.ItemCode
, C.ItemName
, 'Purchasing' AS Memo
, B.PurchaseQty AS Qty
, B.PurchaseQty AS InQty
, 0 AS OutQty
, A.BranchId AS BranchId
, C.AvailableQty
, 2 AS RecOrder
FROM pihd A
INNER JOIN pidt B
ON A.PIHDId = B.PIHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
WHERE A.CancelStatus = 0
AND B.PurchaseQty > 0
UNION ALL
SELECT B.ItemsId
, A.PIHDId AS DocNo
, A.PIDate AS DocDate
, C.ItemCode
, C.ItemName
, 'Purchasing Free Issue' AS Memo
, B.FreeIssue AS Qty
, B.FreeIssue AS InQty
, 0 AS OutQty
, A.BranchId AS BranchId
, C.AvailableQty
, 3 AS RecOrder
FROM pihd A
INNER JOIN pidt B
ON A.PIHDId = B.PIHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
WHERE A.CancelStatus = 0
AND B.FreeIssue > 0
UNION ALL
SELECT A.ItemsId
, B.StkAdjHDId AS DocNo
, B.AdjDate AS DocDate
, C.ItemCode
, C.ItemName
, 'Stock + Adjustments' AS Memo
, A.VarrienceQty AS Qty
, A.VarrienceQty AS InQty
, 0 AS OutQty
, B.BranchId AS BranchId
, C.AvailableQty
, 4 AS RecOrder
FROM stkadjdt A
INNER JOIN stkadjhd B
ON A.StkAdjHDId = B.StkAdjHDId
INNER JOIN itemsummary C
ON A.ItemsId = C.ItemsId
WHERE A.VarrienceQty > 0
UNION ALL
SELECT A.ItemsId
, B.StkAdjHDId AS DocNo
, B.AdjDate AS DocDate
, C.ItemCode
, C.ItemName
, 'Stock - Adjustments' AS Memo
, A.VarrienceQty AS Qty
, 0 AS InQty
, A.VarrienceQty * -1 AS OutQty
, B.BranchId AS BranchId
, C.AvailableQty
, 5 AS RecOrder
FROM stkadjdt A
INNER JOIN stkadjhd B
ON A.StkAdjHDId = B.StkAdjHDId
INNER JOIN itemsummary C
ON A.ItemsId = C.ItemsId
WHERE A.VarrienceQty > 0
UNION ALL
SELECT B.ItemsId
, A.TransferHDId AS DocNo
, A.TransferDate AS DocDate
, C.ItemCode
, C.ItemName
, 'Transfer In' AS Memo
, B.Qty AS Qty
, B.Qty AS InQty
, 0 AS OutQty
, A.ToBranchId AS BranchId
, C.AvailableQty
, 6 AS RecOrder
FROM stocktransferhd A
INNER JOIN stocktransferdt B
ON A.TransferHDId = B.TransferHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
WHERE B.Qty > 0
UNION ALL
SELECT B.ItemsId
, A.TransferHDId AS DocNo
, A.TransferDate AS DocDate
, C.ItemCode
, C.ItemName
, 'Transfer Out' AS Memo
, B.Qty * -1 AS Qty
, 0 AS InQty
, B.Qty AS OutQty
, A.FromBranchId AS BranchId
, C.AvailableQty
, 7 AS RecOrder
FROM stocktransferhd A
INNER JOIN stocktransferdt B
ON A.TransferHDId = B.TransferHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
WHERE B.Qty > 0
UNION ALL
SELECT B.ItemsId
, A.SOHDId AS DocNo
, A.SODate AS DocDate
, C.ItemCode
, IFNULL(B.ItemName, C.ItemName) AS ItemName
, 'Sales' AS Memo
, B.SalesQty * -1 AS Qty
, 0 AS InQty
, B.SalesQty AS OutQty
, A.BranchId AS BranchId
, C.AvailableQty
, 8 AS RecOrder
FROM salesorderhd A
INNER JOIN salesorderdt B
ON A.SOHDId = B.SOHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
WHERE B.SalesQty > 0
AND A.CancelStatus = 0
UNION ALL
SELECT B.ItemsId
, A.SOHDId AS DocNo
, A.SODate AS DocDate
, C.ItemCode
, C.ItemName
, 'Sales Free Issue' AS Memo
, B.FreeIssue * -1 AS Qty
, 0 AS InQty
, B.FreeIssue AS OutQty
, A.BranchId AS BranchId
, C.AvailableQty
, 9 AS RecOrder
FROM salesorderhd A
INNER JOIN salesorderdt B
ON A.SOHDId = B.SOHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
WHERE B.FreeIssue > 0
AND A.CancelStatus = 0
UNION ALL
SELECT B.ItemsId
, A.SOHDId AS DocNo
, A.SODate AS DocDate
, C.ItemCode
, C.ItemName
, 'Sales Return' AS Memo
, B.SalesQty AS Qty
, B.SalesQty AS InQty
, 0 AS OutQty
, A.BranchId AS BranchId
, C.AvailableQty
, 10 AS RecOrder
FROM salesorderhdreturn A
INNER JOIN salesorderdtreturn B
ON A.SOHDId = B.SOHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
WHERE B.SalesQty > 0
AND A.CancelStatus = 0
UNION ALL
SELECT B.ItemsId
, A.SOHDId AS DocNo
, A.SODate AS DocDate
, C.ItemCode
, C.ItemName
, 'Sales Return' AS Memo
, B.SalesQty AS Qty
, B.SalesQty AS InQty
, 0 AS OutQty
, A.BranchId AS BranchId
, C.AvailableQty
, 10 AS RecOrder
FROM salesorderhd A
INNER JOIN directsalesreturn B
ON A.SOHDId = B.SOHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
WHERE B.SalesQty > 0
AND A.CancelStatus = 0
AND B.Damage = 0
UNION ALL
SELECT B.ItemsId
, A.SOHDId AS DocNo
, A.SODate AS DocDate
, C.ItemCode
, C.ItemName
, 'Sales Return [Damage]' AS Memo
, B.SalesQty * -1 AS Qty
, 0 AS InQty
, B.SalesQty AS OutQty
, A.BranchId AS BranchId
, C.AvailableQty
, 10 AS RecOrder
FROM salesorderhd A
INNER JOIN directsalesreturn B
ON A.SOHDId = B.SOHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
WHERE B.SalesQty > 0
AND A.CancelStatus = 0
AND B.Damage = 1
UNION ALL
SELECT BB.ItemsId
, A.SOHDId AS DocNo
, A.SODate AS DocDate
, C.ItemCode
, C.ItemName
, 'Sales Return' AS Memo
, B.ReturnQty AS Qty
, B.ReturnQty AS InQty
, 0 AS OutQty
, A.BranchId AS BranchId
, C.AvailableQty
, 10 AS RecOrder
FROM salesorderhd A
INNER JOIN salesorderdt BB
ON A.SOHDId = BB.SOHDId
INNER JOIN itemsummary C
ON BB.ItemsId = C.ItemsId
INNER JOIN (SELECT E.SOHDId, E.SODTId, SUM(E.ReturnQty) AS ReturnQty
FROM salesreturn E
GROUP BY E.SOHDId, E.SODTId) B
ON BB.SOHDId = B.SOHDId
AND BB.SODTId = B.SODTId
WHERE A.CancelStatus = 0
AND B.ReturnQty > 0
UNION ALL
SELECT B.ItemsId
, A.SOHDId AS DocNo
, A.SODate AS DocDate
, C.ItemCode
, C.ItemName
, 'Sales Return Free Issue' AS Memo
, B.FreeIssue AS Qty
, B.FreeIssue AS InQty
, 0 AS OutQty
, A.BranchId AS BranchId
, C.AvailableQty
, 11 AS RecOrder
FROM salesorderhdreturn A
INNER JOIN salesorderdtreturn B
ON A.SOHDId = B.SOHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
WHERE B.FreeIssue > 0
AND A.CancelStatus = 0
UNION ALL
SELECT B.ItemsId
, A.SOHDId AS DocNo
, A.SODate AS DocDate
, C.ItemCode
, C.ItemName
, 'Sales Return Free Issue' AS Memo
, B.FreeIssue AS Qty
, B.FreeIssue AS InQty
, 0 AS OutQty
, A.BranchId AS BranchId
, C.AvailableQty
, 11 AS RecOrder
FROM salesorderhd A
INNER JOIN directsalesreturn B
ON A.SOHDId = B.SOHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
WHERE B.FreeIssue > 0
AND A.CancelStatus = 0
UNION ALL
SELECT BB.ItemsId
, A.SOHDId AS DocNo
, A.SODate AS DocDate
, C.ItemCode
, C.ItemName
, 'Sales Return Free Issue' AS Memo
, B.FreeIssue AS Qty
, B.FreeIssue AS InQty
, 0 AS OutQty
, A.BranchId AS BranchId
, C.AvailableQty
, 11 AS RecOrder
FROM salesorderhd A
INNER JOIN salesorderdt BB
ON A.SOHDId = BB.SOHDId
INNER JOIN itemsummary C
ON BB.ItemsId = C.ItemsId
INNER JOIN (SELECT E.SOHDId, E.SODTId, SUM(E.FreeIssue) AS FreeIssue
FROM salesreturn E
GROUP BY E.SOHDId, E.SODTId) B
ON BB.SOHDId = B.SOHDId
AND BB.SODTId = B.SODTId
WHERE A.CancelStatus = 0
AND B.FreeIssue > 0
UNION ALL
SELECT A.ItemsId
, A.Id AS DocNo
, A.SpoilDate AS DocDate
, C.ItemCode
, C.ItemName
, 'Damage Item' AS Memo
, A.Qty * -1 AS Qty
, 0 AS InQty
, A.Qty AS OutQty
, A.BranchId AS BranchId
, C.AvailableQty
, 12 AS RecOrder
FROM itemspoilage A
INNER JOIN itemsummary C
ON A.ItemsId = C.ItemsId
WHERE A.Qty > 0
AND A.SOHDId = 0
UNION ALL
SELECT B.ItemsId
, A.PIHDId AS DocNo
, A.PIDate AS DocDate
, C.ItemCode
, C.ItemName
, 'Purchase Return' AS Memo
, B.PurchaseQty * -1 AS Qty
, 0 AS InQty
, B.PurchaseQty AS OutQty
, A.BranchId AS BranchId
, C.AvailableQty
, 13 AS RecOrder
FROM pihdreturn A
INNER JOIN pidtreturn B
ON A.PIHDId = B.PIHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
WHERE B.PurchaseQty > 0
UNION ALL
SELECT B.ItemsId
, A.PIHDId AS DocNo
, A.PIDate AS DocDate
, C.ItemCode
, C.ItemName
, 'Purchase Return' AS Memo
, B.PurchaseQty * -1 AS Qty
, 0 AS InQty
, B.PurchaseQty AS OutQty
, A.BranchId AS BranchId
, C.AvailableQty
, 13 AS RecOrder
FROM pihd A
INNER JOIN pidtrtn B
ON A.PIHDId = B.PIHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
WHERE B.PurchaseQty > 0
AND A.CancelStatus = 0
UNION ALL
SELECT B.ItemsId
, A.PIHDId AS DocNo
, A.PIDate AS DocDate
, C.ItemCode
, C.ItemName
, 'Purchase Free Issue Return' AS Memo
, B.FreeIssue * -1 AS Qty
, 0 AS InQty
, B.FreeIssue AS OutQty
, A.BranchId AS BranchId
, C.AvailableQty
, 14 AS RecOrder
FROM pihdreturn A
INNER JOIN pidtreturn B
ON A.PIHDId = B.PIHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
WHERE B.FreeIssue > 0
UNION ALL
SELECT B.ItemsId
, A.PIHDId AS DocNo
, A.PIDate AS DocDate
, C.ItemCode
, C.ItemName
, 'Purchase Free Issue Return' AS Memo
, B.FreeIssue * -1 AS Qty
, 0 AS InQty
, B.FreeIssue AS OutQty
, A.BranchId AS BranchId
, C.AvailableQty
, 13 AS RecOrder
FROM pihd A
INNER JOIN pidtrtn B
ON A.PIHDId = B.PIHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
WHERE B.FreeIssue > 0
AND A.CancelStatus = 0
UNION ALL
SELECT A.ItemsId
, A.PIHDId AS DocNo
, A.PIDate AS DocDate
, C.ItemCode
, C.ItemName
, 'Production FG' AS Memo
, A.Qty AS Qty
, A.Qty AS InQty
, 0 AS OutQty
, A.BranchId AS BranchId
, C.AvailableQty
, 14 AS RecOrder
FROM productionhd A
INNER JOIN itemsummary C
ON A.ItemsId = C.ItemsId
WHERE A.Qty > 0
AND A.CancelStatus = 0
UNION ALL
SELECT B.ItemsId
, A.PIHDId AS DocNo
, A.PIDate AS DocDate
, C.ItemCode
, C.ItemName
, 'Production RM' AS Memo
, B.PurchaseQty AS Qty
, 0 AS InQty
, B.PurchaseQty AS OutQty
, A.BranchId AS BranchId
, C.AvailableQty
, 15 AS RecOrder
FROM productionhd A
INNER JOIN productiondt B
ON A.PIHDId = B.PIHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
WHERE B.PurchaseQty > 0
AND A.CancelStatus = 0
UNION ALL
SELECT B.ItemsId
, A.SOHDId AS DocNo
, A.MovementDate AS DocDate
, B.ItemCode
, B.ItemName
, CONCAT('Convert From - ', C.ItemCode, '') AS Memo
, A.Qty AS Qty
, A.Qty AS InQty
, 0 AS OutQty
, A.BranchId AS BranchId
, B.AvailableQty
, 16 AS RecOrder
FROM inventorymovement A
INNER JOIN itemsummary B
ON A.ToItemsId = B.ItemsId
INNER JOIN itemsummary C
ON A.FromItemsId = C.ItemsId
WHERE A.ConvertTo = 1
UNION ALL
SELECT B.ItemsId
, A.SOHDId AS DocNo
, A.MovementDate AS DocDate
, B.ItemCode
, B.ItemName
, CONCAT('Convert To - ', C.ItemCode, '') AS Memo
, A.Qty * -1 AS Qty
, 0 AS InQty
, A.Qty AS OutQty
, A.BranchId AS BranchId
, B.AvailableQty
, 17 AS RecOrder
FROM inventorymovement A
INNER JOIN itemsummary B
ON A.FromItemsId = B.ItemsId
INNER JOIN itemsummary C
ON A.ToItemsId = C.ItemsId
WHERE A.ConvertFrom = 1
)A
INNER JOIN branch B
ON A.BranchId = B.BranchId
WHERE A.DocDate BETWEEN date1 AND date2
ORDER BY A.DocDate, A.ItemsId, A.RecOrder
;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportItemHistoryAllBranch`;
DELIMITER |
CREATE PROCEDURE `ReportItemHistoryAllBranch`(in
BranchId1 INT
,date1 date
,date2 date)
BEGIN
SELECT A.ItemsId
, A.DocNo
, A.DocDate
, A.ItemCode
, A.ItemName
, A.Memo
, A.Qty
, A.InQty
, A.OutQty
, A.AvailableQty
,TRIM(Replace(Replace(Replace(B.BranchName,'\t',''),'\n',''),'\r','')) AS BranchName
FROM(
SELECT A.ItemsId
, A.ItemCode AS DocNo
, A.PurchasedDate AS DocDate
, A.ItemCode
, A.ItemName
, 'Opening Balance' AS Memo
, A.OpenBalQty AS Qty
, A.OpenBalQty AS InQty
, 0 AS OutQty
, 1 AS BranchId
, A.AvailableQty
, 1 AS RecOrder
FROM itemsummary A
WHERE A.OpenBalQty > 0
UNION ALL
SELECT B.ItemsId
, A.PIHDId AS DocNo
, A.PIDate AS DocDate
, C.ItemCode
, C.ItemName
, 'Purchasing' AS Memo
, B.PurchaseQty AS Qty
, B.PurchaseQty AS InQty
, 0 AS OutQty
, A.BranchId AS BranchId
, C.AvailableQty
, 2 AS RecOrder
FROM pihd A
INNER JOIN pidt B
ON A.PIHDId = B.PIHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
WHERE A.CancelStatus = 0
AND B.PurchaseQty > 0
UNION ALL
SELECT B.ItemsId
, A.PIHDId AS DocNo
, A.PIDate AS DocDate
, C.ItemCode
, C.ItemName
, 'Purchasing Free Issue' AS Memo
, B.FreeIssue AS Qty
, B.FreeIssue AS InQty
, 0 AS OutQty
, A.BranchId AS BranchId
, C.AvailableQty
, 3 AS RecOrder
FROM pihd A
INNER JOIN pidt B
ON A.PIHDId = B.PIHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
WHERE A.CancelStatus = 0
AND B.FreeIssue > 0
UNION ALL
SELECT A.ItemsId
, B.StkAdjHDId AS DocNo
, B.AdjDate AS DocDate
, C.ItemCode
, C.ItemName
, 'Stock + Adjustments' AS Memo
, A.VarrienceQty AS Qty
, A.VarrienceQty AS InQty
, 0 AS OutQty
, B.BranchId AS BranchId
, C.AvailableQty
, 4 AS RecOrder
FROM stkadjdt A
INNER JOIN stkadjhd B
ON A.StkAdjHDId = B.StkAdjHDId
INNER JOIN itemsummary C
ON A.ItemsId = C.ItemsId
WHERE A.VarrienceQty > 0
UNION ALL
SELECT A.ItemsId
, B.StkAdjHDId AS DocNo
, B.AdjDate AS DocDate
, C.ItemCode
, C.ItemName
, 'Stock - Adjustments' AS Memo
, A.VarrienceQty AS Qty
, 0 AS InQty
, A.VarrienceQty * -1 AS OutQty
, B.BranchId AS BranchId
, C.AvailableQty
, 5 AS RecOrder
FROM stkadjdt A
INNER JOIN stkadjhd B
ON A.StkAdjHDId = B.StkAdjHDId
INNER JOIN itemsummary C
ON A.ItemsId = C.ItemsId
WHERE A.VarrienceQty > 0
UNION ALL
SELECT B.ItemsId
, A.TransferHDId AS DocNo
, A.TransferDate AS DocDate
, C.ItemCode
, C.ItemName
, 'Transfer In' AS Memo
, B.Qty AS Qty
, B.Qty AS InQty
, 0 AS OutQty
, A.ToBranchId AS BranchId
, C.AvailableQty
, 6 AS RecOrder
FROM stocktransferhd A
INNER JOIN stocktransferdt B
ON A.TransferHDId = B.TransferHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
WHERE B.Qty > 0
UNION ALL
SELECT B.ItemsId
, A.TransferHDId AS DocNo
, A.TransferDate AS DocDate
, C.ItemCode
, C.ItemName
, 'Transfer Out' AS Memo
, B.Qty * -1 AS Qty
, 0 AS InQty
, B.Qty AS OutQty
, A.FromBranchId AS BranchId
, C.AvailableQty
, 7 AS RecOrder
FROM stocktransferhd A
INNER JOIN stocktransferdt B
ON A.TransferHDId = B.TransferHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
WHERE B.Qty > 0
UNION ALL
SELECT B.ItemsId
, A.SOHDId AS DocNo
, A.SODate AS DocDate
, C.ItemCode
, IFNULL(B.ItemName, C.ItemName) AS ItemName
, 'Sales' AS Memo
, B.SalesQty * -1 AS Qty
, 0 AS InQty
, B.SalesQty AS OutQty
, A.BranchId AS BranchId
, C.AvailableQty
, 8 AS RecOrder
FROM salesorderhd A
INNER JOIN salesorderdt B
ON A.SOHDId = B.SOHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
WHERE B.SalesQty > 0
AND A.CancelStatus = 0
UNION ALL
SELECT B.ItemsId
, A.SOHDId AS DocNo
, A.SODate AS DocDate
, C.ItemCode
, C.ItemName
, 'Sales Free Issue' AS Memo
, B.FreeIssue * -1 AS Qty
, 0 AS InQty
, B.FreeIssue AS OutQty
, A.BranchId AS BranchId
, C.AvailableQty
, 9 AS RecOrder
FROM salesorderhd A
INNER JOIN salesorderdt B
ON A.SOHDId = B.SOHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
WHERE B.FreeIssue > 0
