DROP PROCEDURE IF EXISTS `ReportItemHistoryAllBranchItemCode`;
DELIMITER |
CREATE PROCEDURE `ReportItemHistoryAllBranchItemCode`(in
BranchId1 INT
, ItemCode1 VARCHAR(50)
,date1 date
,date2 date
)
BEGIN
SELECT A.ItemsId
, A.DocNo
, A.DocDate
, A.ItemCode
, A.ItemName
, A.Memo
, A.Qty
, A.InQty
, A.OutQty
, A.AvailableQty
,TRIM(Replace(Replace(Replace(B.BranchName,'\t',''),'\n',''),'\r','')) AS BranchName
FROM(
SELECT A.ItemsId
, A.ItemCode AS DocNo
, A.PurchasedDate AS DocDate
, A.ItemCode
, A.ItemName
, 'Opening Balance' AS Memo
, A.OpenBalQty AS Qty
, A.OpenBalQty AS InQty
, 0 AS OutQty
, 1 AS BranchId
, A.AvailableQty
, 1 AS RecOrder
FROM itemsummary A
WHERE A.OpenBalQty > 0
UNION ALL
SELECT B.ItemsId
, A.PIHDId AS DocNo
, A.PIDate AS DocDate
, C.ItemCode
, C.ItemName
, 'Purchasing' AS Memo
, B.PurchaseQty AS Qty
, B.PurchaseQty AS InQty
, 0 AS OutQty
, A.BranchId AS BranchId
, C.AvailableQty
, 2 AS RecOrder
FROM pihd A
INNER JOIN pidt B
ON A.PIHDId = B.PIHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
WHERE A.CancelStatus = 0
AND B.PurchaseQty > 0
UNION ALL
SELECT B.ItemsId
, A.PIHDId AS DocNo
, A.PIDate AS DocDate
, C.ItemCode
, C.ItemName
, 'Purchasing Free Issue' AS Memo
