WHERE A.BranchId = BranchId1
AND A.ItemCode = ItemCode1
AND A.DocDate BETWEEN date1 AND date2
ORDER BY A.DocDate, A.ItemsId, A.RecOrder
;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportItemHistoryAllItemCode`;
DELIMITER |
CREATE PROCEDURE `ReportItemHistoryAllItemCode`(in
ItemCode1 VARCHAR(50)
,date1 date
,date2 date)
BEGIN
SELECT A.ItemsId
, A.DocNo
, A.DocDate
, A.ItemCode
, A.ItemName
, A.Memo
, A.Qty
, A.InQty
, A.OutQty
, A.AvailableQty
,TRIM(Replace(Replace(Replace(B.BranchName,'\t',''),'\n',''),'\r','')) AS BranchName
FROM(
SELECT A.ItemsId
, A.ItemCode AS DocNo
, A.PurchasedDate AS DocDate
, A.ItemCode
, A.ItemName
, 'Opening Balance' AS Memo
, A.OpenBalQty AS Qty
, A.OpenBalQty AS InQty
, 0 AS OutQty
, 1 AS BranchId
, A.AvailableQty
, 1 AS RecOrder
FROM itemsummary A
WHERE A.OpenBalQty > 0
UNION ALL
SELECT B.ItemsId
, A.PIHDId AS DocNo
, A.PIDate AS DocDate
, C.ItemCode
, C.ItemName
, 'Purchasing' AS Memo
, B.PurchaseQty AS Qty
, B.PurchaseQty AS InQty
, 0 AS OutQty
, A.BranchId AS BranchId
, C.AvailableQty
, 2 AS RecOrder
FROM pihd A
INNER JOIN pidt B
ON A.PIHDId = B.PIHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
WHERE A.CancelStatus = 0
AND B.PurchaseQty > 0
UNION ALL
SELECT B.ItemsId
, A.PIHDId AS DocNo
, A.PIDate AS DocDate
, C.ItemCode
, C.ItemName
, 'Purchasing Free Issue' AS Memo
, B.FreeIssue AS Qty
, B.FreeIssue AS InQty
, 0 AS OutQty
, A.BranchId AS BranchId
, C.AvailableQty
, 3 AS RecOrder
FROM pihd A
INNER JOIN pidt B
ON A.PIHDId = B.PIHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
WHERE A.CancelStatus = 0
AND B.FreeIssue > 0
UNION ALL
SELECT A.ItemsId
, B.StkAdjHDId AS DocNo
, B.AdjDate AS DocDate
, C.ItemCode
, C.ItemName
, 'Stock + Adjustments' AS Memo
, A.VarrienceQty AS Qty
, A.VarrienceQty AS InQty
, 0 AS OutQty
, B.BranchId AS BranchId
, C.AvailableQty
, 4 AS RecOrder
FROM stkadjdt A
INNER JOIN stkadjhd B
ON A.StkAdjHDId = B.StkAdjHDId
INNER JOIN itemsummary C
ON A.ItemsId = C.ItemsId
WHERE A.VarrienceQty > 0
UNION ALL
SELECT A.ItemsId
, B.StkAdjHDId AS DocNo
, B.AdjDate AS DocDate
, C.ItemCode
, C.ItemName
, 'Stock - Adjustments' AS Memo
, A.VarrienceQty AS Qty
, 0 AS InQty
, A.VarrienceQty * -1 AS OutQty
, B.BranchId AS BranchId
, C.AvailableQty
, 5 AS RecOrder
FROM stkadjdt A
INNER JOIN stkadjhd B
ON A.StkAdjHDId = B.StkAdjHDId
INNER JOIN itemsummary C
ON A.ItemsId = C.ItemsId
WHERE A.VarrienceQty > 0
UNION ALL
SELECT B.ItemsId
, A.TransferHDId AS DocNo
, A.TransferDate AS DocDate
, C.ItemCode
, C.ItemName
, 'Transfer In' AS Memo
, B.Qty AS Qty
, B.Qty AS InQty
, 0 AS OutQty
, A.ToBranchId AS BranchId
, C.AvailableQty
, 6 AS RecOrder
FROM stocktransferhd A
INNER JOIN stocktransferdt B
ON A.TransferHDId = B.TransferHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
WHERE B.Qty > 0
UNION ALL
SELECT B.ItemsId
, A.TransferHDId AS DocNo
, A.TransferDate AS DocDate
, C.ItemCode
, C.ItemName
, 'Transfer Out' AS Memo
, B.Qty * -1 AS Qty
, 0 AS InQty
, B.Qty AS OutQty
, A.FromBranchId AS BranchId
, C.AvailableQty
, 7 AS RecOrder
FROM stocktransferhd A
INNER JOIN stocktransferdt B
ON A.TransferHDId = B.TransferHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
WHERE B.Qty > 0
UNION ALL
SELECT B.ItemsId
, A.SOHDId AS DocNo
, A.SODate AS DocDate
, C.ItemCode
, IFNULL(B.ItemName, C.ItemName) AS ItemName
, 'Sales' AS Memo
, B.SalesQty * -1 AS Qty
, 0 AS InQty
, B.SalesQty AS OutQty
, A.BranchId AS BranchId
, C.AvailableQty
, 8 AS RecOrder
FROM salesorderhd A
INNER JOIN salesorderdt B
ON A.SOHDId = B.SOHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
WHERE B.SalesQty > 0
AND A.CancelStatus = 0
UNION ALL
SELECT B.ItemsId
, A.SOHDId AS DocNo
, A.SODate AS DocDate
, C.ItemCode
, C.ItemName
, 'Sales Free Issue' AS Memo
, B.FreeIssue * -1 AS Qty
, 0 AS InQty
, B.FreeIssue AS OutQty
, A.BranchId AS BranchId
, C.AvailableQty
, 9 AS RecOrder
FROM salesorderhd A
INNER JOIN salesorderdt B
ON A.SOHDId = B.SOHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
WHERE B.FreeIssue > 0
AND A.CancelStatus = 0
UNION ALL
SELECT B.ItemsId
, A.SOHDId AS DocNo
, A.SODate AS DocDate
, C.ItemCode
, C.ItemName
, 'Sales Return' AS Memo
, B.SalesQty AS Qty
, B.SalesQty AS InQty
, 0 AS OutQty
, A.BranchId AS BranchId
, C.AvailableQty
, 10 AS RecOrder
FROM salesorderhdreturn A
INNER JOIN salesorderdtreturn B
ON A.SOHDId = B.SOHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
WHERE B.SalesQty > 0
AND A.CancelStatus = 0
UNION ALL
SELECT B.ItemsId
, A.SOHDId AS DocNo
, A.SODate AS DocDate
, C.ItemCode
, C.ItemName
, 'Sales Return' AS Memo
, B.SalesQty AS Qty
, B.SalesQty AS InQty
, 0 AS OutQty
, A.BranchId AS BranchId
, C.AvailableQty
, 10 AS RecOrder
FROM salesorderhd A
INNER JOIN directsalesreturn B
ON A.SOHDId = B.SOHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
WHERE B.SalesQty > 0
AND A.CancelStatus = 0
AND B.Damage = 0
UNION ALL
SELECT B.ItemsId
, A.SOHDId AS DocNo
, A.SODate AS DocDate
, C.ItemCode
, C.ItemName
, 'Sales Return [Damage]' AS Memo
, B.SalesQty * -1 AS Qty
, 0 AS InQty
, B.SalesQty AS OutQty
, A.BranchId AS BranchId
, C.AvailableQty
, 10 AS RecOrder
FROM salesorderhd A
INNER JOIN directsalesreturn B
ON A.SOHDId = B.SOHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
WHERE B.SalesQty > 0
AND A.CancelStatus = 0
AND B.Damage = 1
UNION ALL
SELECT BB.ItemsId
, A.SOHDId AS DocNo
, A.SODate AS DocDate
, C.ItemCode
, C.ItemName
, 'Sales Return' AS Memo
, B.ReturnQty AS Qty
, B.ReturnQty AS InQty
, 0 AS OutQty
, A.BranchId AS BranchId
, C.AvailableQty
, 10 AS RecOrder
FROM salesorderhd A
INNER JOIN salesorderdt BB
ON A.SOHDId = BB.SOHDId
INNER JOIN itemsummary C
ON BB.ItemsId = C.ItemsId
INNER JOIN (SELECT E.SOHDId, E.SODTId, SUM(E.ReturnQty) AS ReturnQty
FROM salesreturn E
GROUP BY E.SOHDId, E.SODTId) B
ON BB.SOHDId = B.SOHDId
AND BB.SODTId = B.SODTId
WHERE A.CancelStatus = 0
AND B.ReturnQty > 0
UNION ALL
SELECT B.ItemsId
, A.SOHDId AS DocNo
, A.SODate AS DocDate
, C.ItemCode
, C.ItemName
, 'Sales Return Free Issue' AS Memo
, B.FreeIssue AS Qty
, B.FreeIssue AS InQty
, 0 AS OutQty
, A.BranchId AS BranchId
, C.AvailableQty
, 11 AS RecOrder
FROM salesorderhdreturn A
INNER JOIN salesorderdtreturn B
ON A.SOHDId = B.SOHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
WHERE B.FreeIssue > 0
AND A.CancelStatus = 0
UNION ALL
SELECT B.ItemsId
, A.SOHDId AS DocNo
, A.SODate AS DocDate
, C.ItemCode
, C.ItemName
, 'Sales Return Free Issue' AS Memo
, B.FreeIssue AS Qty
, B.FreeIssue AS InQty
, 0 AS OutQty
, A.BranchId AS BranchId
, C.AvailableQty
, 11 AS RecOrder
FROM salesorderhd A
INNER JOIN directsalesreturn B
ON A.SOHDId = B.SOHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
WHERE B.FreeIssue > 0
AND A.CancelStatus = 0
UNION ALL
SELECT BB.ItemsId
, A.SOHDId AS DocNo
, A.SODate AS DocDate
, C.ItemCode
, C.ItemName
, 'Sales Return Free Issue' AS Memo
, B.FreeIssue AS Qty
, B.FreeIssue AS InQty
, 0 AS OutQty
, A.BranchId AS BranchId
, C.AvailableQty
, 11 AS RecOrder
FROM salesorderhd A
INNER JOIN salesorderdt BB
ON A.SOHDId = BB.SOHDId
INNER JOIN itemsummary C
ON BB.ItemsId = C.ItemsId
INNER JOIN (SELECT E.SOHDId, E.SODTId, SUM(E.FreeIssue) AS FreeIssue
FROM salesreturn E
GROUP BY E.SOHDId, E.SODTId) B
ON BB.SOHDId = B.SOHDId
AND BB.SODTId = B.SODTId
WHERE A.CancelStatus = 0
AND B.FreeIssue > 0
UNION ALL
SELECT A.ItemsId
, A.Id AS DocNo
, A.SpoilDate AS DocDate
, C.ItemCode
, C.ItemName
, 'Damage Item' AS Memo
, A.Qty * -1 AS Qty
, 0 AS InQty
, A.Qty AS OutQty
, A.BranchId AS BranchId
, C.AvailableQty
, 12 AS RecOrder
FROM itemspoilage A
INNER JOIN itemsummary C
ON A.ItemsId = C.ItemsId
WHERE A.Qty > 0
AND A.SOHDId = 0
UNION ALL
SELECT B.ItemsId
, A.PIHDId AS DocNo
, A.PIDate AS DocDate
, C.ItemCode
, C.ItemName
, 'Purchase Return' AS Memo
, B.PurchaseQty * -1 AS Qty
, 0 AS InQty
, B.PurchaseQty AS OutQty
, A.BranchId AS BranchId
, C.AvailableQty
, 13 AS RecOrder
FROM pihdreturn A
INNER JOIN pidtreturn B
ON A.PIHDId = B.PIHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
WHERE B.PurchaseQty > 0
UNION ALL
SELECT B.ItemsId
, A.PIHDId AS DocNo
, A.PIDate AS DocDate
, C.ItemCode
, C.ItemName
, 'Purchase Return' AS Memo
, B.PurchaseQty * -1 AS Qty
, 0 AS InQty
, B.PurchaseQty AS OutQty
, A.BranchId AS BranchId
, C.AvailableQty
, 13 AS RecOrder
FROM pihd A
INNER JOIN pidtrtn B
ON A.PIHDId = B.PIHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
WHERE B.PurchaseQty > 0
AND A.CancelStatus = 0
UNION ALL
SELECT B.ItemsId
, A.PIHDId AS DocNo
, A.PIDate AS DocDate
, C.ItemCode
, C.ItemName
, 'Purchase Free Issue Return' AS Memo
, B.FreeIssue * -1 AS Qty
, 0 AS InQty
, B.FreeIssue AS OutQty
, A.BranchId AS BranchId
, C.AvailableQty
, 14 AS RecOrder
FROM pihdreturn A
INNER JOIN pidtreturn B
ON A.PIHDId = B.PIHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
WHERE B.FreeIssue > 0
UNION ALL
SELECT B.ItemsId
, A.PIHDId AS DocNo
, A.PIDate AS DocDate
, C.ItemCode
, C.ItemName
, 'Purchase Free Issue Return' AS Memo
, B.FreeIssue * -1 AS Qty
, 0 AS InQty
, B.FreeIssue AS OutQty
, A.BranchId AS BranchId
, C.AvailableQty
, 13 AS RecOrder
FROM pihd A
INNER JOIN pidtrtn B
ON A.PIHDId = B.PIHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
WHERE B.FreeIssue > 0
AND A.CancelStatus = 0
UNION ALL
SELECT A.ItemsId
, A.PIHDId AS DocNo
, A.PIDate AS DocDate
, C.ItemCode
, C.ItemName
, 'Production FG' AS Memo
, A.Qty AS Qty
, A.Qty AS InQty
, 0 AS OutQty
, A.BranchId AS BranchId
, C.AvailableQty
, 14 AS RecOrder
FROM productionhd A
INNER JOIN itemsummary C
ON A.ItemsId = C.ItemsId
WHERE A.Qty > 0
AND A.CancelStatus = 0
UNION ALL
SELECT B.ItemsId
, A.PIHDId AS DocNo
, A.PIDate AS DocDate
, C.ItemCode
, C.ItemName
, 'Production RM' AS Memo
, B.PurchaseQty AS Qty
, 0 AS InQty
, B.PurchaseQty AS OutQty
, A.BranchId AS BranchId
, C.AvailableQty
, 15 AS RecOrder
FROM productionhd A
INNER JOIN productiondt B
ON A.PIHDId = B.PIHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
WHERE B.PurchaseQty > 0
AND A.CancelStatus = 0
UNION ALL
SELECT B.ItemsId
, A.SOHDId AS DocNo
, A.MovementDate AS DocDate
, B.ItemCode
, B.ItemName
, CONCAT('Convert From - ', C.ItemCode, '') AS Memo
, A.Qty AS Qty
, A.Qty AS InQty
, 0 AS OutQty
, A.BranchId AS BranchId
, B.AvailableQty
, 16 AS RecOrder
FROM inventorymovement A
INNER JOIN itemsummary B
ON A.ToItemsId = B.ItemsId
INNER JOIN itemsummary C
ON A.FromItemsId = C.ItemsId
WHERE A.ConvertTo = 1
UNION ALL
SELECT B.ItemsId
, A.SOHDId AS DocNo
, A.MovementDate AS DocDate
, B.ItemCode
, B.ItemName
, CONCAT('Convert To - ', C.ItemCode, '') AS Memo
, A.Qty * -1 AS Qty
, 0 AS InQty
, A.Qty AS OutQty
, A.BranchId AS BranchId
, B.AvailableQty
, 17 AS RecOrder
FROM inventorymovement A
INNER JOIN itemsummary B
ON A.FromItemsId = B.ItemsId
INNER JOIN itemsummary C
ON A.ToItemsId = C.ItemsId
WHERE A.ConvertFrom = 1
)A
INNER JOIN branch B
ON A.BranchId = B.BranchId
WHERE A.ItemCode = ItemCode1
AND A.DocDate BETWEEN date1 AND date2
ORDER BY A.DocDate, A.ItemsId, A.RecOrder
;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportItemList`;
DELIMITER |
CREATE PROCEDURE `ReportItemList`()
BEGIN
SELECT        itemsummary.ItemName, itemsummary.SellingPrice, companyinfo.CompanyName, companyinfo.CompanyAddress1, companyinfo.CompanyAddress2
FROM            itemsummary, companyinfo
ORDER BY itemsummary.ItemName;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportKOT`;
DELIMITER |
CREATE PROCEDURE `ReportKOT`(in TblNo1 VARCHAR(6))
BEGIN
SELECT        resttable.TblNo, resttable.ItemCode, menuitem.ItemName, resttable.SalesQty
FROM            resttable INNER JOIN
menuitem ON resttable.ItemsId = menuitem.ItemsId
WHERE        (resttable.KOTPrint = 0) AND (resttable.TblNo = TblNo1);
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportMonthlyProfitLost`;
DELIMITER |
CREATE PROCEDURE `ReportMonthlyProfitLost`(in date1 date, date2 date)
BEGIN
SELECT DATE_FORMAT(A.SODate, "%m-%Y") AS SalesMonth, IFNULL(SUM(B.SalesQty * B.SalesPrice), 0) AS TotalSales, IFNULL(SUM(B.SalesQty * C.CostPrice), 0) AS Cost, companyinfo.CompanyName, companyinfo.CompanyAddress1, companyinfo.CompanyAddress2
FROM salesorderhd A
INNER JOIN salesorderdt B
ON A.SOHDId = B.SOHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId, companyinfo
WHERE (A.CancelStatus = 0) AND (A.SODate BETWEEN date1 AND date2)
GROUP BY DATE_FORMAT(A.SODate, "%m-%Y"), companyinfo.CompanyName, companyinfo.CompanyAddress1, companyinfo.CompanyAddress2;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportNAllStock`;
DELIMITER |
CREATE PROCEDURE `ReportNAllStock`()
BEGIN
SELECT        A.ItemName, SUM(B.PurhaseQty) AS PurhaseQty, SUM(C.SalesQty) AS SalesQty, A.MinQty, A.AvailableQty, D.CompanyName, D.CompanyAddress1, D.CompanyAddress2, D.ContactNo1, D.ContactNo2,
D.CompanyLogo
FROM            itemsummary A LEFT OUTER JOIN
purchasing B ON A.ItemCode = B.ItemCode LEFT OUTER JOIN
salesorderdt C ON A.ItemsId = C.ItemsId, companyinfo D
GROUP BY A.ItemName, A.MinQty, A.AvailableQty, D.CompanyName, D.CompanyAddress1, D.CompanyAddress2, D.ContactNo1, D.ContactNo2, D.CompanyLogo
ORDER BY A.ItemName;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportNByItemCode`;
DELIMITER |
CREATE PROCEDURE `ReportNByItemCode`(in date1 date, date2 date, ItemCode1 VARCHAR(50))
BEGIN
SELECT        A.SODate, C.ItemName, SUM(B.SalesQty) AS SalesQty, B.SalesPrice, SUM(B.SalesQty) * B.SalesPrice AS SalesAmount, E.CompanyName, E.CompanyAddress1, E.CompanyAddress2, E.ContactNo1,
E.ContactNo2, E.CompanyLogo, B.ItemCode
FROM            salesorderhd A INNER JOIN
salesorderdt B ON A.SOHDId = B.SOHDId INNER JOIN
itemsummary C ON B.ItemsId = C.ItemsId, companyinfo E
GROUP BY B.SalesPrice, C.ItemName, A.SODate, B.ItemCode
HAVING        (A.SODate BETWEEN date1 AND date2) AND (B.ItemCode = ItemCode1)
ORDER BY A.SODate, C.ItemName;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportNSalesByDateAll`;
DELIMITER |
CREATE PROCEDURE `ReportNSalesByDateAll`(in date1 date, date2 date)
BEGIN
SELECT        A.SODate, C.ItemName, SUM(B.SalesQty) AS SalesQty, B.SalesPrice, SUM(B.SalesQty) * B.SalesPrice AS SalesAmount, E.CompanyName, E.CompanyAddress1, E.CompanyAddress2, E.ContactNo1,
E.ContactNo2, E.CompanyLogo, B.ItemCode
FROM            salesorderhd A INNER JOIN
salesorderdt B ON A.SOHDId = B.SOHDId INNER JOIN
itemsummary C ON B.ItemsId = C.ItemsId, companyinfo E
GROUP BY B.SalesPrice, C.ItemName, A.SODate, B.ItemCode
HAVING        (A.SODate BETWEEN date1 AND date2)
ORDER BY A.SODate, C.ItemName;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportNSalesProfitByDateAll`;
DELIMITER |
CREATE PROCEDURE `ReportNSalesProfitByDateAll`(in date1 date, date2 date)
BEGIN
SELECT        itemsummary.ItemName, salesorderdt.SalesQty * itemsummary.CostPrice AS ItemCost, salesorderdt.SalesQty * salesorderdt.SalesPrice AS SalesIncome,
salesorderdt.SalesQty * salesorderdt.SalesPrice - salesorderdt.SalesQty * itemsummary.CostPrice AS GrossProfit, companyinfo.CompanyName, companyinfo.CompanyAddress1, companyinfo.CompanyAddress2,
companyinfo.ContactNo1, companyinfo.ContactNo2, companyinfo.CompanyLogo
FROM            salesorderdt INNER JOIN
itemsummary ON salesorderdt.ItemsId = itemsummary.ItemsId INNER JOIN
salesorderhd ON salesorderdt.SOHDId = salesorderhd.SOHDId, companyinfo
WHERE        (salesorderhd.SODate BETWEEN date1 AND date2);
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportPIPrint`;
DELIMITER |
CREATE PROCEDURE `ReportPIPrint`(in PIHDId1 BIGINT(20))
BEGIN
SELECT X.PIHDId
, X.PINo
, X.PIDate
, X.SupplierName
, X.ContactPerson
, X.Address
, X.PIDTId
, X.ItemCode
, X.ItemName
, X.SItemName
, X.PurchaseQty
, X.FreeIssue
, X.PurchasePrice
, X.Discount
, X.NetAmount
, X.PIDiscount
, X.CompanyName
, X.CompanyAddress1
, X.CompanyAddress2
, X.ContactNo1
, X.ContactNo2
, X.CompanyLogo
, X.SupplierInvoiceNo
, X.PayMode
, X.ReturnTotal
, X.SellingPrice
, X.SellingPriceValue
, X.VATNo
, X.CompRegNo
, X.VATPer
, X.VATAmount
FROM(
SELECT A.PIHDId
, A.PINo
, A.PIDate
, D.SupplierName
, A.ContactPerson
, D.Address
, B.PIDTId
, B.ItemCode
, C.ItemName
, C.SItemName
, B.PurchaseQty
, B.FreeIssue
, B.PurchasePrice
, B.Discount
, B.NetAmount
, A.PIDiscount
, E.CompanyName
, H.BranchAddress AS CompanyAddress1
, H.BranchAddress2 AS CompanyAddress2
, H.BranchTelNo AS ContactNo1
, H.BranchTelNo2 AS ContactNo2
, E.CompanyLogo
, A.SupplierInvoiceNo
, CASE WHEN A.PayModeId = 3 AND A.CreditDueDays > 0 THEN CONCAT(F.PayMode, ' [', A.CreditDueDays, ' Days]') ELSE F.PayMode END AS PayMode
, A.ReturnTotal
, B.SellingPrice
, (B.SellingPrice * B.PurchaseQty) AS SellingPriceValue
, E.VATNo
, E.CompRegNo
, A.VATPer
, A.VATAmount
FROM pihd A
INNER JOIN pidt B
ON A.PIHDId = B.PIHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
INNER JOIN supplier D
ON A.SupplierId = D.SupplierId
INNER JOIN paymentmode F
ON A.PayModeId = F.PayModeId
INNER JOIN branch H
ON A.BranchId = H.BranchId
, companyinfo E
WHERE (A.PIHDId = PIHDId1)
UNION ALL
SELECT A.PIHDId
, A.PINo
, A.PIDate
, D.SupplierName
, A.ContactPerson
, D.Address
, B.PIDTId
, B.ItemCode
, CONCAT(C.ItemName, '[Return]') AS ItemName
, CONCAT(C.SItemName, ' rsgka') AS SItemName
, B.PurchaseQty * -1 AS PurchaseQty
, B.FreeIssue
, B.PurchasePrice
, B.Discount * -1 AS Discount
, B.NetAmount * -1 AS NetAmount
, A.PIDiscount
, E.CompanyName
, H.BranchAddress AS CompanyAddress1
, H.BranchAddress2 AS CompanyAddress2
, H.BranchTelNo AS ContactNo1
, H.BranchTelNo2 AS ContactNo2
, E.CompanyLogo
, A.SupplierInvoiceNo
, CASE WHEN A.PayModeId = 3 AND A.CreditDueDays > 0 THEN CONCAT(F.PayMode, ' [', A.CreditDueDays, ' Days]') ELSE F.PayMode END AS PayMode
, A.ReturnTotal
, B.SellingPrice
, (B.SellingPrice * B.PurchaseQty)  * -1 AS SellingPriceValue
, E.VATNo
, E.CompRegNo
, 0 AS VATPer
, 0 AS VATAmount
FROM pihd A
INNER JOIN pidtrtn B
ON A.PIHDId = B.PIHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
INNER JOIN supplier D
ON A.SupplierId = D.SupplierId
INNER JOIN paymentmode F
ON A.PayModeId = F.PayModeId
INNER JOIN branch H
ON A.BranchId = H.BranchId
, companyinfo E
WHERE (A.PIHDId = PIHDId1)
)X
ORDER BY X.PIHDId, X.PIDTId;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportPIReport`;
DELIMITER |
CREATE PROCEDURE `ReportPIReport`(in PIHDId1 BIGINT(20))
BEGIN
SELECT X.PIHDId
, X.PINo
, X.PIDate
, X.SupplierName
, X.ContactPerson
, X.Address
, X.PIDTId
, X.ItemCode
, X.ItemName
, X.PurchaseQty
, X.FreeIssue
, X.PurchasePrice
, X.NetAmount
, X.CompanyName
, X.CompanyAddress1
, X.CompanyAddress2
, X.ContactNo1
, X.ContactNo2
, X.SupplierInvoiceNo
, X.PayMode
, X.ReturnTotal
FROM(
SELECT A.PIHDId
, A.PINo
, A.PIDate
, D.SupplierName
, A.ContactPerson
, D.Address
, B.PIDTId
, B.ItemCode
, C.ItemName
, B.PurchaseQty
, B.FreeIssue
, B.PurchasePrice
, B.NetAmount
, E.CompanyName
, E.CompanyAddress1
, E.CompanyAddress2
, E.ContactNo1
, E.ContactNo2
, A.SupplierInvoiceNo
, paymentmode.PayMode
, A.ReturnTotal
FROM pihd A
INNER JOIN pidt B
ON A.PIHDId = B.PIHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
INNER JOIN supplier D
ON A.SupplierId = D.SupplierId
INNER JOIN paymentmode
ON A.PayModeId = paymentmode.PayModeId
, companyinfo E
WHERE (A.PIHDId = PIHDId1)
UNION ALL
SELECT A.PIHDId
, A.PINo
, A.PIDate
, D.SupplierName
, A.ContactPerson
, D.Address
, B.PIDTId
, B.ItemCode
, CONCAT(C.ItemName, '[Return]') AS ItemName
, B.PurchaseQty * -1 AS PurchaseQty
, B.FreeIssue
, B.PurchasePrice
, B.NetAmount * -1 AS NetAmount
, E.CompanyName
, E.CompanyAddress1
, E.CompanyAddress2
, E.ContactNo1
, E.ContactNo2
, A.SupplierInvoiceNo
, paymentmode.PayMode
, A.ReturnTotal
FROM pihd A
INNER JOIN pidtrtn B
ON A.PIHDId = B.PIHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
INNER JOIN supplier D
ON A.SupplierId = D.SupplierId
INNER JOIN paymentmode
ON A.PayModeId = paymentmode.PayModeId
, companyinfo E
WHERE (A.PIHDId = PIHDId1)
)X
ORDER BY X.PIHDId, X.PIDTId;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportPIReturnReport`;
DELIMITER |
CREATE PROCEDURE `ReportPIReturnReport`(in PIHDId1 BIGINT(20))
BEGIN
SELECT X.PIHDId
, X.PINo
, X.PIDate
, X.SupplierName
, X.ContactPerson
, X.Address
, X.PIDTId
, X.ItemCode
, X.ItemName
, X.PurchaseQty
, X.FreeIssue
, X.PurchasePrice
, X.NetAmount
, X.CompanyName
, X.CompanyAddress1
, X.CompanyAddress2
, X.ContactNo1
, X.ContactNo2
, X.SupplierInvoiceNo
, X.PayMode
, X.ReturnTotal
FROM(
SELECT A.PIHDId
, A.PINo
, A.PIDate
, D.SupplierName
, A.ContactPerson
, D.Address
, B.PIDTId
, B.ItemCode
, C.ItemName
, B.PurchaseQty
, B.FreeIssue
, B.PurchasePrice
, B.NetAmount
, E.CompanyName
, E.CompanyAddress1
, E.CompanyAddress2
, E.ContactNo1
, E.ContactNo2
, A.SupplierInvoiceNo
, paymentmode.PayMode
, A.ReturnTotal
FROM pihdreturn A
INNER JOIN pidtreturn B
ON A.PIHDId = B.PIHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
INNER JOIN supplier D
ON A.SupplierId = D.SupplierId
INNER JOIN paymentmode
ON A.PayModeId = paymentmode.PayModeId
, companyinfo E
WHERE (A.PIHDId = PIHDId1)
)X
ORDER BY X.PIHDId, X.PIDTId;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportPOReport`;
DELIMITER |
CREATE PROCEDURE `ReportPOReport`(in POHDId1 BIGINT(20))
BEGIN
SELECT        A.POHDId, A.PONo, A.PODate, D.SupplierName, A.ContactPerson, D.Address, B.PODTId, B.ItemCode, C.ItemName, B.PurchaseQty, B.FreeIssue, B.PurchasePrice, B.NetAmount, E.CompanyName,
E.CompanyAddress1, E.CompanyAddress2, E.ContactNo1, E.ContactNo2
FROM            pohd A INNER JOIN
podt B ON A.POHDId = B.POHDId INNER JOIN
itemsummary C ON B.ItemsId = C.ItemsId INNER JOIN
supplier D ON A.SupplierId = D.SupplierId, companyinfo E
WHERE        (A.POHDId = POHDId1)
ORDER BY A.POHDId, B.PODTId;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportProfitLost`;
DELIMITER |
CREATE PROCEDURE `ReportProfitLost`(in date1 date, date2 date)
BEGIN
DECLARE GrossSale DECIMAL(20,2) DEFAULT 0;
DECLARE TotalSale DECIMAL(20,2) DEFAULT 0;
DECLARE SalesReturn DECIMAL(20,2) DEFAULT 0;
DECLARE SalesReturn1 DECIMAL(20,2) DEFAULT 0;
DECLARE SalesReturn2 DECIMAL(20,2) DEFAULT 0;
DECLARE Cost DECIMAL(20,2) DEFAULT 0;
DECLARE ReturnCost DECIMAL(20,2) DEFAULT 0;
DECLARE ReturnCost1 DECIMAL(20,2) DEFAULT 0;
DECLARE ReturnCost2 DECIMAL(20,2) DEFAULT 0;
DECLARE ItemDiscount1 DECIMAL(20,2) DEFAULT 0;
DECLARE TotalBillDiscount1 DECIMAL(20,2) DEFAULT 0;
DECLARE TotalDiscount1 DECIMAL(20,2) DEFAULT 0;
SELECT IFNULL((SUM(B.Discount)), 0) INTO ItemDiscount1
FROM salesorderhd A
INNER JOIN salesorderdt B
ON A.SOHDId = B.SOHDId
WHERE (A.SODate BETWEEN date1 AND date2)
AND (A.CancelStatus = 0);
SELECT IFNULL((SUM(SODiscount)), 0) INTO TotalBillDiscount1
FROM salesorderhd
WHERE (SODate BETWEEN date1 AND date2)
AND (CancelStatus = 0);
SET TotalDiscount1 = IFNULL((ItemDiscount1), 0) + IFNULL((TotalBillDiscount1), 0);
SELECT SUM(B.SalesQty * B.SalesPrice) INTO GrossSale
FROM salesorderhd A
INNER JOIN salesorderdt B
ON A.SOHDId = B.SOHDId
WHERE (A.CancelStatus = 0)
AND (A.SODate BETWEEN date1 AND date2);
SET TotalSale = GrossSale - TotalDiscount1;
SELECT IFNULL(SUM(B.NetAmount), 0) INTO SalesReturn
FROM salesorderhd A
INNER JOIN salesreturn B
ON A.SOHDId = B.SOHDId
WHERE (A.CancelStatus = 0)
AND (B.RtnDate BETWEEN date1 AND date2);
SELECT IFNULL(SUM(B.NetAmount), 0) INTO SalesReturn1
FROM salesorderhd A
INNER JOIN directsalesreturn B
ON A.SOHDId = B.SOHDId
WHERE (A.CancelStatus = 0)
AND (A.SODate BETWEEN date1 AND date2);
SELECT IFNULL(SUM(SONetTotal), 0) INTO SalesReturn2
FROM salesorderhdreturn
WHERE (SODate BETWEEN date1 AND date2);
SELECT IFNULL(SUM(B.SalesQty * B.CostPrice), 0) INTO Cost
FROM salesorderhd A
INNER JOIN salesorderdt B
ON A.SOHDId = B.SOHDId
WHERE (A.CancelStatus = 0)
AND (A.SODate BETWEEN date1 AND date2);
SELECT IFNULL(SUM(B.ReturnQty * C.CostPrice), 0) INTO ReturnCost
FROM salesorderhd A
INNER JOIN salesreturn B
ON A.SOHDId = B.SOHDId
INNER JOIN salesorderdt C
ON B.ItemsId = C.ItemsId
AND B.SOHDId = C.SOHDId
WHERE (A.CancelStatus = 0)
AND (A.SODate BETWEEN date1 AND date2);
SELECT IFNULL(SUM(B.SalesQty * B.CostPrice), 0) INTO ReturnCost1
FROM salesorderhd A
INNER JOIN directsalesreturn B
ON A.SOHDId = B.SOHDId
WHERE (A.CancelStatus = 0)
AND (A.SODate BETWEEN date1 AND date2);
SELECT IFNULL(SUM(B.SalesQty * B.CostPrice), 0) INTO ReturnCost2
FROM salesorderhdreturn A
INNER JOIN salesorderdtreturn B
ON A.SOHDId = B.SOHDId
AND (A.SODate BETWEEN date1 AND date2);
SELECT X.date1, X.date2, X.TotalSale, X.SalesReturn, X.Cost, X.ReturnCost, X.CatDescription, X.Amount
FROM(
SELECT date1, date2, TotalSale, SalesReturn + SalesReturn1 + SalesReturn2 as SalesReturn, Cost, ReturnCost + ReturnCost1 + ReturnCost2 as ReturnCost, '' AS CatDescription, 0 AS Amount
UNION ALL
SELECT date1, date2, TotalSale, SalesReturn, Cost, ReturnCost, B.CatDescription, IFNULL(SUM(A.PaymentAmount), 0) AS Amount
FROM allexpenses A INNER JOIN
expensescategory B
ON A.PayCatId = B.PayCatId
WHERE (A.PaymentDate BETWEEN date1 AND date2)
AND B.PNLStatus = 1
GROUP BY date1, date2, TotalSale, SalesReturn, Cost, ReturnCost, B.CatDescription
UNION ALL
SELECT date1, date2, TotalSale, SalesReturn, Cost, ReturnCost, 'Asset Depriciation', IFNULL(SUM(A.DepreciationAmount), 0) AS Amount
FROM fixedassetdepreciation A
WHERE (A.DepreciationDate BETWEEN date1 AND date2)
)X
GROUP BY X.CatDescription;
END |
DELIMITER ;

