DROP PROCEDURE IF EXISTS `ReportSalesByAllRep`;
DELIMITER |
CREATE PROCEDURE `ReportSalesByAllRep`(in
date1 date,
date2 date)
BEGIN
SELECT A.SODate
, B.EmployeeName
, SUM(A.SONetTotal - A.ReturnTotal) AS TotalSale
, A.RepId
, date1 as FromDate
, date2 as ToDate
FROM salesorderhd A
INNER JOIN employeeregistration B
ON A.RepId = B.EmployeeID
WHERE (A.CancelStatus = 0)
AND (A.SODate BETWEEN date1 AND date2)
GROUP BY A.SODate, B.EmployeeName, A.RepId
ORDER BY A.SODate;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportSalesByBranch`;
DELIMITER |
CREATE PROCEDURE `ReportSalesByBranch`(in date1 date,
date2 date,
BranchId1 int)
BEGIN
SELECT A.SOHDId AS BillNo
, A.SODate
, C.ItemName
, B.SalesQty
, B.SalesPrice AS SellingPrice
, B.SalesQty * B.SalesPrice AS SalesAmount
, B.Discount
, B.NetAmount
, D.CompanyName
, D.CompanyAddress1
, D.CompanyAddress2
, D.ContactNo1
, D.ContactNo2
, C.ItemCode
, C.ItemCatId
, A.RepId
, A.CustomerId
, E.SODiscount AS TotDisc
, 0 AS ReturnAmount
, date1 as FromDate
, date2 as ToDate
FROM salesorderhd A
INNER JOIN salesorderdt B
ON A.SOHDId = B.SOHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
, companyinfo D,
(SELECT SUM(SODiscount) AS SODiscount
FROM salesorderhd
WHERE (CancelStatus = 0)
and SODate BETWEEN date1 AND date2) E
WHERE (A.CancelStatus = 0)
AND (A.BranchId = BranchId1)
and (A.SODate BETWEEN date1 AND date2)
UNION ALL
SELECT A.SOHDId AS BillNo
, A.SODate
, CONCAT(C.ItemName, '[Return]') AS ItemName
, B.SalesQty * -1 AS SalesQty
, B.SalesPrice AS SellingPrice
, (B.SalesQty * B.SalesPrice) * -1 AS SalesAmount
, (B.Discount * -1) AS Discount
, ((B.SalesQty * B.SalesPrice) - B.Discount) * -1 AS NetAmount
, D.CompanyName
, D.CompanyAddress1
, D.CompanyAddress2
, D.ContactNo1
, D.ContactNo2
, CONCAT(C.ItemCode, '[Rtn]') AS ItemCode
, C.ItemCatId
, A.RepId
, A.CustomerId
, E.SODiscount AS TotDisc
, B.NetAmount AS ReturnAmount
, date1 as FromDate
, date2 as ToDate
FROM salesorderhd A
INNER JOIN directsalesreturn B
ON A.SOHDId = B.SOHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
, companyinfo D,
(SELECT SUM(SODiscount) AS SODiscount
FROM salesorderhd
WHERE (CancelStatus = 0)
and SODate BETWEEN date1 AND date2) E
WHERE (A.CancelStatus = 0)
AND (A.BranchId = BranchId1)
and (A.SODate BETWEEN date1 AND date2)
UNION ALL
SELECT A.SOHDId AS BillNo
, A.SODate
, CONCAT(C.ItemName, '[Return]') AS ItemName
, B.SalesQty * -1 AS 'SalesQty'
, B.SalesPrice AS SellingPrice
, (B.SalesQty * B.SalesPrice) * -1 AS SalesAmount
, B.Discount * -1 AS Discount
, B.NetAmount * -1 AS NetAmount
, D.CompanyName
, D.CompanyAddress1
, D.CompanyAddress2
, D.ContactNo1
, D.ContactNo2
, C.ItemCode
, C.ItemCatId
, A.RepId
, A.CustomerId
, 0 AS TotDisc
, B.NetAmount AS ReturnAmount
, date1 as FromDate
, date2 as ToDate
FROM salesorderhdreturn A
INNER JOIN salesorderdtreturn B
ON A.SOHDId = B.SOHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
, companyinfo D
WHERE (A.CancelStatus = 0)
AND (A.BranchId = BranchId1)
and (A.SODate BETWEEN date1 AND date2)
UNION ALL
SELECT A.SOHDId AS BillNo
, A.SODate
, CONCAT(C.ItemName, '[Return]') AS ItemName
, B.ReturnQty * -1 AS SalesQty
, B.SalesPrice AS SellingPrice
, (B.ReturnQty * B.SalesPrice) * -1 AS SalesAmount
, B.Discount * -1 AS Discount
, ((B.ReturnQty * B.SalesPrice) - B.Discount) * -1 AS NetAmount
, D.CompanyName
, D.CompanyAddress1
, D.CompanyAddress2
, D.ContactNo1
, D.ContactNo2
, CONCAT(C.ItemCode, '[Rtn]') AS ItemCode
, C.ItemCatId
, A.RepId
, A.CustomerId
, E.SODiscount AS TotDisc
, B.NetAmount AS ReturnAmount
, date1 as FromDate
, date2 as ToDate
FROM salesorderhd A
INNER JOIN salesorderdt BB
ON A.SOHDId = BB.SOHDId
INNER JOIN salesreturn B
ON BB.SOHDId = B.SOHDId
AND BB.SODTId = B.SODTId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
, companyinfo D,
(SELECT SUM(SODiscount) AS SODiscount
FROM salesorderhd
WHERE (CancelStatus = 0)
and SODate BETWEEN date1 AND date2) E
WHERE (A.CancelStatus = 0)
AND (A.BranchId = BranchId1)
and (A.SODate BETWEEN date1 AND date2);
END |
DELIMITER ;

