UNION ALL
SELECT A.SOHDId AS BillNo
, A.SODate
, CONCAT(C.ItemName, '[Return]') AS ItemName
, B.SalesQty * -1 AS SalesQty
, B.SalesPrice AS SellingPrice
, (B.SalesQty * B.SalesPrice) * -1 AS SalesAmount
