, companyinfo D,
(SELECT SUM(SODiscount) AS SODiscount
FROM salesorderhd
WHERE (CancelStatus = 0)
and SODate BETWEEN date1 AND date2) E
WHERE (A.CancelStatus = 0)
AND (A.CustomerId = CustomerId1)
and (A.SODate BETWEEN date1 AND date2);
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportSalesRpt`;
DELIMITER |
CREATE PROCEDURE `ReportSalesRpt`(in date1 date, date2 date)
BEGIN
SELECT        salesorderhd.BillNo, salesorderhd.SODate, itemsummary.ItemName, salesorderdt.SalesQty, salesorderdt.SalesPrice,
salesorderdt.SalesQty * salesorderdt.SalesPrice AS GrossSales, salesorderdt.Discount, salesorderdt.NetAmount, IFNULL(salesreturn.ReturnQty, 0) AS ReturnQty,
IFNULL(salesreturn.NetAmount, 0) AS ReturnAmount, IFNULL(salesorderdt.NetAmount, 0) - IFNULL(salesreturn.NetAmount, 0) AS NetSalesAmount,
useraccount.UserName AS Cashier, employeeregistration.EmployeeName AS SalesRep, salesorderhd.CreatedBy, salesorderhd.RepId, salesorderdt.ItemCode,
itemsummary.ItemCatId
FROM            salesorderhd INNER JOIN
salesorderdt ON salesorderhd.SOHDId = salesorderdt.SOHDId INNER JOIN
useraccount ON salesorderhd.CreatedBy = useraccount.UserID INNER JOIN
itemsummary ON salesorderdt.ItemsId = itemsummary.ItemsId LEFT OUTER JOIN
employeeregistration ON salesorderhd.RepId = employeeregistration.EmployeeID LEFT OUTER JOIN
salesreturn ON salesorderdt.SODTId = salesreturn.SODTId
WHERE        (salesorderhd.SODate BETWEEN date1 AND date2) AND (salesorderdt.ItemCode = ItemCode1)
ORDER BY salesorderhd.BillNo, salesorderhd.SODate;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportSalesRtn`;
DELIMITER |
CREATE PROCEDURE `ReportSalesRtn`(in SOHDId1 int, ItemsId1 int)
BEGIN
SELECT        salesorderhd.SOHDId, salesreturn.ItemsId, salesreturn.ItemCode, salesreturn.RtnDate, salesorderhd.SODate, salesreturn.ReturnQty, itemsummary.ItemName, salesreturn.SalesPrice, salesreturn.Discount,
salesreturn.NetAmount, useraccount.UserName, companyinfo.CompanyName, companyinfo.CompanyAddress1, companyinfo.CompanyAddress2, companyinfo.ContactNo1, companyinfo.ContactNo2,
companyinfo.CompanyLogo
FROM            salesorderhd INNER JOIN
salesreturn ON salesorderhd.SOHDId = salesreturn.SOHDId INNER JOIN
itemsummary ON salesreturn.ItemsId = itemsummary.ItemsId INNER JOIN
useraccount ON salesreturn.CreatedBy = useraccount.UserID, companyinfo
WHERE        (salesorderhd.SOHDId = SOHDId1) AND (salesreturn.ItemsId = ItemsId1);
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportSalesSummary`;
DELIMITER |
CREATE PROCEDURE `ReportSalesSummary`(in
date1 date,
date2 date)
BEGIN
SELECT A.SOHDId AS InvoiceNo
, A.SODate AS InvoiceDate
, B.PayMode
, E.CustomerName
, A.SONetTotal AS NetTotal
, D.EmployeeName AS SalesRep
, C.UserName AS Cashier
, CASE A.CancelStatus WHEN 1 THEN 'Cancelled Invoice'
ELSE '' END AS 'CancellStatus'
FROM salesorderhd A
INNER JOIN paymentmode B
ON A.PayModeId = B.PayModeId
INNER JOIN useraccount C
ON A.CreatedBy = C.UserID
LEFT OUTER JOIN employeeregistration D
ON A.RepId = D.EmployeeID
LEFT OUTER JOIN customer E
ON A.CustomerId = E.CustomerId
WHERE (A.SODate BETWEEN date1 AND date2)
ORDER BY InvoiceNo;
SELECT B.ItemCode,
SUM(B.SalesQty) AS SalesQty
FROM salesorderhd A
INNER JOIN salesorderdt B
ON A.SOHDId = B.SOHDId
WHERE (A.CancelStatus = 0)
AND (A.SODate BETWEEN date1 AND date2)
GROUP BY B.ItemCode;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportSalesSummaryByDate`;
DELIMITER |
CREATE PROCEDURE `ReportSalesSummaryByDate`(in date1 date,
date2 date)
BEGIN
SELECT        salesorderhd.SOHDId AS InvoiceNo, salesorderhd.SODate, customer.CustomerName, salesorderhd.SONetTotal, paymentmode.PayMode, customercheque.ChequeBank, customercheque.ChequeNo
FROM            salesorderhd INNER JOIN
paymentmode ON salesorderhd.PayModeId = paymentmode.PayModeId LEFT OUTER JOIN
customer ON salesorderhd.CustomerId = customer.CustomerId LEFT OUTER JOIN
customercheque ON salesorderhd.SOHDId = customercheque.SOHDId
WHERE        (salesorderhd.SODate BETWEEN date1 AND date2);
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportSelectSummaryReport`;
DELIMITER |
CREATE PROCEDURE `ReportSelectSummaryReport`(IN date1 date, date2 date)
BEGIN
call SelectSummaryReport(date1);
SELECT        A.TotalSale, A.TotalDiscount, A.SalesReturn, A.TotalNetSale, A.TotalCashSale, A.TotalChequeSale, A.TotalCreditSale, A.TotalCreditCardSale, A.Expenses, A.TranDate, A.SummaryId, B.CompanyName,
B.CompanyAddress1, B.CompanyAddress2, B.ContactNo1, B.ContactNo2
FROM            salessummary A, companyinfo B
where A.TranDate = date1
ORDER BY A.TranDate;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportSerialSummary`;
DELIMITER |
CREATE PROCEDURE `ReportSerialSummary`()
BEGIN
SELECT B.ItemsId
, A.SerialNo
, B.ItemCode
, B.ItemName
, A.PIHDId AS GRNNo
, F.SupplierName
, A.PurchasePrice
, A.PurchaseDate
, A.SOHDId AS InvoiceNo
, G.CustomerName
, A.SellingPrice AS SellingPrice
, A.SalesDate
, A.Availability
, A.PurchaseReturnDate
, A.SalesReturnDate
,TRIM(Replace(Replace(Replace(C.BranchName,'\t',''),'\n',''),'\r','')) AS BranchName
FROM serialsummary A
INNER JOIN itemsummary B
ON A.ItemsId = B.ItemsId
INNER JOIN branch C
ON A.BranchId = C.BranchId
LEFT OUTER JOIN pihd E
ON A.PIHDId = E.PIHDId
LEFT OUTER JOIN supplier F
ON E.SupplierId = F.SupplierId
LEFT OUTER JOIN salesorderhd G
ON A.SOHDId = G.SOHDId;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportSpoilageByDate`;
DELIMITER |
CREATE PROCEDURE `ReportSpoilageByDate`(in date1 date, date2 date)
BEGIN
SELECT TRIM(Replace(Replace(Replace(C.BranchName,'\t',''),'\n',''),'\r','')) AS Branch
, A.Remarks
, A.SpoilDate AS DamageDate
, A.ItemCode
, B.ItemName
, A.Qty AS DamageQty
FROM itemspoilage A
INNER JOIN itemsummary B
ON A.ItemsId = B.ItemsId
INNER JOIN branch C
ON A.BranchId = C.BranchId
WHERE (A.SpoilDate BETWEEN date1 AND date2);
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportSTKAdgPrint`;
DELIMITER |
CREATE PROCEDURE `ReportSTKAdgPrint`(in StkAdjHDId1 int)
BEGIN
SELECT A.StkAdjHDId
, A.AdjDate
, B.ItemCode
, C.ItemName
, B.SystemQty
, B.PhisicalQty
, B.VarrienceQty
, B.AvgCost
, B.VarrienceValue,
A.TotalVariance
, A.BranchId
, D.BranchName
FROM stkadjhd A
INNER JOIN stkadjdt B
ON A.StkAdjHDId = B.StkAdjHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
INNER JOIN branch D
ON A.BranchId = D.BranchId
WHERE (A.StkAdjHDId = StkAdjHDId1);
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportStock3InAll`;
DELIMITER |
CREATE PROCEDURE `ReportStock3InAll`()
BEGIN
SELECT A.ItemCode
, A.ItemName
, '' AS SupplierName
, A.AvgCost AS CostPrice
, A.SellingPrice
, A.AvailableQty
, A.MinQty
, A.ItemUnit
, A.ItemCatId
, C.CompanyName
, C.CompanyAddress1
, C.CompanyAddress2
, A.ItemCatId
FROM itemsummary A
, companyinfo C
WHERE     (A.AvailableQty > 0)
ORDER BY A.ItemCode;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportStockAdjustment`;
DELIMITER |
CREATE PROCEDURE `ReportStockAdjustment`(in
date1 date,
date2 date)
BEGIN
SELECT A.StkAdjHDId AS AdjustmentNo
, A.AdjDate AS AdjustmentDate
, B.ItemCode
, C.ItemName
, B.SystemQty
, B.PhisicalQty
, B.VarrienceQty
, B.AvgCost
, B.VarrienceValue
, A.TotalVariance
, D.BranchName
FROM stkadjhd A
INNER JOIN stkadjdt B
ON A.StkAdjHDId = B.StkAdjHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
INNER JOIN branch D
ON A.BranchId = D.BranchId
WHERE (A.AdjDate BETWEEN date1 AND date2);
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportStockByBranchItemCat`;
DELIMITER |
CREATE PROCEDURE `ReportStockByBranchItemCat`(in ItemCatId1 int, BranchId1 int)
BEGIN
SELECT A.ItemCode
, A.ItemName
, A.AvgCost AS CostPrice
, A.CostPrice AS LPP
, A.SellingPrice
, B.AvailableQty
, A.MinQty
, A.ItemUnit
, A.ItemCatId
, C.CompanyName
, C.CompanyAddress1
, C.CompanyAddress2
, (A.AvgCost * B.AvailableQty) AS AVGCostValue
, (A.CostPrice * B.AvailableQty) AS LPPCostValue
, (A.SellingPrice * B.AvailableQty) AS SellingPriceValue
FROM itemsummary A
INNER JOIN branchstock B
ON A.ItemsId = B.ItemsId
AND B.BranchId = BranchId1
, companyinfo C
WHERE (A.ItemCatId = ItemCatId1)
ORDER BY A.ItemCode;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportStockByBranchItemCode`;
DELIMITER |
CREATE PROCEDURE `ReportStockByBranchItemCode`(in ItemCode1 varchar(50), BranchId1 int)
BEGIN
SELECT A.ItemCode
, A.ItemName
, A.AvgCost AS CostPrice
, A.CostPrice AS LPP
, A.SellingPrice
, B.AvailableQty
, A.MinQty
, A.ItemUnit
, A.ItemCatId
, C.CompanyName
, C.CompanyAddress1
, C.CompanyAddress2
, (A.AvgCost * B.AvailableQty) AS AVGCostValue
, (A.CostPrice * B.AvailableQty) AS LPPCostValue
, (A.SellingPrice * B.AvailableQty) AS SellingPriceValue
FROM itemsummary A
INNER JOIN branchstock B
ON A.ItemsId = B.ItemsId
AND B.BranchId = BranchId1
, companyinfo C
WHERE (A.ItemCode = ItemCode1)
ORDER BY A.ItemCode;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportStockByCategory`;
DELIMITER |
CREATE PROCEDURE `ReportStockByCategory`(in ItemCatId1 int)
BEGIN
SELECT A.ItemCode
, A.ItemName
, '' AS SupplierName
, A.CostPrice
, A.SellingPrice
, A.AvailableQty
, A.MinQty
, A.ItemUnit
, A.ItemCatId
, C.CompanyName
, C.CompanyAddress1
, C.CompanyAddress2
FROM itemsummary A
, companyinfo C
WHERE (A.ItemCatId = ItemCatId1)
ORDER BY A.ItemName;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportStockByItemCat3In`;
DELIMITER |
CREATE PROCEDURE `ReportStockByItemCat3In`(in ItemCatId1 int)
BEGIN
SELECT A.ItemCode
, A.ItemName
, '' AS SupplierName
, A.AvgCost AS CostPrice
, A.SellingPrice
, A.AvailableQty
, A.MinQty
, A.ItemUnit
, A.ItemCatId
, C.CompanyName
, C.CompanyAddress1
, C.CompanyAddress2
, A.ItemCatId
FROM itemsummary A
, companyinfo C
WHERE     (A.ItemCatId = ItemCatId1)
and (A.AvailableQty > 0)
ORDER BY A.ItemName;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportStockByItemCategory`;
DELIMITER |
CREATE PROCEDURE `ReportStockByItemCategory`(in ItemCatId1 int)
BEGIN
SELECT A.ItemCode
, A.ItemName
, A.AvgCost AS CostPrice
, A.CostPrice AS LPP
, A.SellingPrice
, SUM(B.AvailableQty) AS AvailableQty
, A.MinQty
, A.ItemUnit
, A.ItemCatId
, C.CompanyName
, C.CompanyAddress1
, C.CompanyAddress2
, (A.AvgCost * SUM(B.AvailableQty)) AS AVGCostValue
, (A.CostPrice * SUM(B.AvailableQty)) AS LPPCostValue
, (A.SellingPrice * SUM(B.AvailableQty)) AS SellingPriceValue
FROM itemsummary A
INNER JOIN branchstock B
ON A.ItemsId = B.ItemsId
, companyinfo C
WHERE (A.ItemCatId = ItemCatId1)
GROUP BY A.ItemCode
, A.ItemName
, A.AvgCost
, A.CostPrice
, A.SellingPrice
, A.MinQty
, A.ItemUnit
, A.ItemCatId
, C.CompanyName
, C.CompanyAddress1
, C.CompanyAddress2
ORDER BY A.ItemCode;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportStockByItemCode`;
DELIMITER |
CREATE PROCEDURE `ReportStockByItemCode`(in ItemCode1 varchar(50))
BEGIN
SELECT A.ItemCode
, A.ItemName
, A.AvgCost AS CostPrice
, A.CostPrice AS LPP
, A.SellingPrice
, SUM(B.AvailableQty) AS AvailableQty
, A.MinQty
, A.ItemUnit
, A.ItemCatId
, C.CompanyName
, C.CompanyAddress1
, C.CompanyAddress2
, (A.AvgCost * SUM(B.AvailableQty)) AS AVGCostValue
, (A.CostPrice * SUM(B.AvailableQty)) AS LPPCostValue
, (A.SellingPrice * SUM(B.AvailableQty)) AS SellingPriceValue
FROM itemsummary A
INNER JOIN branchstock B
ON A.ItemsId = B.ItemsId
, companyinfo C
WHERE (A.ItemCode = ItemCode1)
GROUP BY A.ItemCode
, A.ItemName
, A.AvgCost
, A.CostPrice
, A.SellingPrice
, A.MinQty
, A.ItemUnit
, A.ItemCatId
, C.CompanyName
, C.CompanyAddress1
, C.CompanyAddress2
ORDER BY A.ItemCode;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportStockCount`;
DELIMITER |
CREATE PROCEDURE `ReportStockCount`(in BranchId1 int)
BEGIN
SELECT A.ItemCode
, A.ItemName
, B.AvailableQty
, C.BranchName
FROM itemsummary A
INNER JOIN branchstock B
ON A.ItemsId = B.ItemsId
INNER JOIN branch C
ON B.BranchId = C.BranchId
WHERE B.BranchId = BranchId1
ORDER BY A.ItemCode;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportStockTemplate`;
DELIMITER |
CREATE PROCEDURE `ReportStockTemplate`()
BEGIN
SELECT B.ItemCatName AS ItemCategory
, IFNULL(D.ItemSubCatName, B.ItemCatName) AS ItemSubCategory
, A.ItemCode
, A.ItemName
, A.SItemName
, A.Discount AS RetailDiscountAmount
, A.RetailDiscPer AS RetailDiscountPer
, A.WholeSaleDiscount AS WholesaleDiscountAmount
, A.WholesaleDiscPer AS WholesaleDiscountPer
, A.ItemUnit
, A.CostPrice
, A.SellingPrice
, A.SPSellingPrice
, A.ShopPrice
, A.MinSellingPrice
, A.MinQty AS ReOrderLevel
, A.AvailableQty
, A.WarrantyPeriod
, A.RackNo
, A.MaintainQty
, A.TItemName
, A.ScaleItem
, A.BundleItem
, A.RawMaterial
, A.AllowSales
, A.AllowPurchase
, A.AllowInventory
, A.ItemsId
FROM itemsummary A
INNER JOIN itemcategory B
ON A.ItemCatId = B.ItemCatId
LEFT OUTER JOIN itemsubcategory D
ON A.ItemSubCatId = D.ItemSubCatId
WHERE A.IsVariant = 0
order by A.ItemsId;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportStockTemplateVarient`;
DELIMITER |
CREATE PROCEDURE `ReportStockTemplateVarient`()
BEGIN
SELECT B.ItemCatName AS ItemCategory
, IFNULL(D.ItemSubCatName, B.ItemCatName) AS ItemSubCategory
, A.ItemCode
, A.ItemName
, A.SItemName
, A.Discount AS RetailDiscountAmount
, A.RetailDiscPer AS RetailDiscountPer
, A.WholeSaleDiscount AS WholesaleDiscountAmount
, A.WholesaleDiscPer AS WholesaleDiscountPer
, A.ItemUnit
, A.CostPrice
, A.SellingPrice
, A.SPSellingPrice
, A.ShopPrice
, A.MinSellingPrice
, A.MinQty AS ReOrderLevel
, A.AvailableQty
, A.WarrantyPeriod
, A.RackNo
, A.MaintainQty
, A.TItemName
, A.MItemCode AS MainProductCode
, A.ConvertionQty
, A.ScaleItem
, A.BundleItem
, A.RawMaterial
, A.AllowSales
, A.AllowPurchase
, A.AllowInventory
, A.ItemsId
FROM itemsummary A
INNER JOIN itemcategory B
ON A.ItemCatId = B.ItemCatId
LEFT OUTER JOIN itemsubcategory D
ON A.ItemSubCatId = D.ItemSubCatId
WHERE A.IsVariant = 1
order by A.ItemsId;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportSupplierCreditPay`;
DELIMITER |
CREATE PROCEDURE `ReportSupplierCreditPay`(in SupplierId1 int, PayModeId1 int, CreditPayHDId1 INT)
BEGIN
SELECT B.PIHDId AS RefNo
, IFNULL(E.PIDate, B.CreditDate) AS CreditDate
, B.CreditAmount
, A.PaymentDate
, A.PaymentAmount
, (SELECT Z.CreditAmount - Z.PaymentAmount AS BalanceAmount
FROM suppliercredit Z
WHERE (Z.SupplierId = A.SupplierId)
AND (Z.PIHDId = A.BillNo)) AS BalanceAmount
, C.SupplierName
, C.ContactPerson
, C.Address
, C.MobileNo
, D.PayMode
, A.CardChequeNo
, F.CompanyName
, F.CompanyAddress1
, F.CompanyAddress2
, F.ContactNo1
, F.ContactNo2
, F.Web
, F.Email
, A.SupplierId
, G.ChequeAmount
, G.ChequeBank
FROM suppcreditpayment A
INNER JOIN suppliercredit B
ON A.SupplierId = B.SupplierId
AND A.BillNo = B.PIHDId
INNER JOIN supplier C
ON A.SupplierId = C.SupplierId
INNER JOIN paymentmode D
ON A.PayModeId = D.PayModeId
LEFT OUTER JOIN pihd E
ON B.PIHDId = E.PIHDId
LEFT OUTER JOIN suppliercheque G
ON A.SupplierId = C.SupplierId
AND A.CardChequeNo = G.ChequeNo
INNER JOIN suppcreditpaymenthd H
ON A.CreditPayHDId = H.CreditPayHDId
, companyinfo F
WHERE (H.CreditPayHDId = CreditPayHDId1);
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportSupplierCreditPayNew`;
DELIMITER |
CREATE PROCEDURE `ReportSupplierCreditPayNew`(in SupplierId1 int, PayModeId1 int, CreditPayHDId1 INT)
BEGIN
SELECT B.PIHDId AS RefNo
, IFNULL(E.PIDate, B.CreditDate) AS CreditDate
, B.CreditAmount
, A.PaymentDate
, A.PaymentAmount
, (SELECT Z.CreditAmount - Z.PaymentAmount AS BalanceAmount
FROM suppliercredit Z
WHERE (Z.SupplierId = A.SupplierId)
AND (Z.PIHDId = A.BillNo)
and (Z.SuppCreditId = A.SuppCreditId)) AS BalanceAmount
, C.SupplierName
, C.ContactPerson
, C.Address
, C.MobileNo
, D.PayMode
, A.CardChequeNo
, F.CompanyName
, F.CompanyAddress1
, F.CompanyAddress2
, F.ContactNo1
, F.ContactNo2
, F.Web
, F.Email
, A.SupplierId
, G.ChequeAmount
, G.ChequeBank
, H.CreditPayHDId
, H.PaymentDate AS CreditPaymentDate
, H.CreatedOn
, G.ChequeNo
FROM suppcreditpayment A
INNER JOIN suppliercredit B
ON A.SupplierId = B.SupplierId
AND A.BillNo = B.PIHDId
AND A.SuppCreditId = B.SuppCreditId
INNER JOIN supplier C
ON A.SupplierId = C.SupplierId
INNER JOIN paymentmode D
ON A.PayModeId = D.PayModeId
LEFT OUTER JOIN pihd E
ON B.PIHDId = E.PIHDId
LEFT OUTER JOIN (SELECT G.SupplierId, G.ChequeNo , G.ChequeAmount, G.ChequeBank
FROM suppliercheque G
where G.ChequeNo <> ''
GROUP BY G.SupplierId, G.ChequeNo , G.ChequeAmount, G.ChequeBank)G
ON A.SupplierId = G.SupplierId
AND A.CardChequeNo = G.ChequeNo
INNER JOIN suppcreditpaymenthd H
ON A.CreditPayHDId = H.CreditPayHDId
INNER JOIN companyinfo F
ON H.CompanyInfoId = F.CompanyInfoId
WHERE (H.CreditPayHDId = CreditPayHDId1);
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportTakeawayKOT`;
DELIMITER |
CREATE PROCEDURE `ReportTakeawayKOT`(in SOHDId1 int)
BEGIN
SELECT        salesorderdt.SOHDId, salesorderdt.ItemCode, menuitem.ItemName, salesorderdt.SalesQty
FROM            salesorderdt INNER JOIN
menuitem ON salesorderdt.ItemsId = menuitem.ItemsId
WHERE        (salesorderdt.SOHDId = SOHDId1);
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportTAWInvoice`;
DELIMITER |
CREATE PROCEDURE `ReportTAWInvoice`(in BillNo1 int)
BEGIN
DECLARE CurBillCredit DECIMAL(20,2) DEFAULT 0;
DECLARE CustomerId1 int DEFAULT 0;
SELECT IFNULL(CustomerId, 0) INTO CustomerId1
FROM salesorderhd
WHERE (SOHDId = BillNo1);
SELECT IFNULL(CreditAmount, 0) INTO CurBillCredit
FROM customercredit
WHERE (CustomerId = CustomerId1)
AND (BillNo = BillNo1);
SELECT X.BillNo
, X.SODate
, X.ItemCode
, X.ItemName
, X.SalesQty
, X.SalesPrice
, X.GrossAmount
, X.Discount
, X.NetAmount
, X.SOGrossTotal
, X.AdditionalChgs
, X.SODiscount
, X.SONetTotal
, X.PayMode
, X.Cash
, X.CustomerName
, X.CustomerAddress
, X.CustomerTelNo
, X.CompanyName
, X.CompanyAddress1
, X.CompanyAddress2
, X.ContactNo1
, X.ContactNo2
, X.CompanyLogo
, X.SItemName
, X.FooterMsg
, X.FreeIssue
, X.FooterMsg2
, X.UserName
, X.SODTId
, X.Warranty
, X.VATNo
, X.CompRegNo
, X.Web
, X.Email
, X.BranchName
, X.ReturnTotal
, X.CreditPay
, X.CreditTotal
, X.ReferanceNo
, X.RetailPrice
, X.EmployeeName
, X.TerminalNo
, X.VoucherNo
, X.VoucherAmount
, X.ReceivableAmount
, X.SerialNo
, X.TItemName
, X.Charges
, X.Remarks
, X.CreditDueDays
, X.CompletedDate
, X.SystemBy
, X.ReturnNoteAmount
, X.ReturnNoteNo
, X.CashBalance
, X.DiscPer
, X.RackNo
, X.LoyaltyPoints
, X.LoyaltyBalance
, X.TotalPoints
, X.CurrencyCode
, X.ShowCreditBalance
, X.ItemUnit
, X.VAT
, X.NBT
, X.TotDiscPer
, X.VATPer
, X.NBTPer
, X.ChargesPer
, X.AdvanceAmount
, X.DailyId
, X.OurPrice
, X.CustomerVATNo
, CONCAT(DATE_FORMAT(X.SODate, '%y%b'), '_INV_', X.BillNo) AS InvoiceNo
, ifnull(CurBillCredit, 0) as CurrentBillCredit
FROM
(SELECT A.SOHDId AS BillNo
, A.CreatedOn AS SODate
, B.ItemCode
, B.ItemName
, B.SalesQty
, B.SalesPrice
, B.SalesQty * B.SalesPrice AS GrossAmount
, B.Discount
, B.NetAmount
, A.SOGrossTotal
, A.AdditionalChgs
, A.SODiscount
, A.SONetTotal
, CASE WHEN A.PayModeId = 3 AND A.CreditDueDays > 0 THEN CONCAT(F.PayMode, ' [', A.CreditDueDays, ' Days]') ELSE F.PayMode END AS PayMode
, A.Cash
, CASE WHEN A.CustomerName = '' THEN E.CustomerName ELSE A.CustomerName END AS CustomerName
, E.CustomerAddress
, E.CustomerTelNo
, G.CompanyName
, H.BranchAddress AS CompanyAddress1
, H.BranchAddress2 AS CompanyAddress2
, H.BranchTelNo AS ContactNo1
, H.BranchTelNo2 AS ContactNo2
, G.CompanyLogo
, C.SItemName
, G.FooterMsg
, B.FreeIssue
, G.FooterMsg2
, D.UserName
, B.SODTId
, C.WarrantyPeriod AS Warranty
, G.VATNo
, G.CompRegNo
, G.Web
, G.Email
, H.BranchName
, A.ReturnTotal
, A.CreditPay
, A.CreditTotal
, A.ReferanceNo
, B.RetailPrice
, I.EmployeeName
, A.TerminalNo
, A.VoucherNo
, A.VoucherAmount
, A.ReceivableAmount
, CONCAT(' ', B.SerialNo, '') AS SerialNo
, C.TItemName
, A.Charges
, A.Remarks
, A.CreditDueDays
, A.CompletedDate
, G.SystemBy
, A.ReturnNoteAmount
, A.ReturnNoteNo
, A.CashBalance
, B.DiscPer
, C.RackNo
, A.LoyaltyPoints
, A.LoyaltyBalance
, H.CurrencyCode
, (A.LoyaltyPoints + A.LoyaltyBalance) AS TotalPoints
, G.ShowCreditBalance
, C.ItemUnit
, A.VAT
, A.NBT
, A.TotDiscPer
, A.VATPer
, A.NBTPer
, A.ChargesPer
, A.AdvanceAmount
, A.DailyId
, B.OurPrice
, E.CustomerFaxNo AS CustomerVATNo
FROM salesorderhd A
INNER JOIN salesorderdt B
ON A.SOHDId = B.SOHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
INNER JOIN useraccount D
ON A.CreatedBy = D.UserID
INNER JOIN branch H
ON A.BranchId = H.BranchId
LEFT OUTER JOIN customer E
ON A.CustomerId = E.CustomerId
INNER JOIN paymentmode F
ON A.PayModeId = F.PayModeId
LEFT OUTER JOIN employeeregistration I
ON A.RepId = I.EmployeeID
INNER JOIN companyinfo G
ON A.CompanyInfoId = G.CompanyInfoId
WHERE A.SOHDId = BillNo1
UNION ALL
SELECT A.SOHDId AS BillNo
, A.CreatedOn AS SODate
, B.ItemCode
, B.ItemName
, B.FreeIssue as SalesQty
, 0 AS SalesPrice
, 0 AS GrossAmount
, 0 AS Discount
, 0 AS NetAmount
, A.SOGrossTotal
, A.AdditionalChgs
, A.SODiscount
, A.SONetTotal
, CASE WHEN A.PayModeId = 3 AND A.CreditDueDays > 0 THEN CONCAT(F.PayMode, ' [', A.CreditDueDays, ' Days]') ELSE F.PayMode END AS PayMode
, A.Cash
, CASE WHEN A.CustomerName = '' THEN E.CustomerName ELSE A.CustomerName END AS CustomerName
, E.CustomerAddress
, E.CustomerTelNo
, G.CompanyName
, H.BranchAddress AS CompanyAddress1
, H.BranchAddress2 AS CompanyAddress2
, H.BranchTelNo AS ContactNo1
, H.BranchTelNo2 AS ContactNo2
, G.CompanyLogo
, C.SItemName
, G.FooterMsg
, B.FreeIssue
, G.FooterMsg2
, D.UserName
, B.SODTId
, C.WarrantyPeriod AS Warranty
, G.VATNo
, G.CompRegNo
, G.Web
, G.Email
, H.BranchName
, A.ReturnTotal
, A.CreditPay
, A.CreditTotal
, A.ReferanceNo
, 0 AS RetailPrice
, I.EmployeeName
, A.TerminalNo
, A.VoucherNo
, A.VoucherAmount
, A.ReceivableAmount
, CONCAT(' ', B.SerialNo, '') AS SerialNo
, C.TItemName
, A.Charges
, A.Remarks
, A.CreditDueDays
, A.CompletedDate
, G.SystemBy
, A.ReturnNoteAmount
, A.ReturnNoteNo
, A.CashBalance
, 0 AS DiscPer
, C.RackNo
, A.LoyaltyPoints
, A.LoyaltyBalance
, H.CurrencyCode
, (A.LoyaltyPoints + A.LoyaltyBalance) AS TotalPoints
, G.ShowCreditBalance
, C.ItemUnit
, A.VAT
, A.NBT
, A.TotDiscPer
, A.VATPer
, A.NBTPer
, A.ChargesPer
, A.AdvanceAmount
, A.DailyId
, B.OurPrice
, E.CustomerFaxNo AS CustomerVATNo
FROM salesorderhd A
INNER JOIN salesorderdt B
ON A.SOHDId = B.SOHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
INNER JOIN useraccount D
ON A.CreatedBy = D.UserID
INNER JOIN branch H
ON A.BranchId = H.BranchId
LEFT OUTER JOIN customer E
ON A.CustomerId = E.CustomerId
INNER JOIN paymentmode F
ON A.PayModeId = F.PayModeId
LEFT OUTER JOIN employeeregistration I
ON A.RepId = I.EmployeeID
INNER JOIN companyinfo G
ON A.CompanyInfoId = G.CompanyInfoId
WHERE A.SOHDId = BillNo1
and B.FreeIssue > 0
UNION ALL
SELECT A.SOHDId AS BillNo
, A.CreatedOn AS SODate
, B.ItemCode
, CONCAT(B.ItemName, '[Return]', CASE WHEN B.Damage = 1 THEN '[Dmg]' ELSE '' END) AS ItemName
, B.SalesQty * -1 AS 'SalesQty'
, B.SalesPrice
, (B.SalesQty * -1) * B.SalesPrice AS GrossAmount
, B.Discount * -1 AS 'Discount'
, B.NetAmount * -1 AS 'NetAmount'
, A.SOGrossTotal
, A.AdditionalChgs
, A.SODiscount
, A.SONetTotal
, CASE WHEN A.PayModeId = 3 AND A.CreditDueDays > 0 THEN CONCAT(F.PayMode, ' [', A.CreditDueDays, ' Days]') ELSE F.PayMode END AS PayMode
, A.Cash
, CASE WHEN A.CustomerName = '' THEN E.CustomerName ELSE A.CustomerName END AS CustomerName
, E.CustomerAddress
, E.CustomerTelNo
, G.CompanyName
, H.BranchAddress AS CompanyAddress1
, H.BranchAddress2 AS CompanyAddress2
, H.BranchTelNo AS ContactNo1
, H.BranchTelNo2 AS ContactNo2
, G.CompanyLogo
, CONCAT(C.SItemName, ' rsgka') AS SItemName
, G.FooterMsg
, B.FreeIssue
, G.FooterMsg2
, D.UserName
, B.ReturnId AS SODTId
, C.WarrantyPeriod AS Warranty
, G.VATNo
, G.CompRegNo
, G.Web
, G.Email
, H.BranchName
, A.ReturnTotal
, A.CreditPay
, A.CreditTotal
, A.ReferanceNo
, 0 AS RetailPrice
, I.EmployeeName
, A.TerminalNo
, A.VoucherNo
, A.VoucherAmount
, A.ReceivableAmount
, CONCAT(' ', B.SerialNo, '') AS SerialNo
, C.TItemName
, A.Charges
, A.Remarks
, A.CreditDueDays
, A.CompletedDate
, G.SystemBy
, A.ReturnNoteAmount
, A.ReturnNoteNo
, A.CashBalance
, B.DiscPer
, C.RackNo
, A.LoyaltyPoints
, A.LoyaltyBalance
, H.CurrencyCode
, (A.LoyaltyPoints + A.LoyaltyBalance) AS TotalPoints
, G.ShowCreditBalance
, C.ItemUnit
, A.VAT
, A.NBT
, A.TotDiscPer
, A.VATPer
, A.NBTPer
, A.ChargesPer
, A.AdvanceAmount
, A.DailyId
, B.OurPrice
, E.CustomerFaxNo AS CustomerVATNo
FROM salesorderhd A
INNER JOIN directsalesreturn B
ON A.SOHDId = B.SOHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
INNER JOIN useraccount D
ON A.CreatedBy = D.UserID
INNER JOIN branch H
ON A.BranchId = H.BranchId
LEFT OUTER JOIN customer E
ON A.CustomerId = E.CustomerId
INNER JOIN paymentmode F
ON A.PayModeId = F.PayModeId
LEFT OUTER JOIN employeeregistration I
ON A.RepId = I.EmployeeID
INNER JOIN companyinfo G
ON A.CompanyInfoId = G.CompanyInfoId
WHERE A.SOHDId = BillNo1
)X
ORDER BY X.SODTId;
END |
DELIMITER ;

