DROP PROCEDURE IF EXISTS `ReportTAWKOT`;
DELIMITER |
CREATE PROCEDURE `ReportTAWKOT`(in BillNo1 int)
BEGIN
SELECT A.KOTId AS BillNo
,CASE
WHEN  A.RoomId > 0 THEN CONCAT('Room No ', A.RoomId)
WHEN A.TableId > 0 THEN CONCAT('Table No ', A.TableId)
ELSE CONCAT('Bill No ', A.SOHDId)
END AS CustomerName
, A.ItemCode
, A.ItemName
, A.Qty AS SalesQty
, A.OrderedDate AS SODate
, A.OrderedTime AS PayMode
, A.FinishedStatus
, A.SOHDId AS SODTId
, J.InvoiceStatus AS InvoiceMode
FROM kot A
INNER JOIN itemsummary C
ON A.ItemsId = C.ItemsId
INNER JOIN invoicestatus J
ON A.InvoiceStatusId = J.InvoiceStatusId
WHERE A.SOHDId = BillNo1
AND A.PrintStatus = 0;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportTAWPrint`;
DELIMITER |
CREATE PROCEDURE `ReportTAWPrint`(in BillNo1 int)
BEGIN
DECLARE CurBillCredit DECIMAL(20,2) DEFAULT 0;
DECLARE CustomerId1 int DEFAULT 0;
SELECT IFNULL(CustomerId, 0) INTO CustomerId1
FROM salesorderhd
WHERE (SOHDId = BillNo1);
SELECT IFNULL(CreditAmount, 0) INTO CurBillCredit
FROM customercredit
WHERE (CustomerId = CustomerId1)
AND (BillNo = BillNo1);
SELECT X.BillNo
, X.SODate
, X.ItemCode
, X.ItemName
, X.SalesQty
, X.SalesPrice
, X.GrossAmount
, X.Discount
, X.NetAmount
, X.SOGrossTotal
, X.AdditionalChgs
