, X.SItemName
, X.FooterMsg
, X.FreeIssue
, X.FooterMsg2
, X.UserName
, X.SODTId
, X.Warranty
, X.VATNo
, X.CompRegNo
, X.Web
, X.Email
, X.BranchName
, X.ReturnTotal
, X.CreditPay
, X.CreditTotal
, X.ReferanceNo
, X.RetailPrice
, X.EmployeeName
, X.TerminalNo
, X.VoucherNo
, X.VoucherAmount
, X.ReceivableAmount
