, G.CompanyName
, H.BranchAddress AS CompanyAddress1
, H.BranchAddress2 AS CompanyAddress2
, H.BranchTelNo AS ContactNo1
, H.BranchTelNo2 AS ContactNo2
, G.CompanyLogo
, C.SItemName
, G.FooterMsg
, B.FreeIssue
, G.FooterMsg2
, D.UserName
, B.SODTId
, CONCAT('[',C.WarrantyPeriod, CASE WHEN C.WarrantyPeriod <> '1' THEN ' Years Warrenty]' ELSE ' Year Warrenty]' END) AS Warranty
, G.VATNo
, G.CompRegNo
, G.Web
, G.Email
, H.BranchName
, A.ReturnTotal
, A.CreditPay
, A.CreditTotal
, A.ReferanceNo
, B.RetailPrice
, I.EmployeeName
, A.TerminalNo
, A.VoucherNo
, A.VoucherAmount
, A.ReceivableAmount
, CONCAT(' ', B.SerialNo, '') AS SerialNo
, C.TItemName
, A.Charges
, A.Remarks
, A.CreditDueDays
, A.CompletedDate
, G.SystemBy
, A.ReturnNoteAmount
, A.ReturnNoteNo
, A.CashBalance
, 0 AS DiscPer
, C.RackNo
, A.LoyaltyPoints
, A.LoyaltyBalance
, (A.LoyaltyPoints + A.LoyaltyBalance) AS TotalPoints
, J.InvoiceStatus AS InvoiceMode
, A.RoomId
, A.TableId
, A.BookingModeId
, K.ListValue AS BookingMode
, A.FromDate
, A.ToDate
, A.BookingCharges
, A.InvoiceStatusId
, A.AdvanceAmount
FROM salesorderhd A
INNER JOIN holdsalesorderdt B
ON A.SOHDId = B.SOHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
INNER JOIN useraccount D
ON A.CreatedBy = D.UserID
INNER JOIN branch H
ON A.BranchId = H.BranchId
LEFT OUTER JOIN customer E
ON A.CustomerId = E.CustomerId
INNER JOIN paymentmode F
ON A.PayModeId = F.PayModeId
LEFT OUTER JOIN employeeregistration I
ON A.RepId = I.EmployeeID
INNER JOIN companyinfo G
ON A.CompanyInfoId = G.CompanyInfoId
INNER JOIN invoicestatus J
ON A.InvoiceStatusId = J.InvoiceStatusId
LEFT OUTER JOIN listvalue K
ON A.BookingModeId = K.ListValueId
WHERE A.SOHDId = BillNo1
)X
ORDER BY X.SODTId;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportTAWQuotation`;
DELIMITER |
CREATE PROCEDURE `ReportTAWQuotation`(in BillNo1 int)
BEGIN
DECLARE CurBillCredit DECIMAL(20,2) DEFAULT 0;
DECLARE CustomerId1 int DEFAULT 0;
SELECT IFNULL(CustomerId, 0) INTO CustomerId1
FROM salesquotationhd
WHERE (SOHDId = BillNo1);
SELECT X.BillNo
, X.SODate
, X.ItemCode
, X.ItemName
, X.SalesQty
, X.SalesPrice
, X.GrossAmount
, X.Discount
, X.NetAmount
, X.SOGrossTotal
, X.AdditionalChgs
, X.SODiscount
, X.SONetTotal
, X.PayMode
