, X.CustomerAddress
, X.CustomerTelNo
, X.CompanyName
, X.CompanyAddress1
, X.CompanyAddress2
, X.ContactNo1
, X.ContactNo2
, X.CompanyLogo
, X.SItemName
, X.FooterMsg
, X.FreeIssue
, X.FooterMsg2
, X.UserName
, X.SODTId
, X.Warranty
, X.VATNo
, X.CompRegNo
, X.Web
, X.Email
, X.BranchName
, X.ReturnTotal
, X.CreditPay
, X.CreditTotal
, X.ReferanceNo
, X.RetailPrice
, X.EmployeeName
, X.TerminalNo
, X.VoucherNo
, X.VoucherAmount
, X.ReceivableAmount
, X.SystemBy
, X.CurrencyCode
, X.SerialNo
, X.TItemName
, X.Charges
, X.Remarks
, X.CreditDueDays
, X.CompletedDate
, X.ReturnNoteAmount
, X.ReturnNoteNo
, X.CashBalance
, X.DiscPer
, X.RackNo
, X.LoyaltyPoints
, X.LoyaltyBalance
, X.TotalPoints
, X.ShowCreditBalance
, X.ItemUnit
, X.VAT
, X.NBT
, X.TotDiscPer
, X.VATPer
, X.NBTPer
, X.ChargesPer
, X.AdvanceAmount
, X.DailyId
, ifnull(CurBillCredit, 0) as CurrentBillCredit
FROM
(SELECT A.SOHDId AS BillNo
, A.CreatedOn AS SODate
, B.ItemCode
, B.ItemName
, B.SalesQty
, B.SalesPrice
, B.SalesQty * B.SalesPrice AS GrossAmount
, B.Discount, B.NetAmount
, A.SOGrossTotal
, A.AdditionalChgs
, A.SODiscount
, A.SONetTotal
, F.PayMode
, A.Cash
, E.CustomerName
, E.CustomerAddress
, E.CustomerTelNo
, G.CompanyName
, H.BranchAddress AS CompanyAddress1
, H.BranchAddress2 AS CompanyAddress2
, H.BranchTelNo AS ContactNo1
, H.BranchTelNo2 AS ContactNo2
, G.CompanyLogo
, C.SItemName
, G.QuotationFooter as FooterMsg
, B.FreeIssue
, G.FooterMsg2
, D.UserName
, B.SODTId
, B.Warranty
, G.VATNo
, G.CompRegNo
, G.Web
, G.Email
, H.BranchName
, A.ReturnTotal
, A.CreditPay
, A.CreditTotal
, A.ReferanceNo
, B.RetailPrice
, I.EmployeeName
, A.TerminalNo
, A.VoucherNo
, A.VoucherAmount
, A.ReceivableAmount
, G.SystemBy
, H.CurrencyCode
, '' AS SerialNo
, C.TItemName
, A.Charges
, A.Remarks
, A.CreditDueDays
, A.CompletedDate
, A.ReturnNoteAmount
, A.ReturnNoteNo
, A.CashBalance
, 0 as DiscPer
, C.RackNo
, A.LoyaltyPoints
, A.LoyaltyBalance
, 0 AS TotalPoints
, 0 as ShowCreditBalance
, C.ItemUnit
, A.VAT
, A.NBT
, A.TotDiscPer
, A.VATPer
, A.NBTPer
, A.ChargesPer
, A.AdvanceAmount
, A.DailyId
FROM salesquotationhd A
INNER JOIN salesquotationdt B
ON A.SOHDId = BillNo1
AND A.SOHDId = B.SOHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
INNER JOIN useraccount D
ON A.CreatedBy = D.UserID
INNER JOIN branch H
ON A.BranchId = H.BranchId
LEFT OUTER JOIN customer E
ON A.CustomerId = E.CustomerId
INNER JOIN paymentmode F
ON A.PayModeId = F.PayModeId
LEFT OUTER JOIN employeeregistration I
ON A.RepId = I.EmployeeID
INNER JOIN companyinfo G
ON A.CompanyInfoId = G.CompanyInfoId
)X
ORDER BY X.SODTId;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportTAWSO`;
DELIMITER |
CREATE PROCEDURE `ReportTAWSO`(in BillNo1 int)
BEGIN
DECLARE CurBillCredit DECIMAL(20,2) DEFAULT 0;
DECLARE CustomerId1 int DEFAULT 0;
SELECT IFNULL(CustomerId, 0) INTO CustomerId1
FROM sohd
WHERE (SOHDId = BillNo1);
SELECT IFNULL(CreditAmount, 0) INTO CurBillCredit
FROM customercredit
WHERE (CustomerId = CustomerId1)
AND (BillNo = BillNo1);
SELECT X.BillNo
, X.SODate
, X.ItemCode
, X.ItemName
, X.SalesQty
, X.SalesPrice
, X.GrossAmount
, X.Discount
, X.NetAmount
, X.SOGrossTotal
, X.AdditionalChgs
, X.SODiscount
, X.SONetTotal
, X.PayMode
, X.Cash
, X.CustomerName
, X.CustomerAddress
, X.CustomerTelNo
, X.CompanyName
, X.CompanyAddress1
, X.CompanyAddress2
, X.ContactNo1
, X.ContactNo2
, X.CompanyLogo
, X.SItemName
, X.FooterMsg
, X.FreeIssue
, X.FooterMsg2
, X.UserName
, X.SODTId
, X.Warranty
, X.VATNo
, X.CompRegNo
, X.Web
, X.Email
, X.BranchName
, X.CompletedDate
, X.Remarks
, X.SystemBy
, 0 as ReturnTotal
, 0 as CreditPay
, 0 as CreditTotal
, 0 as CurrentBillCredit
, X.CurrencyCode
, X.AdvanceAmount
FROM
(SELECT A.SOHDId AS BillNo
, A.SODate
, B.ItemCode
, B.ItemName
, B.SalesQty
, B.SalesPrice
, B.SalesQty * B.SalesPrice AS GrossAmount
, B.Discount, B.NetAmount
, A.SOGrossTotal
, A.AdditionalChgs
, A.SODiscount
, A.SONetTotal
, '' AS PayMode
, A.Cash
, E.CustomerName
, E.CustomerAddress
, E.CustomerTelNo
, G.CompanyName
, H.BranchAddress AS CompanyAddress1
, H.BranchAddress2 AS CompanyAddress2
, H.BranchTelNo AS ContactNo1
, H.BranchTelNo2 AS ContactNo2
, G.CompanyLogo
, C.SItemName
, G.FooterMsg
, B.FreeIssue
, G.FooterMsg2
, D.UserName
, B.SODTId
, B.Warranty
, G.VATNo
, G.CompRegNo
, G.Web
, G.Email
, H.BranchName
, A.CompletedDate
, A.Remarks
, G.SystemBy
, H.CurrencyCode
, A.AdvanceAmount
FROM sohd A
INNER JOIN sodt B
ON A.SOHDId = B.SOHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
INNER JOIN useraccount D
ON A.CreatedBy = D.UserID
INNER JOIN branch H
ON A.BranchId = H.BranchId
LEFT OUTER JOIN customer E
ON A.CustomerId = E.CustomerId
INNER JOIN companyinfo G
ON A.CompanyInfoId = G.CompanyInfoId
WHERE (A.SOHDId = BillNo1))X
ORDER BY X.SODTId;
END |
DELIMITER ;

