DROP PROCEDURE IF EXISTS `ReportTrialBalance`;
DELIMITER |
CREATE PROCEDURE `ReportTrialBalance`(in date1 date, date2 date)
BEGIN
SELECT X.AccountCode
,X.AccountName
,SUM(X.Debit) AS Debit
,SUM(X.Credit) AS Credit
FROM(
SELECT 'IOB-001' AS 'AccountCode'
,'Inventory OB' AS 'AccountName'
, IFNULL(SUM(OpenBalQty), 0) AS Debit
, 0 AS Credit
FROM itemsummary
WHERE PurchasedDate BETWEEN date1 AND date2
UNION ALL
SELECT 'RevAcc-002' AS 'AccountCode'
,'Revenue Account' AS 'AccountName'
, 0 AS Debit
, IFNULL(SUM(OpenBalQty), 0) AS Credit
FROM itemsummary
WHERE PurchasedDate BETWEEN date1 AND date2
UNION ALL
SELECT 'COB-003' AS 'AccountCode'
,'Customer OB' AS 'AccountName'
, IFNULL(SUM(CreditAmount), 0) AS Debit
, 0 AS Credit
FROM customercredit
WHERE BillNo = 0
AND CreditDate BETWEEN date1 AND date2
UNION ALL
SELECT 'RevAcc-002' AS 'AccountCode'
,'Revenue Account' AS 'AccountName'
, 0 AS Debit
, IFNULL(SUM(CreditAmount), 0)  AS Credit
FROM customercredit A
WHERE BillNo = 0
AND CreditDate BETWEEN date1 AND date2
UNION ALL
SELECT 'VOB-004' AS 'AccountCode'
,'Vendor OB' AS 'AccountName'
, 0 AS Debit
, IFNULL(SUM(CreditAmount), 0) AS Credit
FROM suppliercredit
WHERE PIHDId = 0
AND CreditDate BETWEEN date1 AND date2
UNION ALL
SELECT 'RevAcc-002' AS 'AccountCode'
,'Revenue Account' AS 'AccountName'
, 0 AS Debit
, IFNULL(SUM(CreditAmount), 0) * -1 AS Credit
FROM suppliercredit A
WHERE PIHDId = 0
AND CreditDate BETWEEN date1 AND date2
UNION ALL
SELECT 'C-005' AS 'AccountCode'
,'Cash Account' AS 'AccountName'
, IFNULL(SUM(SONetTotal), 0) AS Debit
, 0 AS Credit
FROM salesorderhd
WHERE CancelStatus = 0
AND PayModeId = 1
AND SODate BETWEEN date1 AND date2
UNION ALL
SELECT 'AR-006' AS 'AccountCode'
,'Accounts Receivable' AS 'AccountName'
, IFNULL(SUM(SONetTotal), 0) AS Debit
, 0 AS Credit
FROM salesorderhd
WHERE CancelStatus = 0
AND PayModeId = 3
AND SODate BETWEEN date1 AND date2
UNION ALL
SELECT 'BA-007' AS 'AccountCode'
,'Bank Account' AS 'AccountName'
, IFNULL(SUM(SONetTotal), 0) AS Debit
, 0 AS Credit
FROM salesorderhd
WHERE CancelStatus = 0
AND PayModeId IN( 2, 4)
AND SODate BETWEEN date1 AND date2
UNION ALL
SELECT 'RevAcc-002' AS 'AccountCode'
,'Revenue Account' AS 'AccountName'
, 0 AS Debit
, IFNULL(SUM(SONetTotal), 0) AS Credit
FROM salesorderhd
WHERE CancelStatus = 0
AND SODate BETWEEN date1 AND date2
UNION ALL
SELECT 'C-005' AS 'AccountCode'
,'Cash Account' AS 'AccountName'
, IFNULL(SUM(ReturnTotal), 0) * -1 AS Debit
, 0 AS Credit
FROM salesorderhd
WHERE CancelStatus = 0
AND PayModeId = 1
AND SODate BETWEEN date1 AND date2
UNION ALL
SELECT 'AR-006' AS 'AccountCode'
,'Accounts Receivable' AS 'AccountName'
, IFNULL(SUM(ReturnTotal), 0) * -1 AS Debit
, 0 AS Credit
FROM salesorderhd
WHERE CancelStatus = 0
AND PayModeId = 3
AND SODate BETWEEN date1 AND date2
UNION ALL
SELECT 'BA-007' AS 'AccountCode'
,'Bank Account' AS 'AccountName'
, IFNULL(SUM(ReturnTotal), 0) * -1 AS Debit
, 0 AS Credit
FROM salesorderhd
WHERE CancelStatus = 0
AND PayModeId IN( 2, 4)
AND SODate BETWEEN date1 AND date2
UNION ALL
SELECT 'RevAcc-002' AS 'AccountCode'
,'Revenue Account' AS 'AccountName'
, 0 AS Debit
, IFNULL(SUM(ReturnTotal), 0) *-1 AS Credit
FROM salesorderhd
WHERE CancelStatus = 0
AND SODate BETWEEN date1 AND date2
UNION ALL
SELECT 'C-005' AS 'AccountCode'
,'Cash Account' AS 'AccountName'
, IFNULL(SUM(PINetTotal), 0) * -1 AS Debit
, 0 AS Credit
FROM pihd
WHERE CancelStatus = 0
AND PayModeId = 1
AND PIDate BETWEEN date1 AND date2
UNION ALL
SELECT 'AP-008' AS 'AccountCode'
,'Accounts Payable' AS 'AccountName'
, 0 AS Debit
, IFNULL(SUM(PINetTotal), 0) AS Credit
FROM pihd
WHERE CancelStatus = 0
AND PayModeId = 3
AND PIDate BETWEEN date1 AND date2
UNION ALL
SELECT 'BA-007' AS 'AccountCode'
,'Bank Account' AS 'AccountName'
, IFNULL(SUM(PINetTotal), 0) * -1 AS Debit
, 0 AS Credit
FROM pihd
WHERE CancelStatus = 0
AND PayModeId IN( 2, 4)
AND PIDate BETWEEN date1 AND date2
UNION ALL
SELECT 'RevAcc-002' AS 'AccountCode'
,'Revenue Account' AS 'AccountName'
, 0 AS Debit
, IFNULL(SUM(PINetTotal), 0) * -1 AS Credit
FROM pihd
WHERE CancelStatus = 0
AND PIDate BETWEEN date1 AND date2
UNION ALL
SELECT 'C-005' AS 'AccountCode'
,'Cash Account' AS 'AccountName'
, IFNULL(SUM(ReturnTotal), 0) AS Debit
, 0 AS Credit
FROM pihd
WHERE CancelStatus = 0
AND PayModeId = 1
AND PIDate BETWEEN date1 AND date2
UNION ALL
SELECT 'AP-008' AS 'AccountCode'
,'Accounts Payable' AS 'AccountName'
, 0 AS Debit
, IFNULL(SUM(ReturnTotal), 0) *-1 AS Credit
FROM pihd
WHERE CancelStatus = 0
AND PayModeId = 3
AND PIDate BETWEEN date1 AND date2
UNION ALL
SELECT 'BA-007' AS 'AccountCode'
,'Bank Account' AS 'AccountName'
, IFNULL(SUM(ReturnTotal), 0) AS Debit
, 0 AS Credit
FROM pihd
WHERE CancelStatus = 0
AND PayModeId IN( 2, 4)
AND PIDate BETWEEN date1 AND date2
UNION ALL
SELECT 'RevAcc-002' AS 'AccountCode'
,'Revenue Account' AS 'AccountName'
, 0 AS Debit
, IFNULL(SUM(ReturnTotal), 0) AS Credit
FROM pihd
WHERE CancelStatus = 0
AND PIDate BETWEEN date1 AND date2
UNION ALL
SELECT 'C-005' AS 'AccountCode'
,'Cash Account' AS 'AccountName'
, IFNULL(SUM(PaymentAmount), 0) * -1 AS Debit
, 0 AS Credit
FROM allexpenses
WHERE PayModeId = 1
AND PaymentDate BETWEEN date1 AND date2
UNION ALL
SELECT 'BA-007' AS 'AccountCode'
,'Bank Account' AS 'AccountName'
, IFNULL(SUM(PaymentAmount), 0) * -1 AS Debit
, 0 AS Credit
FROM allexpenses
WHERE PayModeId IN( 2, 4)
AND PaymentDate BETWEEN date1 AND date2
UNION ALL
SELECT 'Exp-009' AS 'AccountCode'
,'Expenses' AS 'AccountName'
, IFNULL(SUM(PaymentAmount), 0) AS Debit
, 0 AS Credit
FROM allexpenses
WHERE PaymentDate BETWEEN date1 AND date2
UNION ALL
SELECT 'C-005' AS 'AccountCode'
,'Cash Account' AS 'AccountName'
, IFNULL(SUM(LoanAmount), 0) AS Debit
, 0 AS Credit
FROM loanhd
WHERE LoanDate BETWEEN date1 AND date2
UNION ALL
SELECT 'Lo-010' AS 'AccountCode'
,'Loan' AS 'AccountName'
, 0 AS Debit
, IFNULL(SUM(LoanAmount), 0) AS Credit
FROM loanhd
WHERE LoanDate BETWEEN date1 AND date2
UNION ALL
SELECT 'C-005' AS 'AccountCode'
,'Cash Account' AS 'AccountName'
, IFNULL(SUM(PaymentAmount), 0) * -1 AS Debit
, 0 AS Credit
FROM loandt
WHERE PaymentDate BETWEEN date1 AND date2
UNION ALL
SELECT 'Lo-010' AS 'AccountCode'
,'Loan' AS 'AccountName'
, 0 AS Debit
, IFNULL(SUM(PaymentAmount), 0) * -1 AS Credit
FROM loandt
WHERE PaymentDate BETWEEN date1 AND date2
)X
GROUP BY X.AccountCode
,X.AccountName;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportVehicleLogDetail`;
DELIMITER |
CREATE PROCEDURE `ReportVehicleLogDetail`(in
date1 date,
date2 date)
BEGIN
SELECT A.VehicleMilageHDId
, A.VehicleNo
, C.EmployeeName
, D.Designation
, A.FromDate
, A.ToDate
, A.TotalMilage
, A.TotalRate
, A.TotalFuelCost
, B.MilageDate
, E.Purpose
, B.StartingPlace
, B.Destination
, B.StartMile
, B.EndMile
, B.Milage
, B.RatePerMile
, B.Rate
, B.FuelCost
, A.FuelCostPerMile
, (A.TotalRate + A.TotalFuelCost) AS TotalCost
, B.RefInvNo
, B.FuelLeters
, A.Remarks
FROM vehiclemilagehd A
INNER JOIN vehiclemilagedt B
ON A.VehicleMilageHDId = B.VehicleMilageHDId
INNER JOIN employeeregistration C
ON A.EmployeeId = C.EmployeeID
INNER JOIN designations D
ON C.DSId = D.DSId
INNER JOIN vehiclepurpose E
ON B.PurposeId = E.PurposeId
WHERE B.MilageDate BETWEEN date1 AND date2
AND A.CancelStatus = 0;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportVehicleLogPrint`;
DELIMITER |
CREATE PROCEDURE `ReportVehicleLogPrint`(in VehicleMilageHDId1 int)
BEGIN
SELECT A.VehicleMilageHDId
, A.VehicleNo
, C.EmployeeName
, D.Designation
, A.FromDate
, A.ToDate
, A.TotalMilage
, A.TotalRate
, A.TotalFuelCost
, B.MilageDate
, E.Purpose
, B.StartingPlace
, B.Destination
, B.StartMile
, B.EndMile
, B.Milage
, B.RatePerMile
, B.Rate
, B.FuelCost
, A.FuelCostPerMile
, A.Remarks
, B.RefInvNo
, B.FuelLeters
FROM vehiclemilagehd A
INNER JOIN vehiclemilagedt B
ON A.VehicleMilageHDId = B.VehicleMilageHDId
INNER JOIN employeeregistration C
ON A.EmployeeId = C.EmployeeID
INNER JOIN designations D
ON C.DSId = D.DSId
INNER JOIN vehiclepurpose E
ON B.PurposeId = E.PurposeId
WHERE A.VehicleMilageHDId = VehicleMilageHDId1;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReportVehicleLogSummary`;
DELIMITER |
CREATE PROCEDURE `ReportVehicleLogSummary`(in
date1 date,
date2 date)
BEGIN
SELECT A.VehicleMilageHDId
, A.VehicleNo
, C.EmployeeName
, D.Designation
, A.FromDate
, A.ToDate
, A.TotalMilage
, A.RatePerMile
, A.TotalRate
, A.FuelCostPerMile
, A.TotalFuelCost
, (A.TotalRate + A.TotalFuelCost) AS TotalCost
, A.Remarks
FROM vehiclemilagehd A
INNER JOIN employeeregistration C
ON A.EmployeeId = C.EmployeeID
INNER JOIN designations D
ON C.DSId = D.DSId
WHERE A.FromDate >= date1
AND A.ToDate <= date2
AND A.CancelStatus = 0;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReprintExpenses`;
DELIMITER |
CREATE PROCEDURE `ReprintExpenses`(in ExpensesId1 int)
BEGIN
SELECT B.CatDescription as ExpenseCategory
, A.PaymentDate
, A.PaymentAmount
, CASE WHEN A.PayCatId IN (1,2) THEN I.EmployeeName ELSE A.Remarks END AS Remarks
, A.CreatedOn
, C.UserName
, E.PayMode
, D.BranchName
, D.BranchAddress AS CompanyAddress1
, D.BranchAddress2 AS CompanyAddress2
, D.BranchTelNo AS ContactNo1
, D.BranchTelNo2 AS ContactNo2
, G.CompanyName
, G.CompanyLogo
, G.CompRegNo
, G.Web
, G.Email
, A.ExpensesId
, H.VehicleNo
FROM allexpenses A
INNER JOIN expensescategory B
ON A.PayCatId = B.PayCatId
INNER JOIN useraccount C
ON A.CreatedBy = C.UserID
INNER JOIN branch D
ON A.BranchId = D.BranchId
INNER JOIN paymentmode E
ON A.PayModeId = E.PayModeId
INNER JOIN companyinfo G
ON A.CompanyInfoId = G.CompanyInfoId
LEFT OUTER JOIN vehicles H
ON A.VehicleId = H.VehicleId
LEFT OUTER JOIN employeeregistration I
ON A.RefId = I.EmployeeID
AND A.PayCatId IN (1,2)
WHERE A.ExpensesId = ExpensesId1;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ReprintStockAdjustment`;
DELIMITER |
CREATE PROCEDURE `ReprintStockAdjustment`()
BEGIN
SELECT A.StkAdjHDId AS AdjustmentNo
, A.AdjDate AS AdjustmentDate
, A.TotalVariance
, D.UserName AS AdjustedUser
FROM stkadjhd A
INNER JOIN useraccount D
ON A.CreatedBy = D.UserID
ORDER BY A.StkAdjHDId DESC;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ResetAllCustomerLoyaltyPoints`;
DELIMITER |
CREATE PROCEDURE `ResetAllCustomerLoyaltyPoints`()
BEGIN
UPDATE customer
SET TotalLoyaltyPoints = 0;
INSERT INTO usedloyaltypoints
(CustomerId
, UsedDate
, UsedPoints
, ResetStatus
, SOHDId
)
SELECT A.CustomerId
, CONVERT_TZ(now(), @@session.time_zone, '+05:30')
,((SELECT IFNULL(SUM(C.LoyaltyPoints),0) AS LoyaltyPoints
FROM salesorderhd C
WHERE C.CustomerId = A.CustomerId
AND C.CancelStatus = 0
) - (SELECT IFNULL(SUM(D.UsedPoints),0) AS UsedPoints
FROM usedloyaltypoints D
WHERE D.CustomerId = A.CustomerId
)
) AS LoyaltyPointsBalance
, 1
, 0
FROM customer A
;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `ResetCustomerLoyaltyPoints`;
DELIMITER |
CREATE PROCEDURE `ResetCustomerLoyaltyPoints`(in CustomerId1 int)
BEGIN
UPDATE customer
SET TotalLoyaltyPoints = 0
WHERE (CustomerId = CustomerId1);
INSERT INTO usedloyaltypoints
(CustomerId
, UsedDate
, UsedPoints
, ResetStatus
, SOHDId
)
VALUES (CustomerId1
, CONVERT_TZ(now(), @@session.time_zone, '+05:30')
, ((SELECT IFNULL(SUM(C.LoyaltyPoints),0) AS LoyaltyPoints
FROM salesorderhd C
WHERE C.CustomerId = CustomerId1
AND C.CancelStatus = 0
) - (SELECT IFNULL(SUM(D.UsedPoints),0) AS UsedPoints
FROM usedloyaltypoints D
WHERE D.CustomerId = CustomerId1
)
)
,1
,0
)
;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `SalesReportByDateCommon`;
DELIMITER |
CREATE PROCEDURE `SalesReportByDateCommon`(in
date1 date
, date2 date
, BranchId1 int
, PayModeId1 int
, ItemCode1 VARCHAR(50)
, CustomerId1 int
)
BEGIN
SELECT X.BillNo
, X.SODate
, X.ItemName
, X.SalesQty
, X.SellingPrice
, X.SalesAmount
, X.Discount
, X.NetAmount
, X.CompanyName
, X.CompanyAddress1
, X.CompanyAddress2
, X.ContactNo1
, X.ContactNo2
, X.ItemCode
, X.ItemCatId
, X.RepId
, X.CustomerId
, X.TotDisc
, X.ReturnAmount
, date1 as FromDate
, date2 as ToDate
, X.CustomerName
, X.BranchName
FROM(
SELECT A.SOHDId AS BillNo
, A.SODate
, C.ItemName
, B.SalesQty
, B.SalesPrice AS SellingPrice
, B.SalesQty * B.SalesPrice AS SalesAmount
, B.Discount
, B.NetAmount
, D.CompanyName
, D.CompanyAddress1
, D.CompanyAddress2
, D.ContactNo1
, D.ContactNo2
, C.ItemCode
, C.ItemCatId
, A.RepId
, A.CustomerId
, E.SODiscount AS TotDisc
, 0 AS ReturnAmount
, A.CustomerName
, F.BranchName
FROM salesorderhd A
INNER JOIN salesorderdt B
ON A.SOHDId = B.SOHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
INNER JOIN companyinfo D
ON A.CompanyInfoId = D.CompanyInfoId
INNER JOIN branch F
ON A.BranchId = F.BranchId
,(SELECT SUM(SODiscount) AS SODiscount
FROM salesorderhd
WHERE (CancelStatus = 0)
AND SODate BETWEEN date1 AND date2
AND CASE BranchId1 WHEN 0 THEN BranchId ELSE BranchId1 END = BranchId
AND CASE PayModeId1 WHEN 0 THEN PayModeId ELSE PayModeId1 END = PayModeId
AND CASE CustomerId1 WHEN 0 THEN CustomerId ELSE CustomerId1 END = CustomerId
) E
WHERE (A.CancelStatus = 0)
AND (A.SODate BETWEEN date1 AND date2)
AND CASE BranchId1 WHEN 0 THEN A.BranchId ELSE BranchId1 END = A.BranchId
AND CASE PayModeId1 WHEN 0 THEN A.PayModeId ELSE PayModeId1 END = A.PayModeId
AND CASE ItemCode1 WHEN '' THEN C.ItemCode ELSE ItemCode1 END = C.ItemCode
AND CASE CustomerId1 WHEN 0 THEN A.CustomerId ELSE CustomerId1 END = A.CustomerId
)X
ORDER BY X.SODate, X.ItemCode;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `SalesReportWithCustomerByDateCommon`;
DELIMITER |
