, X.ReferanceNo
, X.CustomerName
FROM(
SELECT A.SOHDId AS BillNo
, A.SODate
, C.ItemName
, B.SalesQty
, B.SalesPrice AS SellingPrice
, B.SalesQty * B.SalesPrice AS SalesAmount
, B.Discount
, B.NetAmount
, D.CompanyName
, D.CompanyAddress1
, D.CompanyAddress2
, D.ContactNo1
, D.ContactNo2
, C.ItemCode
, C.ItemCatId
, A.RepId
, A.CustomerId
, E.SODiscount AS TotDisc
, 0 AS ReturnAmount
, F.BranchName
, A.ReferanceNo
, J.CustomerName
