INNER JOIN branch F
ON A.BranchId = F.BranchId
LEFT OUTER JOIN customer J
ON A.CustomerId = J.CustomerId
,(SELECT SUM(SODiscount) AS SODiscount
FROM salesorderhd
WHERE (CancelStatus = 0)
