DROP PROCEDURE IF EXISTS `SaveSupplier`;
DELIMITER |
CREATE PROCEDURE `SaveSupplier`(in
SupplierName1 nvarchar(100),
ContactPerson1 nvarchar(50),
BusinessNo1 nvarchar(25),
MobileNo1 nvarchar(25),
Email1 nvarchar(100),
Address1 nvarchar(250),
Remarks1 nvarchar(100),
CreatedBy1 int,
BalanceAmount1 DECIMAL(20,2),
SupplierTypeId1 INT)
BEGIN
DECLARE SupplierId1 int DEFAULT 0;
INSERT INTO supplier
(SupplierName
, ContactPerson
, BusinessNo
, MobileNo
, Email
, Address
, Remarks
, CreatedOn
, CreatedBy
, SupplierTypeId)
VALUES (SupplierName1
,ContactPerson1
,BusinessNo1
,MobileNo1
,Email1
,Address1
,Remarks1
, CONVERT_TZ(now(), @@session.time_zone, '+05:30')
,CreatedBy1
, SupplierTypeId1);
SET SupplierId1 = LAST_INSERT_ID();
INSERT INTO suppliercredit
(SupplierId
, PIHDId
, CreditDate
, CreditAmount
, CreatedOn
, CreatedBy)
VALUES (SupplierId1
, 0
, CONVERT_TZ(now(), @@session.time_zone, '+05:30')
, BalanceAmount1
, CONVERT_TZ(now(), @@session.time_zone, '+05:30')
, CreatedBy1
);
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `SelectActivationDetails`;
DELIMITER |
CREATE PROCEDURE `SelectActivationDetails`()
BEGIN
SELECT  companyinfo.CompanyName, sysactivation.ActBillNo, sysactivation.ActStatus, sysactivation.DevKey
FROM companyinfo, sysactivation;
SELECT A.ActBillNo, A.ActDate, A.DevKey, B.SellerCode, A.ActStatus
FROM sysactivation A
INNER JOIN sellerdetail B
ON A.ActId = B.SellerDtId;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `SelectAdjStockByItmCat`;
DELIMITER |
CREATE PROCEDURE `SelectAdjStockByItmCat`(in ItemCatId1 int, BranchId1 int)
BEGIN
SELECT A.ItemCode
, B.ItemName
, IFNULL(A.AvailableQty, 0) AS AvailableQty
, IFNULL(A.AvailableQty, 0) AS PhisicalQty
, 0 AS VarrienceQty
, IFNULL(B.AvgCost, B.CostPrice) AS AvgCost
, 0 AS VarrienceValue
, A.ItemsId
, B.ItemCatId
FROM branchstock A
INNER JOIN itemsummary B
ON A.ItemsId = B.ItemsId
WHERE (B.ItemCatId = ItemCatId1)
AND (A.BranchId = BranchId1);
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `SelectAdjustStockByCode`;
DELIMITER |
CREATE PROCEDURE `SelectAdjustStockByCode`(in ItemCode1 varchar(50), BranchId1 int)
BEGIN
SELECT A.ItemCode
, B.ItemName
, IFNULL(A.AvailableQty, 0) AS AvailableQty
, IFNULL(A.AvailableQty, 0) AS PhisicalQty
, 0 AS VarrienceQty
, IFNULL(B.AvgCost, B.CostPrice) AS AvgCost
, 0 AS VarrienceValue
, A.ItemsId
, B.ItemCatId
FROM branchstock A
INNER JOIN itemsummary B
ON A.ItemsId = B.ItemsId
WHERE (A.ItemCode = ItemCode1)
AND (A.BranchId = BranchId1);
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `SelectAll`;
DELIMITER |
CREATE PROCEDURE `SelectAll`()
BEGIN
SELECT A.ItemCode
, A.ItemName
, B.ItemCatName AS ItemCategory
, D.ItemSubCatName AS ItemSubCategory
, A.Discount
, A.ItemUnit
, A.RackNo
, A.CostPrice
, A.SellingPrice
, A.MinQty
, A.AvailableQty
FROM itemsummary A
Left outer JOIN itemcategory B
ON A.ItemCatId = B.ItemCatId
LEFT OUTER JOIN itemsubcategory D
ON A.ItemSubCatId = D.ItemSubCatId
where A.ItemsId < 1000
ORDER BY A.ItemCode, A.ItemName;
SELECT PayCatId, CatDescription
FROM expensescategory;
SELECT menuitem.ItemsId, menuitem.ItemCode AS MenuCode, menuitem.ItemCatId, itemcategory.ItemCatName AS Category, menuitem.ItemName, menuitem.CostPrice, menuitem.SellingPrice
FROM menuitem
INNER JOIN itemcategory
ON menuitem.ItemCatId = itemcategory.ItemCatId
ORDER BY menuitem.ItemCatId, MenuCode;
SELECT        A.ItemCode, A.ItemName, B.SupplierName, A.Discount, A.ItemUnit, A.RackNo, A.CostPrice, A.SellingPrice, A.MinQty, SUM(C.PurhaseQty) AS Purchasing, A.AvailableQty
FROM            itemsummary A INNER JOIN
supplier B ON A.ItemCatId = B.SupplierId LEFT OUTER JOIN
purchasing C ON A.ItemCode = C.ItemCode
GROUP BY A.ItemCode
HAVING        (A.AvailableQty <= A.MinQty)
ORDER BY A.ItemCode, A.ItemName;
SELECT        A.ItemCode, A.ItemName, B.ItemCatName, A.Discount, A.ItemUnit, A.CostPrice, A.SellingPrice, A.MinQty, SUM(C.PurhaseQty) AS Purchasing, A.AvailableQty
FROM            itemsummary A INNER JOIN
itemcategory B ON A.ItemCatId = B.ItemCatId LEFT OUTER JOIN
purchasing C ON A.ItemCode = C.ItemCode
HAVING        (A.AvailableQty < A.MinQty)
ORDER BY A.ItemCode, A.ItemName;
END |
DELIMITER ;

