DROP PROCEDURE IF EXISTS `SelectAllControlls`;
DELIMITER |
CREATE PROCEDURE `SelectAllControlls`(in USERID1 int)
BEGIN
IF(USERID1 = 1)THEN
BEGIN
SELECT DISTINCT ROLE_ID, FORM_NAME AS FormName
, ROLE_TITLE AS ControlName
, PERMISSION_STATUS AS PerStatus
FROM roles
WHERE (NOT EXISTS(SELECT ROLE_ID, roles.ROLE_ID AS Expr1
FROM user_roles
WHERE (USER_ID =  USERID1)
AND (ROLE_ID = roles.ROLE_ID)))
ORDER BY FormName, ControlName;
END;
ELSE
BEGIN
SELECT DISTINCT ROLE_ID, FORM_NAME AS FormName
, ROLE_TITLE AS ControlName
, PERMISSION_STATUS AS PerStatus
FROM roles
WHERE ApprovedRole = 1
AND (NOT EXISTS(SELECT ROLE_ID, roles.ROLE_ID AS Expr1
FROM user_roles
WHERE (USER_ID =  USERID1)
AND (ROLE_ID = roles.ROLE_ID)))
ORDER BY FormName, ControlName;
END;
END IF;
END |
DELIMITER ;

