DROP PROCEDURE IF EXISTS `SelectAllCustomers`;
DELIMITER |
CREATE PROCEDURE `SelectAllCustomers`()
BEGIN
DECLARE CustCredit DECIMAL(20,2) DEFAULT 0;
DECLARE CustCreditPay DECIMAL(20,2) DEFAULT 0;
DECLARE UTCDate1 date;
SET UTCDate1 = (select CONVERT_TZ(now(), @@session.time_zone, '+05:30'));
SELECT A.CustomerId
, A.CustomerName
, A.ContactPerson as CustomerCode
, A.CustomerAddress
, A.CustomerTelNo
, A.CustomerFaxNo
, A.CustomerEmail
, A.CustomerNICNo
, ((SELECT IFNULL((SUM(BB.CreditAmount)), 0) AS CreditAmount
FROM customercredit BB
where A.CustomerId = BB.CustomerId) - (SELECT IFNULL((SUM(BB.PaymentAmount)), 0) AS Expr1
FROM custcreditpayment BB
where A.CustomerId = BB.CustomerId))
AS CreditBalance
, CASE VATCustomer
WHEN 1 THEN 'Yes'
ELSE 'No'
END AS IsVATCustomer
, A.Remarks
,(SELECT IFNULL(SUM(CC.ChequeAmount),0) AS ChequeAmount
FROM customercheque CC
WHERE (CC.CustomerId = A.CustomerId)
AND (CC.ChequeExpDate >= UTCDate1)) AS ChequeBalance
, A.PriceMode
, A.AdvanceAmount
, B.CustomerType
, A.LoyaltyPercentage
, A.LoyaltyAmount
, A.TotalLoyaltyPoints
, C.EmployeeName AS ContactEmployee
FROM customer A
LEFT OUTER JOIN customertypes B
ON A.CustomerTypeId = B.CustomerTypeId
LEFT OUTER JOIN employeeregistration C
ON A.EmployeeID = C.EmployeeID
ORDER BY A.CustomerName;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `SelectAllCustomersByName`;
DELIMITER |
CREATE PROCEDURE `SelectAllCustomersByName`(in CustomerName1 varchar(100))
BEGIN
DECLARE CustCredit DECIMAL(20,2) DEFAULT 0;
DECLARE CustCreditPay DECIMAL(20,2) DEFAULT 0;
DECLARE UTCDate1 date;
SET UTCDate1 = (select CONVERT_TZ(now(), @@session.time_zone, '+05:30'));
SELECT A.CustomerId
, A.CustomerName
, ContactPerson as CustomerCode
, A.CustomerAddress
, A.CustomerTelNo
, A.CustomerFaxNo
, A.CustomerEmail
, A.CustomerNICNo
, ((SELECT IFNULL((SUM(B.CreditAmount)), 0) AS CreditAmount
FROM customercredit B
where A.CustomerId = B.CustomerId) - (SELECT IFNULL((SUM(B.PaymentAmount)), 0) AS Expr1
FROM custcreditpayment B
where A.CustomerId = B.CustomerId))
AS CreditBalance
, CASE VATCustomer
WHEN 1 THEN 'Yes'
ELSE 'No'
END AS IsVATCustomer
, Remarks
,(SELECT IFNULL(SUM(C.ChequeAmount),0) AS ChequeAmount
FROM customercheque C
WHERE (C.CustomerId = A.CustomerId)
AND (C.ChequeExpDate >= UTCDate1)) AS ChequeBalance
, A.PriceMode
, A.AdvanceAmount
, B.CustomerType
FROM customer A
LEFT OUTER JOIN customertypes B
ON A.CustomerTypeId = B.CustomerTypeId
WHERE (A.CustomerName LIKE CONCAT('%', CustomerName1, '%'))
ORDER BY A.CustomerName;
END |
DELIMITER ;

