, A.TransferDate AS GINDate
, TRIM(Replace(Replace(Replace(B.BranchName,'\t',''),'\n',''),'\r','')) AS Branch
, C.CatDescription as ExpenseCategory
, A.TotalCost
, CASE A.CancelStatus
WHEN 1 THEN 'Cancelled'
ELSE ' '
END AS TransferStatus
FROM ginhdnew A
INNER JOIN branch B
