ON A.ToBranchId = C.PayCatId
ORDER BY A.TransferHDId DESC;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `SelectAllInvoiceStatus`;
DELIMITER |
CREATE PROCEDURE `SelectAllInvoiceStatus`()
BEGIN
SELECT X.InvoiceNo
, X.InvoiceDate AS RefDate
, X.CustomerName
, X.CustomerTelNo
, X.EmployeeName AS 'Technician'
, X.UserName
, X.InvoiceStatus
, X.CompletedDate
, X.LastStatusUpdateDate
, X.BranchName
, X.InvoiceStatusId
, X.DocType
, X.Remarks
, X.DocTypeId
FROM(
SELECT A.SOHDId AS InvoiceNo
, A.SODate AS InvoiceDate
, I.CustomerName
, I.CustomerTelNo
, J.EmployeeName
, H.UserName
, B.InvoiceStatus
, A.CompletedDate
, A.StatusUpdateDate AS LastStatusUpdateDate
, TRIM(Replace(Replace(Replace(D.BranchName,'\t',''),'\n',''),'\r','')) AS BranchName
, A.InvoiceStatusId
, 'Invoice' AS DocType
, A.Remarks
, 1 AS DocTypeId
FROM salesorderhd A
INNER JOIN branch D
ON A.BranchId = D.BranchId
INNER JOIN useraccount H
ON A.CreatedBy = H.UserID
INNER JOIN invoicestatus B
ON A.InvoiceStatusId = B.InvoiceStatusId
LEFT OUTER JOIN customer I
ON A.CustomerId = I.CustomerId
LEFT OUTER JOIN employeeregistration J
ON A.RepId = J.EmployeeID
WHERE (A.CancelStatus = 0)
AND (A.RepairBill = 1)
UNION ALL
SELECT A.SOHDId AS InvoiceNo
, A.SODate AS InvoiceDate
, I.CustomerName
, I.CustomerTelNo
, J.EmployeeName
, H.UserName
, B.InvoiceStatus
, A.CompletedDate
, A.StatusUpdateDate AS LastStatusUpdateDate
, TRIM(Replace(Replace(Replace(D.BranchName,'\t',''),'\n',''),'\r','')) AS BranchName
, A.InvoiceStatusId
, 'Sales Order' AS DocType
, A.Remarks
, 2 AS DocTypeId
FROM sohd A
INNER JOIN branch D
ON A.BranchId = D.BranchId
AND A.RepairBill = 1
INNER JOIN useraccount H
ON A.CreatedBy = H.UserID
INNER JOIN invoicestatus B
ON A.InvoiceStatusId = B.InvoiceStatusId
LEFT OUTER JOIN customer I
ON A.CustomerId = I.CustomerId
LEFT OUTER JOIN employeeregistration J
ON A.RepId = J.EmployeeID
)X
ORDER BY X.DocType, X.CompletedDate, X.InvoiceNo
;
END |
DELIMITER ;

