DROP PROCEDURE IF EXISTS `SelectAllOptions`;
DELIMITER |
CREATE PROCEDURE `SelectAllOptions`(in USERID1 int)
BEGIN
SELECT OptionId, OptionName, OptionStatus
FROM mstroptions;
SELECT OptionId
FROM useraccount
WHERE UserID = USERID1
UNION ALL
SELECT OptionId
FROM mstroptions
WHERE (OptionStatus = 1)
AND (OptionId = 1);
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `SelectAllPaymentMods`;
DELIMITER |
CREATE PROCEDURE `SelectAllPaymentMods`()
BEGIN
SELECT        PayModeId, PayMode
FROM            paymentmode
Where PayModeId <> 5
ORDER BY PayModeId;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `SelectAllPurchaseReturn`;
DELIMITER |
CREATE PROCEDURE `SelectAllPurchaseReturn`()
BEGIN
SELECT A.PIHDId as ReturnId
, A.PINo as ReturnNo
, A.PIDate as ReturnDate
, D.SupplierName
, A.ContactPerson
, D.Address SupplierAddress
, A.SupplierInvoiceNo
, E.PayMode
, A.ReturnTotal
FROM pihdreturn A
INNER JOIN supplier D
ON A.SupplierId = D.SupplierId
INNER JOIN paymentmode E
ON A.PayModeId = E.PayModeId
ORDER BY A.PIHDId DESC;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `SelectAllROLevelStock`;
DELIMITER |
CREATE PROCEDURE `SelectAllROLevelStock`()
BEGIN
SELECT A.ItemCode
, A.ItemName
, B.ItemCatName AS ItemCategory
, D.ItemSubCatName AS ItemSubCategory
, A.RetailDiscPer
, A.Discount AS RetailDiscAmount
, A.SellingPrice AS RetailPrice
, A.WholesaleDiscPer
, A.WholeSaleDiscount AS WholeSaleDiscAmount
, A.SPSellingPrice AS WholesalePrice
, A.ShopPrice
, A.ItemUnit
, A.RackNo
, A.CostPrice
, A.AvgCost AS AverageCost
, A.MinQty
, E.AvailableQty AS BranchQty
, A.AvailableQty AS TotalQty
, E.Damage
, F.BranchName
, A.ScaleItem
, A.BundleItem
, A.RawMaterial
, A.AllowSales
, A.AllowPurchase
, A.AllowInventory
, A.ItemsId
, E.BranchId
, A.IsVariant
, A.MItemsId
, A.MItemCode
, A.ConvertionQty
, A.SearchText
FROM itemsummary A
INNER JOIN itemcategory B
ON A.ItemCatId = B.ItemCatId
INNER JOIN branchstock E
ON A.ItemsId = E.ItemsId
INNER JOIN branch F
ON E.BranchId = F.BranchId
LEFT OUTER JOIN itemsubcategory D
ON A.ItemSubCatId = D.ItemSubCatId
WHERE A.AvailableQty <= A.MinQty
ORDER BY A.ItemCode, A.ItemName;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `SelectAllSalesInvoices`;
DELIMITER |
CREATE PROCEDURE `SelectAllSalesInvoices`()
BEGIN
SELECT A.SOHDId AS InvoiceNo
, A.SODate AS InvoiceDate
, A.ReferanceNo
, B.CustomerName
, A.SONetTotal AS InvoiceAmount
, CASE A.UpdateStatus
WHEN 1 THEN 'Updated'
ELSE ' '
END AS UpdateStatus
FROM salesorderhd A
LEFT OUTER JOIN customer B
ON A.CustomerId = B.CustomerId
WHERE A.CancelStatus = 0
ORDER BY A.SODate DESC, A.SOHDId DESC;
END |
DELIMITER ;

