DROP PROCEDURE IF EXISTS `SelectAllStockByBranch`;
DELIMITER |
CREATE PROCEDURE `SelectAllStockByBranch`(in BranchId1 int)
BEGIN
SELECT A.ItemCode
, A.ItemName
, B.ItemCatName AS ItemCategory
, D.ItemSubCatName AS ItemSubCategory
, A.RetailDiscPer
, A.Discount AS RetailDiscAmount
, A.SellingPrice AS RetailPrice
, A.WholesaleDiscPer
, A.WholeSaleDiscount AS WholeSaleDiscAmount
, A.SPSellingPrice AS WholesalePrice
, A.ShopPrice
, A.ItemUnit
, A.RackNo
, A.CostPrice
, A.AvgCost AS AverageCost
, A.MinQty
, E.AvailableQty AS BranchQty
, (SELECT SUM(Y.AvailableQty)
FROM branchstock Y
WHERE Y.ItemsId = A.ItemsId) AS TotalQty
, E.Damage
, F.BranchName
, A.ScaleItem
, A.BundleItem
, A.RawMaterial
, A.AllowSales
, A.AllowPurchase
, A.AllowInventory
, A.ItemsId
, E.BranchId
, A.IsVariant
, A.MItemsId
, A.MItemCode
, A.ConvertionQty
, A.SearchText
FROM itemsummary A
INNER JOIN itemcategory B
ON A.ItemCatId = B.ItemCatId
INNER JOIN branchstock E
ON A.ItemsId = E.ItemsId
INNER JOIN branch F
ON E.BranchId = F.BranchId
LEFT OUTER JOIN itemsubcategory D
ON A.ItemSubCatId = D.ItemSubCatId
WHERE (E.BranchId = BranchId1)
ORDER BY A.ItemCode, A.ItemName;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `SelectAllStockByBranchItmCat`;
DELIMITER |
