BEGIN
SELECT A.ItemCode
, A.ItemName
, B.ItemCatName AS ItemCategory
, D.ItemSubCatName AS ItemSubCategory
, A.RetailDiscPer
, A.Discount AS RetailDiscAmount
, A.SellingPrice AS RetailPrice
, A.WholesaleDiscPer
, A.WholeSaleDiscount AS WholeSaleDiscAmount
, A.SPSellingPrice AS WholesalePrice
, A.ShopPrice
, A.ItemUnit
, A.RackNo
, A.CostPrice
, A.AvgCost AS AverageCost
, A.MinQty
, E.AvailableQty AS BranchQty
, (SELECT SUM(Y.AvailableQty)
FROM branchstock Y
WHERE Y.ItemsId = A.ItemsId) AS TotalQty
, E.Damage
, F.BranchName
, A.ScaleItem
, A.BundleItem
, A.RawMaterial
, A.AllowSales
, A.AllowPurchase
, A.AllowInventory
, A.ItemsId
, E.BranchId
, A.IsVariant
, A.MItemsId
, A.MItemCode
, A.ConvertionQty
