DROP PROCEDURE IF EXISTS `SelectAllStockTransfers`;
DELIMITER |
CREATE PROCEDURE `SelectAllStockTransfers`()
BEGIN
SELECT A.TransferHDId
, A.TransferDate
, TRIM(Replace(Replace(Replace(B.BranchName,'\t',''),'\n',''),'\r','')) AS BranchTransferFrom
, TRIM(Replace(Replace(Replace(C.BranchName,'\t',''),'\n',''),'\r','')) AS BranchTransferTo
, CASE A.CancelStatus
WHEN 1 THEN 'Cancelled'
ELSE ' '
END AS TransferStatus
FROM stocktransferhd A
INNER JOIN branch B
ON A.FromBranchId = B.BranchId
INNER JOIN branch C
ON A.ToBranchId = C.BranchId
ORDER BY A.TransferHDId DESC;
END |
DELIMITER ;

