, CONCAT('Rs. ', B.SPSellingPrice) AS WholesalePrice
, CONCAT('Rs. ', B.ShopPrice) AS ShopPrice
, CONCAT('Rs. ', B.CostPrice) AS CostPrice
, A.InternalNo
, CURDATE() AS CurrentDate
, B.ItemUnit
, B.WarrantyPeriod
