DROP PROCEDURE IF EXISTS `SelectBillRecords`;
DELIMITER |
CREATE PROCEDURE `SelectBillRecords`(in BillNo1 int)
BEGIN
SELECT A.SOHDId
, A.SODate
, B.CustomerName
FROM salesorderhd A
LEFT OUTER JOIN customer B
ON A.CustomerId = B.CustomerId
WHERE (A.SOHDId = BillNo1)
AND (A.CancelStatus = 0);
SELECT A.SOHDId AS BillNo
, B.SODTId
, B.SOHDId
, B.ItemsId
, B.ItemCode
, C.ItemName
, C.ItemCatId
, D.ItemCatName
, (B.SalesQty - IFNULL(E.ReturnQty, 0)) AS SalesQty
, B.SalesPrice
, (B.SalesQty - IFNULL(E.ReturnQty, 0)) * B.SalesPrice AS GrossAmount
, (B.Discount - ((B.Discount / B.SalesQty) * (IFNULL(E.ReturnQty, 0)))) AS Discount
, (((B.SalesQty - IFNULL(E.ReturnQty, 0)) * B.SalesPrice) -(B.Discount - ((B.Discount / B.SalesQty) * (IFNULL(E.ReturnQty, 0))))) AS GrossTotal
, (B.SalesQty - IFNULL(E.ReturnQty, 0)) * B.SalesPrice AS NetAmount
, (B.FreeIssue - IFNULL(E.FreeIssue, 0)) AS FreeIssue
FROM salesorderhd A
INNER JOIN salesorderdt B
ON A.SOHDId = B.SOHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
INNER JOIN itemcategory D
ON C.ItemCatId = D.ItemCatId
LEFT OUTER JOIN (SELECT E.SOHDId, E.SODTId, SUM(E.ReturnQty) AS ReturnQty, SUM(E.FreeIssue) AS FreeIssue
FROM salesreturn E
GROUP BY E.SOHDId, E.SODTId
)E
ON B.SOHDId = E.SOHDId
AND B.SODTId = E.SODTId
WHERE (A.CancelStatus = 0)
AND (A.SOHDId = BillNo1);

END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `SelectBillRecordsForUpdate`;
DELIMITER |
CREATE PROCEDURE `SelectBillRecordsForUpdate`(in BillNo1 int)
BEGIN
