ORDER BY ROLE_TITLE;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `SelectCustomerBillRecord`;
DELIMITER |
CREATE PROCEDURE `SelectCustomerBillRecord`()
BEGIN
SELECT X.CustomerId
, X.CustomerName
, X.CustomerTelNo AS ContactNo
, MIN(X.CreditDate) AS CreditDate
, SUM(X.CreditAmount) AS CreditAmount
, SUM(X.TotalPayment) AS TotalPayment
, SUM(X.BalanceAmount) AS BalanceAmount
, MIN(X.CreditDueDate) AS PaymentDueFrom
, MAX(X.NoOfDueDays) AS NoOfDueDays
, C.CustmorStatus AS MessageSendStatus
FROM(
SELECT A.CustomerId
, A.CustomerName
, A.CustomerTelNo
, B.BillNo
, B.CreditDate
, B.CreditAmount
, B.PaymentAmount AS TotalPayment
, B.CreditAmount - B.PaymentAmount AS BalanceAmount
, B.CreditDueDate
, B.NextDueDate
, B.NoOfDueDays
FROM customer A
INNER JOIN customercredit B
ON A.CustomerId = B.CustomerId
WHERE (B.PaymentCompletedStatus = 0)
AND (B.CreditDueDate <= CURDATE())
AND (A.NextDueDate <= CURDATE())
UNION ALL
SELECT A.CustomerId
, A.CustomerName
, A.CustomerTelNo
, B.BillNo
, B.CreditDate
, B.CreditAmount
, B.PaymentAmount AS TotalPayment
, B.CreditAmount - B.PaymentAmount AS BalanceAmount
, B.CreditDueDate
, B.NextDueDate
, B.NoOfDueDays
FROM customer A
INNER JOIN customercredit B
ON A.CustomerId = B.CustomerId
WHERE (B.PaymentCompletedStatus = 0)
AND (B.CreditDueDate > CURDATE())
AND (A.NextDueDate <= CURDATE())
)X
INNER JOIN customer C
ON X.CustomerId = C.CustomerId
GROUP BY X.CustomerId
, X.CustomerName
, X.CustomerTelNo;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `SelectCustomerByInvoice`;
DELIMITER |
CREATE PROCEDURE `SelectCustomerByInvoice`(in SOHDId1 int)
