DROP PROCEDURE IF EXISTS `SelectCustomerCodeData`;
DELIMITER |
CREATE PROCEDURE `SelectCustomerCodeData`(in CustomerCode1 varchar(80))
BEGIN
DECLARE UTCDate1 date;
SET UTCDate1 = (select CONVERT_TZ(now(), @@session.time_zone, '+05:30'));
SELECT A.CustomerId
, A.CustomerName
, A.ContactPerson
, A.CustomerAddress
, A.CustomerTelNo
, A.CustomerFaxNo
, A.CustomerEmail
, A.CustomerNICNo
, A.Remarks
, A.CustomerImage
, ((SELECT IFNULL((SUM(B.CreditAmount)), 0) AS CreditAmount
FROM customercredit B
where A.CustomerId = B.CustomerId) -
(SELECT IFNULL((SUM(B.PaymentAmount)), 0) AS Expr1
FROM custcreditpayment B
where A.CustomerId = B.CustomerId)) as BalanceAmount
,(SELECT IFNULL(SUM(C.ChequeAmount),0) AS ChequeAmount
FROM customercheque C
WHERE (C.CustomerId = A.CustomerId)
AND (C.ChequeExpDate >= UTCDate1)
AND C.ReturnStatus = 0) AS ChequeAmount
, A.CreditLimit
, A.PriceMode
, A.AdvanceAmount
,((SELECT IFNULL(SUM(C.LoyaltyPoints),0) AS LoyaltyPoints
FROM salesorderhd C
WHERE C.CustomerId = A.CustomerId
AND C.CancelStatus = 0
) - (SELECT IFNULL(SUM(D.UsedPoints),0) AS UsedPoints
FROM usedloyaltypoints D
WHERE D.CustomerId = A.CustomerId
)
) AS LoyaltyPointsBalance
, A.LoyaltyPercentage
, A.LoyaltyAmount
FROM customer A
WHERE (A.ContactPerson = CustomerCode1);
END |
DELIMITER ;

