DROP PROCEDURE IF EXISTS `SelectCustomerHistory`;
DELIMITER |
CREATE PROCEDURE `SelectCustomerHistory`(in
date1 date,
date2 date)
BEGIN
SELECT A.SOHDId AS RefNo
, A.SODate AS RefDate
, B.CustomerName
, B.CustomerTelNo
, A.SONetTotal AS Amount
, C.PayMode
, 'SalesInvoice' AS RefDoc
FROM salesorderhd A
INNER JOIN customer B
ON A.CustomerId = B.CustomerId
INNER JOIN paymentmode C
ON A.PayModeId = C.PayModeId
WHERE (A.CancelStatus = 0)
AND (A.SODate BETWEEN date1 AND date2)
UNION ALL
SELECT A.BillNo AS RefNo
, A.PaymentDate AS RefDate
, B.CustomerName
, B.CustomerTelNo
, A.PaymentAmount AS Amount
, C.PayMode
, 'CreditPayment' AS RefDoc
FROM custcreditpayment A
INNER JOIN customer B
ON A.CustomerId = B.CustomerId
INNER JOIN paymentmode C
ON A.PayModeId = C.PayModeId
WHERE (A.PaymentDate BETWEEN date1 AND date2);
END |
DELIMITER ;

