DROP PROCEDURE IF EXISTS `SelectCustomerIDData`;
DELIMITER |
CREATE PROCEDURE `SelectCustomerIDData`(in CustomerId1 int)
BEGIN
SELECT CustomerId
, CustomerName
, CustomerAddress
, CustomerTelNo
, CustomerFaxNo
, CustomerEmail
, CustomerNICNo
, Remarks
FROM customer
WHERE (CustomerId = CustomerId1);
SELECT BillNo
, CreditDate
, (CreditAmount - PaymentAmount) AS CreditAmount
, CreditAmount AS InvoiceCreditAmount
FROM customercredit
WHERE (CustomerId = CustomerId1)
AND (PaymentCompletedStatus = 0)
AND (CreditAmount - PaymentAmount) > 0;
SELECT PaymentDate
, BillNo
, PaymentAmount
, ReciptNo
FROM custcreditpayment
WHERE (CustomerId = CustomerId1);
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `SelectCustomerPay`;
DELIMITER |
CREATE PROCEDURE `SelectCustomerPay`(in CustomerId1 int)
BEGIN
SELECT        custcreditpayment.CustCreditPayId, custcreditpayment.PaymentAmount, custcreditpayment.PaymentDate, customer.CustomerName, customer.BalanceAmount, custcreditpayment.CustomerId,
companyinfo.CompanyName, companyinfo.CompanyAddress1, companyinfo.CompanyAddress2, companyinfo.ContactNo1, companyinfo.ContactNo2, companyinfo.CompanyLogo
FROM            custcreditpayment INNER JOIN
customer ON custcreditpayment.CustomerId = customer.CustomerId, companyinfo
WHERE        (custcreditpayment.CustCreditPayId =
(SELECT        MAX(CustCreditPayId) AS Expr1
FROM            custcreditpayment custcreditpayment_1)) AND (custcreditpayment.CustomerId = CustomerId1);
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `SelectCustomerTemplate`;
DELIMITER |
CREATE PROCEDURE `SelectCustomerTemplate`()
BEGIN
SELECT A.ContactPerson as CustomerCode
, A.CustomerName
, A.CustomerAddress
, A.CustomerTelNo
, A.CustomerFaxNo
, A.CustomerEmail
, A.CustomerNICNo
, A.Remarks
, A.CreditLimit
, ((SELECT IFNULL((SUM(B.CreditAmount)), 0) AS CreditAmount
FROM customercredit B
where A.CustomerId = B.CustomerId) - (SELECT IFNULL((SUM(B.PaymentAmount)), 0) AS Expr1
FROM custcreditpayment B
where A.CustomerId = B.CustomerId))
AS CreditBalance
, A.CustomerId
FROM customer A
ORDER BY A.ContactPerson;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `SelectDashbordSP`;
DELIMITER |
CREATE PROCEDURE `SelectDashbordSP`()
BEGIN
SELECT        A.SOHDId, A.SODate, E.CustomerName, D.PayMode, B.ItemCode, C.ItemName, B.SalesQty, B.SalesPrice, C.CostPrice, B.Discount, B.NetAmount AS NetSaleAmount, B.SalesQty * C.CostPrice AS SalesCost,
B.NetAmount - B.SalesQty * C.CostPrice AS GrossProfit
FROM            salesorderhd A INNER JOIN
salesorderdt B ON A.SOHDId = B.SOHDId INNER JOIN
itemsummary C ON B.ItemsId = C.ItemsId INNER JOIN
paymentmode D ON A.PayModeId = D.PayModeId LEFT OUTER JOIN
customer E ON A.CustomerId = E.CustomerId
WHERE        (A.CancelStatus = 0)
ORDER BY A.SODate, A.SOHDId;
END |
DELIMITER ;

