DROP PROCEDURE IF EXISTS `SelectEmployeeAdv`;
DELIMITER |
CREATE PROCEDURE `SelectEmployeeAdv`(in EmployeeID1 int, Date1 date, Date2 date)
BEGIN
SELECT IFNULL(SUM(Amount), 0) AS Advance
,(SELECT IFNULL(SUM(TotalHours), 0) FROM employeeattendance WHERE EmployeeID = EmployeeID1 AND AttendanceDate BETWEEN Date1 AND Date2) AS TotalHours
,(SELECT IFNULL(SUM(OTHours), 0) FROM employeeattendance WHERE EmployeeID = EmployeeID1 AND AttendanceDate BETWEEN Date1 AND Date2) AS OTHours
FROM employeeadvance
WHERE (EmployeeID = EmployeeID1)
AND (AdvanceDate BETWEEN Date1 AND Date2);
SELECT IFNULL(SUM(B.NetAmount), 0) AS SalesAmount
FROM salesorderhd A
INNER JOIN salesorderdt B
ON A.SOHDId = B.SOHDId
WHERE (A.RepId = EmployeeID1)
AND (A.CancelStatus = 0)
AND (A.SODate BETWEEN Date1 AND Date2);
SELECT IFNULL(SUM(A.LeaveCount),0) AS LeaveCount, IFNULL(B.LeaveDeductionPerDay,0) AS LeaveDeductionPerDay
FROM employeeleave A
INNER JOIN employeeregistration B
ON A.EmployeeID = B.EmployeeID
WHERE (A.EmployeeID = EmployeeID1)
AND (A.LeaveDate BETWEEN Date1 AND Date2)
GROUP BY B.LeaveDeductionPerDay;
END |
DELIMITER ;

