DROP PROCEDURE IF EXISTS `SelectGiftVouchers`;
DELIMITER |
CREATE PROCEDURE `SelectGiftVouchers`(in
date1 date,
date2 date)
BEGIN
SELECT A.VoucherNo
, A.IssueDate
, A.ExpireDate
, A.UsedOn
, A.VoucherAmount
, A.VoucherCode
, CASE A.VoucherStatus
WHEN 1 THEN 'Used'
ELSE 'Issued'
END AS GiftVoucherStatus
, CASE A.CancelStatus
WHEN 1 THEN 'Cancelled'
ELSE ' '
END AS CancelStatus
, A.SOHDId AS ReferenceInvoice
, B.UserName AS IssuedBy
, A.ModifiedOn AS CancelledOn
, C.UserName AS CancelledBy
FROM giftvoucher A
INNER JOIN useraccount B
ON A.CreatedBy = B.UserID
LEFT OUTER JOIN useraccount C
ON A.ModifiedBy = C.UserID
WHERE (A.IssueDate BETWEEN date1 AND date2);
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `SelectGINNewData`;
