CREATE PROCEDURE `SelectGINNewData`(in TransferHDId1 int)
BEGIN
SELECT A.TransferHDId AS GINId
, D.BranchName AS FromBranch
, E.CatDescription as ExpenseCategory
, B.ItemsId
, C.ItemCode
, C.ItemName
, B.Qty
, CASE C.CostPrice WHEN 0 THEN 1 ELSE C.CostPrice END AS CostPrice
, C.SellingPrice
, B.NetAmount
, A.FromBranchId
FROM ginhdnew A
INNER JOIN gindtnew B
ON A.TransferHDId = B.TransferHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
INNER JOIN branch D
ON A.FromBranchId = D.BranchId
INNER JOIN expensescategory E
ON A.ToBranchId = B.PayCatId
WHERE (A.TransferHDId = TransferHDId1)
ORDER BY B.TransferDTId;
END |
DELIMITER ;

