DROP PROCEDURE IF EXISTS `SelectHoldBills`;
DELIMITER |
CREATE PROCEDURE `SelectHoldBills`()
BEGIN
DECLARE UTCDate1 date;
SET UTCDate1 = (select CONVERT_TZ(now(), @@session.time_zone, '+05:30'));
SELECT        SOHDId AS HoldNo, SUM(NetAmount) AS TotalAmount, HoldTime
FROM            holdinvoice
GROUP BY SOHDId, CreatedOn
HAVING        (CreatedOn = UTCDate1);
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `SelectHoldDTData`;
DELIMITER |
CREATE PROCEDURE `SelectHoldDTData`(in SOHDId1 int)
BEGIN
SELECT A.ItemsId
,A.Itemcode
,A.SalesQty
,A.SalesPrice
,(A.SalesQty * A.SalesPrice) AS Amount
,A.Discount
,A.NetAmount
,A.FreeIssue
,A.InternalNo
,A.Warranty
,B.ItemCatId
,A.ItemName
,A.SODTId
,A.KOTId
,IFNULL(C.PrintStatus, 0) AS PrintStatus
,A.SerialNo
,A.PriceMethod
,A.IsServiceChargeItem
FROM holdsalesorderdt A
INNER JOIN itemsummary B
ON A.ItemsId = B.ItemsId
LEFT OUTER JOIN kot C
ON A.SOHDId = C.SOHDId
AND A.KOTId = C.KOTId
WHERE A.SOHDId = SOHDId1
ORDER BY SODTId;
END |
DELIMITER ;

