DROP PROCEDURE IF EXISTS `SelectInvoiceBalances`;
DELIMITER |
CREATE PROCEDURE `SelectInvoiceBalances`(in UserId1 int)
BEGIN
DECLARE TotalCreditSale DECIMAL(20,2) DEFAULT 0;
DECLARE TotalCardSale DECIMAL(20,2) DEFAULT 0;
DECLARE UTCDate1 date;
SET UTCDate1 = (select CONVERT_TZ(now(), @@session.time_zone, '+05:30'));
SELECT IFNULL((SUM(SONetTotal)), 0) INTO TotalCreditSale
FROM salesorderhd
GROUP BY SODate, PayModeId, CancelStatus
HAVING (SODate = UTCDate1)
AND (PayModeId = 3)
AND (CancelStatus = 0);
SELECT IFNULL((SUM(SONetTotal)), 0) INTO TotalCardSale
FROM salesorderhd
GROUP BY SODate, PayModeId, CancelStatus
HAVING (SODate = UTCDate1)
AND (PayModeId = 4)
AND (CancelStatus = 0);
select A.OpeningBalance,A.CashInAmount,A.CashOutAmount,A.LastBalance, TotalCreditSale, TotalCardSale
from  cashbalance A
where A.UserId = UserId1
and A.BalanceDate = UTCDate1;
END |
DELIMITER ;

