DROP PROCEDURE IF EXISTS `SelectNewSummaryByUserReport`;
DELIMITER |
CREATE PROCEDURE `SelectNewSummaryByUserReport`(in date1 date, UserID1 int)
BEGIN
DECLARE GrossSale DECIMAL(20,2) DEFAULT 0;
DECLARE TotalSale1 DECIMAL(20,2) DEFAULT 0;
DECLARE TotalSalesReturn1 DECIMAL(20,2) DEFAULT 0;
DECLARE TotalSalesReturn2 DECIMAL(20,2) DEFAULT 0;
DECLARE TotalSalesReturn11 DECIMAL(20,2) DEFAULT 0;
DECLARE TotalCashSalesReturn2 DECIMAL(20,2) DEFAULT 0;
DECLARE TotalReturnNoteSale1 DECIMAL(20,2) DEFAULT 0;
DECLARE TotalNetSale1 DECIMAL(20,2) DEFAULT 0;
DECLARE TotalCashSale1 DECIMAL(20,2) DEFAULT 0;
DECLARE TotalCashBillSale1 DECIMAL(20,2) DEFAULT 0;
DECLARE TotalOtherBillCashSale1 DECIMAL(20,2) DEFAULT 0;
DECLARE TotalChequeSale1 DECIMAL(20,2) DEFAULT 0;
DECLARE TotalCreditSale1 DECIMAL(20,2) DEFAULT 0;
DECLARE TotalCardSale1 DECIMAL(20,2) DEFAULT 0;
DECLARE TotalBankTransferSale1 DECIMAL(20,2) DEFAULT 0;
DECLARE Expenses1 DECIMAL(20,2) DEFAULT 0;
DECLARE CashExpenses1 DECIMAL(20,2) DEFAULT 0;
DECLARE CustCreditPayment1 DECIMAL(20,2) DEFAULT 0;
DECLARE SuppCreditPayment1 DECIMAL(20,2) DEFAULT 0;
DECLARE CustCreditPaymentCheque1 DECIMAL(20,2) DEFAULT 0;
DECLARE SuppCreditPaymentCheque1 DECIMAL(20,2) DEFAULT 0;
DECLARE CustCreditPaymentBankTransfer1 DECIMAL(20,2) DEFAULT 0;
DECLARE SuppCreditPaymentBankTransfer1 DECIMAL(20,2) DEFAULT 0;
DECLARE OpeningCashBalance1 DECIMAL(20,2) DEFAULT 0;
DECLARE LastCashBalance1 DECIMAL(20,2) DEFAULT 0;
DECLARE TotalCashIn DECIMAL(20,2) DEFAULT 0;
DECLARE BankDeposit DECIMAL(20,2) DEFAULT 0;
DECLARE IssuedVoucher DECIMAL(20,2) DEFAULT 0;
DECLARE TotalPurchase1 DECIMAL(20,2) DEFAULT 0;
DECLARE TotalCashPurchase1 DECIMAL(20,2) DEFAULT 0;
DECLARE TotalCashBillPurchase1 DECIMAL(20,2) DEFAULT 0;
DECLARE TotalOtherBillCashPurchase1 DECIMAL(20,2) DEFAULT 0;
DECLARE TotalChequePurchase1 DECIMAL(20,2) DEFAULT 0;
DECLARE TotalCreditPurchase1 DECIMAL(20,2) DEFAULT 0;
DECLARE TotalCardPurchase1 DECIMAL(20,2) DEFAULT 0;
DECLARE TotalBankTransferPurchase1 DECIMAL(20,2) DEFAULT 0;
DECLARE ItemDiscount1 DECIMAL(20,2) DEFAULT 0;
DECLARE TotalBillDiscount1 DECIMAL(20,2) DEFAULT 0;
DECLARE TotalDiscount1 DECIMAL(20,2) DEFAULT 0;
DECLARE ReceivedVoucherTotal1 DECIMAL(20,2) DEFAULT 0;
DECLARE ExpensesId1 INT DEFAULT 0;
DECLARE CustCreditPayHDId1 INT DEFAULT 0;
DECLARE CustomerId1 INT DEFAULT 0;
DECLARE ItemsId1 INT DEFAULT 0;
DECLARE PIHDId1 INT DEFAULT 0;
DECLARE SOHDId1 INT DEFAULT 0;
DECLARE StkAdjHDId1 INT DEFAULT 0;
DECLARE TransferHDId1 INT DEFAULT 0;
DECLARE SuppCreditPayHDId1 INT DEFAULT 0;
DECLARE SupplierId1 INT DEFAULT 0;
DECLARE DirectPurchaseReturnTotal1 DECIMAL(20,2) DEFAULT 0;
DECLARE DirectCashPurchaseReturnTotal1 DECIMAL(20,2) DEFAULT 0;
DECLARE Charges1 DECIMAL(20,2) DEFAULT 0;
DECLARE AdvanceAmount1 DECIMAL(20,2) DEFAULT 0;
DECLARE TranDate1 DATE DEFAULT (select CONVERT_TZ(NOW(), @@session.time_zone, '+05:30'));
DECLARE UTCDate1 date;
SET UTCDate1 = (select CONVERT_TZ(now(), @@session.time_zone, '+05:30'));
SELECT IFNULL((SUM(AdvanceAmount)), 0) INTO AdvanceAmount1
FROM sohd
WHERE (SODate = date1)
AND (CancelStatus = 0)
AND (CreatedBy = UserID1);
SELECT IFNULL((SUM(B.Discount)), 0) INTO ItemDiscount1
FROM salesorderhd A
INNER JOIN salesorderdt B
ON A.SOHDId = B.SOHDId
WHERE (A.SODate = date1)
AND (A.CancelStatus = 0)
AND (A.CreatedBy = UserID1);
SELECT IFNULL((SUM(SODiscount)), 0) INTO TotalBillDiscount1
FROM salesorderhd
WHERE (SODate = date1)
AND (CancelStatus = 0)
AND (CreatedBy = UserID1);
SET TotalDiscount1 = IFNULL((ItemDiscount1), 0) + IFNULL((TotalBillDiscount1), 0);
SELECT IFNULL((SUM(Charges)), 0) INTO Charges1
FROM salesorderhd
WHERE (SODate = date1)
AND (CancelStatus = 0)
AND (CreatedBy = UserID1);
SELECT IFNULL((SUM(VoucherAmount)), 0) INTO ReceivedVoucherTotal1
FROM salesorderhd
WHERE (SODate = date1)
AND (CancelStatus = 0)
AND (CreatedBy = UserID1);
SELECT SUM(B.SalesQty * B.SalesPrice) INTO GrossSale
FROM salesorderhd A
INNER JOIN salesorderdt B
ON A.SOHDId = B.SOHDId
WHERE (A.CancelStatus = 0)
AND (A.SODate = date1)
AND (A.CreatedBy = UserID1);
SET TotalSale1 = GrossSale - TotalDiscount1 + Charges1;
SELECT IFNULL((SUM(A.NetAmount)), 0) INTO TotalSalesReturn1
FROM salesreturn A
INNER JOIN salesorderhd B
ON A.SOHDId = B.SOHDId
WHERE (A.RtnDate = date1)
AND (B.CreatedBy = UserID1);
SELECT IFNULL(SUM(B.NetAmount), 0) INTO TotalSalesReturn11
FROM salesorderhd A
INNER JOIN directsalesreturn B
ON A.SOHDId = B.SOHDId
WHERE (A.CancelStatus = 0)
AND (A.SODate = date1)
AND (A.CreatedBy = UserID1)
AND (A.CreatedBy = UserID1);
SELECT IFNULL(SUM(B.NetAmount), 0) INTO TotalSalesReturn2
FROM salesorderhdreturn A
INNER JOIN salesorderdtreturn B
ON A.SOHDId = B.SOHDId
WHERE (A.CancelStatus = 0)
AND (A.SODate = date1)
AND (A.PayModeId <> 1)
AND (A.CreatedBy = UserID1);
SELECT IFNULL(SUM(B.NetAmount), 0) INTO TotalCashSalesReturn2
FROM salesorderhdreturn A
INNER JOIN salesorderdtreturn B
ON A.SOHDId = B.SOHDId
WHERE (A.CancelStatus = 0)
