, TotalCardSale1 AS TotalCardSale
, TotalBankTransferSale1 AS TotalBankTransferSale
, TotalPurchase1 AS TotalPurchase
, TotalCashPurchase1 AS TotalCashPurchase
, TotalChequePurchase1 AS TotalChequePurchase
, TotalCreditPurchase1 AS TotalCreditPurchase
, TotalCardPurchase1 AS TotalCardPurchase
, TotalBankTransferPurchase1 AS TotalBankTransferPurchase
, Expenses1 AS Expenses
, CashExpenses1 AS CashExpenses
, CustCreditPayment1 AS CustCreditPayment
, SuppCreditPayment1 AS SuppCreditPayment
, OpeningCashBalance1 AS OpeningCashBalance
, TotalCashIn AS CashIn
, date1 AS TranDate
, BankDeposit AS BankDeposit
, TotalCashSale1 + CustCreditPayment1 + TotalCashIn + IssuedVoucher + DirectCashPurchaseReturnTotal1 + AdvanceAmount1 AS InAmount
, CashExpenses1 + SuppCreditPayment1 + TotalSalesReturn1 + TotalCashSalesReturn2 + TotalCashPurchase1 AS OutAmount
, (OpeningCashBalance1 + TotalCashSale1 + CustCreditPayment1 + TotalCashIn + IssuedVoucher + DirectCashPurchaseReturnTotal1 + AdvanceAmount1) - (CashExpenses1 + SuppCreditPayment1 + TotalSalesReturn1 + TotalCashSalesReturn2 + TotalCashPurchase1) AS LastCashBalance
, IssuedVoucher
, CustCreditPaymentCheque1 as CustCreditPaymentCheque
, SuppCreditPaymentCheque1 as SuppCreditPaymentCheque
, CustCreditPaymentBankTransfer1 AS CustCreditPaymentBankTransfer
, SuppCreditPaymentBankTransfer1 AS SuppCreditPaymentBankTransfer
, TotalDiscount1 AS TotalDiscount
, ReceivedVoucherTotal1 as ReceivedVoucherTotal
, TotalReturnNoteSale1 AS TotalReturnNoteSale
, ExpensesId1 AS ExpensesId
, CustCreditPayHDId1 AS CustCreditPayHDId
, CustomerId1 AS CustomerId
, ItemsId1 AS ItemsId
, PIHDId1 AS PIHDId
, SOHDId1 AS SOHDId
, StkAdjHDId1 AS StkAdjHDId
, TransferHDId1 AS TransferHDId
, SuppCreditPayHDId1 AS SuppCreditPayHDId
, SupplierId1 AS SupplierId
, DirectPurchaseReturnTotal1 AS DirectPurchaseReturnTotal
, DirectCashPurchaseReturnTotal1 AS DirectCashPurchaseReturnTotal
, AdvanceAmount1 as AdvanceAmount
;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `SelectNewSummaryReport`;
DELIMITER |
CREATE PROCEDURE `SelectNewSummaryReport`(in date1 date)
BEGIN
DECLARE GrossSale DECIMAL(20,2) DEFAULT 0;
DECLARE TotalSale1 DECIMAL(20,2) DEFAULT 0;
DECLARE TotalSalesReturn1 DECIMAL(20,2) DEFAULT 0;
DECLARE TotalSalesReturn2 DECIMAL(20,2) DEFAULT 0;
DECLARE TotalSalesReturn11 DECIMAL(20,2) DEFAULT 0;
DECLARE TotalCashSalesReturn2 DECIMAL(20,2) DEFAULT 0;
DECLARE TotalReturnNoteSale1 DECIMAL(20,2) DEFAULT 0;
DECLARE TotalNetSale1 DECIMAL(20,2) DEFAULT 0;
DECLARE TotalCashSale1 DECIMAL(20,2) DEFAULT 0;
DECLARE TotalCashBillSale1 DECIMAL(20,2) DEFAULT 0;
DECLARE TotalOtherBillCashSale1 DECIMAL(20,2) DEFAULT 0;
DECLARE TotalChequeSale1 DECIMAL(20,2) DEFAULT 0;
DECLARE TotalCreditSale1 DECIMAL(20,2) DEFAULT 0;
DECLARE TotalCardSale1 DECIMAL(20,2) DEFAULT 0;
DECLARE TotalBankTransferSale1 DECIMAL(20,2) DEFAULT 0;
DECLARE Expenses1 DECIMAL(20,2) DEFAULT 0;
DECLARE CashExpenses1 DECIMAL(20,2) DEFAULT 0;
DECLARE CustCreditPayment1 DECIMAL(20,2) DEFAULT 0;
DECLARE SuppCreditPayment1 DECIMAL(20,2) DEFAULT 0;
DECLARE CustCreditPaymentCheque1 DECIMAL(20,2) DEFAULT 0;
DECLARE SuppCreditPaymentCheque1 DECIMAL(20,2) DEFAULT 0;
DECLARE CustCreditPaymentBankTransfer1 DECIMAL(20,2) DEFAULT 0;
DECLARE SuppCreditPaymentBankTransfer1 DECIMAL(20,2) DEFAULT 0;
DECLARE OpeningCashBalance1 DECIMAL(20,2) DEFAULT 0;
DECLARE LastCashBalance1 DECIMAL(20,2) DEFAULT 0;
DECLARE TotalCashIn DECIMAL(20,2) DEFAULT 0;
DECLARE BankDeposit DECIMAL(20,2) DEFAULT 0;
DECLARE IssuedVoucher DECIMAL(20,2) DEFAULT 0;
DECLARE TotalPurchase1 DECIMAL(20,2) DEFAULT 0;
DECLARE TotalCashPurchase1 DECIMAL(20,2) DEFAULT 0;
DECLARE TotalCashBillPurchase1 DECIMAL(20,2) DEFAULT 0;
DECLARE TotalOtherBillCashPurchase1 DECIMAL(20,2) DEFAULT 0;
DECLARE TotalChequePurchase1 DECIMAL(20,2) DEFAULT 0;
DECLARE TotalCreditPurchase1 DECIMAL(20,2) DEFAULT 0;
DECLARE TotalCardPurchase1 DECIMAL(20,2) DEFAULT 0;
DECLARE TotalBankTransferPurchase1 DECIMAL(20,2) DEFAULT 0;
DECLARE ItemDiscount1 DECIMAL(20,2) DEFAULT 0;
DECLARE TotalBillDiscount1 DECIMAL(20,2) DEFAULT 0;
DECLARE TotalDiscount1 DECIMAL(20,2) DEFAULT 0;
DECLARE ReceivedVoucherTotal1 DECIMAL(20,2) DEFAULT 0;
DECLARE ExpensesId1 INT DEFAULT 0;
DECLARE CustCreditPayHDId1 INT DEFAULT 0;
DECLARE CustomerId1 INT DEFAULT 0;
DECLARE ItemsId1 INT DEFAULT 0;
DECLARE PIHDId1 INT DEFAULT 0;
DECLARE SOHDId1 INT DEFAULT 0;
DECLARE StkAdjHDId1 INT DEFAULT 0;
DECLARE TransferHDId1 INT DEFAULT 0;
DECLARE SuppCreditPayHDId1 INT DEFAULT 0;
DECLARE SupplierId1 INT DEFAULT 0;
DECLARE DirectPurchaseReturnTotal1 DECIMAL(20,2) DEFAULT 0;
DECLARE DirectCashPurchaseReturnTotal1 DECIMAL(20,2) DEFAULT 0;
DECLARE Charges1 DECIMAL(20,2) DEFAULT 0;
DECLARE AdvanceAmount1 DECIMAL(20,2) DEFAULT 0;
DECLARE TranDate1 DATE DEFAULT (select CONVERT_TZ(NOW(), @@session.time_zone, '+05:30'));
DECLARE UTCDate1 date;
SET UTCDate1 = (select CONVERT_TZ(now(), @@session.time_zone, '+05:30'));
SELECT IFNULL((SUM(AdvanceAmount)), 0) INTO AdvanceAmount1
FROM sohd
WHERE (SODate = date1)
AND (CancelStatus = 0);
SELECT IFNULL((SUM(B.Discount)), 0) INTO ItemDiscount1
FROM salesorderhd A
INNER JOIN salesorderdt B
ON A.SOHDId = B.SOHDId
WHERE (A.SODate = date1)
AND (A.CancelStatus = 0);
SELECT IFNULL((SUM(SODiscount)), 0) INTO TotalBillDiscount1
FROM salesorderhd
WHERE (SODate = date1)
AND (CancelStatus = 0);
SET TotalDiscount1 = IFNULL((ItemDiscount1), 0) + IFNULL((TotalBillDiscount1), 0);
SELECT IFNULL((SUM(Charges)), 0) INTO Charges1
FROM salesorderhd
WHERE (SODate = date1)
AND (CancelStatus = 0);
SELECT IFNULL((SUM(VoucherAmount)), 0) INTO ReceivedVoucherTotal1
FROM salesorderhd
WHERE (SODate = date1)
AND (CancelStatus = 0);
SELECT SUM(B.SalesQty * B.SalesPrice) INTO GrossSale
FROM salesorderhd A
INNER JOIN salesorderdt B
ON A.SOHDId = B.SOHDId
WHERE (A.CancelStatus = 0)
AND (A.SODate = date1);
SET TotalSale1 = GrossSale - TotalDiscount1 + Charges1;
SELECT IFNULL((SUM(A.NetAmount)), 0) INTO TotalSalesReturn1
FROM salesreturn A
INNER JOIN salesorderhd B
ON A.SOHDId = B.SOHDId
WHERE (A.RtnDate = date1);
SELECT IFNULL(SUM(B.NetAmount), 0) INTO TotalSalesReturn11
FROM salesorderhd A
INNER JOIN directsalesreturn B
ON A.SOHDId = B.SOHDId
WHERE (A.CancelStatus = 0)
AND (A.SODate = date1);
SELECT IFNULL(SUM(B.NetAmount), 0) INTO TotalSalesReturn2
FROM salesorderhdreturn A
INNER JOIN salesorderdtreturn B
ON A.SOHDId = B.SOHDId
WHERE (A.CancelStatus = 0)
AND (A.SODate = date1)
AND (A.PayModeId <> 1);
SELECT IFNULL(SUM(B.NetAmount), 0) INTO TotalCashSalesReturn2
FROM salesorderhdreturn A
INNER JOIN salesorderdtreturn B
ON A.SOHDId = B.SOHDId
WHERE (A.CancelStatus = 0)
AND (A.SODate = date1)
AND (A.PayModeId = 1);
SELECT IFNULL((SUM(ReturnNoteAmount)), 0) INTO TotalReturnNoteSale1
FROM salesorderhd
WHERE (SODate = date1)
AND (CancelStatus = 0);
SET TotalNetSale1 = IFNULL((TotalSale1), 0) - IFNULL((TotalSalesReturn1 + TotalSalesReturn11 + TotalSalesReturn2 + TotalCashSalesReturn2), 0);
SELECT IFNULL((SUM(SONetTotal-ReturnTotal-VoucherAmount-ReturnNoteAmount-AdvanceAmount)), 0) INTO TotalCashBillSale1
FROM salesorderhd
WHERE (SODate = date1)
AND (PayModeId = 1)
AND (CancelStatus = 0);
SELECT IFNULL((SUM(Cash)), 0) INTO TotalOtherBillCashSale1
FROM salesorderhd
WHERE (SODate = date1)
AND (PayModeId <> 1)
AND (CancelStatus = 0);
SET TotalCashSale1 = IFNULL((TotalCashBillSale1), 0) + IFNULL((TotalOtherBillCashSale1), 0);
SELECT IFNULL((SUM(SONetTotal-ReturnTotal-VoucherAmount-Cash-ReturnNoteAmount-AdvanceAmount)), 0) INTO TotalChequeSale1
FROM salesorderhd
WHERE (SODate = date1)
AND (PayModeId = 2)
AND (CancelStatus = 0);
SELECT IFNULL((SUM(SONetTotal-ReturnTotal-VoucherAmount-Cash-ReturnNoteAmount-AdvanceAmount)), 0) INTO TotalCreditSale1
FROM salesorderhd
WHERE (SODate = date1)
AND (PayModeId = 3)
AND (CancelStatus = 0);
SELECT IFNULL((SUM(SONetTotal-ReturnTotal-VoucherAmount-Cash-ReturnNoteAmount-AdvanceAmount)), 0) INTO TotalCardSale1
FROM salesorderhd
WHERE (SODate = date1)
AND (PayModeId = 4)
AND (CancelStatus = 0);
SELECT IFNULL((SUM(SONetTotal-ReturnTotal-VoucherAmount-Cash-ReturnNoteAmount-AdvanceAmount)), 0) INTO TotalBankTransferSale1
FROM salesorderhd
WHERE (SODate = date1)
AND (PayModeId = 7)
AND (CancelStatus = 0);
SELECT IFNULL((SUM(PaymentAmount)), 0) INTO Expenses1
FROM allexpenses
WHERE (PaymentDate = date1);
SELECT IFNULL((SUM(PaymentAmount)), 0) INTO CashExpenses1
FROM allexpenses
WHERE (PaymentDate = date1)
AND (PayModeId = 1);
SELECT IFNULL((SUM(A.PaymentAmount)),0) INTO CustCreditPayment1
FROM custcreditpayment A
INNER JOIN custcreditpaymenthd H
ON A.CreditPayHDId = H.CreditPayHDId
WHERE (A.PaymentDate = date1)
AND (A.PayModeId = 1)
AND (H.CancelStatus = 0);
SELECT IFNULL((SUM(A.PaymentAmount)),0) INTO CustCreditPaymentCheque1
FROM custcreditpayment A
INNER JOIN custcreditpaymenthd H
ON A.CreditPayHDId = H.CreditPayHDId
WHERE (A.PaymentDate = date1)
AND (A.PayModeId = 2)
AND (H.CancelStatus = 0);
SELECT IFNULL((SUM(A.PaymentAmount)),0) INTO CustCreditPaymentBankTransfer1
FROM custcreditpayment A
INNER JOIN custcreditpaymenthd H
ON A.CreditPayHDId = H.CreditPayHDId
WHERE (A.PaymentDate = date1)
AND (A.PayModeId = 7)
AND (H.CancelStatus = 0);
SELECT IFNULL((SUM(A.PaymentAmount)),0) INTO SuppCreditPayment1
FROM suppcreditpayment A
INNER JOIN suppcreditpaymenthd H
ON A.CreditPayHDId = H.CreditPayHDId
WHERE (A.PaymentDate = date1)
AND (A.PayModeId = 1)
AND (H.CancelStatus = 0);
SELECT IFNULL((SUM(A.PaymentAmount)),0) INTO SuppCreditPaymentCheque1
FROM suppcreditpayment A
INNER JOIN suppcreditpaymenthd H
ON A.CreditPayHDId = H.CreditPayHDId
WHERE (A.PaymentDate = date1)
AND (A.PayModeId = 2)
AND (H.CancelStatus = 0);
SELECT IFNULL((SUM(A.PaymentAmount)),0) INTO SuppCreditPaymentBankTransfer1
FROM suppcreditpayment A
INNER JOIN suppcreditpaymenthd H
ON A.CreditPayHDId = H.CreditPayHDId
WHERE (A.PaymentDate = date1)
AND (A.PayModeId = 7)
AND (H.CancelStatus = 0);
SELECT IFNULL((SUM(OpeningBalance)),0) INTO OpeningCashBalance1
FROM cashbalance
WHERE (BalanceDate = date1);
SELECT IFNULL((SUM(PaymentAmount)), 0) INTO TotalCashIn
FROM paidin
WHERE (PaymentDate = date1);
SELECT IFNULL((SUM(PaymentAmount)), 0) INTO BankDeposit
FROM allexpenses
WHERE (PaymentDate = date1)
AND (PayCatId = 8);
SELECT IFNULL((SUM(VoucherAmount)), 0) INTO IssuedVoucher
FROM giftvoucher
WHERE (IssueDate = date1)
AND (CancelStatus = 0);
SELECT IFNULL((SUM(PINetTotal-ReturnTotal)), 0) INTO TotalPurchase1
FROM pihd
WHERE (PIDate = date1)
AND (CancelStatus = 0);
SELECT IFNULL((SUM(PINetTotal-ReturnTotal)), 0) INTO TotalCashBillPurchase1
FROM pihd
WHERE (PIDate = date1)
AND (PayModeId = 1)
AND (CancelStatus = 0);
SELECT IFNULL((SUM(PICash)), 0) INTO TotalOtherBillCashPurchase1
FROM pihd
WHERE (PIDate = date1)
AND (PayModeId <> 1)
AND (CancelStatus = 0);
SET TotalCashPurchase1 = IFNULL((TotalCashBillPurchase1), 0) + IFNULL((TotalOtherBillCashPurchase1), 0);
SELECT IFNULL((SUM(PINetTotal-ReturnTotal-PICash)), 0) INTO TotalChequePurchase1
FROM pihd
WHERE (PIDate = date1)
AND (PayModeId = 2)
AND (CancelStatus = 0);
SELECT IFNULL((SUM(PINetTotal-ReturnTotal-PICash)), 0) INTO TotalCreditPurchase1
FROM pihd
WHERE (PIDate = date1)
AND (PayModeId = 3)
AND (CancelStatus = 0);
SELECT IFNULL((SUM(PINetTotal-ReturnTotal-PICash)), 0) INTO TotalCardPurchase1
FROM pihd
WHERE (PIDate = date1)
AND (PayModeId = 4)
AND (CancelStatus = 0);
SELECT IFNULL((SUM(PINetTotal-ReturnTotal-PICash)), 0) INTO TotalBankTransferPurchase1
FROM pihd
WHERE (PIDate = date1)
AND (PayModeId = 7)
AND (CancelStatus = 0);
SELECT IFNULL(ExpensesId, 0) INTO ExpensesId1
FROM dayendrecord
WHERE DayEndDate = date1;
SELECT IFNULL(CustCreditPayHDId, 0) INTO CustCreditPayHDId1
FROM dayendrecord
WHERE DayEndDate = date1;
SELECT IFNULL(CustomerId, 0) INTO CustomerId1
FROM dayendrecord
WHERE DayEndDate = date1;
SELECT IFNULL(ItemsId, 0) INTO ItemsId1
FROM dayendrecord
WHERE DayEndDate = date1;
SELECT IFNULL(PIHDId, 0) INTO PIHDId1
FROM dayendrecord
WHERE DayEndDate = date1;
SELECT IFNULL(SOHDId, 0) INTO SOHDId1
FROM dayendrecord
WHERE DayEndDate = date1;
SELECT IFNULL(StkAdjHDId, 0) INTO StkAdjHDId1
FROM dayendrecord
WHERE DayEndDate = date1;
SELECT IFNULL(TransferHDId, 0) INTO TransferHDId1
FROM dayendrecord
WHERE DayEndDate = date1;
SELECT IFNULL(SuppCreditPayHDId, 0) INTO SuppCreditPayHDId1
FROM dayendrecord
WHERE DayEndDate = date1;
SELECT IFNULL(SupplierId, 0) INTO SupplierId1
FROM dayendrecord
WHERE DayEndDate = date1;
SELECT IFNULL((SUM(PINetTotal)), 0) INTO DirectPurchaseReturnTotal1
FROM pihdreturn
WHERE (PIDate = date1)
AND (CancelStatus = 0);
SELECT IFNULL((SUM(PINetTotal)), 0) INTO DirectCashPurchaseReturnTotal1
FROM pihdreturn
WHERE (PIDate = date1)
AND (CancelStatus = 0)
AND (PayModeId = 1);
SELECT TotalSale1 AS TotalSale
, TotalSalesReturn1 + TotalSalesReturn11 + TotalSalesReturn2 + TotalCashSalesReturn2 as TotalSalesReturn
, TotalNetSale1 AS TotalNetSale
, Charges1 AS TotalCharges
, TotalCashSale1 AS TotalCashSale
, TotalChequeSale1 AS TotalChequeSale
, TotalCreditSale1 AS TotalCreditSale
, TotalCardSale1 AS TotalCardSale
, TotalBankTransferSale1 AS TotalBankTransferSale
, TotalPurchase1 AS TotalPurchase
, TotalCashPurchase1 AS TotalCashPurchase
, TotalChequePurchase1 AS TotalChequePurchase
, TotalCreditPurchase1 AS TotalCreditPurchase
, TotalCardPurchase1 AS TotalCardPurchase
, TotalBankTransferPurchase1 AS TotalBankTransferPurchase
, Expenses1 AS Expenses
, CashExpenses1 AS CashExpenses
, CustCreditPayment1 AS CustCreditPayment
, SuppCreditPayment1 AS SuppCreditPayment
, OpeningCashBalance1 AS OpeningCashBalance
, TotalCashIn AS CashIn
, date1 AS TranDate
, BankDeposit AS BankDeposit
, TotalCashSale1 + CustCreditPayment1 + TotalCashIn + IssuedVoucher + DirectCashPurchaseReturnTotal1 + AdvanceAmount1 AS InAmount
, CashExpenses1 + SuppCreditPayment1 + TotalSalesReturn1 + TotalCashSalesReturn2 + TotalCashPurchase1 AS OutAmount
, (OpeningCashBalance1 + TotalCashSale1 + CustCreditPayment1 + TotalCashIn + IssuedVoucher + DirectCashPurchaseReturnTotal1 + AdvanceAmount1) - (CashExpenses1 + SuppCreditPayment1 + TotalSalesReturn1 + TotalCashSalesReturn2 + TotalCashPurchase1) AS LastCashBalance
, IssuedVoucher
, CustCreditPaymentCheque1 as CustCreditPaymentCheque
, SuppCreditPaymentCheque1 as SuppCreditPaymentCheque
, CustCreditPaymentBankTransfer1 AS CustCreditPaymentBankTransfer
, SuppCreditPaymentBankTransfer1 AS SuppCreditPaymentBankTransfer
, TotalDiscount1 AS TotalDiscount
, ReceivedVoucherTotal1 as ReceivedVoucherTotal
, TotalReturnNoteSale1 AS TotalReturnNoteSale
, ExpensesId1 AS ExpensesId
, CustCreditPayHDId1 AS CustCreditPayHDId
, CustomerId1 AS CustomerId
, ItemsId1 AS ItemsId
, PIHDId1 AS PIHDId
, SOHDId1 AS SOHDId
, StkAdjHDId1 AS StkAdjHDId
, TransferHDId1 AS TransferHDId
, SuppCreditPayHDId1 AS SuppCreditPayHDId
, SupplierId1 AS SupplierId
, DirectPurchaseReturnTotal1 AS DirectPurchaseReturnTotal
, DirectCashPurchaseReturnTotal1 AS DirectCashPurchaseReturnTotal
, AdvanceAmount1 as AdvanceAmount
;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `SelectNewSummaryReportBranch`;
DELIMITER |
CREATE PROCEDURE `SelectNewSummaryReportBranch`(in date1 date, BranchId1 int)
BEGIN
DECLARE TotalSale1 DECIMAL(20,2) DEFAULT 0;
DECLARE TotalSalesReturn1 DECIMAL(20,2) DEFAULT 0;
DECLARE TotalSalesReturn11 DECIMAL(20,2) DEFAULT 0;
DECLARE TotalNetSale1 DECIMAL(20,2) DEFAULT 0;
DECLARE TotalCashSale1 DECIMAL(20,2) DEFAULT 0;
DECLARE TotalChequeSale1 DECIMAL(20,2) DEFAULT 0;
DECLARE TotalCreditSale1 DECIMAL(20,2) DEFAULT 0;
DECLARE TotalCardSale1 DECIMAL(20,2) DEFAULT 0;
DECLARE Expenses1 DECIMAL(20,2) DEFAULT 0;
DECLARE CashExpenses1 DECIMAL(20,2) DEFAULT 0;
DECLARE CustCreditPayment1 DECIMAL(20,2) DEFAULT 0;
DECLARE SuppCreditPayment1 DECIMAL(20,2) DEFAULT 0;
DECLARE OpeningCashBalance1 DECIMAL(20,2) DEFAULT 0;
DECLARE LastCashBalance1 DECIMAL(20,2) DEFAULT 0;
DECLARE TotalCashIn DECIMAL(20,2) DEFAULT 0;
DECLARE BankDeposit DECIMAL(20,2) DEFAULT 0;
DECLARE TranDate1 DATE DEFAULT (select CONVERT_TZ(NOW(), @@session.time_zone, '+05:30'));
DECLARE UTCDate1 date;
SET UTCDate1 = (select CONVERT_TZ(now(), @@session.time_zone, '+05:30'));
SELECT IFNULL((SUM(SONetTotal)), 0) INTO TotalSale1
FROM salesorderhd
WHERE (SODate = date1)
AND (CancelStatus = 0)
AND (BranchId = BranchId1);
SELECT IFNULL((SUM(NetAmount)), 0) INTO TotalSalesReturn1
FROM salesreturn
WHERE (RtnDate = date1);
SELECT IFNULL(SUM(directsalesreturn.NetAmount), 0) INTO TotalSalesReturn11
FROM salesorderhd
INNER JOIN directsalesreturn
ON salesorderhd.SOHDId = directsalesreturn.SOHDId
WHERE (salesorderhd.CancelStatus = 0)
AND (salesorderhd.SODate = date1)
AND (salesorderhd.BranchId = BranchId1);
SET TotalNetSale1 = IFNULL((TotalSale1), 0) - IFNULL((TotalSalesReturn1 + TotalSalesReturn11), 0);
SELECT IFNULL((SUM(SONetTotal-ReturnTotal)), 0) INTO TotalCashSale1
FROM salesorderhd
WHERE (SODate = date1)
AND (PayModeId = 1)
AND (CancelStatus = 0)
AND (BranchId = BranchId1);
SELECT IFNULL((SUM(SONetTotal-ReturnTotal)), 0) INTO TotalChequeSale1
FROM salesorderhd
WHERE (SODate = date1)
AND (PayModeId = 2)
AND (CancelStatus = 0)
AND (BranchId = BranchId1);
SELECT IFNULL((SUM(SONetTotal-ReturnTotal)), 0) INTO TotalCreditSale1
FROM salesorderhd
WHERE (SODate = date1)
AND (PayModeId = 3)
AND (CancelStatus = 0)
AND (BranchId = BranchId1);
SELECT IFNULL((SUM(SONetTotal-ReturnTotal)), 0) INTO TotalCardSale1
FROM salesorderhd
WHERE (SODate = date1)
AND (PayModeId = 4)
AND (CancelStatus = 0)
AND (BranchId = BranchId1);
SELECT IFNULL((SUM(PaymentAmount)), 0) INTO Expenses1
FROM allexpenses
WHERE (PaymentDate = date1)
AND (BranchId = BranchId1);
SELECT IFNULL((SUM(PaymentAmount)), 0) INTO CashExpenses1
FROM allexpenses
WHERE (PaymentDate = date1)
AND (PayModeId = 1)
AND (BranchId = BranchId1);
SELECT IFNULL((SUM(A.PaymentAmount)),0) INTO CustCreditPayment1
FROM custcreditpayment A
INNER JOIN salesorderhd B
ON A.BillNo = B.SOHDId
WHERE (A.PaymentDate = date1)
AND (A.PayModeId = 1)
AND (B.BranchId = BranchId1);
SELECT IFNULL((SUM(A.PaymentAmount)),0) INTO SuppCreditPayment1
FROM suppcreditpayment A
INNER JOIN pihd B
ON A.BillNo = B.PIHDId
WHERE (A.PaymentDate = date1)
AND (A.PayModeId = 1)
AND (B.BranchId = BranchId1);
SELECT IFNULL((SUM(OpeningBalance)),0) INTO OpeningCashBalance1
FROM cashbalance
WHERE (BalanceDate = date1)
AND (BranchId = BranchId1);
SELECT IFNULL((SUM(PaymentAmount)), 0) INTO TotalCashIn
FROM paidin
WHERE (PaymentDate = date1)
AND (BranchId = BranchId1);
SELECT IFNULL((SUM(PaymentAmount)), 0) INTO BankDeposit
FROM allexpenses
WHERE (PaymentDate = date1)
AND (PayCatId = 8)
AND (BranchId = BranchId1);
SELECT TotalSale1 AS TotalSale
, TotalSalesReturn1 + TotalSalesReturn11 as TotalSalesReturn
, TotalNetSale1 AS TotalNetSale
, TotalCashSale1 AS TotalCashSale
, TotalChequeSale1 AS TotalChequeSale
, TotalCreditSale1 AS TotalCreditSale
, TotalCardSale1 AS TotalCardSale
, Expenses1 AS Expenses
, CashExpenses1 AS CashExpenses
, CustCreditPayment1 AS CustCreditPayment
, SuppCreditPayment1 AS SuppCreditPayment
, OpeningCashBalance1 AS OpeningCashBalance
, TotalCashIn AS CashIn
, date1 AS TranDate
, BankDeposit AS BankDeposit
, OpeningCashBalance1 + TotalCashSale1 + CustCreditPayment1 + TotalCashIn - (CashExpenses1 + SuppCreditPayment1) AS LastCashBalance;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `SelectNewSummaryReportByBranch`;
DELIMITER |
CREATE PROCEDURE `SelectNewSummaryReportByBranch`(in date1 date, BranchId1 int)
BEGIN
DECLARE GrossSale DECIMAL(20,2) DEFAULT 0;
