DECLARE DirectCashPurchaseReturnTotal1 DECIMAL(20,2) DEFAULT 0;
DECLARE Charges1 DECIMAL(20,2) DEFAULT 0;
DECLARE AdvanceAmount1 DECIMAL(20,2) DEFAULT 0;
DECLARE TranDate1 DATE DEFAULT (select CONVERT_TZ(NOW(), @@session.time_zone, '+05:30'));
DECLARE UTCDate1 date;
DECLARE UserName1 VARCHAR(45);
SET UTCDate1 = (select CONVERT_TZ(now(), @@session.time_zone, '+05:30'));

if (UserID1 = 0) then
begin
set UserName1 = "";
end;
else
begin

SELECT UserName INTO UserName1
FROM useraccount
WHERE (UserID = UserID1);

end;
end if;

SELECT IFNULL((SUM(AdvanceAmount)), 0) INTO AdvanceAmount1
FROM sohd
WHERE (SODate = date1)
AND (CancelStatus = 0)
AND CASE BranchId1 WHEN 0 THEN BranchId ELSE BranchId1 END = BranchId
AND CASE UserID1 WHEN 0 THEN CreatedBy ELSE UserID1 END = CreatedBy;

SELECT IFNULL((SUM(B.Discount)), 0) INTO ItemDiscount1
FROM salesorderhd A
INNER JOIN salesorderdt B
ON A.SOHDId = B.SOHDId
WHERE (A.SODate = date1)
AND (A.CancelStatus = 0)
AND CASE BranchId1 WHEN 0 THEN A.BranchId ELSE BranchId1 END = A.BranchId
AND CASE UserID1 WHEN 0 THEN A.CreatedBy ELSE UserID1 END = A.CreatedBy;

SELECT IFNULL((SUM(SODiscount)), 0) INTO TotalBillDiscount1
FROM salesorderhd
WHERE (SODate = date1)
AND (CancelStatus = 0)
AND CASE BranchId1 WHEN 0 THEN BranchId ELSE BranchId1 END = BranchId
AND CASE UserID1 WHEN 0 THEN CreatedBy ELSE UserID1 END = CreatedBy;

SET TotalDiscount1 = IFNULL((ItemDiscount1), 0) + IFNULL((TotalBillDiscount1), 0);
SELECT IFNULL((SUM(Charges)), 0) INTO Charges1
