WHERE (A.PaymentDate = date1)
AND (A.PayModeId = 1)
AND (H.CancelStatus = 0)
AND CASE BranchId1 WHEN 0 THEN H.BranchId ELSE BranchId1 END = H.BranchId
AND CASE UserID1 WHEN 0 THEN H.CreatedBy ELSE UserID1 END = H.CreatedBy;
SELECT IFNULL((SUM(A.PaymentAmount)),0) INTO CustCreditPaymentCheque1
FROM custcreditpayment A
INNER JOIN custcreditpaymenthd H
ON A.CreditPayHDId = H.CreditPayHDId
WHERE (A.PaymentDate = date1)
AND (A.PayModeId = 2)
AND (H.CancelStatus = 0)
AND CASE BranchId1 WHEN 0 THEN H.BranchId ELSE BranchId1 END = H.BranchId
AND CASE UserID1 WHEN 0 THEN H.CreatedBy ELSE UserID1 END = H.CreatedBy;
SELECT IFNULL((SUM(A.PaymentAmount)),0) INTO CustCreditPaymentBankTransfer1
FROM custcreditpayment A
INNER JOIN custcreditpaymenthd H
ON A.CreditPayHDId = H.CreditPayHDId
WHERE (A.PaymentDate = date1)
AND (A.PayModeId = 7)
AND (H.CancelStatus = 0)
AND CASE BranchId1 WHEN 0 THEN H.BranchId ELSE BranchId1 END = H.BranchId
AND CASE UserID1 WHEN 0 THEN H.CreatedBy ELSE UserID1 END = H.CreatedBy;
SELECT IFNULL((SUM(A.PaymentAmount)),0) INTO SuppCreditPayment1
FROM suppcreditpayment A
INNER JOIN suppcreditpaymenthd H
ON A.CreditPayHDId = H.CreditPayHDId
WHERE (A.PaymentDate = date1)
AND (A.PayModeId = 1)
AND (H.CancelStatus = 0)
AND CASE BranchId1 WHEN 0 THEN H.BranchId ELSE BranchId1 END = H.BranchId
AND CASE UserID1 WHEN 0 THEN H.CreatedBy ELSE UserID1 END = H.CreatedBy;
SELECT IFNULL((SUM(A.PaymentAmount)),0) INTO SuppCreditPaymentCheque1
FROM suppcreditpayment A
INNER JOIN suppcreditpaymenthd H
ON A.CreditPayHDId = H.CreditPayHDId
WHERE (A.PaymentDate = date1)
AND (A.PayModeId = 2)
AND (H.CancelStatus = 0)
AND CASE BranchId1 WHEN 0 THEN H.BranchId ELSE BranchId1 END = H.BranchId
AND CASE UserID1 WHEN 0 THEN H.CreatedBy ELSE UserID1 END = H.CreatedBy;
SELECT IFNULL((SUM(A.PaymentAmount)),0) INTO SuppCreditPaymentBankTransfer1
FROM suppcreditpayment A
INNER JOIN suppcreditpaymenthd H
ON A.CreditPayHDId = H.CreditPayHDId
WHERE (A.PaymentDate = date1)
AND (A.PayModeId = 7)
AND (H.CancelStatus = 0)
AND CASE BranchId1 WHEN 0 THEN H.BranchId ELSE BranchId1 END = H.BranchId
AND CASE UserID1 WHEN 0 THEN H.CreatedBy ELSE UserID1 END = H.CreatedBy;
SELECT IFNULL((SUM(OpeningBalance)),0) INTO OpeningCashBalance1
FROM cashbalance
WHERE (BalanceDate = date1)
AND CASE BranchId1 WHEN 0 THEN BranchId ELSE BranchId1 END = BranchId
AND CASE UserID1 WHEN 0 THEN UserId ELSE UserID1 END = UserId;
SELECT IFNULL((SUM(PaymentAmount)), 0) INTO TotalCashIn
FROM paidin
WHERE (PaymentDate = date1)
AND CASE BranchId1 WHEN 0 THEN BranchId ELSE BranchId1 END = BranchId
AND CASE UserID1 WHEN 0 THEN CreatedBy ELSE UserID1 END = CreatedBy;
SELECT IFNULL((SUM(PaymentAmount)), 0) INTO BankDeposit
FROM allexpenses
WHERE (PaymentDate = date1)
AND (PayCatId = 8)
AND CASE BranchId1 WHEN 0 THEN BranchId ELSE BranchId1 END = BranchId
AND CASE UserID1 WHEN 0 THEN CreatedBy ELSE UserID1 END = CreatedBy;

SELECT IFNULL((SUM(VoucherAmount)), 0) INTO IssuedVoucher
FROM giftvoucher
WHERE (IssueDate = date1)
AND (CancelStatus = 0)
AND CASE BranchId1 WHEN 0 THEN BranchId ELSE BranchId1 END = BranchId
AND CASE UserID1 WHEN 0 THEN CreatedBy ELSE UserID1 END = CreatedBy;

SELECT IFNULL((SUM(PINetTotal-ReturnTotal)), 0) INTO TotalPurchase1
FROM pihd
WHERE (PIDate = date1)
AND (CancelStatus = 0)
AND CASE BranchId1 WHEN 0 THEN BranchId ELSE BranchId1 END = BranchId
AND CASE UserID1 WHEN 0 THEN CreatedBy ELSE UserID1 END = CreatedBy;
SELECT IFNULL((SUM(PINetTotal-ReturnTotal)), 0) INTO TotalCashBillPurchase1
FROM pihd
WHERE (PIDate = date1)
AND (PayModeId = 1)
AND (CancelStatus = 0)
AND CASE BranchId1 WHEN 0 THEN BranchId ELSE BranchId1 END = BranchId
AND CASE UserID1 WHEN 0 THEN CreatedBy ELSE UserID1 END = CreatedBy;
SELECT IFNULL((SUM(PICash)), 0) INTO TotalOtherBillCashPurchase1
FROM pihd
WHERE (PIDate = date1)
AND (PayModeId <> 1)
AND (CancelStatus = 0)
AND CASE BranchId1 WHEN 0 THEN BranchId ELSE BranchId1 END = BranchId
AND CASE UserID1 WHEN 0 THEN CreatedBy ELSE UserID1 END = CreatedBy;
SET TotalCashPurchase1 = IFNULL((TotalCashBillPurchase1), 0) + IFNULL((TotalOtherBillCashPurchase1), 0);
SELECT IFNULL((SUM(PINetTotal-ReturnTotal-PICash)), 0) INTO TotalChequePurchase1
FROM pihd
WHERE (PIDate = date1)
AND (PayModeId = 2)
AND (CancelStatus = 0)
AND CASE BranchId1 WHEN 0 THEN BranchId ELSE BranchId1 END = BranchId
AND CASE UserID1 WHEN 0 THEN CreatedBy ELSE UserID1 END = CreatedBy;
SELECT IFNULL((SUM(PINetTotal-ReturnTotal-PICash)), 0) INTO TotalCreditPurchase1
FROM pihd
WHERE (PIDate = date1)
AND (PayModeId = 3)
AND (CancelStatus = 0)
AND CASE BranchId1 WHEN 0 THEN BranchId ELSE BranchId1 END = BranchId
AND CASE UserID1 WHEN 0 THEN CreatedBy ELSE UserID1 END = CreatedBy;
SELECT IFNULL((SUM(PINetTotal-ReturnTotal-PICash)), 0) INTO TotalCardPurchase1
FROM pihd
WHERE (PIDate = date1)
AND (PayModeId = 4)
AND (CancelStatus = 0)
AND CASE BranchId1 WHEN 0 THEN BranchId ELSE BranchId1 END = BranchId
AND CASE UserID1 WHEN 0 THEN CreatedBy ELSE UserID1 END = CreatedBy;
SELECT IFNULL((SUM(PINetTotal-ReturnTotal-PICash)), 0) INTO TotalBankTransferPurchase1
FROM pihd
WHERE (PIDate = date1)
AND (PayModeId = 7)
AND (CancelStatus = 0)
AND CASE BranchId1 WHEN 0 THEN BranchId ELSE BranchId1 END = BranchId
AND CASE UserID1 WHEN 0 THEN CreatedBy ELSE UserID1 END = CreatedBy;


SELECT IFNULL(ExpensesId, 0) INTO ExpensesId1
FROM dayendrecord
WHERE DayEndDate = date1
AND CASE BranchId1 WHEN 0 THEN BranchId ELSE BranchId1 END = BranchId;
SELECT IFNULL(CustCreditPayHDId, 0) INTO CustCreditPayHDId1
FROM dayendrecord
WHERE DayEndDate = date1
AND CASE BranchId1 WHEN 0 THEN BranchId ELSE BranchId1 END = BranchId;
SELECT IFNULL(CustomerId, 0) INTO CustomerId1
FROM dayendrecord
WHERE DayEndDate = date1
AND CASE BranchId1 WHEN 0 THEN BranchId ELSE BranchId1 END = BranchId;
SELECT IFNULL(ItemsId, 0) INTO ItemsId1
FROM dayendrecord
WHERE DayEndDate = date1
AND CASE BranchId1 WHEN 0 THEN BranchId ELSE BranchId1 END = BranchId;
SELECT IFNULL(PIHDId, 0) INTO PIHDId1
FROM dayendrecord
WHERE DayEndDate = date1
AND CASE BranchId1 WHEN 0 THEN BranchId ELSE BranchId1 END = BranchId;
SELECT IFNULL(SOHDId, 0) INTO SOHDId1
FROM dayendrecord
WHERE DayEndDate = date1
AND CASE BranchId1 WHEN 0 THEN BranchId ELSE BranchId1 END = BranchId;
SELECT IFNULL(StkAdjHDId, 0) INTO StkAdjHDId1
FROM dayendrecord
WHERE DayEndDate = date1
AND CASE BranchId1 WHEN 0 THEN BranchId ELSE BranchId1 END = BranchId;
SELECT IFNULL(TransferHDId, 0) INTO TransferHDId1
FROM dayendrecord
WHERE DayEndDate = date1
AND CASE BranchId1 WHEN 0 THEN BranchId ELSE BranchId1 END = BranchId;
SELECT IFNULL(SuppCreditPayHDId, 0) INTO SuppCreditPayHDId1
FROM dayendrecord
WHERE DayEndDate = date1
AND CASE BranchId1 WHEN 0 THEN BranchId ELSE BranchId1 END = BranchId;
SELECT IFNULL(SupplierId, 0) INTO SupplierId1
FROM dayendrecord
WHERE DayEndDate = date1
AND CASE BranchId1 WHEN 0 THEN BranchId ELSE BranchId1 END = BranchId;
SELECT IFNULL((SUM(PINetTotal)), 0) INTO DirectPurchaseReturnTotal1
FROM pihdreturn
WHERE (PIDate = date1)
AND (CancelStatus = 0)
AND CASE BranchId1 WHEN 0 THEN BranchId ELSE BranchId1 END = BranchId
AND CASE UserID1 WHEN 0 THEN CreatedBy ELSE UserID1 END = CreatedBy;
SELECT IFNULL((SUM(PINetTotal)), 0) INTO DirectCashPurchaseReturnTotal1
FROM pihdreturn
WHERE (PIDate = date1)
AND (CancelStatus = 0)
AND (PayModeId = 1)
AND CASE BranchId1 WHEN 0 THEN BranchId ELSE BranchId1 END = BranchId
AND CASE UserID1 WHEN 0 THEN CreatedBy ELSE UserID1 END = CreatedBy;

if (UserID1 = 0) then
begin
SELECT TotalSale1 AS TotalSale
, TotalSalesReturn1 + TotalSalesReturn11 + TotalSalesReturn2 + TotalCashSalesReturn2 as TotalSalesReturn
, TotalNetSale1 AS TotalNetSale
, Charges1 AS TotalCharges
, TotalCashSale1 AS TotalCashSale
, TotalChequeSale1 AS TotalChequeSale
, TotalCreditSale1 AS TotalCreditSale
, TotalCardSale1 AS TotalCardSale
, TotalBankTransferSale1 AS TotalBankTransferSale
, TotalPurchase1 AS TotalPurchase
, TotalCashPurchase1 AS TotalCashPurchase
, TotalChequePurchase1 AS TotalChequePurchase
, TotalCreditPurchase1 AS TotalCreditPurchase
, TotalCardPurchase1 AS TotalCardPurchase
, TotalBankTransferPurchase1 AS TotalBankTransferPurchase
, Expenses1 AS Expenses
, CashExpenses1 AS CashExpenses
, CustCreditPayment1 AS CustCreditPayment
, SuppCreditPayment1 AS SuppCreditPayment
, OpeningCashBalance1 AS OpeningCashBalance
, TotalCashIn AS CashIn
, date1 AS TranDate
, BankDeposit AS BankDeposit
, TotalCashSale1 + CustCreditPayment1 + TotalCashIn + IssuedVoucher + DirectCashPurchaseReturnTotal1 + AdvanceAmount1 AS InAmount
, CashExpenses1 + SuppCreditPayment1 + TotalSalesReturn1 + TotalCashSalesReturn2 + TotalCashPurchase1 AS OutAmount
, (OpeningCashBalance1 + TotalCashSale1 + CustCreditPayment1 + TotalCashIn + IssuedVoucher + DirectCashPurchaseReturnTotal1 + AdvanceAmount1) - (CashExpenses1 + SuppCreditPayment1 + TotalSalesReturn1 + TotalCashSalesReturn2 + TotalCashPurchase1) AS LastCashBalance
, IssuedVoucher
, CustCreditPaymentCheque1 as CustCreditPaymentCheque
, SuppCreditPaymentCheque1 as SuppCreditPaymentCheque
, CustCreditPaymentBankTransfer1 AS CustCreditPaymentBankTransfer
, SuppCreditPaymentBankTransfer1 AS SuppCreditPaymentBankTransfer
, TotalDiscount1 AS TotalDiscount
, ReceivedVoucherTotal1 as ReceivedVoucherTotal
, TotalReturnNoteSale1 AS TotalReturnNoteSale
, ExpensesId1 AS ExpensesId
, CustCreditPayHDId1 AS CustCreditPayHDId
, CustomerId1 AS CustomerId
, ItemsId1 AS ItemsId
, PIHDId1 AS PIHDId
, SOHDId1 AS SOHDId
, StkAdjHDId1 AS StkAdjHDId
, TransferHDId1 AS TransferHDId
, SuppCreditPayHDId1 AS SuppCreditPayHDId
, SupplierId1 AS SupplierId
, DirectPurchaseReturnTotal1 AS DirectPurchaseReturnTotal
, DirectCashPurchaseReturnTotal1 AS DirectCashPurchaseReturnTotal
, AdvanceAmount1 as AdvanceAmount
, X.UserName
, X.CashAmount
, X.NoOfPieces
, X.GrossAmount
FROM(SELECT XX.UserName
, XX.CashAmount AS CashAmount
, SUM(XX.NoOfPieces) AS NoOfPieces
, SUM(XX.GrossAmount) AS GrossAmount
FROM(SELECT UserName1 AS UserName
, 0 AS CashAmount
, 0 AS NoOfPieces
, 0 AS GrossAmount
UNION ALL
SELECT UserName1 AS UserName
, B.CashAmount AS CashAmount
, SUM(B.NoOfPieces) AS NoOfPieces
, SUM(B.GrossAmount) AS GrossAmount
FROM cashcollectionhd A
INNER JOIN cashcollectiondt B
ON A.CashCollectionhdId = B.CashCollectionhdId
WHERE A.CollectionDate = date1
group by B.CashAmount
)XX
GROUP BY XX.UserName, XX.CashAmount)X
;

end;
else
begin

SELECT TotalSale1 AS TotalSale
, TotalSalesReturn1 + TotalSalesReturn11 + TotalSalesReturn2 + TotalCashSalesReturn2 as TotalSalesReturn
, TotalNetSale1 AS TotalNetSale
, Charges1 AS TotalCharges
, TotalCashSale1 AS TotalCashSale
, TotalChequeSale1 AS TotalChequeSale
, TotalCreditSale1 AS TotalCreditSale
, TotalCardSale1 AS TotalCardSale
, TotalBankTransferSale1 AS TotalBankTransferSale
, TotalPurchase1 AS TotalPurchase
, TotalCashPurchase1 AS TotalCashPurchase
, TotalChequePurchase1 AS TotalChequePurchase
, TotalCreditPurchase1 AS TotalCreditPurchase
, TotalCardPurchase1 AS TotalCardPurchase
, TotalBankTransferPurchase1 AS TotalBankTransferPurchase
, Expenses1 AS Expenses
, CashExpenses1 AS CashExpenses
, CustCreditPayment1 AS CustCreditPayment
, SuppCreditPayment1 AS SuppCreditPayment
, OpeningCashBalance1 AS OpeningCashBalance
, TotalCashIn AS CashIn
, date1 AS TranDate
, BankDeposit AS BankDeposit
, TotalCashSale1 + CustCreditPayment1 + TotalCashIn + IssuedVoucher + DirectCashPurchaseReturnTotal1 + AdvanceAmount1 AS InAmount
, CashExpenses1 + SuppCreditPayment1 + TotalSalesReturn1 + TotalCashSalesReturn2 + TotalCashPurchase1 AS OutAmount
, (OpeningCashBalance1 + TotalCashSale1 + CustCreditPayment1 + TotalCashIn + IssuedVoucher + DirectCashPurchaseReturnTotal1 + AdvanceAmount1) - (CashExpenses1 + SuppCreditPayment1 + TotalSalesReturn1 + TotalCashSalesReturn2 + TotalCashPurchase1) AS LastCashBalance
, IssuedVoucher
, CustCreditPaymentCheque1 as CustCreditPaymentCheque
, SuppCreditPaymentCheque1 as SuppCreditPaymentCheque
, CustCreditPaymentBankTransfer1 AS CustCreditPaymentBankTransfer
, SuppCreditPaymentBankTransfer1 AS SuppCreditPaymentBankTransfer
, TotalDiscount1 AS TotalDiscount
, ReceivedVoucherTotal1 as ReceivedVoucherTotal
, TotalReturnNoteSale1 AS TotalReturnNoteSale
, ExpensesId1 AS ExpensesId
, CustCreditPayHDId1 AS CustCreditPayHDId
, CustomerId1 AS CustomerId
, ItemsId1 AS ItemsId
, PIHDId1 AS PIHDId
, SOHDId1 AS SOHDId
, StkAdjHDId1 AS StkAdjHDId
, TransferHDId1 AS TransferHDId
, SuppCreditPayHDId1 AS SuppCreditPayHDId
, SupplierId1 AS SupplierId
, DirectPurchaseReturnTotal1 AS DirectPurchaseReturnTotal
, DirectCashPurchaseReturnTotal1 AS DirectCashPurchaseReturnTotal
, AdvanceAmount1 as AdvanceAmount
, X.UserName
, X.CashAmount
, X.NoOfPieces
, X.GrossAmount
FROM(SELECT XX.UserName
, XX.CashAmount AS CashAmount
, SUM(XX.NoOfPieces) AS NoOfPieces
, SUM(XX.GrossAmount) AS GrossAmount
FROM(SELECT UserName1 AS UserName
, 0 AS CashAmount
, 0 AS NoOfPieces
, 0 AS GrossAmount
UNION ALL
SELECT UserName1 AS UserName
, B.CashAmount
, B.NoOfPieces
, B.GrossAmount
FROM cashcollectionhd A
INNER JOIN cashcollectiondt B
ON A.CashCollectionhdId = B.CashCollectionhdId
WHERE A.CollectionDate = date1
AND A.UserId = UserID1)XX
GROUP BY XX.UserName, XX.CashAmount)X
;

end;
end if;


END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `SelectOldPassword`;
DELIMITER |
CREATE PROCEDURE `SelectOldPassword`(in USERID1 int, PASWORD1 nvarchar(30))
BEGIN
SELECT        Password
FROM            useraccount
WHERE        (UserID =  USERID1) AND (Password =  PASWORD1);
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `SelectPaymodes`;
DELIMITER |
CREATE PROCEDURE `SelectPaymodes`()
BEGIN
SELECT        PayModeId, PayMode
FROM            paymentmode
Where PayModeId not in(3, 4)
ORDER BY PayModeId;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `SelectPendingDepriaciationFixedAssets`;
DELIMITER |
CREATE PROCEDURE `SelectPendingDepriaciationFixedAssets`(
)
BEGIN
SELECT FAId
, AssetCode
, AssetDescription
, Qty
, UnitPrice
, Amount
, DepreciatedAmount
, NetAmount
, DepreciationPerPeriod
, TotalDepreciationPeriod
, RemainingDepreciationPeriod
, WarrantyPeriod
, DepreciationStartDate
, NextDepreciationDate
, LastDepreciationDate
FROM fixedasset
WHERE RemainingDepreciationPeriod > 0
AND NextDepreciationDate <= curdate()
ORDER BY FAId;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `SelectPendingStock`;
DELIMITER |
CREATE PROCEDURE `SelectPendingStock`(in BranchId1 int)
BEGIN
SELECT        A.ItemCode, B.ItemName, A.AvailableQty, A.ItemsId
FROM            branchstock A INNER JOIN
itemsummary B ON A.ItemsId = B.ItemsId
WHERE        (A.BranchId = BranchId1)
ORDER BY A.ItemCode;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `SelectPermission`;
DELIMITER |
CREATE PROCEDURE `SelectPermission`(in USERID1 int)
BEGIN
SELECT DISTINCT roles.ROLE_TITLE
FROM user_roles
INNER JOIN roles
ON user_roles.ROLE_ID = roles.ROLE_ID
WHERE (user_roles.USER_ID =  USERID1)
AND roles.ApprovedRole = 1;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `SelectPIByDate`;
DELIMITER |
CREATE PROCEDURE `SelectPIByDate`(in date1 date, date2 date)
BEGIN
SELECT        A.PIHDId, A.PINo as InvoiceNo, A.PIDate as InvoiceDate, A.SupplierInvoiceNo, B.SupplierName, B.Address, A.ContactPerson, A.PINetTotal AS InvoiceAmount, A.Remarks
, CASE A.CancelStatus
WHEN 1 THEN 'Cancelled'
ELSE ' '
END AS InvoiceStatus
FROM            pihd A INNER JOIN
supplier B ON A.SupplierId = B.SupplierId
WHERE        (A.PIDate BETWEEN date1 AND date2)
ORDER BY A.PIDate DESC, A.PIHDId DESC;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `SelectPIByDateSupplier`;
DELIMITER |
CREATE PROCEDURE `SelectPIByDateSupplier`(in date1 date, date2 date, SupplierId1 int)
BEGIN
SELECT        A.PIHDId, A.PINo as InvoiceNo, A.PIDate as InvoiceDate, A.SupplierInvoiceNo, B.SupplierName, B.Address, A.ContactPerson, A.PINetTotal AS InvoiceAmount, A.Remarks
, CASE A.CancelStatus
WHEN 1 THEN 'Cancelled'
ELSE ' '
END AS InvoiceStatus
FROM            pihd A INNER JOIN
supplier B ON A.SupplierId = B.SupplierId
WHERE        (A.PIDate BETWEEN date1 AND date2) and (A.SupplierId = SupplierId1)
ORDER BY A.PIDate DESC, A.PIHDId DESC;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `SelectPIHDIdData`;
DELIMITER |
CREATE PROCEDURE `SelectPIHDIdData`(in PIHDId1 int)
BEGIN
SELECT A.PIHDId
, A.PINo
, A.PIDate
, A.SupplierId
, B.Address
, A.ContactPerson
, A.PIGrossTotal
, A.Remarks
, A.PIDiscount
, A.PINetTotal
, A.PICash
, A.PIBalance
, A.PayModeId
, A.SupplierInvoiceNo
FROM pihd A
INNER JOIN supplier B
ON A.SupplierId = B.SupplierId
WHERE (A.PIHDId = PIHDId1);
SELECT A.PIDTId
, A.PIHDId
, A.ItemsId
, A.ItemCode
, A.ItemCatId
, A.ItemUnit
, A.PurchaseQty
, A.MinQty
, A.PurchasePrice
, A.SellingPrice
, A.FreeIssue
, A.NetAmount
, B.ItemName
, A.Discount
, B.SPSellingPrice
, B.ShopPrice
, A.SerialNo
, A.FromBranchId
FROM pidt A
INNER JOIN itemsummary B
ON A.ItemsId = B.ItemsId
WHERE (A.PIHDId = PIHDId1)
ORDER BY A.PIDTId;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `SelectPIID`;
DELIMITER |
CREATE PROCEDURE `SelectPIID`()
BEGIN
SELECT IFNULL(MAX(PIHDId), 0) + 1 AS PIHDId FROM pihd;
SELECT IFNULL(MAX(PIHDId), 0) + 1 AS PIHDId FROM pihdreturn;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `SelectPIRetuenByDate`;
DELIMITER |
CREATE PROCEDURE `SelectPIRetuenByDate`(in date1 date, date2 date)
BEGIN
SELECT        A.PIHDId, A.PINo as ReturnNo, A.PIDate as ReturnDate, A.SupplierInvoiceNo, B.SupplierName, B.Address, A.ContactPerson, A.PINetTotal AS InvoiceAmount, A.Remarks
FROM pihdreturn A
INNER JOIN supplier B
ON A.SupplierId = B.SupplierId
WHERE (A.PIDate BETWEEN date1 AND date2)
ORDER BY A.PIDate DESC, A.PIHDId DESC;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `SelectPOByDate`;
DELIMITER |
CREATE PROCEDURE `SelectPOByDate`(in date1 date, date2 date)
BEGIN
SELECT        A.POHDId, A.PONo, A.PODate, B.SupplierName, B.Address, A.ContactPerson, A.PONetTotal AS POAmount, A.Remarks
FROM            pohd A INNER JOIN
supplier B ON A.SupplierId = B.SupplierId
WHERE        (A.PODate BETWEEN date1 AND date2)
ORDER BY A.PODate DESC, A.POHDId DESC;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `SelectPOByDateSupplier`;
DELIMITER |
CREATE PROCEDURE `SelectPOByDateSupplier`(in date1 date, date2 date, SupplierId1 int)
BEGIN
SELECT        A.POHDId, A.PONo, A.PODate, B.SupplierName, B.Address, A.ContactPerson, A.PONetTotal AS POAmount, A.Remarks
FROM            pohd A INNER JOIN
supplier B ON A.SupplierId = B.SupplierId
WHERE        (A.PODate BETWEEN date1 AND date2) and (A.SupplierId = SupplierId1)
ORDER BY A.PODate DESC, A.POHDId DESC;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `SelectPODataCategory`;
DELIMITER |
CREATE PROCEDURE `SelectPODataCategory`(in ItemCatId1 int)
BEGIN
SELECT        purchaseorderhd.POHDId, purchaseorderhd.PONo, supplier.SupplierName, purchaseorderhd.PurchaseDate, paymentmode.PayMode, purchaseorderhd.InvoiceNo,
purchaseorderdt.ItemCode, itemcategory.ItemCatName AS ItemCategory, purchaseorderdt.ItemName, purchaseorderdt.ItemLocation, purchaseorderdt.PurchaseQty,
purchaseorderdt.PurchasePrice, itemsummary.MinQty, itemsummary.AvailableQty, purchaseorderdt.Discount, purchaseorderdt.NetAmount
FROM            purchaseorderhd INNER JOIN
purchaseorderdt ON purchaseorderhd.POHDId = purchaseorderdt.POHDId INNER JOIN
supplier ON purchaseorderhd.SupplierId = supplier.SupplierId INNER JOIN
paymentmode ON purchaseorderhd.PayModeId = paymentmode.PayModeId INNER JOIN
itemsummary ON purchaseorderdt.ItemCode = itemsummary.ItemCode INNER JOIN
itemcategory ON purchaseorderdt.ItemCatId = itemcategory.ItemCatId
WHERE        (purchaseorderdt.ItemCatId = ItemCatId1)
ORDER BY purchaseorderhd.POHDId, purchaseorderhd.PurchaseDate;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `SelectPODataDateRange`;
DELIMITER |
CREATE PROCEDURE `SelectPODataDateRange`(in date1 date, date2 date)
BEGIN
SELECT        purchaseorderhd.POHDId, purchaseorderhd.PONo, supplier.SupplierName, purchaseorderhd.PurchaseDate, paymentmode.PayMode, purchaseorderhd.InvoiceNo,
purchaseorderdt.ItemCode, itemcategory.ItemCatName AS ItemCategory, purchaseorderdt.ItemName, purchaseorderdt.ItemLocation, purchaseorderdt.PurchaseQty,
purchaseorderdt.PurchasePrice, itemsummary.MinQty, itemsummary.AvailableQty, purchaseorderdt.Discount, purchaseorderdt.NetAmount
FROM            purchaseorderhd INNER JOIN
purchaseorderdt ON purchaseorderhd.POHDId = purchaseorderdt.POHDId INNER JOIN
supplier ON purchaseorderhd.SupplierId = supplier.SupplierId INNER JOIN
paymentmode ON purchaseorderhd.PayModeId = paymentmode.PayModeId INNER JOIN
itemsummary ON purchaseorderdt.ItemCode = itemsummary.ItemCode INNER JOIN
itemcategory ON purchaseorderdt.ItemCatId = itemcategory.ItemCatId
WHERE        (purchaseorderhd.PurchaseDate BETWEEN date1 AND date2)
ORDER BY purchaseorderhd.POHDId, purchaseorderhd.PurchaseDate;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `SelectPODataSupplier`;
DELIMITER |
CREATE PROCEDURE `SelectPODataSupplier`(in SupplierId1 int)
BEGIN
SELECT        purchaseorderhd.POHDId, purchaseorderhd.PONo, supplier.SupplierName, purchaseorderhd.PurchaseDate, paymentmode.PayMode, purchaseorderhd.InvoiceNo,
purchaseorderdt.ItemCode, itemcategory.ItemCatName AS ItemCategory, purchaseorderdt.ItemName, purchaseorderdt.ItemLocation, purchaseorderdt.PurchaseQty,
purchaseorderdt.PurchasePrice, itemsummary.MinQty, itemsummary.AvailableQty, purchaseorderdt.Discount, purchaseorderdt.NetAmount
FROM            purchaseorderhd INNER JOIN
purchaseorderdt ON purchaseorderhd.POHDId = purchaseorderdt.POHDId INNER JOIN
supplier ON purchaseorderhd.SupplierId = supplier.SupplierId INNER JOIN
paymentmode ON purchaseorderhd.PayModeId = paymentmode.PayModeId INNER JOIN
itemsummary ON purchaseorderdt.ItemCode = itemsummary.ItemCode INNER JOIN
itemcategory ON purchaseorderdt.ItemCatId = itemcategory.ItemCatId
WHERE        (purchaseorderhd.SupplierId = SupplierId1)
ORDER BY purchaseorderhd.POHDId, purchaseorderhd.PurchaseDate;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `SelectPOHDIdData`;
DELIMITER |
CREATE PROCEDURE `SelectPOHDIdData`(in POHDId1 int)
BEGIN
SELECT        purchaseorderhd.PONo, purchaseorderhd.InvoiceNo, purchaseorderhd.PurchaseDate, purchaseorderhd.SupplierId, purchaseorderhd.PayModeId, suppliercheque.ChequeBank, suppliercheque.ChequeNo,
suppliercheque.ChequeExpDate, purchaseorderhd.Remarks, purchaseorderhd.POGrossTotal, purchaseorderhd.PODiscount, purchaseorderhd.PONetTotal, purchaseorderhd.POCash,
purchaseorderhd.POBalance
FROM            purchaseorderhd LEFT OUTER JOIN
suppliercheque ON purchaseorderhd.POHDId = suppliercheque.POHDId
WHERE        (purchaseorderhd.POHDId = POHDId1);
SELECT        purchaseorderdt.PODTId, purchaseorderdt.POHDId, purchaseorderdt.ItemCode, purchaseorderdt.ItemCatId, itemcategory.ItemCatName AS ItemCategory, purchaseorderdt.ItemName, purchaseorderdt.ItemUnit,
purchaseorderdt.ItemLocation, purchaseorderdt.PurchaseQty, purchaseorderdt.MinQty, purchaseorderdt.PurchasePrice, itemsummary.SellingPrice,
purchaseorderdt.PurchasePrice * purchaseorderdt.PurchaseQty AS GrossAmount, purchaseorderdt.Discount, purchaseorderdt.NetAmount
FROM            purchaseorderdt INNER JOIN
itemcategory ON purchaseorderdt.ItemCatId = itemcategory.ItemCatId INNER JOIN
itemsummary ON purchaseorderdt.ItemCode = itemsummary.ItemCode
WHERE        (purchaseorderdt.POHDId = POHDId1);
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `SelectPOID`;
DELIMITER |
CREATE PROCEDURE `SelectPOID`()
BEGIN
select IFNULL(MAX(POHDId), 0) + 1 AS POHDId from purchaseorderhd;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `SelectPOLoad`;
DELIMITER |
CREATE PROCEDURE `SelectPOLoad`()
BEGIN
SELECT SupplierId, SupplierName
FROM supplier
WHERE ExpenseStatus = 0
ORDER BY SupplierName;
SELECT        PayModeId, PayMode
FROM            paymentmode
Where PayModeId <> 5
ORDER BY PayModeId;
SELECT        ItemCatId, ItemCatName
FROM            itemcategory
ORDER BY ItemCatName;
SELECT        ItemCatId, ItemCatName
FROM            itemcategory
ORDER BY ItemCatName;
SELECT        PayCatId, CatDescription
FROM            expensescategory
ORDER BY CatDescription;
SELECT BranchId, BranchName
FROM branch
ORDER BY BranchId;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `SelectPOrderData`;
DELIMITER |
CREATE PROCEDURE `SelectPOrderData`(IN POHDId1 int)
BEGIN
SELECT POHDId
, PONo
, SupplierId
, PODate
, ContactPerson
, POGrossTotal
, PONetTotal
, Remarks
FROM pohd
WHERE (POHDId = POHDId1);
SELECT A.PODTId
, A.POHDId
, A.ItemsId
, A.ItemCode
, A.ItemCatId
, A.ItemUnit
, A.PurchaseQty
, A.MinQty
, A.PurchasePrice
, A.SellingPrice
, A.FreeIssue
, A.NetAmount
, B.ItemName
, B.SPSellingPrice
, B.ShopPrice
FROM podt A
INNER JOIN itemsummary B
ON A.ItemsId = B.ItemsId
WHERE (A.POHDId = POHDId1)
ORDER BY A.PODTId;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `SelectPOrderHDIdData`;
DELIMITER |
CREATE PROCEDURE `SelectPOrderHDIdData`(in POHDId1 int)
BEGIN
SELECT        A.POHDId, A.PONo, A.PODate, A.SupplierId, B.Address, A.ContactPerson, A.POGrossTotal, A.Remarks
FROM            pohd A INNER JOIN
supplier B ON A.SupplierId = B.SupplierId
WHERE        (A.POHDId = POHDId1);
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `SelectPOrderID`;
DELIMITER |
CREATE PROCEDURE `SelectPOrderID`()
BEGIN
SELECT IFNULL(MAX(POHDId), 0) + 1 AS POHDId FROM pohd;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `SelectPOReportData`;
DELIMITER |
CREATE PROCEDURE `SelectPOReportData`(in POHDId1 int)
BEGIN
SELECT        purchaseorderhd.POHDId, purchaseorderhd.PONo, supplier.SupplierName, purchaseorderhd.PurchaseDate, paymentmode.PayMode, purchaseorderhd.InvoiceNo,
purchaseorderdt.ItemCode, itemcategory.ItemCatName AS ItemCategory, purchaseorderdt.ItemName, purchaseorderdt.ItemLocation, purchaseorderdt.PurchaseQty,
purchaseorderdt.PurchasePrice, purchaseorderdt.PurchaseQty * purchaseorderdt.PurchasePrice AS ItemAmount, purchaseorderdt.Discount, itemsummary.MinQty,
itemsummary.AvailableQty, purchaseorderdt.NetAmount, purchaseorderhd.POGrossTotal, purchaseorderhd.PODiscount, purchaseorderhd.PONetTotal,
purchaseorderhd.Remarks, itemsummary.SellingPrice
FROM            purchaseorderhd INNER JOIN
purchaseorderdt ON purchaseorderhd.POHDId = purchaseorderdt.POHDId INNER JOIN
supplier ON purchaseorderhd.SupplierId = supplier.SupplierId INNER JOIN
paymentmode ON purchaseorderhd.PayModeId = paymentmode.PayModeId INNER JOIN
itemsummary ON purchaseorderdt.ItemCode = itemsummary.ItemCode INNER JOIN
itemcategory ON purchaseorderdt.ItemCatId = itemcategory.ItemCatId
WHERE        (purchaseorderhd.POHDId = POHDId1)
ORDER BY purchaseorderhd.POHDId, purchaseorderhd.PurchaseDate;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `SelectPrintOptions`;
DELIMITER |
CREATE PROCEDURE `SelectPrintOptions`()
BEGIN
SELECT OptionId, OptionName
FROM mstroptions
WHERE OptionId <> 1
ORDER BY OptionId;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `SelectProfileControlls`;
DELIMITER |
CREATE PROCEDURE `SelectProfileControlls`(in USERID1 int, USERTYPEID1 int)
BEGIN
SELECT DISTINCT roles.ROLE_ID, roles.FORM_NAME AS FormName, roles.ROLE_TITLE AS ControlName, roles.PERMISSION_STATUS AS PerStatus
FROM            roles INNER JOIN
user_profile ON roles.ROLE_ID = user_profile.ROLE_ID INNER JOIN
user_type ON user_profile.USER_TYPE_ID = user_type.USER_TYPE_ID
WHERE        (NOT EXISTS
(SELECT        ROLE_ID, roles.ROLE_ID AS Expr1
FROM            user_roles
WHERE        (USER_ID =  USERID1) AND (ROLE_ID = roles.ROLE_ID))) AND (user_profile.PERMISSION_STATUS = 1) AND
(user_type.USER_TYPE_ID =  USERTYPEID1)
ORDER BY FormName, ControlName;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `SelectProfileRoles`;
DELIMITER |
CREATE PROCEDURE `SelectProfileRoles`()
BEGIN
SELECT        user_type.USER_TYPE AS ProfileName, roles.FORM_NAME AS FormName, roles.ROLE_TITLE AS ControlName,
user_profile.PERMISSION_STATUS AS PermissionStatus
FROM            user_profile INNER JOIN
user_type ON user_profile.USER_TYPE_ID = user_type.USER_TYPE_ID INNER JOIN
roles ON user_profile.ROLE_ID = roles.ROLE_ID
ORDER BY ProfileName, FormName, ControlName;
END |
DELIMITER ;

