SELECT B.ItemCode
, B.ItemName
, B.InternalNo
, C.SItemName
, B.SalesQty
, B.SalesPrice
, B.SalesQty * B.SalesPrice AS GrossAmount
, B.Discount
, B.NetAmount
, B.ItemsId
, C.ItemCatId
, B.FreeIssue
, B.Warranty
, '' AS SerialNo
FROM salesquotationhd A
INNER JOIN salesquotationdt B
ON A.SOHDId = B.SOHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
WHERE (A.SOHDId = SOHDId1);
END |
