DROP PROCEDURE IF EXISTS `SelectRoomBookingDetails`;
DELIMITER |
CREATE PROCEDURE `SelectRoomBookingDetails`(in
date1 date,
date2 date)
BEGIN
SELECT A.SOHDId AS InvoiceNo
, A.SODate AS InvoiceDate
, A.FromTime
, A.ToTime
, B.ItemCode
, B.ItemName
, B.SalesQty
, B.SalesPrice
, B.SalesQty * B.SalesPrice AS GrossAmount
, B.Discount
, B.NetAmount
, E.CustomerName
, E.CustomerAddress
, E.CustomerTelNo
, D.UserName AS CreatedBy
, I.EmployeeName
, J.InvoiceStatus AS InvoiceMode
, A.AdvanceAmount
, A.AdvanceDate
,CASE WHEN  A.TableId > 0 THEN CONCAT(J.InvoiceStatus, ' No ', A.TableId)
ELSE CONCAT(J.InvoiceStatus,' Bill No ', A.SOHDId) END AS RefType
FROM salesorderhd A
INNER JOIN holdsalesorderdt B
ON A.SOHDId = B.SOHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
INNER JOIN useraccount D
ON A.CreatedBy = D.UserID
LEFT OUTER JOIN customer E
ON A.CustomerId = E.CustomerId
LEFT OUTER JOIN employeeregistration I
ON A.RepId = I.EmployeeID
INNER JOIN invoicestatus J
ON A.InvoiceStatusId = J.InvoiceStatusId
WHERE (A.CancelStatus = 0)
AND (A.FromDate >= date1)
AND (A.ToDate <= date2)
AND A.InvoiceStatusId = 2
UNION all
SELECT A.SOHDId AS InvoiceNo
, A.SODate AS InvoiceDate
, A.FromTime
, A.ToTime
, B.ItemCode
, B.ItemName
, B.SalesQty
, B.SalesPrice
, B.SalesQty * B.SalesPrice AS GrossAmount
, B.Discount
, B.NetAmount
, E.CustomerName
, E.CustomerAddress
, E.CustomerTelNo
, D.UserName AS CreatedBy
, I.EmployeeName
, J.InvoiceStatus AS InvoiceMode
, A.AdvanceAmount
, A.AdvanceDate
,CASE WHEN  A.TableId > 0 THEN CONCAT(J.InvoiceStatus, ' No ', A.TableId)
ELSE CONCAT(J.InvoiceStatus,' Bill No ', A.SOHDId) END AS RefType
FROM salesorderhd A
INNER JOIN salesorderdt B
ON A.SOHDId = B.SOHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
INNER JOIN useraccount D
ON A.CreatedBy = D.UserID
LEFT OUTER JOIN customer E
ON A.CustomerId = E.CustomerId
LEFT OUTER JOIN employeeregistration I
ON A.RepId = I.EmployeeID
INNER JOIN invoicestatus J
ON A.InvoiceStatusId = J.InvoiceStatusId
WHERE (A.CancelStatus = 0)
AND (A.FromDate >= date1)
AND (A.ToDate <= date2)
AND A.InvoiceStatusId = 2;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `SelectSalesInvois`;
DELIMITER |
CREATE PROCEDURE `SelectSalesInvois`(in date1 date, date2 date)
BEGIN
SELECT A.SOHDId AS InvoiceNo
, A.SODate AS InvoiceDate
, A.ReferanceNo
, B.CustomerName
, A.SONetTotal AS InvoiceAmount
, CASE A.UpdateStatus
WHEN 1 THEN 'Updated'
ELSE ' '
END AS UpdateStatus
FROM salesorderhd A
LEFT OUTER JOIN customer B
ON A.CustomerId = B.CustomerId
WHERE (A.SODate BETWEEN date1 AND date2)
AND A.CancelStatus = 0
ORDER BY A.SODate DESC, A.SOHDId DESC;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `SelectSalesOrders`;
DELIMITER |
CREATE PROCEDURE `SelectSalesOrders`(in date1 date, date2 date)
