, A.AdvanceBalanceAmount
, A.ReferanceNo AS ReferanceOrderNo
FROM sohd A
LEFT OUTER JOIN customer B
ON A.CustomerId = B.CustomerId
WHERE (A.SODate BETWEEN date1 AND date2);
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `SelectSalesReport`;
DELIMITER |
CREATE PROCEDURE `SelectSalesReport`()
BEGIN
declare TotDisc DECIMAL(20,2);
SELECT        SUM(SODiscount) into TotDisc
FROM            salesorderhd
WHERE      (CancelStatus = 0);
SELECT        A.SOHDId AS BillNo, A.SODate, C.ItemName, B.SalesQty, B.SalesPrice AS SellingPrice, B.SalesQty * B.SalesPrice AS SalesAmount, B.Discount, B.NetAmount, D.CompanyName, D.CompanyAddress1,
D.CompanyAddress2, D.ContactNo1, D.ContactNo2, D.CompanyLogo, C.ItemCode, C.ItemCatId, A.RepId, A.CustomerId, TotDisc
FROM            salesorderhd A INNER JOIN
salesorderdt B ON A.SOHDId = B.SOHDId INNER JOIN
itemsummary C ON B.ItemsId = C.ItemsId, companyinfo D
WHERE        (A.CancelStatus = 0)
ORDER BY BillNo, A.SODate, C.ItemName;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `SelectSalesSummaryReport`;
DELIMITER |
CREATE PROCEDURE `SelectSalesSummaryReport`(in date1 date)
BEGIN
DECLARE TotalSale DECIMAL(20,2) DEFAULT 0;
DECLARE ItemDiscount DECIMAL(20,2) DEFAULT 0;
DECLARE TotalValDiscount DECIMAL(20,2) DEFAULT 0;
DECLARE SalesReturn DECIMAL(20,2) DEFAULT 0;
SELECT IFNULL((SUM(SONetTotal)), 0) INTO TotalSale
FROM salesorderhd
GROUP BY SODate, CancelStatus
HAVING (SODate = date1) AND (CancelStatus = 0);
SELECT SUM(B.Discount) INTO ItemDiscount
FROM salesorderhd A
INNER JOIN salesorderdt B
ON A.SOHDId = B.SOHDId
GROUP BY A.SODate, A.CancelStatus
HAVING (A.SODate = date1) AND (A.CancelStatus = 0);
SELECT SUM(SODiscount) INTO TotalValDiscount
FROM salesorderhd A
GROUP BY SODate, CancelStatus
HAVING (SODate = date1) AND (CancelStatus = 0);
SELECT SUM(NetAmount) INTO SalesReturn
FROM salesreturn
GROUP BY RtnDate
HAVING (RtnDate = date1);
SELECT A.SODate, TotalSale, ItemDiscount, TotalValDiscount, SalesReturn, (TotalSale - (ItemDiscount + TotalValDiscount + SalesReturn)) AS NetSale
, B.CompanyName, B.CompanyAddress1,
B.CompanyAddress2
FROM salesorderhd A , companyinfo B
GROUP BY A.SODate
HAVING        (A.SODate = date1)
ORDER BY A.SODate;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `SelectSearchBOMByCode`;
DELIMITER |
CREATE PROCEDURE `SelectSearchBOMByCode`(in ItemCode1 varchar(50))
