DROP PROCEDURE IF EXISTS `SelectSODataDateRange`;
DELIMITER |
CREATE PROCEDURE `SelectSODataDateRange`(in date1 date, date2 date)
BEGIN
SELECT        salesorderhd.CustomerId, itemsummary.ItemCatId, salesorderhd.BillNo, salesorderhd.SODate AS SalesDate, paymentmode.PayMode,
itemcategory.ItemCatName AS ItemCategory, customer.CustomerName, salesorderdt.ItemCode, itemsummary.ItemName, salesorderdt.SalesQty,
salesorderdt.SalesPrice, salesorderdt.NetAmount
FROM            salesorderhd INNER JOIN
salesorderdt ON salesorderhd.SOHDId = salesorderdt.SOHDId INNER JOIN
itemsummary ON salesorderdt.ItemsId = itemsummary.ItemsId INNER JOIN
itemcategory ON itemsummary.ItemCatId = itemcategory.ItemCatId LEFT OUTER JOIN
paymentmode ON salesorderhd.PayModeId = paymentmode.PayModeId LEFT OUTER JOIN
customer ON salesorderhd.CustomerId = customer.CustomerId
WHERE        (salesorderhd.SODate BETWEEN date1 AND date2);
END |
DELIMITER ;

