BEGIN
SELECT A.SOGrossTotal
, A.SODiscount
, A.SONetTotal
, A.CreatedOn
, A.Charges
, A.InvoiceStatusId
, A.ReceivableAmount
FROM salesorderhd A
WHERE (A.SOHDId = SOHDId1);
END;
ELSE
BEGIN
SELECT A.SOGrossTotal
, A.SODiscount
, A.SONetTotal
, A.CompletedDate
, 0 AS Charges
, A.InvoiceStatusId
FROM sohd A
WHERE (A.SOHDId = SOHDId1);
END;
END IF;
END |
DELIMITER ;

