DROP PROCEDURE IF EXISTS `SelectSOHDInvoiceRemarks`;
DELIMITER |
CREATE PROCEDURE `SelectSOHDInvoiceRemarks`(in SOHDId1 int, DocTypeId1 int)
BEGIN
IF(DocTypeId1 = 1) THEN
BEGIN
SELECT B.SOHDRemarkId as RemarkId
, B.RemarksDate as CreatedOn
, B.Remarks as Remark
, H.UserName AS CreatedUser
FROM salesorderhd A
INNER JOIN salesorderhdremarks B
ON A.SOHDId = B.SOHDId
INNER JOIN useraccount H
ON B.CreatedBy = H.UserID
WHERE (A.SOHDId = SOHDId1)
AND (DocTypeId = 1)
;
END;
else
BEGIN
SELECT B.SOHDRemarkId as RemarkId
, B.RemarksDate as CreatedOn
, B.Remarks as Remark
, H.UserName AS CreatedUser
FROM sohd A
INNER JOIN salesorderhdremarks B
ON A.SOHDId = B.SOHDId
INNER JOIN useraccount H
ON B.CreatedBy = H.UserID
WHERE (A.SOHDId = SOHDId1)
AND (DocTypeId = 2)
;
END;
END IF;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `SelectSOHeader`;
DELIMITER |
CREATE PROCEDURE `SelectSOHeader`(in SOHDId1 int)
BEGIN
SELECT B.ContactPerson AS CustomerCode
, A.RepId
, A.CompletedDate
, A.InvoiceStatusId
, A.RepairBill
, A.Remarks
, A.AdvanceBalanceAmount
FROM sohd A
LEFT OUTER JOIN customer B
ON A.CustomerId = B.CustomerId
WHERE (A.SOHDId = SOHDId1);

SELECT B.ItemCode
, B.ItemName
, B.InternalNo
, C.SItemName
, B.SalesQty
, B.SalesPrice
, B.SalesQty * B.SalesPrice AS GrossAmount
, B.Discount
, B.NetAmount
, B.ItemsId
, C.ItemCatId
, B.FreeIssue
, B.Warranty
, B.SerialNo
, A.AdvanceAmount
FROM sohd A
INNER JOIN sodt B
ON A.SOHDId = B.SOHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
WHERE (A.SOHDId = SOHDId1);

SELECT B.ItemCode
, B.ItemName
, B.InternalNo
, C.SItemName
, B.SalesQty
, B.SalesPrice
, B.SalesQty * B.SalesPrice AS GrossAmount
, B.Discount
, B.NetAmount
, B.ItemsId
, C.ItemCatId
, B.FreeIssue
, B.Warranty
, B.SerialNo
FROM sohd A
INNER JOIN directsoreturn B
ON A.SOHDId = B.SOHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
WHERE (A.SOHDId = SOHDId1);
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `SelectStockItemCodeData`;
DELIMITER |
CREATE PROCEDURE `SelectStockItemCodeData`(in ItemCode1 VARCHAR(50))
BEGIN
SELECT ItemCatId
, ItemName
, Discount
, ItemUnit
, CostPrice
, SellingPrice
, MinQty
, ItemsId
, AvailableQty
, ItemMode
, SItemName
, WarrantyPeriod
, FreeIssueEffectFrom
, SPSellingPrice
, SPPRiceEffectFrom
, RackNo
, ItemSubCatId
, DefaultCostPrice
, MinSellingPrice
, WholeSaleDiscount
, SPSellingPrice
, ShopPrice
, RetailDiscPer
, WholesaleDiscPer
, MaintainQty
, TItemName
, ScaleItem
, BundleItem
, SupplierId
, RawMaterial
, AllowSales
, AllowPurchase
, AllowInventory
FROM itemsummary
WHERE (ItemCode = ItemCode1);
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `SelectStockMaintainReport`;
DELIMITER |
CREATE PROCEDURE `SelectStockMaintainReport`()
BEGIN
SELECT ItemsId
, ItemCode
, ItemName
, AvailableQty
, MaintainQty
, MaintainQty - AvailableQty AS BalanceQty
FROM itemsummary;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `SelectStockTransferData`;
DELIMITER |
CREATE PROCEDURE `SelectStockTransferData`(in TransferHDId1 int)
BEGIN
SELECT A.TransferHDId
, B.ItemsId
, C.ItemCode
, C.ItemName
, B.Qty
, CASE C.CostPrice WHEN 0 THEN 1 ELSE C.CostPrice END AS CostPrice
, C.SellingPrice
, A.FromBranchId
, D.BranchName AS FromBranch
FROM stocktransferhd A
INNER JOIN stocktransferdt B
ON A.TransferHDId = B.TransferHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
INNER JOIN branch D
ON A.FromBranchId = D.BranchId
WHERE (A.TransferHDId = TransferHDId1)
ORDER BY B.TransferDTId;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `SelectSummaryReport`;
DELIMITER |
CREATE PROCEDURE `SelectSummaryReport`()
BEGIN
DECLARE TotalSale1 DECIMAL(20,2) DEFAULT 0;
DECLARE TotalSalesReturn1 DECIMAL(20,2) DEFAULT 0;
DECLARE TotalSalesReturn2 DECIMAL(20,2) DEFAULT 0;
DECLARE TotalSalesReturn11 DECIMAL(20,2) DEFAULT 0;
DECLARE TotalNetSale1 DECIMAL(20,2) DEFAULT 0;
DECLARE TotalCashSale1 DECIMAL(20,2) DEFAULT 0;
DECLARE TotalChequeSale1 DECIMAL(20,2) DEFAULT 0;
DECLARE TotalCreditSale1 DECIMAL(20,2) DEFAULT 0;
DECLARE TotalCardSale1 DECIMAL(20,2) DEFAULT 0;
DECLARE Expenses1 DECIMAL(20,2) DEFAULT 0;
DECLARE CashExpenses1 DECIMAL(20,2) DEFAULT 0;
DECLARE CustCreditPayment1 DECIMAL(20,2) DEFAULT 0;
DECLARE SuppCreditPayment1 DECIMAL(20,2) DEFAULT 0;
DECLARE OpeningCashBalance1 DECIMAL(20,2) DEFAULT 0;
DECLARE LastCashBalance1 DECIMAL(20,2) DEFAULT 0;
DECLARE TotalCashIn DECIMAL(20,2) DEFAULT 0;
DECLARE BankDeposit DECIMAL(20,2) DEFAULT 0;
DECLARE IssuedVoucher DECIMAL(20,2) DEFAULT 0;
DECLARE TranDate1 DATE DEFAULT (select CONVERT_TZ(NOW(), @@session.time_zone, '+05:30'));
DECLARE UTCDate1 date;
DECLARE date1 date;
SET UTCDate1 = (select CONVERT_TZ(now(), @@session.time_zone, '+05:30'));
SET date1 = (select CONVERT_TZ(now(), @@session.time_zone, '+05:30'));
SELECT IFNULL((SUM(SONetTotal)), 0) INTO TotalSale1
FROM salesorderhd
WHERE (SODate = date1)
AND (CancelStatus = 0);
SELECT IFNULL((SUM(NetAmount)), 0) INTO TotalSalesReturn1
FROM salesreturn
WHERE (RtnDate = date1);
SELECT IFNULL(SUM(B.NetAmount), 0) INTO TotalSalesReturn11
FROM salesorderhd A
INNER JOIN directsalesreturn B
ON A.SOHDId = B.SOHDId
WHERE (A.CancelStatus = 0)
AND (A.SODate = date1);
SELECT IFNULL(SUM(B.NetAmount), 0) INTO TotalSalesReturn2
FROM salesorderhdreturn A
INNER JOIN salesorderdtreturn B
ON A.SOHDId = B.SOHDId
WHERE (A.CancelStatus = 0)
AND (A.SODate = date1);
SET TotalNetSale1 = IFNULL((TotalSale1), 0) - IFNULL((TotalSalesReturn1 + TotalSalesReturn11 + TotalSalesReturn2), 0);
SELECT IFNULL((SUM(SONetTotal-ReturnTotal-VoucherAmount)), 0) INTO TotalCashSale1
FROM salesorderhd
WHERE (SODate = date1)
AND (PayModeId = 1)
AND (CancelStatus = 0);
SELECT IFNULL((SUM(SONetTotal-ReturnTotal-VoucherAmount)), 0) INTO TotalChequeSale1
FROM salesorderhd
WHERE (SODate = date1)
AND (PayModeId = 2)
AND (CancelStatus = 0);
SELECT IFNULL((SUM(SONetTotal-ReturnTotal-VoucherAmount)), 0) INTO TotalCreditSale1
FROM salesorderhd
WHERE (SODate = date1)
AND (PayModeId = 3)
AND (CancelStatus = 0);
SELECT IFNULL((SUM(SONetTotal-ReturnTotal-VoucherAmount)), 0) INTO TotalCardSale1
FROM salesorderhd
WHERE (SODate = date1)
AND (PayModeId = 4)
AND (CancelStatus = 0);
SELECT IFNULL((SUM(PaymentAmount)), 0) INTO Expenses1
FROM allexpenses
WHERE (PaymentDate = date1);
SELECT IFNULL((SUM(PaymentAmount)), 0) INTO CashExpenses1
FROM allexpenses
WHERE (PaymentDate = date1)
AND (PayModeId = 1);
SELECT IFNULL((SUM(PaymentAmount)),0) INTO CustCreditPayment1
FROM custcreditpayment
WHERE (PaymentDate = date1)
AND (PayModeId = 1);
SELECT IFNULL((SUM(PaymentAmount)),0) INTO SuppCreditPayment1
FROM suppcreditpayment
WHERE (PaymentDate = date1)
AND (PayModeId = 1);
SELECT IFNULL((SUM(OpeningBalance)),0) INTO OpeningCashBalance1
FROM cashbalance
WHERE (BalanceDate = date1);
SELECT IFNULL((SUM(PaymentAmount)), 0) INTO TotalCashIn
FROM paidin
WHERE (PaymentDate = date1);
SELECT IFNULL((SUM(PaymentAmount)), 0) INTO BankDeposit
FROM allexpenses
WHERE (PaymentDate = date1)
AND (PayCatId = 8);
SELECT IFNULL((SUM(VoucherAmount)), 0) INTO IssuedVoucher
FROM giftvoucher
WHERE (IssueDate = date1)
AND (CancelStatus = 0);
SELECT TotalSale1 AS TotalSale
, TotalSalesReturn1 + TotalSalesReturn11 + TotalSalesReturn2 as TotalSalesReturn
, TotalNetSale1 AS TotalNetSale
, TotalCashSale1 AS TotalCashSale
, TotalChequeSale1 AS TotalChequeSale
, TotalCreditSale1 AS TotalCreditSale
, TotalCardSale1 AS TotalCardSale
, Expenses1 AS Expenses
, CashExpenses1 AS CashExpenses
, CustCreditPayment1 AS CustCreditPayment
, SuppCreditPayment1 AS SuppCreditPayment
, OpeningCashBalance1 AS OpeningCashBalance
, TotalCashIn AS CashIn
, date1 AS TranDate
, BankDeposit AS BankDeposit
, TotalCashSale1 + CustCreditPayment1 + TotalCashIn + IssuedVoucher AS InAmount
, CashExpenses1 + SuppCreditPayment1 + TotalSalesReturn1 + TotalSalesReturn2 AS OutAmount
, (OpeningCashBalance1 + TotalCashSale1 + CustCreditPayment1 + TotalCashIn + IssuedVoucher) - (Expenses1 + SuppCreditPayment1 + TotalSalesReturn1 + TotalSalesReturn2) AS LastCashBalance
, IssuedVoucher;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `SelectSummaryReportNew`;
DELIMITER |
CREATE PROCEDURE `SelectSummaryReportNew`()
BEGIN
DECLARE TotalSale1 DECIMAL(20,2) DEFAULT 0;
DECLARE TotalSalesReturn1 DECIMAL(20,2) DEFAULT 0;
DECLARE TotalSalesReturn11 DECIMAL(20,2) DEFAULT 0;
DECLARE TotalNetSale1 DECIMAL(20,2) DEFAULT 0;
DECLARE TotalCashSale1 DECIMAL(20,2) DEFAULT 0;
DECLARE TotalChequeSale1 DECIMAL(20,2) DEFAULT 0;
DECLARE TotalCreditSale1 DECIMAL(20,2) DEFAULT 0;
DECLARE TotalCardSale1 DECIMAL(20,2) DEFAULT 0;
DECLARE Expenses1 DECIMAL(20,2) DEFAULT 0;
DECLARE CustCreditPayment1 DECIMAL(20,2) DEFAULT 0;
DECLARE SuppCreditPayment1 DECIMAL(20,2) DEFAULT 0;
DECLARE OpeningCashBalance1 DECIMAL(20,2) DEFAULT 0;
DECLARE LastCashBalance1 DECIMAL(20,2) DEFAULT 0;
DECLARE TranDate1 DATE DEFAULT (select CONVERT_TZ(NOW(), @@session.time_zone, '+05:30'));
DECLARE UTCDate1 date;
SET UTCDate1 = (select CONVERT_TZ(now(), @@session.time_zone, '+05:30'));
SET UTCDate1 = UTCDate1 - 1;
SELECT IFNULL((SUM(SONetTotal)), 0) INTO TotalSale1
FROM salesorderhd
WHERE (SODate = UTCDate1)
AND (CancelStatus = 0);
SELECT IFNULL((SUM(NetAmount)), 0) INTO TotalSalesReturn1
FROM salesreturn
WHERE (RtnDate = UTCDate1);
SELECT IFNULL(SUM(directsalesreturn.NetAmount), 0) INTO TotalSalesReturn11
FROM salesorderhd
INNER JOIN directsalesreturn
ON salesorderhd.SOHDId = directsalesreturn.SOHDId
WHERE (salesorderhd.CancelStatus = 0)
AND (salesorderhd.SODate = UTCDate1);
SET TotalNetSale1 = IFNULL((TotalSale1), 0) - IFNULL((TotalSalesReturn1 + TotalSalesReturn11), 0);
SELECT IFNULL((SUM(SONetTotal-ReturnTotal)), 0) INTO TotalCashSale1
FROM salesorderhd
WHERE (SODate = UTCDate1)
AND (PayModeId = 1)
AND (CancelStatus = 0);
SELECT IFNULL((SUM(SONetTotal-ReturnTotal)), 0) INTO TotalChequeSale1
FROM salesorderhd
WHERE (SODate = UTCDate1)
AND (PayModeId = 2)
AND (CancelStatus = 0);
SELECT IFNULL((SUM(SONetTotal-ReturnTotal)), 0) INTO TotalCreditSale1
FROM salesorderhd
WHERE (SODate = UTCDate1)
AND (PayModeId = 3)
AND (CancelStatus = 0);
SELECT IFNULL((SUM(SONetTotal-ReturnTotal)), 0) INTO TotalCardSale1
FROM salesorderhd
WHERE (SODate = UTCDate1)
AND (PayModeId = 4)
AND (CancelStatus = 0);
SELECT IFNULL((SUM(PaymentAmount)), 0) INTO Expenses1
FROM allexpenses
WHERE (PaymentDate = UTCDate1);
SELECT IFNULL((SUM(PaymentAmount)),0) INTO CustCreditPayment1
FROM custcreditpayment
WHERE (PaymentDate = UTCDate1)
AND (PayModeId = 1);
SELECT IFNULL((SUM(PaymentAmount)),0) INTO SuppCreditPayment1
FROM suppcreditpayment
WHERE (PaymentDate = UTCDate1)
AND (PayModeId = 1);
SELECT IFNULL((SUM(OpeningBalance)),0) INTO OpeningCashBalance1
FROM cashbalance
WHERE (BalanceDate = UTCDate1);
SELECT TotalSale1 AS TotalSale
, TotalSalesReturn1 + TotalSalesReturn11 as TotalSalesReturn
, TotalNetSale1 AS TotalNetSale
, TotalCashSale1 AS TotalCashSale
, TotalChequeSale1 AS TotalChequeSale
, TotalCreditSale1 AS TotalCreditSale
, TotalCardSale1 AS TotalCardSale
, Expenses1 AS Expenses
, CustCreditPayment1 AS CustCreditPayment
, SuppCreditPayment1 AS SuppCreditPayment
, OpeningCashBalance1 AS OpeningCashBalance
, UTCDate1 AS TranDate
, OpeningCashBalance1 + TotalCashSale1 + CustCreditPayment1 - (Expenses1 + SuppCreditPayment1) AS LastCashBalance;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `SelectSupplierAccount`;
DELIMITER |
CREATE PROCEDURE `SelectSupplierAccount`(in SupplierId1 int)
BEGIN
SELECT        SupAccId, BankName, AccountNo
FROM            supplieraccount
WHERE        (SupplierId = SupplierId1);
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `SelectSupplierAddress`;
DELIMITER |
CREATE PROCEDURE `SelectSupplierAddress`(in SupplierId1 int)
BEGIN
SELECT Address
, ContactPerson
, SupplierTypeId
FROM supplier
WHERE (SupplierId = SupplierId1);
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `SelectSupplierByName`;
DELIMITER |
CREATE PROCEDURE `SelectSupplierByName`(in SupplierName1 VARCHAR(100))
BEGIN
SELECT A.SupplierId
, A.SupplierName
, A.ContactPerson
, A.BusinessNo
, A.MobileNo
, A.Email
, A.Address
, A.Remarks
, A.BalanceAmount
, B.SupplierType
, A.SupplierTypeId
FROM supplier A
LEFT OUTER JOIN suppliertypes B
ON A.SupplierTypeId = B.SupplierTypeId
WHERE (A.SupplierName LIKE CONCAT(SupplierName1, '%'));
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `SelectSupplierChequesBySupp`;
DELIMITER |
CREATE PROCEDURE `SelectSupplierChequesBySupp`(in SupplierId1 int)
BEGIN
SELECT A.SuppChqId
, A.SupplierId
, B.SupplierName
, A.POHDId AS PurInvNo
, A.ChequeNo
, A.ChequeBank AS Bank
, A.ChequeAmount
, A.IssueDate
, A.ChequeExpDate AS RealizeDate
, A.ReturnStatus
FROM suppliercheque A
INNER JOIN supplier B
ON A.SupplierId = B.SupplierId
WHERE (A.ReturnStatus = 0)
AND (A.RealizeStatus = 0)
AND(A.SupplierId = SupplierId1)
ORDER BY B.SupplierName, RealizeDate;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `SelectSupplierHistory`;
DELIMITER |
CREATE PROCEDURE `SelectSupplierHistory`(in
date1 date,
date2 date)
BEGIN
SELECT A.PIHDId AS RefNo
, A.PIDate AS RefDate
, B.SupplierName
, B.MobileNo
, A.PINetTotal AS Amount
, C.PayMode
, 'PurchaseInvoice' AS RefDoc
FROM pihd A
INNER JOIN supplier B
ON A.SupplierId = B.SupplierId
INNER JOIN paymentmode C
ON A.PayModeId = C.PayModeId
WHERE (A.CancelStatus = 0)
AND (A.PIDate BETWEEN date1 AND date2)
UNION ALL
SELECT A.BillNo AS RefNo
, A.PaymentDate AS RefDate
, B.SupplierName
, B.MobileNo
, A.PaymentAmount AS Amount
, C.PayMode
, 'CreditPayment' AS RefDoc
FROM supplier B
INNER JOIN suppcreditpayment A
ON B.SupplierId = A.SupplierId
INNER JOIN paymentmode C
ON A.PayModeId = C.PayModeId
WHERE (A.PaymentDate BETWEEN date1 AND date1);
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `SelectSupplierIdData`;
DELIMITER |
CREATE PROCEDURE `SelectSupplierIdData`(in SupplierId1 int)
BEGIN
SELECT SupplierId, SupplierName, ContactPerson, BusinessNo, MobileNo, Email, Address, Remarks
FROM            supplier
WHERE        (SupplierId = SupplierId1);

SELECT A.PIHDId as InvoiceNo
, C.PINo
, A.CreditDate
, (A.CreditAmount - A.PaymentAmount) as CreditAmount
, A.SupplierId
, A.SuppCreditId
FROM suppliercredit A
INNER JOIN supplier B
ON A.SupplierId = B.SupplierId
left outer JOIN pihd C
ON A.PIHDId = C.PIHDId
WHERE (A.SupplierId = SupplierId1)
AND (A.PaymentCompletedStatus = 0)
AND (A.CreditAmount - A.PaymentAmount) > 0
ORDER BY A.CreditDate;

SELECT suppcreditpayment.PaymentDate, suppcreditpayment.BillNo, suppcreditpayment.PaymentAmount
FROM supplier
INNER JOIN suppcreditpayment
ON supplier.SupplierId = suppcreditpayment.SupplierId
WHERE (supplier.SupplierId = SupplierId1)
ORDER BY suppcreditpayment.PaymentDate;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `SelectSuppliers`;
DELIMITER |
CREATE PROCEDURE `SelectSuppliers`()
BEGIN
SELECT SupplierId, SupplierName
FROM supplier
ORDER BY SupplierName;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `SelectSupplierTemplate`;
DELIMITER |
CREATE PROCEDURE `SelectSupplierTemplate`()
BEGIN
SELECT SupplierName
, ContactPerson
, BusinessNo
, MobileNo
, Email
, Address
, Remarks
, BalanceAmount
, SupplierId
FROM supplier
WHERE ExpenseStatus = 0;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `SelectTableAvailability`;
DELIMITER |
CREATE PROCEDURE `SelectTableAvailability`(IN TableId1 INT, SOHDId1 INT)
BEGIN
SELECT SOHDId AS InvoiceNo
FROM salesorderhd
WHERE TableId = TableId1
AND SOHDId <> SOHDId1
AND InvoiceCompleted = 0
AND CancelStatus = 0
order by SOHDId;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `SelectTableData`;
DELIMITER |
CREATE PROCEDURE `SelectTableData`(in TblNo1 VARCHAR(6))
BEGIN
SELECT        TblCategory, NoOfCustomers, Steward, TblStatus
FROM            resttable
WHERE        (TblNo = TblNo1);
SELECT        resttable.ItemCode, menuitem.ItemName, resttable.SalesQty, resttable.SalesAmount, resttable.Price, resttable.ItemsId, resttable.ItemCatId
FROM            resttable INNER JOIN
menuitem ON resttable.ItemsId = menuitem.ItemsId
WHERE        (resttable.TblNo = TblNo1);
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `SelectTaxInvoice`;
DELIMITER |
CREATE PROCEDURE `SelectTaxInvoice`(in date1 date, date2 date)
BEGIN
SELECT A.SOHDId AS InvoiceNo, A.SODate AS SalesDate, C.PayMode AS PaymentMode, B.ItemCode, D.ItemName, B.SalesQty, B.NetAmount AS GrossAmount, A.SONetTotal AS InvoiceAmount,
A.TaxStatus
FROM paymentmode C
INNER JOIN salesorderhd A
ON C.PayModeId = A.PayModeId
INNER JOIN salesorderdt B
ON A.SOHDId = B.SOHDId
INNER JOIN itemsummary D
ON B.ItemsId = D.ItemsId
WHERE (A.SODate BETWEEN date1 AND date2)
order by A.SODate DESC, A.SOHDId DESC;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `SelectUNPW`;
DELIMITER |
CREATE PROCEDURE `SelectUNPW`(in USERNAME1 nvarchar(30) , PASWORD1 nvarchar(30))
BEGIN
SELECT        USER_NAME, PASSWORD
FROM            users
WHERE        (USER_NAME =  USERNAME1) AND (PASSWORD =  PASWORD1) AND (Status = N'Active');
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `SelectUserData`;
DELIMITER |
CREATE PROCEDURE `SelectUserData`(in USERNAME1 nvarchar(30))
BEGIN
SELECT        UserID, UserName, Fullname, UserType
FROM            useraccount
WHERE        (UserName = USERNAME1);
SELECT        user_roles.USER_ROLE_ID, roles.FORM_NAME AS FormName, roles.ROLE_TITLE AS ControlName, user_roles.PERMISSION_STATUS AS PermStatus
FROM            user_roles INNER JOIN
roles ON user_roles.ROLE_ID = roles.ROLE_ID INNER JOIN
useraccount ON user_roles.USER_ID = useraccount.UserID
WHERE        (useraccount.UserName = USERNAME1)
ORDER BY FormName, ControlName;
SELECT DISTINCT user_type.USER_TYPE_ID, user_type.USER_TYPE, roles.PERMISSION_STATUS AS SelectProfile
FROM            user_type INNER JOIN
user_profile ON user_type.USER_TYPE_ID = user_profile.USER_TYPE_ID INNER JOIN
roles ON user_profile.ROLE_ID = roles.ROLE_ID
ORDER BY user_type.USER_TYPE;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `SelectUserGRNPrint`;
DELIMITER |
CREATE PROCEDURE `SelectUserGRNPrint`(in USERID1 int)
BEGIN
SELECT GRNPrintId
FROM useraccount
WHERE UserID = USERID1;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `SelectUserInvoice`;
DELIMITER |
CREATE PROCEDURE `SelectUserInvoice`(in CreatedBy1 int)
BEGIN
SELECT MAX(SOHDId)
FROM salesorderhd
GROUP BY CreatedBy
HAVING (CreatedBy = CreatedBy1);
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `SelectUserName`;
DELIMITER |
CREATE PROCEDURE `SelectUserName`()
BEGIN
SELECT UserName
FROM useraccount
WHERE (UserID <> 1)
ORDER BY UserName;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `SelectUserPort`;
DELIMITER |
CREATE PROCEDURE `SelectUserPort`(in USERID1 int)
BEGIN
SELECT Comport
FROM useraccount
WHERE UserID = USERID1;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `SelectUserRec`;
DELIMITER |
CREATE PROCEDURE `SelectUserRec`(in USERNAME1 nvarchar(30))
BEGIN
SELECT        USER_NAME, NAME, CONTACT_NO, EMAIL, Status, USER_TYPE_ID, DEPARTMENT_ID, USER_ID
FROM            users
WHERE        (USER_NAME =  USERNAME1);
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `SelectUsers`;
DELIMITER |
CREATE PROCEDURE `SelectUsers`()
BEGIN
SELECT A.UserID
, A.UserName
, A.Password
, A.Fullname
, A.UserType
, A.Comport
, A.OptionId
, B.OptionName
, A.GRNPrintId
, C.OptionName AS GRNPrintOption
, A.BranchId
, D.BranchName
FROM useraccount A
LEFT OUTER JOIN mstroptions B
ON A.OptionId = B.OptionId
INNER JOIN grnprint C
ON A.GRNPrintId = C.GRNPrintId
INNER JOIN branch D
ON A.BranchId = D.BranchId
WHERE (A.UserID <> 1)
ORDER BY A.UserID
;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `SelectUserType`;
DELIMITER |
CREATE PROCEDURE `SelectUserType`()
BEGIN
SELECT        USER_TYPE_ID, USER_TYPE
FROM            user_type;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `SelectVariantItemCodeData`;
DELIMITER |
CREATE PROCEDURE `SelectVariantItemCodeData`(in ItemCode1 VARCHAR(50))
BEGIN
SELECT ItemCatId
, ItemName
, Discount
, ItemUnit
, CostPrice
, SellingPrice
, MinQty
, ItemsId
, AvailableQty
, ItemMode
, SItemName
, WarrantyPeriod
, FreeIssueEffectFrom
, SPSellingPrice
, SPPRiceEffectFrom
, RackNo
, ItemSubCatId
, DefaultCostPrice
, MinSellingPrice
, WholeSaleDiscount
, SPSellingPrice
, ShopPrice
, RetailDiscPer
, WholesaleDiscPer
, ItemsId
, ItemCode
, ConvertionQty
, MaintainQty
, ScaleItem
, TItemName
, BundleItem
, SupplierId
, RawMaterial
, AllowSales
, AllowPurchase
, AllowInventory
, MItemsId
, MItemCode
FROM itemsummary
WHERE (ItemCode = ItemCode1);
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `SelectVATInvioce`;
DELIMITER |
CREATE PROCEDURE `SelectVATInvioce`(in
SOHDId1 int
)
BEGIN
SELECT A.BillNo, A.SODate, B.ItemCode, C.ItemName, B.InternalNo, B.SalesQty, B.SalesPrice, B.SalesQty * B.SalesPrice AS GrossAmount, B.Discount, B.NetAmount, A.SOGrossTotal, A.AdditionalChgs, A.SODiscount,
A.VAT, A.NBT, A.SONetTotal, F.PayMode, A.Cash, E.CustomerName, G.CompanyName, G.CompanyAddress1, G.CompanyAddress2, G.ContactNo1, G.ContactNo2, G.CompanyLogo, C.SItemName, G.FooterMsg,
G.VATNo, D.Fullname AS Cashier
FROM salesorderhd A INNER JOIN
salesorderdt B ON A.SOHDId = B.SOHDId INNER JOIN
itemsummary C ON B.ItemsId = C.ItemsId LEFT OUTER JOIN
useraccount D ON A.CreatedBy = D.UserID LEFT OUTER JOIN
customer E ON A.CustomerId = E.CustomerId LEFT OUTER JOIN
paymentmode F ON A.PayModeId = F.PayModeId, companyinfo G
WHERE (A.SOHDId = SOHDId1)
ORDER BY C.ItemName;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `SelectVehicleInvoive`;
DELIMITER |
CREATE PROCEDURE `SelectVehicleInvoive`(in VehicleNo1 VARCHAR(10))
BEGIN
SELECT A.SOHDId AS BillNo, A.SODate, C.CustomerName, C.CustomerFaxNo AS VehicleNo, B.ItemCode, D.ItemName, B.SalesQty, B.SalesPrice, B.Discount, B.NetAmount
FROM            salesorderhd A INNER JOIN
salesorderdt B ON A.SOHDId = B.SOHDId INNER JOIN
customer C ON A.CustomerId = C.CustomerId INNER JOIN
itemsummary D ON B.ItemsId = D.ItemsId
WHERE        (C.CustomerFaxNo = VehicleNo1)
ORDER BY A.SODate DESC, BillNo;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `SelectVehicleRate`;
DELIMITER |
