DROP PROCEDURE IF EXISTS `SupplierCreditAll`;
DELIMITER |
CREATE PROCEDURE `SupplierCreditAll`(in date1 date, date2 date)
BEGIN
SELECT B.SupplierName
, A.PIHDId AS InvoiceNo
, A.CreditDate
, A.CreditAmount
, A.PaymentDate
, A.PaymentAmount
, A.SupplierId
FROM suppliercredit A
INNER JOIN supplier B
ON A.SupplierId = B.SupplierId
WHERE (A.CreditDate BETWEEN date1 AND date2)
AND (A.CreditAmount > 0)
AND (A.CreditAmount > A.PaymentAmount)
ORDER BY B.SupplierName, InvoiceNo;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `SupplierCreditPaySupp`;
DELIMITER |
CREATE PROCEDURE `SupplierCreditPaySupp`(in SupplierId1 int)
BEGIN
DECLARE TotalBalance1 DECIMAL(10,2) DEFAULT 0;
SELECT (SUM(A.CreditAmount) - IFNULL(SUM(D.PaymentAmount), 0)) INTO TotalBalance1
FROM suppliercredit A
LEFT OUTER JOIN (SELECT Z.SupplierId, SUM(Z.PaymentAmount) AS PaymentAmount, Z.BillNo
FROM suppcreditpayment Z
WHERE Z.SupplierId = SupplierId1
AND Z.PaymentAmount > 0
GROUP BY Z.SupplierId, Z.BillNo) D
ON A.SupplierId = D.SupplierId
AND A.PIHDId = D.BillNo
WHERE A.SupplierId = SupplierId1
AND A.CreditAmount > 0;
SELECT B.SupplierName AS CustomerName
, B.ContactPerson AS CustomerCode
, B.Address AS CustomerAddress
, B.MobileNo AS CustomerTelNo
, A.PIHDId AS BillNo
, A.CreditDate
, A.CreditAmount
, IFNULL(D.PaymentAmount, 0) AS TotalPayment
, (A.CreditAmount - IFNULL(D.PaymentAmount, 0)) AS BalanceAmount
, C.CreditPayHDId AS PaymentReceiptNo
, C.PaymentDate
, C.PaymentAmount
, E.CompanyName
, E.CompanyAddress1
, E.CompanyAddress2
, E.ContactNo1
, E.ContactNo2
, E.Web
, E.Email
, E.CompanyLogo
, A.SupplierId AS CustomerId
, TotalBalance1 AS TotalBalance
FROM suppliercredit A
INNER JOIN supplier B
ON A.SupplierId = B.SupplierId
LEFT OUTER JOIN (SELECT Z.SupplierId, Z.PaymentDate, SUM(Z.PaymentAmount) AS PaymentAmount, Z.BillNo, Z.CreditPayHDId
FROM suppcreditpayment Z
WHERE Z.SupplierId = SupplierId1
AND Z.PaymentAmount > 0
GROUP BY Z.SupplierId, Z.PaymentDate, Z.BillNo, Z.CreditPayHDId) C
ON A.SupplierId = C.SupplierId
AND A.PIHDId = C.BillNo
LEFT OUTER JOIN (SELECT Z.SupplierId, SUM(Z.PaymentAmount) AS PaymentAmount, Z.BillNo
FROM suppcreditpayment Z
WHERE Z.SupplierId = SupplierId1
AND Z.PaymentAmount > 0
GROUP BY Z.SupplierId, Z.BillNo) D
ON A.SupplierId = D.SupplierId
AND A.PIHDId = D.BillNo
, companyinfo E
WHERE A.SupplierId = SupplierId1
AND A.CreditAmount > 0;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `SupplierCreditSupp`;
DELIMITER |
CREATE PROCEDURE `SupplierCreditSupp`(in date1 date, date2 date, SupplierId1 int)
BEGIN
SELECT B.SupplierName
, A.PIHDId AS InvoiceNo
, A.CreditDate
, A.CreditAmount
, A.PaymentDate
, A.PaymentAmount
, A.SupplierId
FROM suppliercredit A
INNER JOIN supplier B
ON A.SupplierId = B.SupplierId
WHERE (A.CreditDate BETWEEN date1 AND date2)
AND (A.SupplierId = SupplierId1)
AND (A.CreditAmount > 0)
AND (A.CreditAmount > A.PaymentAmount)
ORDER BY B.SupplierName, InvoiceNo;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `SupplierHistoryAll`;
DELIMITER |
CREATE PROCEDURE `SupplierHistoryAll`(in date1 DATE, date2 DATE)
BEGIN
SELECT X.SupplierId
, X.SupplierName
, X.Id
, X.DocDate
, X.Memo
, X.Debit
, X.Credit
FROM
(
SELECT A.SupplierId
, B.SupplierName
, A.PIHDId AS Id
, A.CreditDate AS DocDate
, 'Credit - Opening Balance' AS Memo
, 0 AS Debit
, A.CreditAmount AS Credit
FROM suppliercredit A
INNER JOIN supplier B
ON A.SupplierId = B.SupplierId
WHERE (A.CreditDate BETWEEN date1 AND date2)
AND (A.PIHDId = 0)
UNION ALL
SELECT A.SupplierId
, B.SupplierName
, A.PIHDId AS Id
, A.CreditDate AS DocDate
, 'Credit - Purchasing' AS Memo
, 0 AS Debit
, A.CreditAmount AS Credit
FROM suppliercredit A
INNER JOIN supplier B
ON A.SupplierId = B.SupplierId
WHERE (A.CreditDate BETWEEN date1 AND date2)
AND (A.PIHDId <> 0)
UNION ALL
SELECT A.SupplierId
, B.SupplierName
, A.BillNo AS Id
, A.PaymentDate AS DocDate
, CONCAT('[Credit Payment]', C.PayMode) AS Memo
, A.PaymentAmount AS Debit
, 0 AS Credit
FROM suppcreditpayment A
INNER JOIN supplier B
ON A.SupplierId = B.SupplierId
INNER JOIN paymentmode C
ON A.PayModeId = C.PayModeId
WHERE (A.PaymentDate BETWEEN date1 AND date2)
)X
ORDER BY X.SupplierName, X.DocDate;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `SupplierHistoryBySupp`;
DELIMITER |
CREATE PROCEDURE `SupplierHistoryBySupp`(in SupplierId1 int, date1 DATE, date2 DATE)
BEGIN
SELECT X.SupplierId
, X.SupplierName
, X.Id
, X.DocDate
, X.Memo
, X.Debit
, X.Credit
FROM
(
SELECT A.SupplierId
, B.SupplierName
, A.PIHDId AS Id
, A.CreditDate AS DocDate
, 'Credit - Opening Balance' AS Memo
, 0 AS Debit
, A.CreditAmount AS Credit
FROM suppliercredit A
INNER JOIN supplier B
ON A.SupplierId = B.SupplierId
WHERE (A.CreditDate BETWEEN date1 AND date2)
AND (A.PIHDId = 0)
AND (A.SupplierId = SupplierId1)
UNION ALL
SELECT A.SupplierId
, B.SupplierName
, A.PIHDId AS Id
, A.CreditDate AS DocDate
, 'Credit - Purchasing' AS Memo
, 0 AS Debit
, A.CreditAmount AS Credit
FROM suppliercredit A
INNER JOIN supplier B
ON A.SupplierId = B.SupplierId
WHERE (A.CreditDate BETWEEN date1 AND date2)
AND (A.PIHDId <> 0)
AND (A.SupplierId = SupplierId1)
UNION ALL
SELECT A.SupplierId
, B.SupplierName
, A.BillNo AS Id
, A.PaymentDate AS DocDate
, CONCAT('[Credit Payment]', C.PayMode) AS Memo
, A.PaymentAmount AS Debit
, 0 AS Credit
FROM suppcreditpayment A
INNER JOIN supplier B
ON A.SupplierId = B.SupplierId
INNER JOIN paymentmode C
ON A.PayModeId = C.PayModeId
WHERE (A.SupplierId = SupplierId1)
AND (A.PaymentDate BETWEEN date1 AND date2)
)X
ORDER BY X.SupplierName, X.DocDate;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `TaxReportBySalesDate`;
DELIMITER |
CREATE PROCEDURE `TaxReportBySalesDate`(in
date1 date,
date2 date
)
BEGIN
DROP TABLE IF EXISTS `taxsales`;
CREATE TEMPORARY TABLE IF NOT EXISTS `taxsales` (
`TaxSalesId` bigint(20) NOT NULL AUTO_INCREMENT,
`SOHDId` bigint(20) NOT NULL,
`SODate` date DEFAULT NULL,
PRIMARY KEY (`TaxSalesId`,`SOHDId`)
);
INSERT INTO taxsales (SOHDId, SODate)
SELECT X.SOHDId, X.SODate
FROM(
SELECT A.SOHDId, A.SODate
FROM salesorderhd A
where (A.SODate BETWEEN date1 AND date2)
and A.TaxStatus = 1
UNION all
SELECT A.SOHDId, A.SODate
FROM salesorderhd A
where A.SODate = curdate())X;
SELECT E.TaxSalesId AS BillNo
, A.SODate
, C.ItemName
, B.SalesQty
, B.SalesPrice AS SellingPrice
, B.SalesQty * B.SalesPrice AS SalesAmount
, B.Discount, B.NetAmount
, D.CompanyName
, D.CompanyAddress1
, D.CompanyAddress2
, D.ContactNo1
, D.ContactNo2
, D.CompanyLogo
, C.ItemCode
, C.ItemCatId
FROM salesorderhd A
INNER JOIN salesorderdt B
ON A.SOHDId = B.SOHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
INNER JOIN taxsales E
ON A.SOHDId = E.SOHDId
, companyinfo D
where (E.SODate BETWEEN date1 AND date2)
ORDER BY BillNo, A.SODate, C.ItemName;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `TaxReportBySalesDateSummary`;
DELIMITER |
CREATE PROCEDURE `TaxReportBySalesDateSummary`(in date1 date,
date2 date)
BEGIN
SELECT date1
, date2
, D.BranchName AS CompanyName
, D.BranchAddress AS CompanyAddress1
, D.BranchAddress2 AS CompanyAddress2
, D.BranchTelNo AS ContactNo1
, D.BranchTelNo2 AS ContactNo2
, A.SODate
, SUM(B.SalesQty * (B.SalesPrice * (G.CommissionRate/100))) - SUM(B.Discount * (G.CommissionRate/100)) AS NetAmount
FROM salesorderhd A
INNER JOIN salesorderdt B
ON A.SOHDId = B.SOHDId
INNER JOIN branch D
ON A.BranchId = D.BranchId
INNER JOIN companyinfo G
ON A.CompanyInfoId = G.CompanyInfoId
WHERE (A.CancelStatus = 0)
and (A.SODate BETWEEN date1 AND date2)
GROUP BY A.SODate;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `TaxReportBySalesDateSummaryBranch`;
DELIMITER |
CREATE PROCEDURE `TaxReportBySalesDateSummaryBranch`(in
date1 date,
date2 date,
BranchId1 int)
BEGIN
SELECT date1
, date2
, D.BranchName AS CompanyName
, D.BranchAddress AS CompanyAddress1
, D.BranchAddress2 AS CompanyAddress2
, D.BranchTelNo AS ContactNo1
, D.BranchTelNo2 AS ContactNo2
, A.SODate
, SUM(B.SalesQty * (B.SalesPrice * (G.CommissionRate/100))) - SUM(B.Discount * (G.CommissionRate/100)) AS NetAmount
FROM salesorderhd A
INNER JOIN salesorderdt B
ON A.SOHDId = B.SOHDId
INNER JOIN branch D
ON A.BranchId = D.BranchId
INNER JOIN companyinfo G
ON A.CompanyInfoId = G.CompanyInfoId
WHERE (A.CancelStatus = 0)
AND (A.BranchId = BranchId1)
and (A.SODate BETWEEN date1 AND date2)
GROUP BY A.SODate;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `TaxSalesReportByItemCategory`;
DELIMITER |
CREATE PROCEDURE `TaxSalesReportByItemCategory`(in
date1 date,
date2 date,
ItemCatId1 int
)
BEGIN
SELECT E.TaxSalesId AS BillNo
, A.SODate
, C.ItemName
, B.SalesQty
, B.SalesPrice AS SellingPrice
, B.SalesQty * B.SalesPrice AS SalesAmount
, B.Discount, B.NetAmount
, D.CompanyName
, D.CompanyAddress1
, D.CompanyAddress2
, D.ContactNo1
, D.ContactNo2
, D.CompanyLogo
, C.ItemCode
, C.ItemCatId
FROM salesorderhd A
INNER JOIN salesorderdt B
ON A.SOHDId = B.SOHDId
INNER JOIN itemsummary C
ON B.ItemsId = C.ItemsId
INNER JOIN taxsales E
