where (C.ItemCatId = ItemCatId1) AND (E.SODate BETWEEN date1 AND date2)
ORDER BY BillNo, A.SODate, C.ItemName;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `TaxSalesReportByItemCode`;
DELIMITER |
CREATE PROCEDURE `TaxSalesReportByItemCode`(in
date1 date,
date2 date,
ItemCode1 VARCHAR(50)
)
BEGIN
SELECT E.TaxSalesId AS BillNo
, A.SODate
