DROP PROCEDURE IF EXISTS `UpdateAllStock`;
DELIMITER |
CREATE PROCEDURE `UpdateAllStock`(in
ItemCode1 VARCHAR(50),
ItemName1 VARCHAR(150),
CostPrice1 decimal(10, 2),
SellingPrice1 decimal(10, 2),
SellingPrice2 decimal(10, 2),
MinQty1 decimal(10, 2),
AvailableQty1 decimal(10, 2),
BranchId1 int,
RackNo1 VARCHAR(25),
DefaultCostPrice1 decimal(10, 2),
OpenStates int,
ItemsId1 int,
ShopPrice1 decimal(10, 2)
)
BEGIN
DECLARE ExistQty1 decimal(10, 2) DEFAULT 0;
if(OpenStates = 1)Then
begin
IF EXISTS (SELECT 1 FROM itemsummary WHERE (ItemsId = ItemsId1)) THEN
BEGIN
DELETE from branchstock
WHERE BranchId = BranchId1
AND ItemsId = ItemsId1;
INSERT INTO branchstock
(BranchId
, ItemsId
, ItemCode
, AvailableQty)
VALUES
(BranchId1
, ItemsId1
, ItemCode1
, AvailableQty1);
UPDATE itemsummary
SET  ItemName = ItemName1
, CostPrice = CostPrice1
, SellingPrice = SellingPrice1
, SPSellingPrice = SellingPrice2
, MinQty = MinQty1
, RackNo = RackNo1
, DefaultCostPrice = DefaultCostPrice1
, OpenBalQty = AvailableQty1
,ShopPrice = ShopPrice1
WHERE (ItemsId = ItemsId1);
UPDATE itemsummary t1
INNER JOIN branchstock t2
ON t1.ItemsId = t2.ItemsId
SET t1.AvailableQty = (SELECT IFNULL((SUM(Y.AvailableQty)), 0)
FROM branchstock Y
WHERE Y.ItemsId = t1.ItemsId)
AND t1.ItemsId = ItemsId1;
END;
END IF;
end;
else
begin
IF EXISTS (SELECT 1 FROM itemsummary WHERE (ItemsId = ItemsId1)) THEN
BEGIN
UPDATE branchstock
SET  AvailableQty = AvailableQty1
WHERE BranchId = BranchId1
AND ItemsId = ItemsId1;
UPDATE itemsummary
SET  ItemName = ItemName1
, CostPrice = CostPrice1
, SellingPrice = SellingPrice1
, SPSellingPrice = SellingPrice2
, MinQty = MinQty1
, RackNo = RackNo1
, DefaultCostPrice = DefaultCostPrice1
,ShopPrice = ShopPrice1
WHERE (ItemCode = ItemCode1);
UPDATE itemsummary t1
INNER JOIN branchstock t2
ON t1.ItemsId = t2.ItemsId
SET t1.AvailableQty = (SELECT IFNULL((SUM(Y.AvailableQty)), 0)
FROM branchstock Y
WHERE Y.ItemsId = t1.ItemsId)
AND t1.ItemsId = ItemsId1;
END;
END IF;
end;
end if;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `UpdateAllStock1`;
DELIMITER |
