DROP PROCEDURE IF EXISTS `UpdateAttendance`;
DELIMITER |
CREATE PROCEDURE `UpdateAttendance`(in
AttendanceDate1 datetime
, EmployeeID1 int
, AttendanceStatus1 tinyint
, AttendanceType1 varchar(10)
, AttendanceDate2 date
, DayType1 varchar(10)
)
BEGIN
DECLARE WorkingHoursPerDay1 DECIMAL(20,2) DEFAULT 0;
SELECT WorkingHoursPerDay INTO WorkingHoursPerDay1
FROM employeeregistration
WHERE (EmployeeID = EmployeeID1);
IF EXISTS (SELECT 1 FROM employeeattendance WHERE (EmployeeID = EmployeeID1) AND (AttendanceDate = AttendanceDate2)) THEN
BEGIN
IF(AttendanceType1 = 'In') THEN
BEGIN
UPDATE employeeattendance
SET AttendanceIn = AttendanceDate1
,TotalHours = CASE WHEN DayType1 = 'Full' THEN WorkingHoursPerDay1 ELSE (WorkingHoursPerDay1/2) END
WHERE (EmployeeID = EmployeeID1)
AND (AttendanceDate = AttendanceDate2);
END;
ELSEIF(AttendanceType1 = 'Out') THEN
BEGIN
UPDATE employeeattendance
SET AttendanceOut = AttendanceDate1
, WorkingHours = (time_to_sec(timediff(AttendanceDate1, AttendanceIn)) / 3600)
, OTHours = ((time_to_sec(timediff(AttendanceDate1, AttendanceIn)) / 3600) - TotalHours)
WHERE (EmployeeID = EmployeeID1)
AND (AttendanceDate = AttendanceDate2);
END;
END IF;
END;
ELSE
BEGIN
IF(AttendanceType1 = 'In') THEN
BEGIN
INSERT INTO employeeattendance
(EmployeeID
, AttendanceDate
, AttendanceIn
, TotalHours
)
VALUES (EmployeeID1
, AttendanceDate1
, AttendanceDate1
, CASE WHEN DayType1 = 'Full' THEN WorkingHoursPerDay1 ELSE (WorkingHoursPerDay1/2) END
);
END;
END IF;
END;
END IF;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `UpdateBranch`;
DELIMITER |
CREATE PROCEDURE `UpdateBranch`(in
BranchName1 varchar(100),
BranchAddress1 varchar(200),
BranchAddress21 varchar(200),
BranchTelNo1 varchar(25),
BranchTelNo21 varchar(15),
BranchFaxNo1 varchar(25),
BranchEmail1 varchar(125),
Remarks1 varchar(100),
ModifiedBy1 int,
BranchId1 int)
BEGIN
UPDATE branch
SET BranchName = BranchName1,
BranchAddress = BranchAddress1,
BranchAddress2 = BranchAddress21,
BranchTelNo = BranchTelNo1,
BranchTelNo2 = BranchTelNo21,
BranchFaxNo = BranchFaxNo1,
BranchEmail = BranchEmail1,
Remarks = Remarks1,
ModifiedOn = CONVERT_TZ(now(), @@session.time_zone, '+05:30'),
ModifiedBy = ModifiedBy1
WHERE (BranchId = BranchId1);
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `UpdateCustCreditPayCancel`;
DELIMITER |
CREATE PROCEDURE `UpdateCustCreditPayCancel`(in CreditPayHDId1 int)
BEGIN
IF EXISTS (SELECT 1 FROM custcreditpaymenthd WHERE (CreditPayHDId = CreditPayHDId1) AND (CancelStatus = 0)) THEN
BEGIN
UPDATE customer t1
INNER JOIN custcreditpayment t2
ON t1.CustomerId = t2.CustomerId
SET t1.BalanceAmount = t1.BalanceAmount + (SELECT IFNULL((SUM(Y.PaymentAmount)), 0)
FROM custcreditpayment Y
WHERE Y.CreditPayHDId = CreditPayHDId1)
where t2.CreditPayHDId = CreditPayHDId1;
UPDATE customercredit t1
INNER JOIN custcreditpayment t2
ON t1.CustomerId = t2.CustomerId
AND t1.BillNo = t2.BillNo
SET t1.PaymentCompletedStatus = 0
where t2.CreditPayHDId = CreditPayHDId1;
UPDATE customercredit t1
INNER JOIN custcreditpayment t2
ON t1.CustomerId = t2.CustomerId
AND t1.BillNo = t2.BillNo
SET t1.PaymentAmount = t1.PaymentAmount - (SELECT IFNULL(((Y.PaymentAmount)), 0)
FROM custcreditpayment Y
WHERE Y.CreditPayHDId = CreditPayHDId1
AND Y.BillNo = t2.BillNo)
, t1.BalanceAmount = t1.BalanceAmount + (SELECT IFNULL(((Y.PaymentAmount)), 0)
FROM custcreditpayment Y
WHERE Y.CreditPayHDId = CreditPayHDId1
AND Y.BillNo = t2.BillNo)
where t2.CreditPayHDId = CreditPayHDId1;
UPDATE custcreditpayment
SET PaymentAmount = 0
WHERE CreditPayHDId = CreditPayHDId1;
UPDATE custcreditpaymenthd
SET CancelStatus = 1
WHERE CreditPayHDId = CreditPayHDId1;
END;
END IF;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `UpdateCustomer`;
DELIMITER |
CREATE PROCEDURE `UpdateCustomer`(in CustomerName1 nvarchar(100),
CustomerAddress1 nvarchar(200),
CustomerTelNo1 nvarchar(25),
CustomerFaxNo1 nvarchar(25),
CustomerEmail1 nvarchar(125),
CustomerNICNo1 nvarchar(15),
Remarks1 varchar(100),
VATCustomer1 TINYINT(4),
ModifiedBy1 int,
CustomerId1 int,
ContactPerson1 varchar(80),
BalanceAmount1 DECIMAL(20,2),
CustomerImage1 LONGBLOB,
AreaId1 int,
NewAreaId1 int,
CreditLimit1 DECIMAL(20,2),
PriceMode1 varchar(10),
CustomerTypeId1 int,
LoyaltyPercentage1 DECIMAL(20,2),
LoyaltyAmount1 DECIMAL(20,2),
EmployeeID1 int)
BEGIN
UPDATE customer
SET CustomerName = CustomerName1,
CustomerAddress = CustomerAddress1,
CustomerTelNo = CustomerTelNo1,
CustomerFaxNo = CustomerFaxNo1,
CustomerEmail = CustomerEmail1,
CustomerNICNo = CustomerNICNo1,
Remarks = Remarks1,
VATCustomer = VATCustomer1,
ModifiedOn = CONVERT_TZ(now(), @@session.time_zone, '+05:30'),
ModifiedBy = ModifiedBy1,
ContactPerson = ContactPerson1,
CustomerImage = CustomerImage1,
AreaId = AreaId1,
NewAreaId = NewAreaId1,
CreditLimit = CreditLimit1,
PriceMode = PriceMode1,
CustomerTypeId = CustomerTypeId1,
LoyaltyPercentage = LoyaltyPercentage1,
LoyaltyAmount = LoyaltyAmount1,
