DROP PROCEDURE IF EXISTS `UpdateCustomerOB`;
DELIMITER |
CREATE PROCEDURE `UpdateCustomerOB`(in
CustomerId1 int,
BalanceAmount1 DECIMAL(20,2)
)
BEGIN
if exists (SELECT 1 FROM customercredit WHERE (BillNo = 0) AND (CustomerId = CustomerId1)) THEN
begin
UPDATE customercredit
SET CreditAmount = BalanceAmount1
, CreditDate = CONVERT_TZ(now(), @@session.time_zone, '+05:30')
, PaymentCompletedStatus = CASE WHEN BalanceAmount1 > 0 THEN 0 ELSE 1 END
WHERE (CustomerId = CustomerId1) AND (BillNo = 0);
end;
ELSE
BEGIN
INSERT INTO customercredit
(CustomerId
, BillNo
, CreditDate
, CreditAmount
, CreatedOn
, CreatedBy)
SELECT CustomerId1
, 0
, CONVERT_TZ(now(), @@session.time_zone, '+05:30')
, BalanceAmount1
, CONVERT_TZ(now(), @@session.time_zone, '+05:30')
, CreatedBy
FROM  customer
WHERE (CustomerId = CustomerId1)
;
END;
END IF;
UPDATE customercredit
SET PaymentCompletedStatus = 1
WHERE CreditAmount = 0
AND CustomerId = CustomerId1;
UPDATE customer
SET BalanceAmount = BalanceAmount1
WHERE (CustomerId = CustomerId1);
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `UpdateCustReturnCredit`;
DELIMITER |
CREATE PROCEDURE `UpdateCustReturnCredit`(in BillNo1 int, CustomerId1 int,CreditAmount1 DECIMAL(20,2))
BEGIN
UPDATE       customercredit
SET                CreditAmount = CreditAmount - CreditAmount1
WHERE        (BillNo = BillNo1);
END |
