DROP PROCEDURE IF EXISTS `UpdateDayEnd`;
DELIMITER |
CREATE PROCEDURE `UpdateDayEnd`(in CreatedBy1 int, BranchId1 int)
BEGIN
DECLARE UTCDate1 date;
DECLARE ExpensesId1 INT DEFAULT 0;
DECLARE CustCreditPayHDId1 INT DEFAULT 0;
DECLARE CustomerId1 INT DEFAULT 0;
DECLARE ItemsId1 INT DEFAULT 0;
DECLARE PIHDId1 INT DEFAULT 0;
DECLARE SOHDId1 INT DEFAULT 0;
DECLARE StkAdjHDId1 INT DEFAULT 0;
DECLARE TransferHDId1 INT DEFAULT 0;
DECLARE SuppCreditPayHDId1 INT DEFAULT 0;
DECLARE SupplierId1 INT DEFAULT 0;
SET UTCDate1 = (select CONVERT_TZ(now(), @@session.time_zone, '+05:30'));
SELECT IFNULL(MAX(ExpensesId), 0) INTO ExpensesId1
FROM allexpenses;
SELECT IFNULL(MAX(CreditPayHDId), 0) INTO CustCreditPayHDId1
FROM custcreditpaymenthd;
SELECT IFNULL(MAX(CustomerId), 0) INTO CustomerId1
FROM customer;
SELECT IFNULL(MAX(ItemsId), 0) INTO ItemsId1
FROM itemsummary;
SELECT IFNULL(MAX(PIHDId), 0) INTO PIHDId1
FROM pihd;
SELECT IFNULL(MAX(SOHDId), 0) INTO SOHDId1
FROM salesorderhd;
SELECT IFNULL(MAX(StkAdjHDId), 0) INTO StkAdjHDId1
FROM stkadjhd;
SELECT IFNULL(MAX(TransferHDId), 0) INTO TransferHDId1
FROM stocktransferhd;
SELECT IFNULL(MAX(CreditPayHDId), 0) INTO SuppCreditPayHDId1
FROM suppcreditpaymenthd;
SELECT IFNULL(MAX(SupplierId), 0) INTO SupplierId1
FROM supplier;
IF EXISTS (SELECT 1 FROM dayendrecord WHERE (DayEndDate = UTCDate1)) THEN
BEGIN
UPDATE dayendrecord
SET BranchId = BranchId1
, ExpensesId =ExpensesId1
, CustCreditPayHDId = CustCreditPayHDId1
, CustomerId = CustomerId1
, ItemsId = ItemsId1
, PIHDId = PIHDId1
, SOHDId = SOHDId1
, StkAdjHDId = StkAdjHDId1
, TransferHDId = TransferHDId1
, SuppCreditPayHDId = SuppCreditPayHDId1
, SupplierId = SupplierId1
WHERE (DayEndDate = UTCDate1);
END;
ELSE
BEGIN
INSERT INTO dayendrecord
(DayEndDate
, CreatedOn
, CreatedBy
, BranchId
, ExpensesId
, CustCreditPayHDId
, CustomerId
, ItemsId
, PIHDId
, SOHDId
, StkAdjHDId
, TransferHDId
, SuppCreditPayHDId
, SupplierId)
VALUES (CONVERT_TZ(now(), @@session.time_zone, '+05:30')
, CONVERT_TZ(now(), @@session.time_zone, '+05:30')
, CreatedBy1
, BranchId1
, ExpensesId1
, CustCreditPayHDId1
, CustomerId1
, ItemsId1
, PIHDId1
, SOHDId1
, StkAdjHDId1
, TransferHDId1
, SuppCreditPayHDId1
, SupplierId1);
END;
END IF;
END |
DELIMITER ;

