DROP PROCEDURE IF EXISTS `UpdateGINNEWCancel`;
DELIMITER |
CREATE PROCEDURE `UpdateGINNEWCancel`(in TransferHDId1 int)
BEGIN
DECLARE ExpensesId1 int DEFAULT 0;

SELECT ExpensesId INTO ExpensesId1
FROM ginhdnew
WHERE TransferHDId = TransferHDId1;

UPDATE branchstock A
INNER JOIN (SELECT B.TransferHDId, B.FromBranchId, C.ItemsId, SUM(C.Qty) AS Qty
FROM ginhdnew B
INNER JOIN gindtnew C
ON B.TransferHDId = C.TransferHDId
WHERE B.TransferHDId = TransferHDId1
GROUP BY B.TransferHDId, B.FromBranchId, C.ItemsId)B
ON A.ItemsId = B.ItemsId
SET A.AvailableQty =  A.AvailableQty + B.Qty
WHERE B.TransferHDId = TransferHDId1
AND A.BranchId = B.FromBranchId;

UPDATE itemsummary A
INNER JOIN (SELECT B.TransferHDId, C.ItemsId, SUM(C.Qty) AS Qty
FROM ginhdnew B
INNER JOIN gindtnew C
ON B.TransferHDId = C.TransferHDId
WHERE B.TransferHDId = TransferHDId1
GROUP BY B.TransferHDId, C.ItemsId)B
ON A.ItemsId = B.ItemsId
SET A.AvailableQty =  A.AvailableQty + B.Qty
WHERE B.TransferHDId = TransferHDId1;

UPDATE ginhdnew
SET CancelStatus = 1
WHERE TransferHDId = TransferHDId1;

DELETE FROM allexpenses
WHERE ExpensesId = ExpensesId1;

END |
DELIMITER ;

