DROP PROCEDURE IF EXISTS `UpdateImportStock`;
DELIMITER |
CREATE PROCEDURE `UpdateImportStock`(in
ItemCode1 VARCHAR(50),
CostPrice1 decimal(10, 2),
SellingPrice1 decimal(10, 2),
SellingPrice2 decimal(10, 2),
DefaultCostPrice1 decimal(10, 2),
ShopPrice1 decimal(10, 2),
Discount1 decimal(10, 2),
WholeSaleDiscount1 decimal(10, 2)
)
BEGIN

IF EXISTS (SELECT 1 FROM itemsummary WHERE (ItemCode = ItemCode1)) THEN
BEGIN

UPDATE itemsummary
SET SellingPrice = CASE SellingPrice1 WHEN -1 THEN SellingPrice ELSE SellingPrice1 END
, SPSellingPrice = CASE SellingPrice2 WHEN -1 THEN SPSellingPrice ELSE SellingPrice2 END
, CostPrice = CASE CostPrice1 WHEN -1 THEN CostPrice ELSE CostPrice1 END
, ShopPrice = CASE ShopPrice1 WHEN -1 THEN ShopPrice ELSE ShopPrice1 END
, DefaultCostPrice = CASE DefaultCostPrice1 WHEN -1 THEN DefaultCostPrice ELSE DefaultCostPrice1 END
, Discount = CASE Discount1 WHEN -1 THEN Discount ELSE Discount1 END
, WholeSaleDiscount = CASE WholeSaleDiscount1 WHEN -1 THEN WholeSaleDiscount ELSE WholeSaleDiscount1 END
WHERE ItemCode = ItemCode1;

END;
END IF;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `UpdateInvoice`;
DELIMITER |
CREATE PROCEDURE `UpdateInvoice`(in 
SOHDId1 int
,SOGrossTotal1 DECIMAL(20,2)
,SODiscount1 DECIMAL(20,2)
,Charges1 DECIMAL(20,2)
,SONetTotal1 DECIMAL(20,2)
,CreatedBy1 int
)
BEGIN

DECLARE CustomerId1 INT;
DECLARE CurDiscountAmount1 DECIMAL(20,2) DEFAULT 0;
DECLARE CurChargeAmount1 DECIMAL(20,2) DEFAULT 0;
DECLARE DiscountAmount1 DECIMAL(20,2) DEFAULT 0;
DECLARE ChargeAmount1 DECIMAL(20,2) DEFAULT 0;

SELECT SODiscount INTO CurDiscountAmount1
FROM salesorderhd
WHERE (SOHDId = SOHDId1);

SELECT Charges INTO CurChargeAmount1
FROM salesorderhd
WHERE (SOHDId = SOHDId1);

SET DiscountAmount1 = SODiscount1 - CurDiscountAmount1;
SET ChargeAmount1 = Charges1 - CurChargeAmount1;

SET CustomerId1 = (SELECT CustomerId
FROM salesorderhd
WHERE (SOHDId = SOHDId1));

INSERT INTO updatedinvoice
(SOHDId
, SOGrossTotal
, SODiscount
, Charges
, SONetTotal
, CreatedOn
, CreatedBy
)
VALUES (SOHDId1
, SOGrossTotal1
, SODiscount1
, Charges1
, SONetTotal1
, CONVERT_TZ(now(), @@session.time_zone, '+05:30')
, CreatedBy1)
;

UPDATE salesorderhd
SET SONetTotal = SONetTotal - DiscountAmount1
, ReceivableAmount = ReceivableAmount - DiscountAmount1
WHERE SOHDId = SOHDId1;

UPDATE salesorderhd
SET SONetTotal = SONetTotal + ChargeAmount1
, ReceivableAmount = ReceivableAmount + ChargeAmount1
WHERE SOHDId = SOHDId1;

UPDATE customercredit
SET CreditAmount = CreditAmount - DiscountAmount1
, BalanceAmount = BalanceAmount - DiscountAmount1
WHERE BillNo = SOHDId1;

UPDATE customercredit
SET CreditAmount = CreditAmount + ChargeAmount1
, BalanceAmount = BalanceAmount + ChargeAmount1
WHERE BillNo = SOHDId1;

UPDATE customer
SET BalanceAmount = BalanceAmount - DiscountAmount1
WHERE (CustomerId = CustomerId1);

UPDATE customer
SET BalanceAmount = BalanceAmount + ChargeAmount1
WHERE (CustomerId = CustomerId1);


UPDATE salesorderhd
SET SODiscount = SODiscount1
, Charges = Charges1
WHERE SOHDId = SOHDId1;

END |
DELIMITER ;

