DROP PROCEDURE IF EXISTS `UpdateIssueChqRealize`;
DELIMITER |
CREATE PROCEDURE `UpdateIssueChqRealize`(in
SuppChqId1 int
, SupplierId1 int
, POHDId1 int
, ChequeAmount1 DECIMAL(20,2)
, RtnRemark1 VARCHAR(100)
, CreatedBy1 int
, BankId1 int)
