SET RealizeStatus = 1
, RtnRemark = RtnRemark1
, BankId = BankId1
WHERE (SuppChqId = SuppChqId1);
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `UpdateIssueChqRtn`;
DELIMITER |
CREATE PROCEDURE `UpdateIssueChqRtn`(in
SuppChqId1 int
, SupplierId1 int
, POHDId1 int
, ChequeAmount1 DECIMAL(20,2)
, RtnRemark1 VARCHAR(100)
, CreatedBy1 int)
BEGIN
DECLARE PaymentAmount1 DECIMAL(20,2) DEFAULT 0;
DECLARE CreditPayHDId1 INT DEFAULT 0;

SELECT ChequeAmount INTO PaymentAmount1
FROM suppliercheque
WHERE (SuppChqId = SuppChqId1);

SELECT CreditPayHDId INTO CreditPayHDId1
FROM suppliercheque
WHERE (SuppChqId = SuppChqId1);

IF(CreditPayHDId1) <> 0 THEN
BEGIN

UPDATE suppliercredit D
INNER JOIN suppcreditpayment B
ON B.SupplierId = D.SupplierId
AND B.BillNo = D.PIHDId
AND B.SuppCreditId = D.SuppCreditId
INNER JOIN suppcreditpaymenthd A
ON A.CreditPayHDId = B.CreditPayHDId
AND A.PayModeId = B.PayModeId
AND A.CreditPayHDId = CreditPayHDId1
INNER JOIN suppliercheque C
ON B.SupplierId = C.SupplierId
AND B.CardChequeNo = C.ChequeNo
SET D.PaymentAmount = D.PaymentAmount - B.PaymentAmount
, D.PaymentCompletedStatus = 0
WHERE A.PayModeId = 2
AND A.CancelStatus = 0
AND C.SuppChqId = SuppChqId1;

UPDATE suppcreditpayment B
INNER JOIN suppliercredit D
ON B.SupplierId = D.SupplierId
AND B.BillNo = D.PIHDId
AND B.SuppCreditId = D.SuppCreditId
INNER JOIN suppcreditpaymenthd A
ON A.CreditPayHDId = B.CreditPayHDId
AND A.PayModeId = B.PayModeId
AND A.CreditPayHDId = CreditPayHDId1
INNER JOIN suppliercheque C
ON B.SupplierId = C.SupplierId
AND B.CardChequeNo = C.ChequeNo
SET B.PaymentAmount = 0
WHERE A.PayModeId = 2
AND A.CancelStatus = 0
AND C.SuppChqId = SuppChqId1;

UPDATE suppcreditpaymenthd
SET CancelStatus = 1
WHERE CreditPayHDId = CreditPayHDId1;

END;
ELSE
BEGIN

INSERT INTO suppliercredit
(SupplierId
, PIHDId
, CreditDate
, CreditAmount
, CreatedOn
, CreatedBy)
SELECT SupplierId
, POHDId
, IssueDate
, ChequeAmount
, CONVERT_TZ(now(), @@session.time_zone, '+05:30')
, CreatedBy1
FROM suppliercheque
WHERE (SuppChqId = SuppChqId1);

END;
END IF;

