DROP PROCEDURE IF EXISTS `UpdateNewHoldInvoiceSOHD`;
DELIMITER |
CREATE PROCEDURE `UpdateNewHoldInvoiceSOHD`(in
PayModeId1 int,
CustomerId1 int,
BillNo1 int,
SOGrossTotal1 DECIMAL(20,2),
AdditionalChgs1 DECIMAL(20,2),
SODiscount1 DECIMAL(20,2),
SONetTotal1 DECIMAL(20,2),
CreatedBy1 int,
Cash1 DECIMAL(20,2),
Remarks1 varchar(100),
RepId1 int,
VAT1 DECIMAL(20,2),
NBT1 DECIMAL(20,2),
BranchId1 int,
ReturnTotal1 DECIMAL(20,2),
CreditPay1 DECIMAL(20,2),
CreditTotal1 DECIMAL(20,2),
RefNo1 int,
ReferanceNo1 varchar(20),
TerminalNo1 int,
VoucherNo1 int,
VoucherAmount1 DECIMAL(20,2),
ReceivableAmount1 DECIMAL(20,2),
CustomerName1 varchar(100),
Charges1 DECIMAL(20,2),
CreditDueDays1 int,
CompletedDate1 date,
InvoiceStatusId1 INT,
RepairBill1 TINYINT(1),
LoyaltyPoints1 DECIMAL(20,2),
LoyaltyBalance1 DECIMAL(20,2),
CashBalance1 DECIMAL(20,2),
ReturnNoteNo1 INT,
ReturnNoteAmount1 DECIMAL(20,2),
OUT SOHDId1 INT
)
BEGIN
DECLARE UTCDate1 date;
SET UTCDate1 = (select CONVERT_TZ(now(), @@session.time_zone, '+05:30'));
DELETE FROM salesorderdthold
WHERE SOHDId = BillNo1;
UPDATE salesorderhd
SET SODate = CONVERT_TZ(now(), @@session.time_zone, '+05:30')
, PayModeId = PayModeId1
, CustomerId = CustomerId1
, RepId = RepId1
, SOGrossTotal = SOGrossTotal1
, AdditionalChgs = AdditionalChgs1
, SODiscount = SODiscount1
, SONetTotal = SONetTotal1
, Cash = Cash1
, Remarks = Remarks1
, BranchId = BranchId1
, ReturnTotal = ReturnTotal1
, CreditPay = CreditPay1
, CreditTotal = CreditTotal1
, ReferanceNo = ReferanceNo1
, TerminalNo = TerminalNo1
, VoucherNo = VoucherNo1
, VoucherAmount = VoucherAmount1
, ReceivableAmount = ReceivableAmount1
, CustomerName = CustomerName1
, Charges = Charges1
, CreditDueDays = CreditDueDays1
, CompletedDate = CompletedDate1
, InvoiceStatusId = InvoiceStatusId1
, LoyaltyPoints = LoyaltyPoints1
, LoyaltyBalance = LoyaltyBalance1
, CashBalance = CashBalance1
, ReturnNoteNo = ReturnNoteNo1
, ReturnNoteAmount = ReturnNoteAmount1
WHERE SOHDId = BillNo1;
SET SOHDId1 = BillNo1;
if(PayModeId1 = 1) THEN
BEGIN
UPDATE cashbalance
SET CashInAmount = CashInAmount + (SONetTotal1 - ReturnTotal1 - VoucherAmount1)
, LastBalance = LastBalance + (SONetTotal1 - ReturnTotal1 - VoucherAmount1)
WHERE BalanceDate= UTCDate1
AND UserId = CreatedBy1;
END;
elseif(PayModeId1 = 8) THEN
BEGIN
INSERT INTO usedloyaltypoints
(CustomerId
, UsedDate
, UsedPoints
, ResetStatus
, SOHDId
)
VALUES (CustomerId1
, CONVERT_TZ(now(), @@session.time_zone, '+05:30')
, (ReceivableAmount1 - Cash1)
,0
,SOHDId1
)
;
UPDATE customer
SET TotalLoyaltyPoints = TotalLoyaltyPoints - (ReceivableAmount1 - Cash1)
WHERE (CustomerId = CustomerId1);
END;
ELSE
BEGIN
UPDATE cashbalance
SET CashInAmount = CashInAmount + Cash1
, LastBalance = LastBalance + Cash1
WHERE BalanceDate= UTCDate1
AND UserId = CreatedBy1;
END;
END IF;
UPDATE sohd
SET RefInvNo = SOHDId1
WHERE (SOHDId = RefNo1);
UPDATE salesorderhd
SET BillNo = SOHDId1
WHERE (SOHDId = SOHDId1);
IF(VoucherNo1 > 0) then
begin
UPDATE giftvoucher
SET VoucherStatus = 1
,UsedOn = UTCDate1
,SOHDId = SOHDId1
WHERE VoucherNo = VoucherNo1;
end;
end if;
UPDATE customer
SET TotalLoyaltyPoints = TotalLoyaltyPoints + LoyaltyPoints1
WHERE (CustomerId = CustomerId1);
SELECT SOHDId1;
END |
DELIMITER ;

