DROP PROCEDURE IF EXISTS `UpdateNextDueDate`;
DELIMITER |
CREATE PROCEDURE `UpdateNextDueDate`(in CustomerId1 int)
BEGIN
DECLARE UTCDate1 date;
SET UTCDate1 = (select CONVERT_TZ(now(), @@session.time_zone, '+05:30'));
CREATE TEMPORARY TABLE IF NOT EXISTS temp1 ENGINE=MEMORY
as (
SELECT X.CustomerId
, X.BillNo
FROM(
SELECT A.CustomerId
, B.BillNo
FROM customer A
INNER JOIN customercredit B
ON A.CustomerId = B.CustomerId
WHERE (A.CustomerId = CustomerId1)
AND (B.PaymentCompletedStatus = 0)
AND (B.CreditDueDate <= CURDATE())
AND (A.NextDueDate <= CURDATE())
UNION ALL
SELECT A.CustomerId
, B.BillNo
FROM customer A
INNER JOIN customercredit B
ON A.CustomerId = B.CustomerId
WHERE (A.CustomerId = CustomerId1)
AND (B.PaymentCompletedStatus = 0)
AND (B.CreditDueDate > CURDATE())
AND (A.NextDueDate <= CURDATE())
)X
);
UPDATE customer
SET NextDueDate = (SELECT DATE_ADD(UTCDate1, INTERVAL 7 DAY))
WHERE CustomerId = CustomerId1;
UPDATE customercredit
INNER JOIN temp1
ON customercredit.BillNo = temp1.BillNo
SET customercredit.NextDueDate = (SELECT DATE_ADD(UTCDate1, INTERVAL 7 DAY))
WHERE customercredit.CustomerId = CustomerId1;
drop table temp1;
END |
DELIMITER ;

