DROP PROCEDURE IF EXISTS `UpdatePriceCategoryDecrease`;
DELIMITER |
CREATE PROCEDURE `UpdatePriceCategoryDecrease`(in
ItemCatId1 int
,PriceMode1 VARCHAR(10)
,RetailPrice1 decimal(10, 2)
)
BEGIN
IF (PriceMode1 = 'Retail') THEN
begin
UPDATE itemsummary
SET SellingPrice = SellingPrice - RetailPrice1
WHERE ItemCatId = ItemCatId1;
END;
ELSEIF(PriceMode1 = 'Wholesale') THEN
BEGIN
UPDATE itemsummary
SET SPSellingPrice = SPSellingPrice - RetailPrice1
WHERE ItemCatId = ItemCatId1;
END;
ELSE
BEGIN
UPDATE itemsummary
SET ShopPrice = ShopPrice - RetailPrice1
WHERE ItemCatId = ItemCatId1;
END;
END IF;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `UpdatePriceCategoryIncrease`;
DELIMITER |
CREATE PROCEDURE `UpdatePriceCategoryIncrease`(in
ItemCatId1 int
,PriceMode1 VARCHAR(10)
,RetailPrice1 decimal(10, 2)
)
BEGIN
IF (PriceMode1 = 'Retail') THEN
begin
UPDATE itemsummary
SET SellingPrice = SellingPrice + RetailPrice1
WHERE ItemCatId = ItemCatId1;
END;
ELSEIF(PriceMode1 = 'Wholesale') THEN
BEGIN
UPDATE itemsummary
SET SPSellingPrice = SPSellingPrice + RetailPrice1
WHERE ItemCatId = ItemCatId1;
END;
ELSE
BEGIN
UPDATE itemsummary
SET ShopPrice = ShopPrice + RetailPrice1
WHERE ItemCatId = ItemCatId1;
END;
END IF;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `UpdatePriceCategoryPerDecrease`;
DELIMITER |
CREATE PROCEDURE `UpdatePriceCategoryPerDecrease`(in
ItemCatId1 int
,PriceMode1 VARCHAR(10)
,RetailPrice1 decimal(10, 2)
)
BEGIN
IF (PriceMode1 = 'Retail') THEN
begin
UPDATE itemsummary
SET SellingPrice = SellingPrice - (SellingPrice * (RetailPrice1/100))
WHERE ItemCatId = ItemCatId1;
END;
ELSEIF(PriceMode1 = 'Wholesale') THEN
BEGIN
UPDATE itemsummary
SET SPSellingPrice = SPSellingPrice - (SPSellingPrice * (RetailPrice1/100))
WHERE ItemCatId = ItemCatId1;
END;
ELSE
BEGIN
UPDATE itemsummary
SET ShopPrice = ShopPrice - (ShopPrice * (RetailPrice1/100))
WHERE ItemCatId = ItemCatId1;
END;
END IF;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `UpdatePriceCategoryPerIncrease`;
DELIMITER |
CREATE PROCEDURE `UpdatePriceCategoryPerIncrease`(in
ItemCatId1 int
,PriceMode1 VARCHAR(10)
,RetailPrice1 decimal(10, 2)
)
BEGIN
IF (PriceMode1 = 'Retail') THEN
begin
UPDATE itemsummary
SET SellingPrice = (SellingPrice * (RetailPrice1/100)) + SellingPrice
WHERE ItemCatId = ItemCatId1;
END;
ELSEIF(PriceMode1 = 'Wholesale') THEN
BEGIN
UPDATE itemsummary
SET SPSellingPrice = (SPSellingPrice * (RetailPrice1/100)) + SPSellingPrice
WHERE ItemCatId = ItemCatId1;
END;
ELSE
BEGIN
UPDATE itemsummary
SET ShopPrice = (ShopPrice * (RetailPrice1/100)) + ShopPrice
WHERE ItemCatId = ItemCatId1;
END;
END IF;
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `UpdateProductConvert`;
DELIMITER |
CREATE PROCEDURE `UpdateProductConvert`(in
FromItemId1 int,
ToItemId1 int,
FromItemCode1 VARCHAR(50),
ToItemCode1 VARCHAR(50),
FromQty1 decimal(10, 2),
ToQty1 decimal(10, 2),
BranchId1 int
)
BEGIN
DECLARE ConvertionQty1 DECIMAL(20,2) DEFAULT 1;
SELECT ConvertionQty INTO ConvertionQty1
FROM itemsummary
WHERE (ItemsId = ToItemId1);
INSERT INTO inventorymovement
(ItemsId, MovementDate, RefDocId, RefDocType, Qty)
VALUES (ToItemId1, CONVERT_TZ(now(), @@session.time_zone, '+05:30'), ToItemId1, 'ConvertTo', (FromQty1 * ConvertionQty1));
UPDATE itemsummary
SET  AvailableQty = AvailableQty + (FromQty1 * ConvertionQty1)
WHERE (ItemsId = ToItemId1);
IF EXISTS (SELECT 1 FROM branchstock WHERE (BranchId = BranchId1) AND (ItemsId = ToItemId1)) THEN
BEGIN
UPDATE branchstock
SET AvailableQty = AvailableQty + (FromQty1 * ConvertionQty1)
WHERE (BranchId = BranchId1)
AND (ItemsId = ToItemId1);
END;
ELSE
BEGIN
INSERT INTO branchstock
(BranchId
, ItemsId
, ItemCode
, AvailableQty
, RefId)
VALUES
(BranchId1
, ToItemId1
, ToItemCode1
, (FromQty1 / ConvertionQty1)
, 0);
end;
end if;
INSERT INTO inventorymovement
(ItemsId, MovementDate, RefDocId, RefDocType, Qty)
VALUES (FromItemId1, CONVERT_TZ(now(), @@session.time_zone, '+05:30'), FromItemId1, 'ConvertFrom', FromQty1);
UPDATE branchstock
SET AvailableQty = AvailableQty - FromQty1
WHERE (BranchId = BranchId1)
AND (ItemsId = FromItemId1);
UPDATE itemsummary
SET  AvailableQty = AvailableQty - FromQty1
WHERE (ItemsId = FromItemId1);
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `UpdateProductConvertNew`;
DELIMITER |
CREATE PROCEDURE `UpdateProductConvertNew`(in
FromItemId1 int,
ToItemId1 int,
FromItemCode1 VARCHAR(50),
ToItemCode1 VARCHAR(50),
FromQty1 decimal(10, 6),
ToQty1 decimal(10, 6),
BranchId1 int,
SOHDId1 int
)
BEGIN
INSERT INTO inventorymovement
(ItemsId, MovementDate, RefDocId, RefDocType, Qty, SOHDId, ConvertFrom, ConvertTo, FromItemsId, ToItemsId, BranchId)
VALUES (ToItemId1, CONVERT_TZ(now(), @@session.time_zone, '+05:30'), FromItemId1, 'ConvertTo', ToQty1, SOHDId1, 0, 1, FromItemId1, ToItemId1, BranchId1);
INSERT INTO inventorymovement
(ItemsId, MovementDate, RefDocId, RefDocType, Qty, SOHDId, ConvertFrom, ConvertTo, FromItemsId, ToItemsId, BranchId)
VALUES (FromItemId1, CONVERT_TZ(now(), @@session.time_zone, '+05:30'), ToItemId1, 'ConvertFrom', FromQty1, SOHDId1, 1, 0, FromItemId1, ToItemId1, BranchId1);
UPDATE itemsummary
SET  AvailableQty = AvailableQty + ToQty1
WHERE (ItemsId = ToItemId1);
UPDATE branchstock
SET AvailableQty = AvailableQty + ToQty1
WHERE (BranchId = BranchId1)
AND (ItemsId = ToItemId1);
UPDATE branchstock
SET AvailableQty = AvailableQty - FromQty1
WHERE (BranchId = BranchId1)
AND (ItemsId = FromItemId1);
UPDATE itemsummary
SET  AvailableQty = AvailableQty - FromQty1
WHERE (ItemsId = FromItemId1);
END |
DELIMITER ;

