DROP PROCEDURE IF EXISTS `UpdateReceivedChqRtn`;
DELIMITER |
CREATE PROCEDURE `UpdateReceivedChqRtn`(in
CustChqId1 int
, CustomerId1 int
, SOHDId1 int
, ChequeAmount1 DECIMAL(20,2)
, RtnRemark1 VARCHAR(100)
, CreatedBy1 int)
BEGIN
DECLARE PaymentAmount1 DECIMAL(20,2) DEFAULT 0;
DECLARE CreditPayHDId1 INT DEFAULT 0;

SELECT ChequeAmount INTO PaymentAmount1
FROM customercheque
WHERE (CustChqId = CustChqId1);

SELECT A.CreditPayHDId INTO CreditPayHDId1
FROM custcreditpaymenthd A
INNER JOIN custcreditpayment B
ON A.CreditPayHDId = B.CreditPayHDId
AND A.PayModeId = B.PayModeId
INNER JOIN customercheque C
ON B.CustomerId = C.CustomerId
AND B.CardChequeNo = C.ChequeNo
INNER JOIN customercredit D
ON B.CustomerId = D.CustomerId
AND B.BillNo = D.BillNo
WHERE A.PayModeId = 2
AND A.CancelStatus = 0
AND A.CustChqId = CustChqId1
GROUP BY A.CreditPayHDId;

UPDATE customer
SET BalanceAmount = BalanceAmount + PaymentAmount1
WHERE CustomerId = CustomerId1;

IF(CreditPayHDId1) <> 0 THEN
BEGIN
UPDATE customercredit D
INNER JOIN custcreditpayment B
ON B.CustomerId = D.CustomerId
AND B.BillNo = D.BillNo
INNER JOIN custcreditpaymenthd A
ON A.CreditPayHDId = B.CreditPayHDId
AND A.PayModeId = B.PayModeId
INNER JOIN customercheque C
ON B.CustomerId = C.CustomerId
AND B.CardChequeNo = C.ChequeNo
SET D.PaymentAmount = D.PaymentAmount - B.PaymentAmount
, D.PaymentCompletedStatus = 0
, D.BalanceAmount = D.BalanceAmount + B.PaymentAmount
WHERE A.PayModeId = 2
AND A.CancelStatus = 0
AND A.CustChqId = CustChqId1;

UPDATE custcreditpayment B
INNER JOIN customercredit D
ON B.CustomerId = D.CustomerId
AND B.BillNo = D.BillNo
INNER JOIN custcreditpaymenthd A
ON A.CreditPayHDId = B.CreditPayHDId
AND A.PayModeId = B.PayModeId
INNER JOIN customercheque C
ON B.CustomerId = C.CustomerId
AND B.CardChequeNo = C.ChequeNo
SET B.PaymentAmount = 0
WHERE A.PayModeId = 2
AND A.CancelStatus = 0
AND A.CustChqId = CustChqId1;
UPDATE custcreditpaymenthd
SET CancelStatus = 1
WHERE CreditPayHDId = CreditPayHDId1;
END;
ELSE
BEGIN
INSERT INTO customercredit
(CustomerId
, BillNo
, CreditDate
, CreditAmount
, CreatedOn
, CreatedBy
, BalanceAmount
, CreditDueDate
, NextDueDate
, CreditDueDays
, CreditDueDayDate)
SELECT CustomerId
, SOHDId
, IssueDate
, ChequeAmount
, CONVERT_TZ(now(), @@session.time_zone, '+05:30')
, CreatedBy1
, ChequeAmount
, (SELECT DATE_ADD(NOW(), INTERVAL 14 DAY))
, (SELECT DATE_ADD(NOW(), INTERVAL 14 DAY))
, 0
, (SELECT DATE_ADD(NOW(), INTERVAL 1 DAY))
FROM customercheque
WHERE (CustChqId = CustChqId1);
END;
END IF;
UPDATE customercheque
SET ReturnStatus = 1
, RealizeStatus = 0
, RtnRemark = RtnRemark1
, ReturnDate = CONVERT_TZ(now(), @@session.time_zone, '+05:30')
WHERE (CustChqId = CustChqId1);
END |
DELIMITER ;

