DELIMITER |
CREATE PROCEDURE `UpdateStockAdjustment`(in
ItemsId1 int,
ItemCode1 VARCHAR(50),
ExistingQty1 decimal(10, 2),
NewQty1 decimal(10, 2),
AdjustedQty1 decimal(10, 2),
BranchId1 int,
