)
BEGIN
INSERT INTO stocktrnsaction
(ItemsId
, ItemCode
, ExistingQty
, NewQty
, AdjustedQty
, BranchId
, CreatedOn
, CreatedBy)
VALUES (ItemsId1
, ItemCode1
, ExistingQty1
, NewQty1
, AdjustedQty1
, BranchId1
, CONVERT_TZ(now(), @@session.time_zone, '+05:30')
, UserID1);
UPDATE itemsummary
SET  AvailableQty = NewQty1
