DROP PROCEDURE IF EXISTS `UpdateStockTransferCancel`;
DELIMITER |
CREATE PROCEDURE `UpdateStockTransferCancel`(in TransferHDId1 int)
BEGIN
IF EXISTS (SELECT 1 FROM stocktransferhd WHERE (TransferHDId = TransferHDId1) AND (CancelStatus = 0)) THEN
BEGIN
UPDATE branchstock A
INNER JOIN (SELECT B.TransferHDId, B.FromBranchId, C.ItemsId, SUM(C.Qty) AS Qty
FROM stocktransferhd B
INNER JOIN stocktransferdt C
ON B.TransferHDId = C.TransferHDId
WHERE B.TransferHDId = TransferHDId1
GROUP BY B.TransferHDId, B.FromBranchId, C.ItemsId)B
ON A.ItemsId = B.ItemsId
SET A.AvailableQty =  A.AvailableQty + B.Qty
WHERE B.TransferHDId = TransferHDId1
AND A.BranchId = B.FromBranchId;
UPDATE branchstock A
INNER JOIN (SELECT B.TransferHDId, B.ToBranchId, C.ItemsId, SUM(C.Qty) AS Qty
FROM stocktransferhd B
INNER JOIN stocktransferdt C
ON B.TransferHDId = C.TransferHDId
WHERE B.TransferHDId = TransferHDId1
GROUP BY B.TransferHDId, B.ToBranchId, C.ItemsId)B
ON A.ItemsId = B.ItemsId
SET A.AvailableQty =  A.AvailableQty - B.Qty
WHERE B.TransferHDId = TransferHDId1
AND A.BranchId = B.ToBranchId;
UPDATE stocktransferhd
SET CancelStatus = 1
WHERE TransferHDId = TransferHDId1;
end;
end if;
END |
DELIMITER ;

