DROP PROCEDURE IF EXISTS `UpdateSuppCreditPayCancel`;
DELIMITER |
CREATE PROCEDURE `UpdateSuppCreditPayCancel`(in CreditPayHDId1 int)
BEGIN
IF EXISTS (SELECT 1 FROM suppcreditpaymenthd WHERE (CreditPayHDId = CreditPayHDId1) AND (CancelStatus = 0)) THEN
BEGIN
UPDATE supplier t1
INNER JOIN suppcreditpayment t2
ON t1.SupplierId = t2.SupplierId
SET t1.BalanceAmount = t1.BalanceAmount + (SELECT IFNULL((SUM(Y.PaymentAmount)), 0)
FROM suppcreditpayment Y
WHERE Y.CreditPayHDId = CreditPayHDId1)
where t2.CreditPayHDId = CreditPayHDId1;

UPDATE suppliercredit t1
INNER JOIN suppcreditpayment t2
ON t1.SupplierId = t2.SupplierId
AND t1.PIHDId = t2.BillNo
AND t1.SuppCreditId = t2.SuppCreditId
SET t1.PaymentCompletedStatus = 0
where t2.CreditPayHDId = CreditPayHDId1;

UPDATE suppliercredit t1
INNER JOIN suppcreditpayment t2
ON t1.SupplierId = t2.SupplierId
AND t1.PIHDId = t2.BillNo
AND t1.SuppCreditId = t2.SuppCreditId
SET t1.PaymentAmount = t1.PaymentAmount - (SELECT IFNULL(((Y.PaymentAmount)), 0)
FROM suppcreditpayment Y
WHERE Y.CreditPayHDId = CreditPayHDId1
AND Y.BillNo = t2.BillNo
AND Y.SuppCreditId = t2.SuppCreditId)
where t2.CreditPayHDId = CreditPayHDId1;

UPDATE suppcreditpayment
SET PaymentAmount = 0
WHERE CreditPayHDId = CreditPayHDId1;

UPDATE suppcreditpaymenthd
SET CancelStatus = 1
WHERE CreditPayHDId = CreditPayHDId1;
END;
END IF;
END |
DELIMITER ;

