DROP PROCEDURE IF EXISTS `UpdateSystemActivation`;
DELIMITER |
CREATE PROCEDURE `UpdateSystemActivation`(in
ActBillNo1 int
, ActStatus1 TINYINT(1)
, ActivationType1 VARCHAR(15)
, DevKey1 VARCHAR(45)
)
BEGIN
UPDATE sellerdetail
SET SellerCode = DevKey1
WHERE (SellerDtId = 1);
UPDATE sysactivation
SET ActBillNo = ActBillNo1
, ActStatus = 0
, ActDate = CASE ActivationType1 WHEN '1 Month' THEN (SELECT DATE_ADD(NOW(), INTERVAL 31 DAY))
WHEN '6 Months' THEN (SELECT DATE_ADD(NOW(), INTERVAL 190 DAY))
WHEN '1 Year' THEN (SELECT DATE_ADD(NOW(), INTERVAL 365 DAY))
WHEN 'Life time' THEN (SELECT DATE_ADD(NOW(), INTERVAL 900 DAY))
ELSE CONVERT_TZ(now(), @@session.time_zone, '+05:30') END
, DevKey = DevKey1
WHERE (ActId = 1);
END |
DELIMITER ;

DROP PROCEDURE IF EXISTS `UpdateTAXSales`;
DELIMITER |
CREATE PROCEDURE `UpdateTAXSales`()
BEGIN
DECLARE HalfSales DECIMAL(20,2) DEFAULT 0;
DECLARE HalfSalesSONo BIGINT DEFAULT 0;
DECLARE TempMaxSONo BIGINT DEFAULT 0;
DECLARE UTCDate1 date;
SET UTCDate1 = (select CONVERT_TZ(now(), @@session.time_zone, '+05:30'));
DROP TEMPORARY TABLE IF EXISTS tempAccuSales;
DROP TEMPORARY TABLE IF EXISTS tempTaxSales;
SET HalfSales = (SELECT SUM(SONetTotal) / 2 AS NetSales
FROM salesorderhd
WHERE (SODate = UTCDate1)
GROUP BY SODate);
SET @csum := 0;
CREATE TEMPORARY TABLE tempAccuSales ENGINE=MEMORY
AS (
SELECT SOHDId, SODate, SONetTotal, (@csum := @csum + SONetTotal) AS Acumulative_sum
FROM salesorderhd
WHERE (SODate = UTCDate1)
ORDER BY SOHDId
);
SET HalfSalesSONo =  (SELECT MAX(SOHDId) AS SOHDId
FROM tempAccuSales
WHERE (Acumulative_sum <= HalfSales));
DELETE FROM tempAccuSales
WHERE (SOHDId > HalfSalesSONo);
DELETE FROM taxsales
WHERE (SODate = UTCDate1);
CREATE TEMPORARY TABLE tempTaxSales ENGINE=MEMORY
AS (
SELECT SOHDId, SODate
FROM taxsales
);
TRUNCATE TABLE taxsales;
INSERT INTO taxsales (SOHDId, SODate)
SELECT SOHDId, SODate
FROM tempTaxSales
ORDER BY SOHDId;
INSERT INTO taxsales (SOHDId, SODate)
SELECT SOHDId, SODate
FROM tempAccuSales
ORDER BY SOHDId;
DROP TABLE tempAccuSales;
DROP TABLE tempTaxSales;
END |
DELIMITER ;

