DROP PROCEDURE IF EXISTS `UpdateVehicleLogCancel`;
DELIMITER |
CREATE PROCEDURE `UpdateVehicleLogCancel`(in VehicleMilageHDId1 int, ModifiedBy1 INT)
BEGIN
DECLARE Milage1 decimal;
DECLARE VehicleId1 INT;
IF EXISTS (SELECT 1 FROM vehiclemilagehd WHERE (VehicleMilageHDId = VehicleMilageHDId1) AND (CancelStatus = 0)) THEN
BEGIN
UPDATE vehiclemilagehd
SET CancelStatus = 1
, ModifiedBy = ModifiedBy1
, ModifiedOn = CONVERT_TZ(now(), @@session.time_zone, '+05:30')
WHERE (VehicleMilageHDId = VehicleMilageHDId1);
SELECT SUM(Milage) INTO Milage1
FROM vehiclemilagedt
WHERE (VehicleMilageHDId = VehicleMilageHDId1);
SELECT VehicleId INTO VehicleId1
FROM vehiclemilagehd
WHERE (VehicleMilageHDId = VehicleMilageHDId1);
UPDATE vehicles
SET CurrentMeeter = CurrentMeeter - Milage1
WHERE VehicleId = VehicleId1;
END;
END IF;
END |
DELIMITER ;
